window.BIBLE["John"] = {"1":{"chapter":"1","title":"IN THE BEGINNING WAS THE WORD","verses":{"1":{"text":"In the beginning was the Word, and the Word was with God, and the Word was God.","ref":"John 1:1","synthesized":"In the beginning was the Word, and the Word was with God, and the Word was God.","sources":{"KJV":{"text":"In the beginning was the Word, and the Word was with God, and the Word was God."},"BSB":{"text":"In the beginning was the Word, and the Word was with God, and the Word was God."}},"definableWords":["beginning","word","God"],"peopleInVerse":[],"kingdomLens":"John deliberately echoes Genesis 1:1. Where Genesis says 'In the beginning God,' John says 'In the beginning was the Word — and the Word was God.' Jesus is identified with the Logos: the eternal expression and reason of God, through whom everything was made. Verse 14 — 'the Word was made flesh, and dwelt (literally: tabernacled) among us' — declares the Shekinah glory has returned to Israel.","cultural":{"title":"In the beginning was the Word","detail":"The Greek 'Logos' had rich background in both Greek philosophy (Stoics, Philo) and Jewish thought ('the Word of the LORD came to...'). John fuses both: this Logos is not abstract reason — He is a person who walks among us.","sources":"SWRV Kingdom Study Protocol — synthesis from approved library (Rule 06)"}},"2":{"text":"The same was in the beginning with God.","ref":"John 1:2","synthesized":"He was with God in the beginning.","sources":{"KJV":{"text":"The same was in the beginning with God."},"BSB":{"text":"He was with God in the beginning."}},"definableWords":["God","beginning"],"peopleInVerse":[]},"3":{"text":"All things were made by him; and without him was not any thing made that was made.","ref":"John 1:3","synthesized":"Through Him all things were made, and without Him nothing was made that has been made.","sources":{"KJV":{"text":"All things were made by him; and without him was not any thing made that was made."},"BSB":{"text":"Through Him all things were made, and without Him nothing was made that has been made."}},"definableWords":["made"],"peopleInVerse":[]},"4":{"text":"In him was life; and the life was the light of men.","ref":"John 1:4","synthesized":"In Him was life, and that life was the light of men.","sources":{"KJV":{"text":"In him was life; and the life was the light of men."},"BSB":{"text":"In Him was life, and that life was the light of men."}},"definableWords":["life","light","men"],"peopleInVerse":[]},"5":{"text":"And the light shineth in darkness; and the darkness comprehended it not.","ref":"John 1:5","synthesized":"The Light shines in the darkness, and the darkness has not overcome it.","sources":{"KJV":{"text":"And the light shineth in darkness; and the darkness comprehended it not."},"BSB":{"text":"The Light shines in the darkness, and the darkness has not overcome it."}},"definableWords":["light","darkness","overcome"],"peopleInVerse":[]},"6":{"text":"There was a man sent from God, whose name was John.","ref":"John 1:6","synthesized":"There came a man who was sent from God. His name was John.","sources":{"KJV":{"text":"There was a man sent from God, whose name was John."},"BSB":{"text":"There came a man who was sent from God. His name was John."}},"definableWords":["man","God","name"],"peopleInVerse":["John"]},"7":{"text":"The same came for a witness, to bear witness of the Light, that all men through him might believe.","ref":"John 1:7","synthesized":"He came as a witness to testify about the Light, so that through him everyone might believe.","sources":{"KJV":{"text":"The same came for a witness, to bear witness of the Light, that all men through him might believe."},"BSB":{"text":"He came as a witness to testify about the Light, so that through him everyone might believe."}},"definableWords":["light"],"peopleInVerse":[]},"8":{"text":"He was not that Light, but was sent to bear witness of that Light.","ref":"John 1:8","synthesized":"He himself was not the Light, but he came to testify about the Light.","sources":{"KJV":{"text":"He was not that Light, but was sent to bear witness of that Light."},"BSB":{"text":"He himself was not the Light, but he came to testify about the Light."}},"definableWords":["light"],"peopleInVerse":[]},"9":{"text":"That was the true Light, which lighteth every man that cometh into the world.","ref":"John 1:9","synthesized":"The true Light who gives light to every man was coming into the world.","sources":{"KJV":{"text":"That was the true Light, which lighteth every man that cometh into the world."},"BSB":{"text":"The true Light who gives light to every man was coming into the world."}},"definableWords":["light","man"],"peopleInVerse":[]},"10":{"text":"He was in the world, and the world was made by him, and the world knew him not.","ref":"John 1:10","synthesized":"He was in the world, and though the world was made through Him, the world did not recognize Him.","sources":{"KJV":{"text":"He was in the world, and the world was made by him, and the world knew him not."},"BSB":{"text":"He was in the world, and though the world was made through Him, the world did not recognize Him."}},"definableWords":["made"],"peopleInVerse":[]},"11":{"text":"He came unto his own, and his own received him not.","ref":"John 1:11","synthesized":"He came to His own, and His own did not receive Him.","sources":{"KJV":{"text":"He came unto his own, and his own received him not."},"BSB":{"text":"He came to His own, and His own did not receive Him."}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"But as many as received him, to them gave he power to become the sons of God, even to them that believe on his name:","ref":"John 1:12","synthesized":"But to all who did receive Him, to those who believed in His name, He gave the right to become children of God—","sources":{"KJV":{"text":"But as many as received him, to them gave he power to become the sons of God, even to them that believe on his name:"},"BSB":{"text":"But to all who did receive Him, to those who believed in His name, He gave the right to become children of God—"}},"definableWords":["believed","name","God"],"peopleInVerse":[]},"13":{"text":"Which were born, not of blood, nor of the will of the flesh, nor of the will of man, but of God.","ref":"John 1:13","synthesized":"children born not of blood, nor of the desire or will of man, but born of God.","sources":{"KJV":{"text":"Which were born, not of blood, nor of the will of the flesh, nor of the will of man, but of God."},"BSB":{"text":"children born not of blood, nor of the desire or will of man, but born of God."}},"definableWords":["blood","or","man","God"],"peopleInVerse":[]},"14":{"text":"And the Word was made flesh, and dwelt among us, (and we beheld his glory, the glory as of the only begotten of the Father,) full of grace and truth.","ref":"John 1:14","synthesized":"The Word became flesh and made His dwelling among us. We have seen His glory, the glory of the one and only Son from the Father, full of grace and truth.","sources":{"KJV":{"text":"And the Word was made flesh, and dwelt among us, (and we beheld his glory, the glory as of the only begotten of the Father,) full of grace and truth."},"BSB":{"text":"The Word became flesh and made His dwelling among us. We have seen His glory, the glory of the one and only Son from the Father, full of grace and truth."}},"definableWords":["word","flesh","made","glory","one","Son","Father","grace","truth"],"peopleInVerse":[]},"15":{"text":"John bare witness of him, and cried, saying, This was he of whom I spake, He that cometh after me is preferred before me: for he was before me.","ref":"John 1:15","synthesized":"John testified concerning Him. He cried out, saying, “This is He of whom I said, ‘He who comes after me has surpassed me because He was before me.’”","sources":{"KJV":{"text":"John bare witness of him, and cried, saying, This was he of whom I spake, He that cometh after me is preferred before me: for he was before me."},"BSB":{"text":"John testified concerning Him. He cried out, saying, “This is He of whom I said, ‘He who comes after me has surpassed me because He was before me.’”"}},"definableWords":[],"peopleInVerse":["John"]},"16":{"text":"And of his fulness have all we received, and grace for grace.","ref":"John 1:16","synthesized":"From His fullness we have all received grace upon grace.","sources":{"KJV":{"text":"And of his fulness have all we received, and grace for grace."},"BSB":{"text":"From His fullness we have all received grace upon grace."}},"definableWords":["grace"],"peopleInVerse":[]},"17":{"text":"For the law was given by Moses, but grace and truth came by Jesus Christ.","ref":"John 1:17","synthesized":"For the law was given through Moses; grace and truth came through Jesus Christ.","sources":{"KJV":{"text":"For the law was given by Moses, but grace and truth came by Jesus Christ."},"BSB":{"text":"For the law was given through Moses; grace and truth came through Jesus Christ."}},"definableWords":["law","grace","truth","Christ"],"peopleInVerse":["Moses","Jesus"]},"18":{"text":"No man hath seen God at any time; the only begotten Son, which is in the bosom of the Father, he hath declared him.","ref":"John 1:18","synthesized":"No one has ever seen God, but the one and only Son, who is Himself God and is at the Father’s side, has made Him known.","sources":{"KJV":{"text":"No man hath seen God at any time; the only begotten Son, which is in the bosom of the Father, he hath declared him."},"BSB":{"text":"No one has ever seen God, but the one and only Son, who is Himself God and is at the Father’s side, has made Him known."}},"definableWords":["one","God","Son","Father","made"],"peopleInVerse":[]},"19":{"text":"And this is the record of John, when the Jews sent priests and Levites from Jerusalem to ask him, Who art thou?","ref":"John 1:19","synthesized":"And this was John’s testimony when the Jews of Jerusalem sent priests and Levites to ask him, “Who are you?”","sources":{"KJV":{"text":"And this is the record of John, when the Jews sent priests and Levites from Jerusalem to ask him, Who art thou?"},"BSB":{"text":"And this was John’s testimony when the Jews of Jerusalem sent priests and Levites to ask him, “Who are you?”"}},"definableWords":["Jerusalem"],"peopleInVerse":["John"]},"20":{"text":"And he confessed, and denied not; but confessed, I am not the Christ.","ref":"John 1:20","synthesized":"He did not refuse to confess, but openly declared, “I am not the Christ.”","sources":{"KJV":{"text":"And he confessed, and denied not; but confessed, I am not the Christ."},"BSB":{"text":"He did not refuse to confess, but openly declared, “I am not the Christ.”"}},"definableWords":["Christ"],"peopleInVerse":[]},"21":{"text":"And they asked him, What then? Art thou Elias? And he saith, I am not. Art thou that prophet? And he answered, No.","ref":"John 1:21","synthesized":"“Then who are you?” they inquired. “Are you Elijah?”  He said, “I am not.”  “Are you the Prophet?”  He answered, “No.”","sources":{"KJV":{"text":"And they asked him, What then? Art thou Elias? And he saith, I am not. Art thou that prophet? And he answered, No."},"BSB":{"text":"“Then who are you?” they inquired. “Are you Elijah?”  He said, “I am not.”  “Are you the Prophet?”  He answered, “No.”"}},"definableWords":["prophet"],"peopleInVerse":["Elijah"]},"22":{"text":"Then said they unto him, Who art thou? that we may give an answer to them that sent us. What sayest thou of thyself?","ref":"John 1:22","synthesized":"So they said to him, “Who are you? We need an answer for those who sent us. What do you say about yourself?”","sources":{"KJV":{"text":"Then said they unto him, Who art thou? that we may give an answer to them that sent us. What sayest thou of thyself?"},"BSB":{"text":"So they said to him, “Who are you? We need an answer for those who sent us. What do you say about yourself?”"}},"definableWords":[],"peopleInVerse":[]},"23":{"text":"He said, I am the voice of one crying in the wilderness, Make straight the way of the Lord, as said the prophet Esaias.","ref":"John 1:23","synthesized":"John replied in the words of Isaiah the prophet:  “I am a voice of one calling in the wilderness, ‘Make straight the way for the Lord.’”","sources":{"KJV":{"text":"He said, I am the voice of one crying in the wilderness, Make straight the way of the Lord, as said the prophet Esaias."},"BSB":{"text":"John replied in the words of Isaiah the prophet:  “I am a voice of one calling in the wilderness, ‘Make straight the way for the Lord.’”"}},"definableWords":["prophet","voice","one","make","way","Lord"],"peopleInVerse":["John","Isaiah"]},"24":{"text":"And they which were sent were of the Pharisees.","ref":"John 1:24","synthesized":"Then the Pharisees who had been sent","sources":{"KJV":{"text":"And they which were sent were of the Pharisees."},"BSB":{"text":"Then the Pharisees who had been sent"}},"definableWords":[],"peopleInVerse":[]},"25":{"text":"And they asked him, and said unto him, Why baptizest thou then, if thou be not that Christ, nor Elias, neither that prophet?","ref":"John 1:25","synthesized":"asked him, “Why then do you baptize, if you are not the Christ, nor Elijah, nor the Prophet?”","sources":{"KJV":{"text":"And they asked him, and said unto him, Why baptizest thou then, if thou be not that Christ, nor Elias, neither that prophet?"},"BSB":{"text":"asked him, “Why then do you baptize, if you are not the Christ, nor Elijah, nor the Prophet?”"}},"definableWords":["Christ","prophet"],"peopleInVerse":["Elijah"]},"26":{"text":"John answered them, saying, I baptize with water: but there standeth one among you, whom ye know not;","ref":"John 1:26","synthesized":"“I baptize with water,” John replied, “but among you stands One you do not know.","sources":{"KJV":{"text":"John answered them, saying, I baptize with water: but there standeth one among you, whom ye know not;"},"BSB":{"text":"“I baptize with water,” John replied, “but among you stands One you do not know."}},"definableWords":["water","one"],"peopleInVerse":["John"]},"27":{"text":"He it is, who coming after me is preferred before me, whose shoe’s latchet I am not worthy to unloose.","ref":"John 1:27","synthesized":"He is the One who comes after me, the straps of whose sandals I am not worthy to untie.”","sources":{"KJV":{"text":"He it is, who coming after me is preferred before me, whose shoe’s latchet I am not worthy to unloose."},"BSB":{"text":"He is the One who comes after me, the straps of whose sandals I am not worthy to untie.”"}},"definableWords":["one"],"peopleInVerse":[]},"28":{"text":"These things were done in Bethabara beyond Jordan, where John was baptizing.","ref":"John 1:28","synthesized":"All this happened at Bethany beyond the Jordan, where John was baptizing.","sources":{"KJV":{"text":"These things were done in Bethabara beyond Jordan, where John was baptizing."},"BSB":{"text":"All this happened at Bethany beyond the Jordan, where John was baptizing."}},"definableWords":[],"peopleInVerse":["John"]},"29":{"text":"The next day John seeth Jesus coming unto him, and saith, Behold the Lamb of God, which taketh away the sin of the world.","ref":"John 1:29","synthesized":"The next day John saw Jesus coming toward him and said, “Look, the Lamb of God, who takes away the sin of the world!","sources":{"KJV":{"text":"The next day John seeth Jesus coming unto him, and saith, Behold the Lamb of God, which taketh away the sin of the world."},"BSB":{"text":"The next day John saw Jesus coming toward him and said, “Look, the Lamb of God, who takes away the sin of the world!"}},"definableWords":["day","saw","Lamb","God","sin"],"peopleInVerse":["John","Jesus"]},"30":{"text":"This is he of whom I said, After me cometh a man which is preferred before me: for he was before me.","ref":"John 1:30","synthesized":"This is He of whom I said, ‘A man who comes after me has surpassed me because He was before me.’","sources":{"KJV":{"text":"This is he of whom I said, After me cometh a man which is preferred before me: for he was before me."},"BSB":{"text":"This is He of whom I said, ‘A man who comes after me has surpassed me because He was before me.’"}},"definableWords":["man"],"peopleInVerse":[]},"31":{"text":"And I knew him not: but that he should be made manifest to Israel, therefore am I come baptizing with water.","ref":"John 1:31","synthesized":"I myself did not know Him, but the reason I came baptizing with water was that He might be revealed to Israel.”","sources":{"KJV":{"text":"And I knew him not: but that he should be made manifest to Israel, therefore am I come baptizing with water."},"BSB":{"text":"I myself did not know Him, but the reason I came baptizing with water was that He might be revealed to Israel.”"}},"definableWords":["water","Israel"],"peopleInVerse":[]},"32":{"text":"And John bare record, saying, I saw the Spirit descending from heaven like a dove, and it abode upon him.","ref":"John 1:32","synthesized":"Then John testified, “I saw the Spirit descending from heaven like a dove and resting on Him.","sources":{"KJV":{"text":"And John bare record, saying, I saw the Spirit descending from heaven like a dove, and it abode upon him."},"BSB":{"text":"Then John testified, “I saw the Spirit descending from heaven like a dove and resting on Him."}},"definableWords":["saw","Spirit","heaven"],"peopleInVerse":["John"]},"33":{"text":"And I knew him not: but he that sent me to baptize with water, the same said unto me, Upon whom thou shalt see the Spirit descending, and remaining on him, the same is he which baptizeth with the Holy Ghost.","ref":"John 1:33","synthesized":"I myself did not know Him, but the One who sent me to baptize with water told me, ‘The man on whom you see the Spirit descend and rest is He who will baptize with the Holy Spirit.’","sources":{"KJV":{"text":"And I knew him not: but he that sent me to baptize with water, the same said unto me, Upon whom thou shalt see the Spirit descending, and remaining on him, the same is he which baptizeth with the Holy Ghost."},"BSB":{"text":"I myself did not know Him, but the One who sent me to baptize with water told me, ‘The man on whom you see the Spirit descend and rest is He who will baptize with the Holy Spirit.’"}},"definableWords":["one","water","man","see","Spirit","rest","holy","spirit"],"peopleInVerse":[]},"34":{"text":"And I saw, and bare record that this is the Son of God.","ref":"John 1:34","synthesized":"I have seen and testified that this is the Son of God.”","sources":{"KJV":{"text":"And I saw, and bare record that this is the Son of God."},"BSB":{"text":"I have seen and testified that this is the Son of God.”"}},"definableWords":["Son","God"],"peopleInVerse":[]},"35":{"text":"Again the next day after John stood, and two of his disciples;","ref":"John 1:35","synthesized":"The next day John was there again with two of his disciples.","sources":{"KJV":{"text":"Again the next day after John stood, and two of his disciples;"},"BSB":{"text":"The next day John was there again with two of his disciples."}},"definableWords":["day"],"peopleInVerse":["John"]},"36":{"text":"And looking upon Jesus as he walked, he saith, Behold the Lamb of God!","ref":"John 1:36","synthesized":"When he saw Jesus walking by, he said, “Look, the Lamb of God!”","sources":{"KJV":{"text":"And looking upon Jesus as he walked, he saith, Behold the Lamb of God!"},"BSB":{"text":"When he saw Jesus walking by, he said, “Look, the Lamb of God!”"}},"definableWords":["saw","Lamb","God"],"peopleInVerse":["Jesus"]},"37":{"text":"And the two disciples heard him speak, and they followed Jesus.","ref":"John 1:37","synthesized":"And when the two disciples heard him say this, they followed Jesus.","sources":{"KJV":{"text":"And the two disciples heard him speak, and they followed Jesus."},"BSB":{"text":"And when the two disciples heard him say this, they followed Jesus."}},"definableWords":[],"peopleInVerse":["Jesus"]},"38":{"text":"Then Jesus turned, and saw them following, and saith unto them, What seek ye? They said unto him, Rabbi, (which is to say, being interpreted, Master,) where dwellest thou?","ref":"John 1:38","synthesized":"Jesus turned and saw them following. “What do you want?” He asked.  They said to Him, “Rabbi” (which means Teacher), “where are You staying?”","sources":{"KJV":{"text":"Then Jesus turned, and saw them following, and saith unto them, What seek ye? They said unto him, Rabbi, (which is to say, being interpreted, Master,) where dwellest thou?"},"BSB":{"text":"Jesus turned and saw them following. “What do you want?” He asked.  They said to Him, “Rabbi” (which means Teacher), “where are You staying?”"}},"definableWords":["saw"],"peopleInVerse":["Jesus"]},"39":{"text":"He saith unto them, Come and see. They came and saw where he dwelt, and abode with him that day: for it was about the tenth hour.","ref":"John 1:39","synthesized":"“Come and see,” He replied. So they went and saw where He was staying, and spent that day with Him. It was about the tenth hour.","sources":{"KJV":{"text":"He saith unto them, Come and see. They came and saw where he dwelt, and abode with him that day: for it was about the tenth hour."},"BSB":{"text":"“Come and see,” He replied. So they went and saw where He was staying, and spent that day with Him. It was about the tenth hour."}},"definableWords":["see","saw","day"],"peopleInVerse":[]},"40":{"text":"One of the two which heard John speak, and followed him, was Andrew, Simon Peter’s brother.","ref":"John 1:40","synthesized":"Andrew, Simon Peter’s brother, was one of the two who heard John’s testimony and followed Jesus.","sources":{"KJV":{"text":"One of the two which heard John speak, and followed him, was Andrew, Simon Peter’s brother."},"BSB":{"text":"Andrew, Simon Peter’s brother, was one of the two who heard John’s testimony and followed Jesus."}},"definableWords":["brother","one"],"peopleInVerse":["Andrew","Peter","John","Jesus"]},"41":{"text":"He first findeth his own brother Simon, and saith unto him, We have found the Messias, which is, being interpreted, the Christ.","ref":"John 1:41","synthesized":"He first found his brother Simon and told him, “We have found the Messiah” (which is translated as Christ).","sources":{"KJV":{"text":"He first findeth his own brother Simon, and saith unto him, We have found the Messias, which is, being interpreted, the Christ."},"BSB":{"text":"He first found his brother Simon and told him, “We have found the Messiah” (which is translated as Christ)."}},"definableWords":["brother","Messiah","Christ"],"peopleInVerse":[]},"42":{"text":"And he brought him to Jesus. And when Jesus beheld him, he said, Thou art Simon the son of Jona: thou shalt be called Cephas, which is by interpretation, A stone.","ref":"John 1:42","synthesized":"Andrew brought him to Jesus, who looked at him and said, “You are Simon son of John. You will be called Cephas” (which is translated as Peter).","sources":{"KJV":{"text":"And he brought him to Jesus. And when Jesus beheld him, he said, Thou art Simon the son of Jona: thou shalt be called Cephas, which is by interpretation, A stone."},"BSB":{"text":"Andrew brought him to Jesus, who looked at him and said, “You are Simon son of John. You will be called Cephas” (which is translated as Peter)."}},"definableWords":["son"],"peopleInVerse":["Andrew","Jesus","John","Peter"]},"43":{"text":"The day following Jesus would go forth into Galilee, and findeth Philip, and saith unto him, Follow me.","ref":"John 1:43","synthesized":"The next day Jesus decided to set out for Galilee. Finding Philip, He told him, “Follow Me.”","sources":{"KJV":{"text":"The day following Jesus would go forth into Galilee, and findeth Philip, and saith unto him, Follow me."},"BSB":{"text":"The next day Jesus decided to set out for Galilee. Finding Philip, He told him, “Follow Me.”"}},"definableWords":["day","Galilee"],"peopleInVerse":["Jesus"]},"44":{"text":"Now Philip was of Bethsaida, the city of Andrew and Peter.","ref":"John 1:44","synthesized":"Now Philip was from Bethsaida, the same town as Andrew and Peter.","sources":{"KJV":{"text":"Now Philip was of Bethsaida, the city of Andrew and Peter."},"BSB":{"text":"Now Philip was from Bethsaida, the same town as Andrew and Peter."}},"definableWords":[],"peopleInVerse":["Andrew","Peter"]},"45":{"text":"Philip findeth Nathanael, and saith unto him, We have found him, of whom Moses in the law, and the prophets, did write, Jesus of Nazareth, the son of Joseph.","ref":"John 1:45","synthesized":"Philip found Nathanael and told him, “We have found the One Moses wrote about in the Law, the One the prophets foretold—Jesus of Nazareth, the son of Joseph.”","sources":{"KJV":{"text":"Philip findeth Nathanael, and saith unto him, We have found him, of whom Moses in the law, and the prophets, did write, Jesus of Nazareth, the son of Joseph."},"BSB":{"text":"Philip found Nathanael and told him, “We have found the One Moses wrote about in the Law, the One the prophets foretold—Jesus of Nazareth, the son of Joseph.”"}},"definableWords":["one","law","son","Joseph"],"peopleInVerse":["Moses","Jesus","Joseph"]},"46":{"text":"And Nathanael said unto him, Can there any good thing come out of Nazareth? Philip saith unto him, Come and see.","ref":"John 1:46","synthesized":"“Can anything good come from Nazareth?” Nathanael asked.  “Come and see,” said Philip.","sources":{"KJV":{"text":"And Nathanael said unto him, Can there any good thing come out of Nazareth? Philip saith unto him, Come and see."},"BSB":{"text":"“Can anything good come from Nazareth?” Nathanael asked.  “Come and see,” said Philip."}},"definableWords":["good","see"],"peopleInVerse":[]},"47":{"text":"Jesus saw Nathanael coming to him, and saith of him, Behold an Israelite indeed, in whom is no guile!","ref":"John 1:47","synthesized":"When Jesus saw Nathanael approaching, He said of him, “Here is a true Israelite, in whom there is no deceit.”","sources":{"KJV":{"text":"Jesus saw Nathanael coming to him, and saith of him, Behold an Israelite indeed, in whom is no guile!"},"BSB":{"text":"When Jesus saw Nathanael approaching, He said of him, “Here is a true Israelite, in whom there is no deceit.”"}},"definableWords":["saw"],"peopleInVerse":["Jesus"]},"48":{"text":"Nathanael saith unto him, Whence knowest thou me? Jesus answered and said unto him, Before that Philip called thee, when thou wast under the fig tree, I saw thee.","ref":"John 1:48","synthesized":"“How do You know me?” Nathanael asked.  Jesus replied, “Before Philip called you, I saw you under the fig tree.”","sources":{"KJV":{"text":"Nathanael saith unto him, Whence knowest thou me? Jesus answered and said unto him, Before that Philip called thee, when thou wast under the fig tree, I saw thee."},"BSB":{"text":"“How do You know me?” Nathanael asked.  Jesus replied, “Before Philip called you, I saw you under the fig tree.”"}},"definableWords":["saw","tree"],"peopleInVerse":["Jesus"]},"49":{"text":"Nathanael answered and saith unto him, Rabbi, thou art the Son of God; thou art the King of Israel.","ref":"John 1:49","synthesized":"“Rabbi,” Nathanael answered, “You are the Son of God! You are the King of Israel!”","sources":{"KJV":{"text":"Nathanael answered and saith unto him, Rabbi, thou art the Son of God; thou art the King of Israel."},"BSB":{"text":"“Rabbi,” Nathanael answered, “You are the Son of God! You are the King of Israel!”"}},"definableWords":["Son","God","King","Israel"],"peopleInVerse":[]},"50":{"text":"Jesus answered and said unto him, Because I said unto thee, I saw thee under the fig tree, believest thou? thou shalt see greater things than these.","ref":"John 1:50","synthesized":"Jesus said to him, “Do you believe just because I told you I saw you under the fig tree? You will see greater things than these.”","sources":{"KJV":{"text":"Jesus answered and said unto him, Because I said unto thee, I saw thee under the fig tree, believest thou? thou shalt see greater things than these."},"BSB":{"text":"Jesus said to him, “Do you believe just because I told you I saw you under the fig tree? You will see greater things than these.”"}},"definableWords":["saw","tree","see"],"peopleInVerse":["Jesus"]},"51":{"text":"And he saith unto him, Verily, verily, I say unto you, Hereafter ye shall see heaven open, and the angels of God ascending and descending upon the Son of man.","ref":"John 1:51","synthesized":"Then He declared, “Truly, truly, I tell you, you will all see heaven open and the angels of God ascending and descending on the Son of Man.”","sources":{"KJV":{"text":"And he saith unto him, Verily, verily, I say unto you, Hereafter ye shall see heaven open, and the angels of God ascending and descending upon the Son of man."},"BSB":{"text":"Then He declared, “Truly, truly, I tell you, you will all see heaven open and the angels of God ascending and descending on the Son of Man.”"}},"definableWords":["see","heaven","God","Son","man"],"peopleInVerse":[]}}},"2":{"chapter":"2","title":"WATER INTO WINE AT CANA","verses":{"1":{"text":"And the third day there was a marriage in Cana of Galilee; and the mother of Jesus was there:","ref":"John 2:1","synthesized":"On the third day a wedding took place at Cana in Galilee. Jesus’ mother was there,","sources":{"KJV":{"text":"And the third day there was a marriage in Cana of Galilee; and the mother of Jesus was there:"},"BSB":{"text":"On the third day a wedding took place at Cana in Galilee. Jesus’ mother was there,"}},"definableWords":["day","Galilee","mother"],"peopleInVerse":["Jesus"]},"2":{"text":"And both Jesus was called, and his disciples, to the marriage.","ref":"John 2:2","synthesized":"and Jesus and His disciples had also been invited to the wedding.","sources":{"KJV":{"text":"And both Jesus was called, and his disciples, to the marriage."},"BSB":{"text":"and Jesus and His disciples had also been invited to the wedding."}},"definableWords":[],"peopleInVerse":["Jesus"]},"3":{"text":"And when they wanted wine, the mother of Jesus saith unto him, They have no wine.","ref":"John 2:3","synthesized":"When the wine ran out, Jesus’ mother said to Him, “They have no more wine.”","sources":{"KJV":{"text":"And when they wanted wine, the mother of Jesus saith unto him, They have no wine."},"BSB":{"text":"When the wine ran out, Jesus’ mother said to Him, “They have no more wine.”"}},"definableWords":["mother"],"peopleInVerse":["Jesus"]},"4":{"text":"Jesus saith unto her, Woman, what have I to do with thee? mine hour is not yet come.","ref":"John 2:4","synthesized":"“Woman, why does this concern us?” Jesus replied. “My hour has not yet come.”","sources":{"KJV":{"text":"Jesus saith unto her, Woman, what have I to do with thee? mine hour is not yet come."},"BSB":{"text":"“Woman, why does this concern us?” Jesus replied. “My hour has not yet come.”"}},"definableWords":["woman"],"peopleInVerse":["Jesus"]},"5":{"text":"His mother saith unto the servants, Whatsoever he saith unto you, do it.","ref":"John 2:5","synthesized":"His mother said to the servants, “Do whatever He tells you.”","sources":{"KJV":{"text":"His mother saith unto the servants, Whatsoever he saith unto you, do it."},"BSB":{"text":"His mother said to the servants, “Do whatever He tells you.”"}},"definableWords":["mother","servants"],"peopleInVerse":[]},"6":{"text":"And there were set there six waterpots of stone, after the manner of the purifying of the Jews, containing two or three firkins apiece.","ref":"John 2:6","synthesized":"Now six stone water jars had been set there for the Jewish rites of purification. Each could hold from twenty to thirty gallons.","sources":{"KJV":{"text":"And there were set there six waterpots of stone, after the manner of the purifying of the Jews, containing two or three firkins apiece."},"BSB":{"text":"Now six stone water jars had been set there for the Jewish rites of purification. Each could hold from twenty to thirty gallons."}},"definableWords":["stone","water"],"peopleInVerse":[]},"7":{"text":"Jesus saith unto them, Fill the waterpots with water. And they filled them up to the brim.","ref":"John 2:7","synthesized":"Jesus told the servants, “Fill the jars with water.”  So they filled them to the brim.","sources":{"KJV":{"text":"Jesus saith unto them, Fill the waterpots with water. And they filled them up to the brim."},"BSB":{"text":"Jesus told the servants, “Fill the jars with water.”  So they filled them to the brim."}},"definableWords":["servants","fill","water"],"peopleInVerse":["Jesus"]},"8":{"text":"And he saith unto them, Draw out now, and bear unto the governor of the feast. And they bare it.","ref":"John 2:8","synthesized":"“Now draw some out,” He said, “and take it to the master of the banquet.”  They did so,","sources":{"KJV":{"text":"And he saith unto them, Draw out now, and bear unto the governor of the feast. And they bare it."},"BSB":{"text":"“Now draw some out,” He said, “and take it to the master of the banquet.”  They did so,"}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"When the ruler of the feast had tasted the water that was made wine, and knew not whence it was: (but the servants which drew the water knew;) the governor of the feast called the bridegroom,","ref":"John 2:9","synthesized":"and the master of the banquet tasted the water that had been turned into wine. He did not know where it was from, but the servants who had drawn the water knew. Then he called the bridegroom aside","sources":{"KJV":{"text":"When the ruler of the feast had tasted the water that was made wine, and knew not whence it was: (but the servants which drew the water knew;) the governor of the feast called the bridegroom,"},"BSB":{"text":"and the master of the banquet tasted the water that had been turned into wine. He did not know where it was from, but the servants who had drawn the water knew. Then he called the bridegroom aside"}},"definableWords":["water","servants"],"peopleInVerse":[]},"10":{"text":"And saith unto him, Every man at the beginning doth set forth good wine; and when men have well drunk, then that which is worse: but thou hast kept the good wine until now.","ref":"John 2:10","synthesized":"and said, “Everyone serves the fine wine first, and then the cheap wine after the guests are drunk. But you have saved the fine wine until now!”","sources":{"KJV":{"text":"And saith unto him, Every man at the beginning doth set forth good wine; and when men have well drunk, then that which is worse: but thou hast kept the good wine until now."},"BSB":{"text":"and said, “Everyone serves the fine wine first, and then the cheap wine after the guests are drunk. But you have saved the fine wine until now!”"}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"This beginning of miracles did Jesus in Cana of Galilee, and manifested forth his glory; and his disciples believed on him.","ref":"John 2:11","synthesized":"Jesus performed this, the first of His signs, at Cana in Galilee. He thus revealed His glory, and His disciples believed in Him.","sources":{"KJV":{"text":"This beginning of miracles did Jesus in Cana of Galilee, and manifested forth his glory; and his disciples believed on him."},"BSB":{"text":"Jesus performed this, the first of His signs, at Cana in Galilee. He thus revealed His glory, and His disciples believed in Him."}},"definableWords":["Galilee","glory","believed"],"peopleInVerse":["Jesus"]},"12":{"text":"After this he went down to Capernaum, he, and his mother, and his brethren, and his disciples: and they continued there not many days.","ref":"John 2:12","synthesized":"After this, He went down to Capernaum with His mother and brothers and His disciples, and they stayed there a few days.","sources":{"KJV":{"text":"After this he went down to Capernaum, he, and his mother, and his brethren, and his disciples: and they continued there not many days."},"BSB":{"text":"After this, He went down to Capernaum with His mother and brothers and His disciples, and they stayed there a few days."}},"definableWords":["mother","days"],"peopleInVerse":[]},"13":{"text":"And the Jews’ passover was at hand, and Jesus went up to Jerusalem,","ref":"John 2:13","synthesized":"When the Jewish Passover was near, Jesus went up to Jerusalem.","sources":{"KJV":{"text":"And the Jews’ passover was at hand, and Jesus went up to Jerusalem,"},"BSB":{"text":"When the Jewish Passover was near, Jesus went up to Jerusalem."}},"definableWords":["Passover","Jerusalem"],"peopleInVerse":["Jesus"]},"14":{"text":"And found in the temple those that sold oxen and sheep and doves, and the changers of money sitting:","ref":"John 2:14","synthesized":"In the temple courts He found men selling cattle, sheep, and doves, and money changers seated at their tables.","sources":{"KJV":{"text":"And found in the temple those that sold oxen and sheep and doves, and the changers of money sitting:"},"BSB":{"text":"In the temple courts He found men selling cattle, sheep, and doves, and money changers seated at their tables."}},"definableWords":["temple","men","cattle"],"peopleInVerse":[]},"15":{"text":"And when he had made a scourge of small cords, he drove them all out of the temple, and the sheep, and the oxen; and poured out the changers’ money, and overthrew the tables;","ref":"John 2:15","synthesized":"So He made a whip out of cords and drove all from the temple courts, both sheep and cattle. He poured out the coins of the money changers and overturned their tables.","sources":{"KJV":{"text":"And when he had made a scourge of small cords, he drove them all out of the temple, and the sheep, and the oxen; and poured out the changers’ money, and overthrew the tables;"},"BSB":{"text":"So He made a whip out of cords and drove all from the temple courts, both sheep and cattle. He poured out the coins of the money changers and overturned their tables."}},"definableWords":["made","temple","cattle"],"peopleInVerse":[]},"16":{"text":"And said unto them that sold doves, Take these things hence; make not my Father’s house an house of merchandise.","ref":"John 2:16","synthesized":"To those selling doves He said, “Get these out of here! How dare you turn My Father’s house into a marketplace!”","sources":{"KJV":{"text":"And said unto them that sold doves, Take these things hence; make not my Father’s house an house of merchandise."},"BSB":{"text":"To those selling doves He said, “Get these out of here! How dare you turn My Father’s house into a marketplace!”"}},"definableWords":["Father","house"],"peopleInVerse":[]},"17":{"text":"And his disciples remembered that it was written, The zeal of thine house hath eaten me up.","ref":"John 2:17","synthesized":"His disciples remembered that it is written: “Zeal for Your house will consume Me.”","sources":{"KJV":{"text":"And his disciples remembered that it was written, The zeal of thine house hath eaten me up."},"BSB":{"text":"His disciples remembered that it is written: “Zeal for Your house will consume Me.”"}},"definableWords":["remembered","house"],"peopleInVerse":[]},"18":{"text":"Then answered the Jews and said unto him, What sign shewest thou unto us, seeing that thou doest these things?","ref":"John 2:18","synthesized":"On account of this, the Jews demanded, “What sign can You show us to prove Your authority to do these things?”","sources":{"KJV":{"text":"Then answered the Jews and said unto him, What sign shewest thou unto us, seeing that thou doest these things?"},"BSB":{"text":"On account of this, the Jews demanded, “What sign can You show us to prove Your authority to do these things?”"}},"definableWords":[],"peopleInVerse":[]},"19":{"text":"Jesus answered and said unto them, Destroy this temple, and in three days I will raise it up.","ref":"John 2:19","synthesized":"Jesus answered, “Destroy this temple, and in three days I will raise it up again.”","sources":{"KJV":{"text":"Jesus answered and said unto them, Destroy this temple, and in three days I will raise it up."},"BSB":{"text":"Jesus answered, “Destroy this temple, and in three days I will raise it up again.”"}},"definableWords":["temple","days"],"peopleInVerse":["Jesus"]},"20":{"text":"Then said the Jews, Forty and six years was this temple in building, and wilt thou rear it up in three days?","ref":"John 2:20","synthesized":"“This temple took forty-six years to build,” the Jews replied, “and You are going to raise it up in three days?”","sources":{"KJV":{"text":"Then said the Jews, Forty and six years was this temple in building, and wilt thou rear it up in three days?"},"BSB":{"text":"“This temple took forty-six years to build,” the Jews replied, “and You are going to raise it up in three days?”"}},"definableWords":["temple","years","days"],"peopleInVerse":[]},"21":{"text":"But he spake of the temple of his body.","ref":"John 2:21","synthesized":"But Jesus was speaking about the temple of His body.","sources":{"KJV":{"text":"But he spake of the temple of his body."},"BSB":{"text":"But Jesus was speaking about the temple of His body."}},"definableWords":["temple"],"peopleInVerse":["Jesus"]},"22":{"text":"When therefore he was risen from the dead, his disciples remembered that he had said this unto them; and they believed the scripture, and the word which Jesus had said.","ref":"John 2:22","synthesized":"After He was raised from the dead, His disciples remembered that He had said this. Then they believed the Scripture and the word that Jesus had spoken.","sources":{"KJV":{"text":"When therefore he was risen from the dead, his disciples remembered that he had said this unto them; and they believed the scripture, and the word which Jesus had said."},"BSB":{"text":"After He was raised from the dead, His disciples remembered that He had said this. Then they believed the Scripture and the word that Jesus had spoken."}},"definableWords":["remembered","believed","word"],"peopleInVerse":["Jesus"]},"23":{"text":"Now when he was in Jerusalem at the passover, in the feast day, many believed in his name, when they saw the miracles which he did.","ref":"John 2:23","synthesized":"While He was in Jerusalem at the Passover Feast, many people saw the signs He was doing and believed in His name.","sources":{"KJV":{"text":"Now when he was in Jerusalem at the passover, in the feast day, many believed in his name, when they saw the miracles which he did."},"BSB":{"text":"While He was in Jerusalem at the Passover Feast, many people saw the signs He was doing and believed in His name."}},"definableWords":["Jerusalem","Passover","people","saw","believed","name"],"peopleInVerse":[]},"24":{"text":"But Jesus did not commit himself unto them, because he knew all men,","ref":"John 2:24","synthesized":"But Jesus did not entrust Himself to them, for He knew them all.","sources":{"KJV":{"text":"But Jesus did not commit himself unto them, because he knew all men,"},"BSB":{"text":"But Jesus did not entrust Himself to them, for He knew them all."}},"definableWords":[],"peopleInVerse":["Jesus"]},"25":{"text":"And needed not that any should testify of man: for he knew what was in man.","ref":"John 2:25","synthesized":"He did not need any testimony about man, for He knew what was in a man.","sources":{"KJV":{"text":"And needed not that any should testify of man: for he knew what was in man."},"BSB":{"text":"He did not need any testimony about man, for He knew what was in a man."}},"definableWords":["man"],"peopleInVerse":[]}}},"3":{"chapter":"3","title":"NICODEMUS AND 'GOD SO LOVED'","verses":{"1":{"text":"There was a man of the Pharisees, named Nicodemus, a ruler of the Jews:","ref":"John 3:1","synthesized":"Now there was a man of the Pharisees named Nicodemus, a leader of the Jews.","sources":{"KJV":{"text":"There was a man of the Pharisees, named Nicodemus, a ruler of the Jews:"},"BSB":{"text":"Now there was a man of the Pharisees named Nicodemus, a leader of the Jews."}},"definableWords":["man"],"peopleInVerse":[],"kingdomLens":"A Pharisee comes to Jesus at night — afraid to be seen. Jesus tells him he must be 'born again' (Greek: gennethe anothen — born from above). Their conversation produces John 3:16, the most famous verse in the Bible: 'For God so loved the world, that he gave his only begotten Son.' The 'whosoever' is unrestricted. The 'world' includes the prostitute, the tax collector, the Roman soldier, the Pharisee at night.","cultural":{"title":"Nicodemus by night and 'God so loved'","detail":"Nicodemus appears three times in John — chapter 3 (night), chapter 7 (defending Jesus tentatively), chapter 19 (bringing 100 pounds of spices to bury Jesus, in broad daylight). His journey from secret seeker to public disciple is one of the great quiet transformations in the Gospels.","sources":"SWRV Kingdom Study Protocol — synthesis from approved library (Rule 06)"}},"2":{"text":"The same came to Jesus by night, and said unto him, Rabbi, we know that thou art a teacher come from God: for no man can do these miracles that thou doest, except God be with him.","ref":"John 3:2","synthesized":"He came to Jesus at night and said, “Rabbi, we know that You are a teacher who has come from God. For no one could perform the signs You are doing if God were not with him.”","sources":{"KJV":{"text":"The same came to Jesus by night, and said unto him, Rabbi, we know that thou art a teacher come from God: for no man can do these miracles that thou doest, except God be with him."},"BSB":{"text":"He came to Jesus at night and said, “Rabbi, we know that You are a teacher who has come from God. For no one could perform the signs You are doing if God were not with him.”"}},"definableWords":["night","God","one"],"peopleInVerse":["Jesus"]},"3":{"text":"Jesus answered and said unto him, Verily, verily, I say unto thee, Except a man be born again, he cannot see the kingdom of God.","ref":"John 3:3","synthesized":"Jesus replied, “Truly, truly, I tell you, no one can see the kingdom of God unless he is born again.”","sources":{"KJV":{"text":"Jesus answered and said unto him, Verily, verily, I say unto thee, Except a man be born again, he cannot see the kingdom of God."},"BSB":{"text":"Jesus replied, “Truly, truly, I tell you, no one can see the kingdom of God unless he is born again.”"}},"definableWords":["one","see","kingdom","God"],"peopleInVerse":["Jesus"]},"4":{"text":"Nicodemus saith unto him, How can a man be born when he is old? can he enter the second time into his mother’s womb, and be born?","ref":"John 3:4","synthesized":"“How can a man be born when he is old?” Nicodemus asked. “Can he enter his mother’s womb a second time to be born?”","sources":{"KJV":{"text":"Nicodemus saith unto him, How can a man be born when he is old? can he enter the second time into his mother’s womb, and be born?"},"BSB":{"text":"“How can a man be born when he is old?” Nicodemus asked. “Can he enter his mother’s womb a second time to be born?”"}},"definableWords":["man","mother"],"peopleInVerse":[]},"5":{"text":"Jesus answered, Verily, verily, I say unto thee, Except a man be born of water and of the Spirit, he cannot enter into the kingdom of God.","ref":"John 3:5","synthesized":"Jesus answered, “Truly, truly, I tell you, no one can enter the kingdom of God unless he is born of water and the Spirit.","sources":{"KJV":{"text":"Jesus answered, Verily, verily, I say unto thee, Except a man be born of water and of the Spirit, he cannot enter into the kingdom of God."},"BSB":{"text":"Jesus answered, “Truly, truly, I tell you, no one can enter the kingdom of God unless he is born of water and the Spirit."}},"definableWords":["one","kingdom","God","water","Spirit"],"peopleInVerse":["Jesus"]},"6":{"text":"That which is born of the flesh is flesh; and that which is born of the Spirit is spirit.","ref":"John 3:6","synthesized":"Flesh is born of flesh, but spirit is born of the Spirit.","sources":{"KJV":{"text":"That which is born of the flesh is flesh; and that which is born of the Spirit is spirit."},"BSB":{"text":"Flesh is born of flesh, but spirit is born of the Spirit."}},"definableWords":["flesh","spirit","Spirit"],"peopleInVerse":[]},"7":{"text":"Marvel not that I said unto thee, Ye must be born again.","ref":"John 3:7","synthesized":"Do not be amazed that I said, ‘You must be born again.’","sources":{"KJV":{"text":"Marvel not that I said unto thee, Ye must be born again."},"BSB":{"text":"Do not be amazed that I said, ‘You must be born again.’"}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"The wind bloweth where it listeth, and thou hearest the sound thereof, but canst not tell whence it cometh, and whither it goeth: so is every one that is born of the Spirit.","ref":"John 3:8","synthesized":"The wind blows where it wishes. You hear its sound, but you do not know where it comes from or where it is going. So it is with everyone born of the Spirit.”","sources":{"KJV":{"text":"The wind bloweth where it listeth, and thou hearest the sound thereof, but canst not tell whence it cometh, and whither it goeth: so is every one that is born of the Spirit."},"BSB":{"text":"The wind blows where it wishes. You hear its sound, but you do not know where it comes from or where it is going. So it is with everyone born of the Spirit.”"}},"definableWords":["hear","or","Spirit"],"peopleInVerse":[]},"9":{"text":"Nicodemus answered and said unto him, How can these things be?","ref":"John 3:9","synthesized":"“How can this be?” Nicodemus asked.","sources":{"KJV":{"text":"Nicodemus answered and said unto him, How can these things be?"},"BSB":{"text":"“How can this be?” Nicodemus asked."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"Jesus answered and said unto him, Art thou a master of Israel, and knowest not these things?","ref":"John 3:10","synthesized":"“You are Israel’s teacher,” said Jesus, “and you do not understand these things?","sources":{"KJV":{"text":"Jesus answered and said unto him, Art thou a master of Israel, and knowest not these things?"},"BSB":{"text":"“You are Israel’s teacher,” said Jesus, “and you do not understand these things?"}},"definableWords":["Israel"],"peopleInVerse":["Jesus"]},"11":{"text":"Verily, verily, I say unto thee, We speak that we do know, and testify that we have seen; and ye receive not our witness.","ref":"John 3:11","synthesized":"Truly, truly, I tell you, we speak of what we know, and we testify to what we have seen, and yet you people do not accept our testimony.","sources":{"KJV":{"text":"Verily, verily, I say unto thee, We speak that we do know, and testify that we have seen; and ye receive not our witness."},"BSB":{"text":"Truly, truly, I tell you, we speak of what we know, and we testify to what we have seen, and yet you people do not accept our testimony."}},"definableWords":["people"],"peopleInVerse":[]},"12":{"text":"If I have told you earthly things, and ye believe not, how shall ye believe, if I tell you of heavenly things?","ref":"John 3:12","synthesized":"If I have told you about earthly things and you do not believe, how will you believe if I tell you about heavenly things?","sources":{"KJV":{"text":"If I have told you earthly things, and ye believe not, how shall ye believe, if I tell you of heavenly things?"},"BSB":{"text":"If I have told you about earthly things and you do not believe, how will you believe if I tell you about heavenly things?"}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"And no man hath ascended up to heaven, but he that came down from heaven, even the Son of man which is in heaven.","ref":"John 3:13","synthesized":"No one has ascended into heaven except the One who descended from heaven—the Son of Man.","sources":{"KJV":{"text":"And no man hath ascended up to heaven, but he that came down from heaven, even the Son of man which is in heaven."},"BSB":{"text":"No one has ascended into heaven except the One who descended from heaven—the Son of Man."}},"definableWords":["one","heaven","Son","man"],"peopleInVerse":[]},"14":{"text":"And as Moses lifted up the serpent in the wilderness, even so must the Son of man be lifted up:","ref":"John 3:14","synthesized":"Just as Moses lifted up the snake in the wilderness, so the Son of Man must be lifted up,","sources":{"KJV":{"text":"And as Moses lifted up the serpent in the wilderness, even so must the Son of man be lifted up:"},"BSB":{"text":"Just as Moses lifted up the snake in the wilderness, so the Son of Man must be lifted up,"}},"definableWords":["Son","man"],"peopleInVerse":["Moses"]},"15":{"text":"That whosoever believeth in him should not perish, but have eternal life.","ref":"John 3:15","synthesized":"that everyone who believes in Him may have eternal life.","sources":{"KJV":{"text":"That whosoever believeth in him should not perish, but have eternal life."},"BSB":{"text":"that everyone who believes in Him may have eternal life."}},"definableWords":["eternal","life"],"peopleInVerse":[]},"16":{"text":"For God so loved the world, that he gave his only begotten Son, that whosoever believeth in him should not perish, but have everlasting life.","ref":"John 3:16","synthesized":"For God so loved the world that He gave His one and only Son, that everyone who believes in Him shall not perish but have eternal life.","sources":{"KJV":{"text":"For God so loved the world, that he gave his only begotten Son, that whosoever believeth in him should not perish, but have everlasting life."},"BSB":{"text":"For God so loved the world that He gave His one and only Son, that everyone who believes in Him shall not perish but have eternal life."}},"definableWords":["God","one","Son","eternal","life"],"peopleInVerse":[]},"17":{"text":"For God sent not his Son into the world to condemn the world; but that the world through him might be saved.","ref":"John 3:17","synthesized":"For God did not send His Son into the world to condemn the world, but to save the world through Him.","sources":{"KJV":{"text":"For God sent not his Son into the world to condemn the world; but that the world through him might be saved."},"BSB":{"text":"For God did not send His Son into the world to condemn the world, but to save the world through Him."}},"definableWords":["God","Son"],"peopleInVerse":[]},"18":{"text":"He that believeth on him is not condemned: but he that believeth not is condemned already, because he hath not believed in the name of the only begotten Son of God.","ref":"John 3:18","synthesized":"Whoever believes in Him is not condemned, but whoever does not believe has already been condemned, because he has not believed in the name of God’s one and only Son.","sources":{"KJV":{"text":"He that believeth on him is not condemned: but he that believeth not is condemned already, because he hath not believed in the name of the only begotten Son of God."},"BSB":{"text":"Whoever believes in Him is not condemned, but whoever does not believe has already been condemned, because he has not believed in the name of God’s one and only Son."}},"definableWords":["believed","name","God","one","Son"],"peopleInVerse":[]},"19":{"text":"And this is the condemnation, that light is come into the world, and men loved darkness rather than light, because their deeds were evil.","ref":"John 3:19","synthesized":"And this is the verdict: The Light has come into the world, but men loved the darkness rather than the Light because their deeds were evil.","sources":{"KJV":{"text":"And this is the condemnation, that light is come into the world, and men loved darkness rather than light, because their deeds were evil."},"BSB":{"text":"And this is the verdict: The Light has come into the world, but men loved the darkness rather than the Light because their deeds were evil."}},"definableWords":["light","men","darkness","evil"],"peopleInVerse":[]},"20":{"text":"For every one that doeth evil hateth the light, neither cometh to the light, lest his deeds should be reproved.","ref":"John 3:20","synthesized":"Everyone who does evil hates the Light, and does not come into the Light for fear that his deeds will be exposed.","sources":{"KJV":{"text":"For every one that doeth evil hateth the light, neither cometh to the light, lest his deeds should be reproved."},"BSB":{"text":"Everyone who does evil hates the Light, and does not come into the Light for fear that his deeds will be exposed."}},"definableWords":["evil","light","fear"],"peopleInVerse":[]},"21":{"text":"But he that doeth truth cometh to the light, that his deeds may be made manifest, that they are wrought in God.","ref":"John 3:21","synthesized":"But whoever practices the truth comes into the Light, so that it may be seen clearly that what he has done has been accomplished in God.”","sources":{"KJV":{"text":"But he that doeth truth cometh to the light, that his deeds may be made manifest, that they are wrought in God."},"BSB":{"text":"But whoever practices the truth comes into the Light, so that it may be seen clearly that what he has done has been accomplished in God.”"}},"definableWords":["truth","light","God"],"peopleInVerse":[]},"22":{"text":"After these things came Jesus and his disciples into the land of Judaea; and there he tarried with them, and baptized.","ref":"John 3:22","synthesized":"After this, Jesus and His disciples went into the Judean countryside, where He spent some time with them and baptized.","sources":{"KJV":{"text":"After these things came Jesus and his disciples into the land of Judaea; and there he tarried with them, and baptized."},"BSB":{"text":"After this, Jesus and His disciples went into the Judean countryside, where He spent some time with them and baptized."}},"definableWords":[],"peopleInVerse":["Jesus"]},"23":{"text":"And John also was baptizing in Aenon near to Salim, because there was much water there: and they came, and were baptized.","ref":"John 3:23","synthesized":"Now John was also baptizing at Aenon near Salim, because the water was plentiful there, and people kept coming to be baptized.","sources":{"KJV":{"text":"And John also was baptizing in Aenon near to Salim, because there was much water there: and they came, and were baptized."},"BSB":{"text":"Now John was also baptizing at Aenon near Salim, because the water was plentiful there, and people kept coming to be baptized."}},"definableWords":["water","people"],"peopleInVerse":["John"]},"24":{"text":"For John was not yet cast into prison.","ref":"John 3:24","synthesized":"(For John had not yet been thrown into prison.)","sources":{"KJV":{"text":"For John was not yet cast into prison."},"BSB":{"text":"(For John had not yet been thrown into prison.)"}},"definableWords":[],"peopleInVerse":["John"]},"25":{"text":"Then there arose a question between some of John’s disciples and the Jews about purifying.","ref":"John 3:25","synthesized":"Then a dispute arose between John’s disciples and a certain Jew over the issue of ceremonial washing.","sources":{"KJV":{"text":"Then there arose a question between some of John’s disciples and the Jews about purifying."},"BSB":{"text":"Then a dispute arose between John’s disciples and a certain Jew over the issue of ceremonial washing."}},"definableWords":["Jew"],"peopleInVerse":["John"]},"26":{"text":"And they came unto John, and said unto him, Rabbi, he that was with thee beyond Jordan, to whom thou barest witness, behold, the same baptizeth, and all men come to him.","ref":"John 3:26","synthesized":"So John’s disciples came to him and said, “Look, Rabbi, the One who was with you beyond the Jordan, the One you testified about—He is baptizing, and everyone is going to Him.”","sources":{"KJV":{"text":"And they came unto John, and said unto him, Rabbi, he that was with thee beyond Jordan, to whom thou barest witness, behold, the same baptizeth, and all men come to him."},"BSB":{"text":"So John’s disciples came to him and said, “Look, Rabbi, the One who was with you beyond the Jordan, the One you testified about—He is baptizing, and everyone is going to Him.”"}},"definableWords":["one"],"peopleInVerse":["John"]},"27":{"text":"John answered and said, A man can receive nothing, except it be given him from heaven.","ref":"John 3:27","synthesized":"John replied, “A man can receive only what is given him from heaven.","sources":{"KJV":{"text":"John answered and said, A man can receive nothing, except it be given him from heaven."},"BSB":{"text":"John replied, “A man can receive only what is given him from heaven."}},"definableWords":["man","heaven"],"peopleInVerse":["John"]},"28":{"text":"Ye yourselves bear me witness, that I said, I am not the Christ, but that I am sent before him.","ref":"John 3:28","synthesized":"You yourselves can testify that I said, ‘I am not the Christ, but am sent ahead of Him.’","sources":{"KJV":{"text":"Ye yourselves bear me witness, that I said, I am not the Christ, but that I am sent before him."},"BSB":{"text":"You yourselves can testify that I said, ‘I am not the Christ, but am sent ahead of Him.’"}},"definableWords":["Christ"],"peopleInVerse":[]},"29":{"text":"He that hath the bride is the bridegroom: but the friend of the bridegroom, which standeth and heareth him, rejoiceth greatly because of the bridegroom’s voice: this my joy therefore is fulfilled.","ref":"John 3:29","synthesized":"The bride belongs to the bridegroom. The friend of the bridegroom stands and listens for him, and is overjoyed to hear the bridegroom’s voice. That joy is mine, and it is now complete.","sources":{"KJV":{"text":"He that hath the bride is the bridegroom: but the friend of the bridegroom, which standeth and heareth him, rejoiceth greatly because of the bridegroom’s voice: this my joy therefore is fulfilled."},"BSB":{"text":"The bride belongs to the bridegroom. The friend of the bridegroom stands and listens for him, and is overjoyed to hear the bridegroom’s voice. That joy is mine, and it is now complete."}},"definableWords":["hear","voice","joy"],"peopleInVerse":[]},"30":{"text":"He must increase, but I must decrease.","ref":"John 3:30","synthesized":"He must increase; I must decrease.","sources":{"KJV":{"text":"He must increase, but I must decrease."},"BSB":{"text":"He must increase; I must decrease."}},"definableWords":[],"peopleInVerse":[]},"31":{"text":"He that cometh from above is above all: he that is of the earth is earthly, and speaketh of the earth: he that cometh from heaven is above all.","ref":"John 3:31","synthesized":"The One who comes from above is above all. The one who is from the earth belongs to the earth and speaks as one from the earth. The One who comes from heaven is above all.","sources":{"KJV":{"text":"He that cometh from above is above all: he that is of the earth is earthly, and speaketh of the earth: he that cometh from heaven is above all."},"BSB":{"text":"The One who comes from above is above all. The one who is from the earth belongs to the earth and speaks as one from the earth. The One who comes from heaven is above all."}},"definableWords":["one","earth","heaven"],"peopleInVerse":[]},"32":{"text":"And what he hath seen and heard, that he testifieth; and no man receiveth his testimony.","ref":"John 3:32","synthesized":"He testifies to what He has seen and heard, yet no one accepts His testimony.","sources":{"KJV":{"text":"And what he hath seen and heard, that he testifieth; and no man receiveth his testimony."},"BSB":{"text":"He testifies to what He has seen and heard, yet no one accepts His testimony."}},"definableWords":["one"],"peopleInVerse":[]},"33":{"text":"He that hath received his testimony hath set to his seal that God is true.","ref":"John 3:33","synthesized":"Whoever accepts His testimony has certified that God is truthful.","sources":{"KJV":{"text":"He that hath received his testimony hath set to his seal that God is true."},"BSB":{"text":"Whoever accepts His testimony has certified that God is truthful."}},"definableWords":["God"],"peopleInVerse":[]},"34":{"text":"For he whom God hath sent speaketh the words of God: for God giveth not the Spirit by measure unto him.","ref":"John 3:34","synthesized":"For the One whom God has sent speaks the words of God, for God gives the Spirit without limit.","sources":{"KJV":{"text":"For he whom God hath sent speaketh the words of God: for God giveth not the Spirit by measure unto him."},"BSB":{"text":"For the One whom God has sent speaks the words of God, for God gives the Spirit without limit."}},"definableWords":["one","God","Spirit"],"peopleInVerse":[]},"35":{"text":"The Father loveth the Son, and hath given all things into his hand.","ref":"John 3:35","synthesized":"The Father loves the Son and has placed all things in His hands.","sources":{"KJV":{"text":"The Father loveth the Son, and hath given all things into his hand."},"BSB":{"text":"The Father loves the Son and has placed all things in His hands."}},"definableWords":["Father","Son"],"peopleInVerse":[]},"36":{"text":"He that believeth on the Son hath everlasting life: and he that believeth not the Son shall not see life; but the wrath of God abideth on him.","ref":"John 3:36","synthesized":"Whoever believes in the Son has eternal life. Whoever rejects the Son will not see life. Instead, the wrath of God remains on him.”","sources":{"KJV":{"text":"He that believeth on the Son hath everlasting life: and he that believeth not the Son shall not see life; but the wrath of God abideth on him."},"BSB":{"text":"Whoever believes in the Son has eternal life. Whoever rejects the Son will not see life. Instead, the wrath of God remains on him.”"}},"definableWords":["Son","eternal","life","see","wrath","God"],"peopleInVerse":[]}}},"4":{"chapter":"4","title":"THE WOMAN AT THE WELL","verses":{"1":{"text":"When therefore the LORD knew how the Pharisees had heard that Jesus made and baptized more disciples than John,","ref":"John 4:1","synthesized":"When Jesus realized that the Pharisees were aware He was gaining and baptizing more disciples than John","sources":{"KJV":{"text":"When therefore the LORD knew how the Pharisees had heard that Jesus made and baptized more disciples than John,"},"BSB":{"text":"When Jesus realized that the Pharisees were aware He was gaining and baptizing more disciples than John"}},"definableWords":[],"peopleInVerse":["Jesus","John"],"kingdomLens":"Jesus deliberately goes through Samaria (most Jews bypassed it). He meets a Samaritan woman at Jacob's well — a woman who came at noon (avoiding the morning crowd, probably because of her reputation). He asks her for a drink. He knows about her five husbands. She runs and brings the whole city. She becomes the first evangelist to the Samaritans. The Gospel jumps the racial barrier on day one of Jesus' ministry.","cultural":{"title":"The woman at the well","detail":"Samaritans were despised by Jews — a mixed-race remnant of the Northern Kingdom mingled with Assyrian settlers. Jews would walk extra days around Samaria. Jesus went STRAIGHT THROUGH it. The woman's response to revelation: she left her water pot (4:28) — she came thirsty, left filled.","sources":"SWRV Kingdom Study Protocol — synthesis from approved library (Rule 06)"}},"2":{"text":"(Though Jesus himself baptized not, but his disciples,)","ref":"John 4:2","synthesized":"(although it was not Jesus who baptized, but His disciples),","sources":{"KJV":{"text":"(Though Jesus himself baptized not, but his disciples,)"},"BSB":{"text":"(although it was not Jesus who baptized, but His disciples),"}},"definableWords":[],"peopleInVerse":["Jesus"]},"3":{"text":"He left Judaea, and departed again into Galilee.","ref":"John 4:3","synthesized":"He left Judea and returned to Galilee.","sources":{"KJV":{"text":"He left Judaea, and departed again into Galilee."},"BSB":{"text":"He left Judea and returned to Galilee."}},"definableWords":["Judea","Galilee"],"peopleInVerse":[]},"4":{"text":"And he must needs go through Samaria.","ref":"John 4:4","synthesized":"Now He had to pass through Samaria.","sources":{"KJV":{"text":"And he must needs go through Samaria."},"BSB":{"text":"Now He had to pass through Samaria."}},"definableWords":["Samaria"],"peopleInVerse":[]},"5":{"text":"Then cometh he to a city of Samaria, which is called Sychar, near to the parcel of ground that Jacob gave to his son Joseph.","ref":"John 4:5","synthesized":"So He came to a town of Samaria called Sychar, near the plot of ground that Jacob had given to his son Joseph.","sources":{"KJV":{"text":"Then cometh he to a city of Samaria, which is called Sychar, near to the parcel of ground that Jacob gave to his son Joseph."},"BSB":{"text":"So He came to a town of Samaria called Sychar, near the plot of ground that Jacob had given to his son Joseph."}},"definableWords":["Samaria","ground","Jacob","son","Joseph"],"peopleInVerse":["Jacob","Joseph"]},"6":{"text":"Now Jacob’s well was there. Jesus therefore, being wearied with his journey, sat thus on the well: and it was about the sixth hour.","ref":"John 4:6","synthesized":"Since Jacob’s well was there, Jesus, weary from His journey, sat down by the well. It was about the sixth hour.","sources":{"KJV":{"text":"Now Jacob’s well was there. Jesus therefore, being wearied with his journey, sat thus on the well: and it was about the sixth hour."},"BSB":{"text":"Since Jacob’s well was there, Jesus, weary from His journey, sat down by the well. It was about the sixth hour."}},"definableWords":["Jacob"],"peopleInVerse":["Jacob","Jesus"]},"7":{"text":"There cometh a woman of Samaria to draw water: Jesus saith unto her, Give me to drink.","ref":"John 4:7","synthesized":"When a Samaritan woman came to draw water, Jesus said to her, “Give Me a drink.”","sources":{"KJV":{"text":"There cometh a woman of Samaria to draw water: Jesus saith unto her, Give me to drink."},"BSB":{"text":"When a Samaritan woman came to draw water, Jesus said to her, “Give Me a drink.”"}},"definableWords":["woman","water"],"peopleInVerse":["Jesus"]},"8":{"text":"(For his disciples were gone away unto the city to buy meat.)","ref":"John 4:8","synthesized":"(His disciples had gone into the town to buy food.)","sources":{"KJV":{"text":"(For his disciples were gone away unto the city to buy meat.)"},"BSB":{"text":"(His disciples had gone into the town to buy food.)"}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"Then saith the woman of Samaria unto him, How is it that thou, being a Jew, askest drink of me, which am a woman of Samaria? for the Jews have no dealings with the Samaritans.","ref":"John 4:9","synthesized":"“You are a Jew,” said the woman. “How can You ask for a drink from me, a Samaritan woman?” (For Jews do not associate with Samaritans.)","sources":{"KJV":{"text":"Then saith the woman of Samaria unto him, How is it that thou, being a Jew, askest drink of me, which am a woman of Samaria? for the Jews have no dealings with the Samaritans."},"BSB":{"text":"“You are a Jew,” said the woman. “How can You ask for a drink from me, a Samaritan woman?” (For Jews do not associate with Samaritans.)"}},"definableWords":["Jew","woman"],"peopleInVerse":[]},"10":{"text":"Jesus answered and said unto her, If thou knewest the gift of God, and who it is that saith to thee, Give me to drink; thou wouldest have asked of him, and he would have given thee living water.","ref":"John 4:10","synthesized":"Jesus answered, “If you knew the gift of God and who is asking you for a drink, you would have asked Him, and He would have given you living water.”","sources":{"KJV":{"text":"Jesus answered and said unto her, If thou knewest the gift of God, and who it is that saith to thee, Give me to drink; thou wouldest have asked of him, and he would have given thee living water."},"BSB":{"text":"Jesus answered, “If you knew the gift of God and who is asking you for a drink, you would have asked Him, and He would have given you living water.”"}},"definableWords":["God","living","water"],"peopleInVerse":["Jesus"]},"11":{"text":"The woman saith unto him, Sir, thou hast nothing to draw with, and the well is deep: from whence then hast thou that living water?","ref":"John 4:11","synthesized":"“Sir,” the woman replied, “You have nothing to draw with and the well is deep. Where then will You get this living water?","sources":{"KJV":{"text":"The woman saith unto him, Sir, thou hast nothing to draw with, and the well is deep: from whence then hast thou that living water?"},"BSB":{"text":"“Sir,” the woman replied, “You have nothing to draw with and the well is deep. Where then will You get this living water?"}},"definableWords":["woman","deep","living","water"],"peopleInVerse":[]},"12":{"text":"Art thou greater than our father Jacob, which gave us the well, and drank thereof himself, and his children, and his cattle?","ref":"John 4:12","synthesized":"Are You greater than our father Jacob, who gave us this well and drank from it himself, as did his sons and his livestock?”","sources":{"KJV":{"text":"Art thou greater than our father Jacob, which gave us the well, and drank thereof himself, and his children, and his cattle?"},"BSB":{"text":"Are You greater than our father Jacob, who gave us this well and drank from it himself, as did his sons and his livestock?”"}},"definableWords":["father","Jacob","sons"],"peopleInVerse":["Jacob"]},"13":{"text":"Jesus answered and said unto her, Whosoever drinketh of this water shall thirst again:","ref":"John 4:13","synthesized":"Jesus said to her, “Everyone who drinks this water will be thirsty again.","sources":{"KJV":{"text":"Jesus answered and said unto her, Whosoever drinketh of this water shall thirst again:"},"BSB":{"text":"Jesus said to her, “Everyone who drinks this water will be thirsty again."}},"definableWords":["water"],"peopleInVerse":["Jesus"]},"14":{"text":"But whosoever drinketh of the water that I shall give him shall never thirst; but the water that I shall give him shall be in him a well of water springing up into everlasting life.","ref":"John 4:14","synthesized":"But whoever drinks the water I give him will never thirst. Indeed, the water I give him will become in him a fount of water springing up to eternal life.”","sources":{"KJV":{"text":"But whosoever drinketh of the water that I shall give him shall never thirst; but the water that I shall give him shall be in him a well of water springing up into everlasting life."},"BSB":{"text":"But whoever drinks the water I give him will never thirst. Indeed, the water I give him will become in him a fount of water springing up to eternal life.”"}},"definableWords":["water","eternal","life"],"peopleInVerse":[]},"15":{"text":"The woman saith unto him, Sir, give me this water, that I thirst not, neither come hither to draw.","ref":"John 4:15","synthesized":"The woman said to Him, “Sir, give me this water so that I will not get thirsty and have to keep coming here to draw water.”","sources":{"KJV":{"text":"The woman saith unto him, Sir, give me this water, that I thirst not, neither come hither to draw."},"BSB":{"text":"The woman said to Him, “Sir, give me this water so that I will not get thirsty and have to keep coming here to draw water.”"}},"definableWords":["woman","water","keep"],"peopleInVerse":[]},"16":{"text":"Jesus saith unto her, Go, call thy husband, and come hither.","ref":"John 4:16","synthesized":"Jesus told her, “Go, call your husband and come back.”","sources":{"KJV":{"text":"Jesus saith unto her, Go, call thy husband, and come hither."},"BSB":{"text":"Jesus told her, “Go, call your husband and come back.”"}},"definableWords":["husband"],"peopleInVerse":["Jesus"]},"17":{"text":"The woman answered and said, I have no husband. Jesus said unto her, Thou hast well said, I have no husband:","ref":"John 4:17","synthesized":"“I have no husband,” the woman replied.  Jesus said to her, “You are correct to say that you have no husband.","sources":{"KJV":{"text":"The woman answered and said, I have no husband. Jesus said unto her, Thou hast well said, I have no husband:"},"BSB":{"text":"“I have no husband,” the woman replied.  Jesus said to her, “You are correct to say that you have no husband."}},"definableWords":["husband","woman"],"peopleInVerse":["Jesus"]},"18":{"text":"For thou hast had five husbands; and he whom thou now hast is not thy husband: in that saidst thou truly.","ref":"John 4:18","synthesized":"In fact, you have had five husbands, and the man you now have is not your husband. You have spoken truthfully.”","sources":{"KJV":{"text":"For thou hast had five husbands; and he whom thou now hast is not thy husband: in that saidst thou truly."},"BSB":{"text":"In fact, you have had five husbands, and the man you now have is not your husband. You have spoken truthfully.”"}},"definableWords":["man","husband"],"peopleInVerse":[]},"19":{"text":"The woman saith unto him, Sir, I perceive that thou art a prophet.","ref":"John 4:19","synthesized":"“Sir,” the woman said, “I see that You are a prophet.","sources":{"KJV":{"text":"The woman saith unto him, Sir, I perceive that thou art a prophet."},"BSB":{"text":"“Sir,” the woman said, “I see that You are a prophet."}},"definableWords":["woman","see","prophet"],"peopleInVerse":[]},"20":{"text":"Our fathers worshipped in this mountain; and ye say, that in Jerusalem is the place where men ought to worship.","ref":"John 4:20","synthesized":"Our fathers worshiped on this mountain, but you Jews say that the place where one must worship is in Jerusalem.”","sources":{"KJV":{"text":"Our fathers worshipped in this mountain; and ye say, that in Jerusalem is the place where men ought to worship."},"BSB":{"text":"Our fathers worshiped on this mountain, but you Jews say that the place where one must worship is in Jerusalem.”"}},"definableWords":["fathers","one","worship","Jerusalem"],"peopleInVerse":[]},"21":{"text":"Jesus saith unto her, Woman, believe me, the hour cometh, when ye shall neither in this mountain, nor yet at Jerusalem, worship the Father.","ref":"John 4:21","synthesized":"“Believe Me, woman,” Jesus replied, “a time is coming when you will worship the Father neither on this mountain nor in Jerusalem.","sources":{"KJV":{"text":"Jesus saith unto her, Woman, believe me, the hour cometh, when ye shall neither in this mountain, nor yet at Jerusalem, worship the Father."},"BSB":{"text":"“Believe Me, woman,” Jesus replied, “a time is coming when you will worship the Father neither on this mountain nor in Jerusalem."}},"definableWords":["woman","worship","Father","Jerusalem"],"peopleInVerse":["Jesus"]},"22":{"text":"Ye worship ye know not what: we know what we worship: for salvation is of the Jews.","ref":"John 4:22","synthesized":"You worship what you do not know; we worship what we do know, for salvation is from the Jews.","sources":{"KJV":{"text":"Ye worship ye know not what: we know what we worship: for salvation is of the Jews."},"BSB":{"text":"You worship what you do not know; we worship what we do know, for salvation is from the Jews."}},"definableWords":["worship","salvation"],"peopleInVerse":[]},"23":{"text":"But the hour cometh, and now is, when the true worshippers shall worship the Father in spirit and in truth: for the Father seeketh such to worship him.","ref":"John 4:23","synthesized":"But a time is coming and has now come when the true worshipers will worship the Father in spirit and in truth, for the Father is seeking such as these to worship Him.","sources":{"KJV":{"text":"But the hour cometh, and now is, when the true worshippers shall worship the Father in spirit and in truth: for the Father seeketh such to worship him."},"BSB":{"text":"But a time is coming and has now come when the true worshipers will worship the Father in spirit and in truth, for the Father is seeking such as these to worship Him."}},"definableWords":["worship","Father","spirit","truth"],"peopleInVerse":[]},"24":{"text":"God is a Spirit: and they that worship him must worship him in spirit and in truth.","ref":"John 4:24","synthesized":"God is Spirit, and His worshipers must worship Him in spirit and in truth.”","sources":{"KJV":{"text":"God is a Spirit: and they that worship him must worship him in spirit and in truth."},"BSB":{"text":"God is Spirit, and His worshipers must worship Him in spirit and in truth.”"}},"definableWords":["God","Spirit","worship","spirit","truth"],"peopleInVerse":[]},"25":{"text":"The woman saith unto him, I know that Messias cometh, which is called Christ: when he is come, he will tell us all things.","ref":"John 4:25","synthesized":"The woman said, “I know that Messiah” (called Christ) “is coming. When He comes, He will explain everything to us.”","sources":{"KJV":{"text":"The woman saith unto him, I know that Messias cometh, which is called Christ: when he is come, he will tell us all things."},"BSB":{"text":"The woman said, “I know that Messiah” (called Christ) “is coming. When He comes, He will explain everything to us.”"}},"definableWords":["woman","Messiah","Christ"],"peopleInVerse":[]},"26":{"text":"Jesus saith unto her, I that speak unto thee am he.","ref":"John 4:26","synthesized":"Jesus answered, “I who speak to you am He.”","sources":{"KJV":{"text":"Jesus saith unto her, I that speak unto thee am he."},"BSB":{"text":"Jesus answered, “I who speak to you am He.”"}},"definableWords":[],"peopleInVerse":["Jesus"]},"27":{"text":"And upon this came his disciples, and marvelled that he talked with the woman: yet no man said, What seekest thou? or, Why talkest thou with her?","ref":"John 4:27","synthesized":"Just then His disciples returned and were surprised that He was speaking with a woman. But no one asked Him, “What do You want from her?” or “Why are You talking with her?”","sources":{"KJV":{"text":"And upon this came his disciples, and marvelled that he talked with the woman: yet no man said, What seekest thou? or, Why talkest thou with her?"},"BSB":{"text":"Just then His disciples returned and were surprised that He was speaking with a woman. But no one asked Him, “What do You want from her?” or “Why are You talking with her?”"}},"definableWords":["woman","one","or"],"peopleInVerse":[]},"28":{"text":"The woman then left her waterpot, and went her way into the city, and saith to the men,","ref":"John 4:28","synthesized":"Then the woman left her water jar, went back into the town, and said to the people,","sources":{"KJV":{"text":"The woman then left her waterpot, and went her way into the city, and saith to the men,"},"BSB":{"text":"Then the woman left her water jar, went back into the town, and said to the people,"}},"definableWords":["woman","water","people"],"peopleInVerse":[]},"29":{"text":"Come, see a man, which told me all things that ever I did: is not this the Christ?","ref":"John 4:29","synthesized":"“Come, see a man who told me everything I ever did. Could this be the Christ?”","sources":{"KJV":{"text":"Come, see a man, which told me all things that ever I did: is not this the Christ?"},"BSB":{"text":"“Come, see a man who told me everything I ever did. Could this be the Christ?”"}},"definableWords":["see","man","Christ"],"peopleInVerse":[]},"30":{"text":"Then they went out of the city, and came unto him.","ref":"John 4:30","synthesized":"So they left the town and made their way toward Jesus.","sources":{"KJV":{"text":"Then they went out of the city, and came unto him."},"BSB":{"text":"So they left the town and made their way toward Jesus."}},"definableWords":["made","way"],"peopleInVerse":["Jesus"]},"31":{"text":"In the mean while his disciples prayed him, saying, Master, eat.","ref":"John 4:31","synthesized":"Meanwhile the disciples urged Him, “Rabbi, eat something.”","sources":{"KJV":{"text":"In the mean while his disciples prayed him, saying, Master, eat."},"BSB":{"text":"Meanwhile the disciples urged Him, “Rabbi, eat something.”"}},"definableWords":[],"peopleInVerse":[]},"32":{"text":"But he said unto them, I have meat to eat that ye know not of.","ref":"John 4:32","synthesized":"But He told them, “I have food to eat that you know nothing about.”","sources":{"KJV":{"text":"But he said unto them, I have meat to eat that ye know not of."},"BSB":{"text":"But He told them, “I have food to eat that you know nothing about.”"}},"definableWords":[],"peopleInVerse":[]},"33":{"text":"Therefore said the disciples one to another, Hath any man brought him ought to eat?","ref":"John 4:33","synthesized":"So the disciples asked one another, “Could someone have brought Him food?”","sources":{"KJV":{"text":"Therefore said the disciples one to another, Hath any man brought him ought to eat?"},"BSB":{"text":"So the disciples asked one another, “Could someone have brought Him food?”"}},"definableWords":["one"],"peopleInVerse":[]},"34":{"text":"Jesus saith unto them, My meat is to do the will of him that sent me, and to finish his work.","ref":"John 4:34","synthesized":"Jesus explained, “My food is to do the will of Him who sent Me and to finish His work.","sources":{"KJV":{"text":"Jesus saith unto them, My meat is to do the will of him that sent me, and to finish his work."},"BSB":{"text":"Jesus explained, “My food is to do the will of Him who sent Me and to finish His work."}},"definableWords":["work"],"peopleInVerse":["Jesus"]},"35":{"text":"Say not ye, There are yet four months, and then cometh harvest? behold, I say unto you, Lift up your eyes, and look on the fields; for they are white already to harvest.","ref":"John 4:35","synthesized":"Do you not say, ‘There are still four months until the harvest’? I tell you, lift up your eyes and look at the fields, for they are ripe for harvest.","sources":{"KJV":{"text":"Say not ye, There are yet four months, and then cometh harvest? behold, I say unto you, Lift up your eyes, and look on the fields; for they are white already to harvest."},"BSB":{"text":"Do you not say, ‘There are still four months until the harvest’? I tell you, lift up your eyes and look at the fields, for they are ripe for harvest."}},"definableWords":[],"peopleInVerse":[]},"36":{"text":"And he that reapeth receiveth wages, and gathereth fruit unto life eternal: that both he that soweth and he that reapeth may rejoice together.","ref":"John 4:36","synthesized":"Already the reaper draws his wages and gathers a crop for eternal life, so that the sower and the reaper may rejoice together.","sources":{"KJV":{"text":"And he that reapeth receiveth wages, and gathereth fruit unto life eternal: that both he that soweth and he that reapeth may rejoice together."},"BSB":{"text":"Already the reaper draws his wages and gathers a crop for eternal life, so that the sower and the reaper may rejoice together."}},"definableWords":["eternal","life"],"peopleInVerse":[]},"37":{"text":"And herein is that saying true, One soweth, and another reapeth.","ref":"John 4:37","synthesized":"For in this case the saying ‘One sows and another reaps’ is true.","sources":{"KJV":{"text":"And herein is that saying true, One soweth, and another reapeth."},"BSB":{"text":"For in this case the saying ‘One sows and another reaps’ is true."}},"definableWords":["one"],"peopleInVerse":[]},"38":{"text":"I sent you to reap that whereon ye bestowed no labour: other men laboured, and ye are entered into their labours.","ref":"John 4:38","synthesized":"I sent you to reap what you have not worked for; others have done the hard work, and now you have taken up their labor.”","sources":{"KJV":{"text":"I sent you to reap that whereon ye bestowed no labour: other men laboured, and ye are entered into their labours."},"BSB":{"text":"I sent you to reap what you have not worked for; others have done the hard work, and now you have taken up their labor.”"}},"definableWords":["work"],"peopleInVerse":[]},"39":{"text":"And many of the Samaritans of that city believed on him for the saying of the woman, which testified, He told me all that ever I did.","ref":"John 4:39","synthesized":"Many of the Samaritans from that town believed in Jesus because of the woman’s testimony, “He told me everything I ever did.”","sources":{"KJV":{"text":"And many of the Samaritans of that city believed on him for the saying of the woman, which testified, He told me all that ever I did."},"BSB":{"text":"Many of the Samaritans from that town believed in Jesus because of the woman’s testimony, “He told me everything I ever did.”"}},"definableWords":["believed","woman"],"peopleInVerse":["Jesus"]},"40":{"text":"So when the Samaritans were come unto him, they besought him that he would tarry with them: and he abode there two days.","ref":"John 4:40","synthesized":"So when the Samaritans came to Him, they asked Him to stay with them, and He stayed two days.","sources":{"KJV":{"text":"So when the Samaritans were come unto him, they besought him that he would tarry with them: and he abode there two days."},"BSB":{"text":"So when the Samaritans came to Him, they asked Him to stay with them, and He stayed two days."}},"definableWords":["days"],"peopleInVerse":[]},"41":{"text":"And many more believed because of his own word;","ref":"John 4:41","synthesized":"And many more believed because of His message.","sources":{"KJV":{"text":"And many more believed because of his own word;"},"BSB":{"text":"And many more believed because of His message."}},"definableWords":["believed"],"peopleInVerse":[]},"42":{"text":"And said unto the woman, Now we believe, not because of thy saying: for we have heard him ourselves, and know that this is indeed the Christ, the Saviour of the world.","ref":"John 4:42","synthesized":"They said to the woman, “We now believe not only because of your words; we have heard for ourselves, and we know that this man truly is the Savior of the world.”","sources":{"KJV":{"text":"And said unto the woman, Now we believe, not because of thy saying: for we have heard him ourselves, and know that this is indeed the Christ, the Saviour of the world."},"BSB":{"text":"They said to the woman, “We now believe not only because of your words; we have heard for ourselves, and we know that this man truly is the Savior of the world.”"}},"definableWords":["woman","man"],"peopleInVerse":[]},"43":{"text":"Now after two days he departed thence, and went into Galilee.","ref":"John 4:43","synthesized":"After two days, Jesus left for Galilee.","sources":{"KJV":{"text":"Now after two days he departed thence, and went into Galilee."},"BSB":{"text":"After two days, Jesus left for Galilee."}},"definableWords":["days","Galilee"],"peopleInVerse":["Jesus"]},"44":{"text":"For Jesus himself testified, that a prophet hath no honour in his own country.","ref":"John 4:44","synthesized":"Now He Himself had testified that a prophet has no honor in his own hometown.","sources":{"KJV":{"text":"For Jesus himself testified, that a prophet hath no honour in his own country."},"BSB":{"text":"Now He Himself had testified that a prophet has no honor in his own hometown."}},"definableWords":["prophet"],"peopleInVerse":[]},"45":{"text":"Then when he was come into Galilee, the Galilaeans received him, having seen all the things that he did at Jerusalem at the feast: for they also went unto the feast.","ref":"John 4:45","synthesized":"Yet when He arrived, the Galileans welcomed Him. They had seen all the great things He had done in Jerusalem at the feast, for they had gone there as well.","sources":{"KJV":{"text":"Then when he was come into Galilee, the Galilaeans received him, having seen all the things that he did at Jerusalem at the feast: for they also went unto the feast."},"BSB":{"text":"Yet when He arrived, the Galileans welcomed Him. They had seen all the great things He had done in Jerusalem at the feast, for they had gone there as well."}},"definableWords":["great","Jerusalem"],"peopleInVerse":[]},"46":{"text":"So Jesus came again into Cana of Galilee, where he made the water wine. And there was a certain nobleman, whose son was sick at Capernaum.","ref":"John 4:46","synthesized":"So once again He came to Cana in Galilee, where He had turned the water into wine. And there was a royal official whose son lay sick at Capernaum.","sources":{"KJV":{"text":"So Jesus came again into Cana of Galilee, where he made the water wine. And there was a certain nobleman, whose son was sick at Capernaum."},"BSB":{"text":"So once again He came to Cana in Galilee, where He had turned the water into wine. And there was a royal official whose son lay sick at Capernaum."}},"definableWords":["Galilee","water","son"],"peopleInVerse":[]},"47":{"text":"When he heard that Jesus was come out of Judaea into Galilee, he went unto him, and besought him that he would come down, and heal his son: for he was at the point of death.","ref":"John 4:47","synthesized":"When he heard that Jesus had come from Judea to Galilee, he went and begged Him to come down and heal his son, who was about to die.","sources":{"KJV":{"text":"When he heard that Jesus was come out of Judaea into Galilee, he went unto him, and besought him that he would come down, and heal his son: for he was at the point of death."},"BSB":{"text":"When he heard that Jesus had come from Judea to Galilee, he went and begged Him to come down and heal his son, who was about to die."}},"definableWords":["Judea","Galilee","heal","son","die"],"peopleInVerse":["Jesus"]},"48":{"text":"Then said Jesus unto him, Except ye see signs and wonders, ye will not believe.","ref":"John 4:48","synthesized":"Jesus said to him, “Unless you people see signs and wonders, you will never believe.”","sources":{"KJV":{"text":"Then said Jesus unto him, Except ye see signs and wonders, ye will not believe."},"BSB":{"text":"Jesus said to him, “Unless you people see signs and wonders, you will never believe.”"}},"definableWords":["people","see"],"peopleInVerse":["Jesus"]},"49":{"text":"The nobleman saith unto him, Sir, come down ere my child die.","ref":"John 4:49","synthesized":"“Sir,” the official said, “come down before my child dies.”","sources":{"KJV":{"text":"The nobleman saith unto him, Sir, come down ere my child die."},"BSB":{"text":"“Sir,” the official said, “come down before my child dies.”"}},"definableWords":[],"peopleInVerse":[]},"50":{"text":"Jesus saith unto him, Go thy way; thy son liveth. And the man believed the word that Jesus had spoken unto him, and he went his way.","ref":"John 4:50","synthesized":"“Go,” said Jesus. “Your son will live.”  The man took Jesus at His word and departed.","sources":{"KJV":{"text":"Jesus saith unto him, Go thy way; thy son liveth. And the man believed the word that Jesus had spoken unto him, and he went his way."},"BSB":{"text":"“Go,” said Jesus. “Your son will live.”  The man took Jesus at His word and departed."}},"definableWords":["son","live","man","word"],"peopleInVerse":["Jesus"]},"51":{"text":"And as he was now going down, his servants met him, and told him, saying, Thy son liveth.","ref":"John 4:51","synthesized":"And while he was still on the way, his servants met him with the news that his boy was alive.","sources":{"KJV":{"text":"And as he was now going down, his servants met him, and told him, saying, Thy son liveth."},"BSB":{"text":"And while he was still on the way, his servants met him with the news that his boy was alive."}},"definableWords":["way","servants"],"peopleInVerse":[]},"52":{"text":"Then enquired he of them the hour when he began to amend. And they said unto him, Yesterday at the seventh hour the fever left him.","ref":"John 4:52","synthesized":"So he inquired as to the hour when his son had recovered, and they told him, “The fever left him yesterday at the seventh hour.”","sources":{"KJV":{"text":"Then enquired he of them the hour when he began to amend. And they said unto him, Yesterday at the seventh hour the fever left him."},"BSB":{"text":"So he inquired as to the hour when his son had recovered, and they told him, “The fever left him yesterday at the seventh hour.”"}},"definableWords":["son"],"peopleInVerse":[]},"53":{"text":"So the father knew that it was at the same hour, in the which Jesus said unto him, Thy son liveth: and himself believed, and his whole house.","ref":"John 4:53","synthesized":"Then the father realized that this was the very hour in which Jesus had told him, “Your son will live.” And he and all his household believed.","sources":{"KJV":{"text":"So the father knew that it was at the same hour, in the which Jesus said unto him, Thy son liveth: and himself believed, and his whole house."},"BSB":{"text":"Then the father realized that this was the very hour in which Jesus had told him, “Your son will live.” And he and all his household believed."}},"definableWords":["father","son","live","believed"],"peopleInVerse":["Jesus"]},"54":{"text":"This is again the second miracle that Jesus did, when he was come out of Judaea into Galilee.","ref":"John 4:54","synthesized":"This was now the second sign that Jesus performed after coming from Judea into Galilee.","sources":{"KJV":{"text":"This is again the second miracle that Jesus did, when he was come out of Judaea into Galilee."},"BSB":{"text":"This was now the second sign that Jesus performed after coming from Judea into Galilee."}},"definableWords":["Judea","Galilee"],"peopleInVerse":["Jesus"]}}},"5":{"chapter":"5","title":"HEALING AT BETHESDA","verses":{"1":{"text":"After this there was a feast of the Jews; and Jesus went up to Jerusalem.","ref":"John 5:1","synthesized":"Some time later there was a feast of the Jews, and Jesus went up to Jerusalem.","sources":{"KJV":{"text":"After this there was a feast of the Jews; and Jesus went up to Jerusalem."},"BSB":{"text":"Some time later there was a feast of the Jews, and Jesus went up to Jerusalem."}},"definableWords":["Jerusalem"],"peopleInVerse":["Jesus"]},"2":{"text":"Now there is at Jerusalem by the sheep market a pool, which is called in the Hebrew tongue Bethesda, having five porches.","ref":"John 5:2","synthesized":"Now there is in Jerusalem near the Sheep Gate a pool with five covered colonnades, which in Hebrew is called Bethesda.","sources":{"KJV":{"text":"Now there is at Jerusalem by the sheep market a pool, which is called in the Hebrew tongue Bethesda, having five porches."},"BSB":{"text":"Now there is in Jerusalem near the Sheep Gate a pool with five covered colonnades, which in Hebrew is called Bethesda."}},"definableWords":["Jerusalem"],"peopleInVerse":[]},"3":{"text":"In these lay a great multitude of impotent folk, of blind, halt, withered, waiting for the moving of the water.","ref":"John 5:3","synthesized":"On these walkways lay a great number of the sick, the blind, the lame, and the paralyzed.","sources":{"KJV":{"text":"In these lay a great multitude of impotent folk, of blind, halt, withered, waiting for the moving of the water."},"BSB":{"text":"On these walkways lay a great number of the sick, the blind, the lame, and the paralyzed."}},"definableWords":["great"],"peopleInVerse":[]},"4":{"text":"For an angel went down at a certain season into the pool, and troubled the water: whosoever then first after the troubling of the water stepped in was made whole of whatsoever disease he had.","ref":"John 5:4","synthesized":"For an angel went down at a certain season into the pool, and troubled the water: whosoever then first after the troubling of the water stepped in was made whole of whatsoever disease he had.","sources":{"KJV":{"text":"For an angel went down at a certain season into the pool, and troubled the water: whosoever then first after the troubling of the water stepped in was made whole of whatsoever disease he had."}},"definableWords":["angel","water","made"],"peopleInVerse":[]},"5":{"text":"And a certain man was there, which had an infirmity thirty and eight years.","ref":"John 5:5","synthesized":"One man there had been an invalid for thirty-eight years.","sources":{"KJV":{"text":"And a certain man was there, which had an infirmity thirty and eight years."},"BSB":{"text":"One man there had been an invalid for thirty-eight years."}},"definableWords":["one","man","years"],"peopleInVerse":[]},"6":{"text":"When Jesus saw him lie, and knew that he had been now a long time in that case, he saith unto him, Wilt thou be made whole?","ref":"John 5:6","synthesized":"When Jesus saw him lying there and realized that he had spent a long time in this condition, He asked him, “Do you want to get well?”","sources":{"KJV":{"text":"When Jesus saw him lie, and knew that he had been now a long time in that case, he saith unto him, Wilt thou be made whole?"},"BSB":{"text":"When Jesus saw him lying there and realized that he had spent a long time in this condition, He asked him, “Do you want to get well?”"}},"definableWords":["saw"],"peopleInVerse":["Jesus"]},"7":{"text":"The impotent man answered him, Sir, I have no man, when the water is troubled, to put me into the pool: but while I am coming, another steppeth down before me.","ref":"John 5:7","synthesized":"“Sir,” the invalid replied, “I have no one to help me into the pool when the water is stirred. While I am on my way, someone else goes in before me.”","sources":{"KJV":{"text":"The impotent man answered him, Sir, I have no man, when the water is troubled, to put me into the pool: but while I am coming, another steppeth down before me."},"BSB":{"text":"“Sir,” the invalid replied, “I have no one to help me into the pool when the water is stirred. While I am on my way, someone else goes in before me.”"}},"definableWords":["one","water","way"],"peopleInVerse":[]},"8":{"text":"Jesus saith unto him, Rise, take up thy bed, and walk.","ref":"John 5:8","synthesized":"Then Jesus told him, “Get up, pick up your mat, and walk.”","sources":{"KJV":{"text":"Jesus saith unto him, Rise, take up thy bed, and walk."},"BSB":{"text":"Then Jesus told him, “Get up, pick up your mat, and walk.”"}},"definableWords":["walk"],"peopleInVerse":["Jesus"]},"9":{"text":"And immediately the man was made whole, and took up his bed, and walked: and on the same day was the sabbath.","ref":"John 5:9","synthesized":"Immediately the man was made well, and he picked up his mat and began to walk.  Now this happened on the Sabbath day,","sources":{"KJV":{"text":"And immediately the man was made whole, and took up his bed, and walked: and on the same day was the sabbath."},"BSB":{"text":"Immediately the man was made well, and he picked up his mat and began to walk.  Now this happened on the Sabbath day,"}},"definableWords":["man","made","walk","Sabbath","day"],"peopleInVerse":[]},"10":{"text":"The Jews therefore said unto him that was cured, It is the sabbath day: it is not lawful for thee to carry thy bed.","ref":"John 5:10","synthesized":"so the Jews said to the man who had been healed, “This is the Sabbath! It is unlawful for you to carry your mat.”","sources":{"KJV":{"text":"The Jews therefore said unto him that was cured, It is the sabbath day: it is not lawful for thee to carry thy bed."},"BSB":{"text":"so the Jews said to the man who had been healed, “This is the Sabbath! It is unlawful for you to carry your mat.”"}},"definableWords":["man","Sabbath"],"peopleInVerse":[]},"11":{"text":"He answered them, He that made me whole, the same said unto me, Take up thy bed, and walk.","ref":"John 5:11","synthesized":"But he answered, “The man who made me well told me, ‘Pick up your mat and walk.’”","sources":{"KJV":{"text":"He answered them, He that made me whole, the same said unto me, Take up thy bed, and walk."},"BSB":{"text":"But he answered, “The man who made me well told me, ‘Pick up your mat and walk.’”"}},"definableWords":["man","made","walk"],"peopleInVerse":[]},"12":{"text":"Then asked they him, What man is that which said unto thee, Take up thy bed, and walk?","ref":"John 5:12","synthesized":"“Who is this man who told you to pick it up and walk?” they asked.","sources":{"KJV":{"text":"Then asked they him, What man is that which said unto thee, Take up thy bed, and walk?"},"BSB":{"text":"“Who is this man who told you to pick it up and walk?” they asked."}},"definableWords":["man","walk"],"peopleInVerse":[]},"13":{"text":"And he that was healed wist not who it was: for Jesus had conveyed himself away, a multitude being in that place.","ref":"John 5:13","synthesized":"But the man who was healed did not know who it was, for Jesus had slipped away while the crowd was there.","sources":{"KJV":{"text":"And he that was healed wist not who it was: for Jesus had conveyed himself away, a multitude being in that place."},"BSB":{"text":"But the man who was healed did not know who it was, for Jesus had slipped away while the crowd was there."}},"definableWords":["man"],"peopleInVerse":["Jesus"]},"14":{"text":"Afterward Jesus findeth him in the temple, and said unto him, Behold, thou art made whole: sin no more, lest a worse thing come unto thee.","ref":"John 5:14","synthesized":"Afterward, Jesus found the man at the temple and said to him, “See, you have been made well. Stop sinning, or something worse may happen to you.”","sources":{"KJV":{"text":"Afterward Jesus findeth him in the temple, and said unto him, Behold, thou art made whole: sin no more, lest a worse thing come unto thee."},"BSB":{"text":"Afterward, Jesus found the man at the temple and said to him, “See, you have been made well. Stop sinning, or something worse may happen to you.”"}},"definableWords":["man","temple","see","made","or"],"peopleInVerse":["Jesus"]},"15":{"text":"The man departed, and told the Jews that it was Jesus, which had made him whole.","ref":"John 5:15","synthesized":"And the man went away and told the Jews that it was Jesus who had made him well.","sources":{"KJV":{"text":"The man departed, and told the Jews that it was Jesus, which had made him whole."},"BSB":{"text":"And the man went away and told the Jews that it was Jesus who had made him well."}},"definableWords":["man","made"],"peopleInVerse":["Jesus"]},"16":{"text":"And therefore did the Jews persecute Jesus, and sought to slay him, because he had done these things on the sabbath day.","ref":"John 5:16","synthesized":"Now because Jesus was doing these things on the Sabbath, the Jews began to persecute Him.","sources":{"KJV":{"text":"And therefore did the Jews persecute Jesus, and sought to slay him, because he had done these things on the sabbath day."},"BSB":{"text":"Now because Jesus was doing these things on the Sabbath, the Jews began to persecute Him."}},"definableWords":["Sabbath"],"peopleInVerse":["Jesus"]},"17":{"text":"But Jesus answered them, My Father worketh hitherto, and I work.","ref":"John 5:17","synthesized":"But Jesus answered them, “To this very day My Father is at His work, and I too am working.”","sources":{"KJV":{"text":"But Jesus answered them, My Father worketh hitherto, and I work."},"BSB":{"text":"But Jesus answered them, “To this very day My Father is at His work, and I too am working.”"}},"definableWords":["day","Father","work"],"peopleInVerse":["Jesus"]},"18":{"text":"Therefore the Jews sought the more to kill him, because he not only had broken the sabbath, but said also that God was his Father, making himself equal with God.","ref":"John 5:18","synthesized":"Because of this, the Jews tried all the harder to kill Him. Not only was He breaking the Sabbath, but He was even calling God His own Father, making Himself equal with God.","sources":{"KJV":{"text":"Therefore the Jews sought the more to kill him, because he not only had broken the sabbath, but said also that God was his Father, making himself equal with God."},"BSB":{"text":"Because of this, the Jews tried all the harder to kill Him. Not only was He breaking the Sabbath, but He was even calling God His own Father, making Himself equal with God."}},"definableWords":["Sabbath","God","Father"],"peopleInVerse":[]},"19":{"text":"Then answered Jesus and said unto them, Verily, verily, I say unto you, The Son can do nothing of himself, but what he seeth the Father do: for what things soever he doeth, these also doeth the Son likewise.","ref":"John 5:19","synthesized":"So Jesus replied, “Truly, truly, I tell you, the Son can do nothing by Himself, unless He sees the Father doing it. For whatever the Father does, the Son also does.","sources":{"KJV":{"text":"Then answered Jesus and said unto them, Verily, verily, I say unto you, The Son can do nothing of himself, but what he seeth the Father do: for what things soever he doeth, these also doeth the Son likewise."},"BSB":{"text":"So Jesus replied, “Truly, truly, I tell you, the Son can do nothing by Himself, unless He sees the Father doing it. For whatever the Father does, the Son also does."}},"definableWords":["Son","Father"],"peopleInVerse":["Jesus"]},"20":{"text":"For the Father loveth the Son, and sheweth him all things that himself doeth: and he will shew him greater works than these, that ye may marvel.","ref":"John 5:20","synthesized":"The Father loves the Son and shows Him all He does. And to your amazement, He will show Him even greater works than these.","sources":{"KJV":{"text":"For the Father loveth the Son, and sheweth him all things that himself doeth: and he will shew him greater works than these, that ye may marvel."},"BSB":{"text":"The Father loves the Son and shows Him all He does. And to your amazement, He will show Him even greater works than these."}},"definableWords":["Father","Son","works"],"peopleInVerse":[]},"21":{"text":"For as the Father raiseth up the dead, and quickeneth them; even so the Son quickeneth whom he will.","ref":"John 5:21","synthesized":"For just as the Father raises the dead and gives them life, so also the Son gives life to whom He wishes.","sources":{"KJV":{"text":"For as the Father raiseth up the dead, and quickeneth them; even so the Son quickeneth whom he will."},"BSB":{"text":"For just as the Father raises the dead and gives them life, so also the Son gives life to whom He wishes."}},"definableWords":["Father","life","Son"],"peopleInVerse":[]},"22":{"text":"For the Father judgeth no man, but hath committed all judgment unto the Son:","ref":"John 5:22","synthesized":"Furthermore, the Father judges no one, but has assigned all judgment to the Son,","sources":{"KJV":{"text":"For the Father judgeth no man, but hath committed all judgment unto the Son:"},"BSB":{"text":"Furthermore, the Father judges no one, but has assigned all judgment to the Son,"}},"definableWords":["Father","one","judgment","Son"],"peopleInVerse":[]},"23":{"text":"That all men should honour the Son, even as they honour the Father. He that honoureth not the Son honoureth not the Father which hath sent him.","ref":"John 5:23","synthesized":"so that all may honor the Son just as they honor the Father. Whoever does not honor the Son does not honor the Father who sent Him.","sources":{"KJV":{"text":"That all men should honour the Son, even as they honour the Father. He that honoureth not the Son honoureth not the Father which hath sent him."},"BSB":{"text":"so that all may honor the Son just as they honor the Father. Whoever does not honor the Son does not honor the Father who sent Him."}},"definableWords":["Son","Father"],"peopleInVerse":[]},"24":{"text":"Verily, verily, I say unto you, He that heareth my word, and believeth on him that sent me, hath everlasting life, and shall not come into condemnation; but is passed from death unto life.","ref":"John 5:24","synthesized":"Truly, truly, I tell you, whoever hears My word and believes Him who sent Me has eternal life and will not come under judgment. Indeed, he has crossed over from death to life.","sources":{"KJV":{"text":"Verily, verily, I say unto you, He that heareth my word, and believeth on him that sent me, hath everlasting life, and shall not come into condemnation; but is passed from death unto life."},"BSB":{"text":"Truly, truly, I tell you, whoever hears My word and believes Him who sent Me has eternal life and will not come under judgment. Indeed, he has crossed over from death to life."}},"definableWords":["word","eternal","life","judgment","death"],"peopleInVerse":[]},"25":{"text":"Verily, verily, I say unto you, The hour is coming, and now is, when the dead shall hear the voice of the Son of God: and they that hear shall live.","ref":"John 5:25","synthesized":"Truly, truly, I tell you, the hour is coming and has now come when the dead will hear the voice of the Son of God, and those who hear will live.","sources":{"KJV":{"text":"Verily, verily, I say unto you, The hour is coming, and now is, when the dead shall hear the voice of the Son of God: and they that hear shall live."},"BSB":{"text":"Truly, truly, I tell you, the hour is coming and has now come when the dead will hear the voice of the Son of God, and those who hear will live."}},"definableWords":["hear","voice","Son","God","live"],"peopleInVerse":[]},"26":{"text":"For as the Father hath life in himself; so hath he given to the Son to have life in himself;","ref":"John 5:26","synthesized":"For as the Father has life in Himself, so also He has granted the Son to have life in Himself.","sources":{"KJV":{"text":"For as the Father hath life in himself; so hath he given to the Son to have life in himself;"},"BSB":{"text":"For as the Father has life in Himself, so also He has granted the Son to have life in Himself."}},"definableWords":["Father","life","Son"],"peopleInVerse":[]},"27":{"text":"And hath given him authority to execute judgment also, because he is the Son of man.","ref":"John 5:27","synthesized":"And He has given Him authority to execute judgment, because He is the Son of Man.","sources":{"KJV":{"text":"And hath given him authority to execute judgment also, because he is the Son of man."},"BSB":{"text":"And He has given Him authority to execute judgment, because He is the Son of Man."}},"definableWords":["judgment","Son","man"],"peopleInVerse":[]},"28":{"text":"Marvel not at this: for the hour is coming, in the which all that are in the graves shall hear his voice,","ref":"John 5:28","synthesized":"Do not be amazed at this, for the hour is coming when all who are in their graves will hear His voice","sources":{"KJV":{"text":"Marvel not at this: for the hour is coming, in the which all that are in the graves shall hear his voice,"},"BSB":{"text":"Do not be amazed at this, for the hour is coming when all who are in their graves will hear His voice"}},"definableWords":["hear","voice"],"peopleInVerse":[]},"29":{"text":"And shall come forth; they that have done good, unto the resurrection of life; and they that have done evil, unto the resurrection of damnation.","ref":"John 5:29","synthesized":"and come out—those who have done good to the resurrection of life, and those who have done evil to the resurrection of judgment.","sources":{"KJV":{"text":"And shall come forth; they that have done good, unto the resurrection of life; and they that have done evil, unto the resurrection of damnation."},"BSB":{"text":"and come out—those who have done good to the resurrection of life, and those who have done evil to the resurrection of judgment."}},"definableWords":["good","resurrection","life","evil","judgment"],"peopleInVerse":[]},"30":{"text":"I can of mine own self do nothing: as I hear, I judge: and my judgment is just; because I seek not mine own will, but the will of the Father which hath sent me.","ref":"John 5:30","synthesized":"I can do nothing by Myself; I judge only as I hear. And My judgment is just, because I do not seek My own will, but the will of Him who sent Me.","sources":{"KJV":{"text":"I can of mine own self do nothing: as I hear, I judge: and my judgment is just; because I seek not mine own will, but the will of the Father which hath sent me."},"BSB":{"text":"I can do nothing by Myself; I judge only as I hear. And My judgment is just, because I do not seek My own will, but the will of Him who sent Me."}},"definableWords":["hear","judgment","seek"],"peopleInVerse":[]},"31":{"text":"If I bear witness of myself, my witness is not true.","ref":"John 5:31","synthesized":"If I testify about Myself, My testimony is not valid.","sources":{"KJV":{"text":"If I bear witness of myself, my witness is not true."},"BSB":{"text":"If I testify about Myself, My testimony is not valid."}},"definableWords":[],"peopleInVerse":[]},"32":{"text":"There is another that beareth witness of me; and I know that the witness which he witnesseth of me is true.","ref":"John 5:32","synthesized":"There is another who testifies about Me, and I know that His testimony about Me is valid.","sources":{"KJV":{"text":"There is another that beareth witness of me; and I know that the witness which he witnesseth of me is true."},"BSB":{"text":"There is another who testifies about Me, and I know that His testimony about Me is valid."}},"definableWords":[],"peopleInVerse":[]},"33":{"text":"Ye sent unto John, and he bare witness unto the truth.","ref":"John 5:33","synthesized":"You have sent to John, and he has testified to the truth.","sources":{"KJV":{"text":"Ye sent unto John, and he bare witness unto the truth."},"BSB":{"text":"You have sent to John, and he has testified to the truth."}},"definableWords":["truth"],"peopleInVerse":["John"]},"34":{"text":"But I receive not testimony from man: but these things I say, that ye might be saved.","ref":"John 5:34","synthesized":"Even though I do not accept human testimony, I say these things so that you may be saved.","sources":{"KJV":{"text":"But I receive not testimony from man: but these things I say, that ye might be saved."},"BSB":{"text":"Even though I do not accept human testimony, I say these things so that you may be saved."}},"definableWords":[],"peopleInVerse":[]},"35":{"text":"He was a burning and a shining light: and ye were willing for a season to rejoice in his light.","ref":"John 5:35","synthesized":"John was a lamp that burned and gave light, and you were willing for a season to bask in his light.","sources":{"KJV":{"text":"He was a burning and a shining light: and ye were willing for a season to rejoice in his light."},"BSB":{"text":"John was a lamp that burned and gave light, and you were willing for a season to bask in his light."}},"definableWords":["light"],"peopleInVerse":["John"]},"36":{"text":"But I have greater witness than that of John: for the works which the Father hath given me to finish, the same works that I do, bear witness of me, that the Father hath sent me.","ref":"John 5:36","synthesized":"But I have testimony more substantial than that of John. For the works that the Father has given Me to accomplish—the very works I am doing—testify about Me that the Father has sent Me.","sources":{"KJV":{"text":"But I have greater witness than that of John: for the works which the Father hath given me to finish, the same works that I do, bear witness of me, that the Father hath sent me."},"BSB":{"text":"But I have testimony more substantial than that of John. For the works that the Father has given Me to accomplish—the very works I am doing—testify about Me that the Father has sent Me."}},"definableWords":["works","Father"],"peopleInVerse":["John"]},"37":{"text":"And the Father himself, which hath sent me, hath borne witness of me. Ye have neither heard his voice at any time, nor seen his shape.","ref":"John 5:37","synthesized":"And the Father who sent Me has Himself testified about Me. You have never heard His voice nor seen His form,","sources":{"KJV":{"text":"And the Father himself, which hath sent me, hath borne witness of me. Ye have neither heard his voice at any time, nor seen his shape."},"BSB":{"text":"And the Father who sent Me has Himself testified about Me. You have never heard His voice nor seen His form,"}},"definableWords":["Father","voice","form"],"peopleInVerse":[]},"38":{"text":"And ye have not his word abiding in you: for whom he hath sent, him ye believe not.","ref":"John 5:38","synthesized":"nor does His word abide in you, because you do not believe the One He sent.","sources":{"KJV":{"text":"And ye have not his word abiding in you: for whom he hath sent, him ye believe not."},"BSB":{"text":"nor does His word abide in you, because you do not believe the One He sent."}},"definableWords":["word","abide","one"],"peopleInVerse":[]},"39":{"text":"Search the scriptures; for in them ye think ye have eternal life: and they are they which testify of me.","ref":"John 5:39","synthesized":"You pore over the Scriptures because you presume that by them you possess eternal life. These are the very words that testify about Me,","sources":{"KJV":{"text":"Search the scriptures; for in them ye think ye have eternal life: and they are they which testify of me."},"BSB":{"text":"You pore over the Scriptures because you presume that by them you possess eternal life. These are the very words that testify about Me,"}},"definableWords":["eternal","life"],"peopleInVerse":[]},"40":{"text":"And ye will not come to me, that ye might have life.","ref":"John 5:40","synthesized":"yet you refuse to come to Me to have life.","sources":{"KJV":{"text":"And ye will not come to me, that ye might have life."},"BSB":{"text":"yet you refuse to come to Me to have life."}},"definableWords":["life"],"peopleInVerse":[]},"41":{"text":"I receive not honour from men.","ref":"John 5:41","synthesized":"I do not accept glory from men,","sources":{"KJV":{"text":"I receive not honour from men."},"BSB":{"text":"I do not accept glory from men,"}},"definableWords":["glory","men"],"peopleInVerse":[]},"42":{"text":"But I know you, that ye have not the love of God in you.","ref":"John 5:42","synthesized":"but I know you, that you do not have the love of God within you.","sources":{"KJV":{"text":"But I know you, that ye have not the love of God in you."},"BSB":{"text":"but I know you, that you do not have the love of God within you."}},"definableWords":["love","God"],"peopleInVerse":[]},"43":{"text":"I am come in my Father’s name, and ye receive me not: if another shall come in his own name, him ye will receive.","ref":"John 5:43","synthesized":"I have come in My Father’s name, and you have not received Me; but if someone else comes in his own name, you will receive him.","sources":{"KJV":{"text":"I am come in my Father’s name, and ye receive me not: if another shall come in his own name, him ye will receive."},"BSB":{"text":"I have come in My Father’s name, and you have not received Me; but if someone else comes in his own name, you will receive him."}},"definableWords":["Father","name"],"peopleInVerse":[]},"44":{"text":"How can ye believe, which receive honour one of another, and seek not the honour that cometh from God only?","ref":"John 5:44","synthesized":"How can you believe if you accept glory from one another, yet do not seek the glory that comes from the only God?","sources":{"KJV":{"text":"How can ye believe, which receive honour one of another, and seek not the honour that cometh from God only?"},"BSB":{"text":"How can you believe if you accept glory from one another, yet do not seek the glory that comes from the only God?"}},"definableWords":["glory","one","seek","God"],"peopleInVerse":[]},"45":{"text":"Do not think that I will accuse you to the Father: there is one that accuseth you, even Moses, in whom ye trust.","ref":"John 5:45","synthesized":"Do not think that I will accuse you before the Father. Your accuser is Moses, in whom you have put your hope.","sources":{"KJV":{"text":"Do not think that I will accuse you to the Father: there is one that accuseth you, even Moses, in whom ye trust."},"BSB":{"text":"Do not think that I will accuse you before the Father. Your accuser is Moses, in whom you have put your hope."}},"definableWords":["Father","hope"],"peopleInVerse":["Moses"]},"46":{"text":"For had ye believed Moses, ye would have believed me: for he wrote of me.","ref":"John 5:46","synthesized":"If you had believed Moses, you would believe Me, because he wrote about Me.","sources":{"KJV":{"text":"For had ye believed Moses, ye would have believed me: for he wrote of me."},"BSB":{"text":"If you had believed Moses, you would believe Me, because he wrote about Me."}},"definableWords":["believed"],"peopleInVerse":["Moses"]},"47":{"text":"But if ye believe not his writings, how shall ye believe my words?","ref":"John 5:47","synthesized":"But since you do not believe what he wrote, how will you believe what I say?”","sources":{"KJV":{"text":"But if ye believe not his writings, how shall ye believe my words?"},"BSB":{"text":"But since you do not believe what he wrote, how will you believe what I say?”"}},"definableWords":[],"peopleInVerse":[]}}},"6":{"chapter":"6","title":"I AM THE BREAD OF LIFE","verses":{"1":{"text":"After these things Jesus went over the sea of Galilee, which is the sea of Tiberias.","ref":"John 6:1","synthesized":"After this, Jesus crossed to the other side of the Sea of Galilee (that is, the Sea of Tiberias).","sources":{"KJV":{"text":"After these things Jesus went over the sea of Galilee, which is the sea of Tiberias."},"BSB":{"text":"After this, Jesus crossed to the other side of the Sea of Galilee (that is, the Sea of Tiberias)."}},"definableWords":["sea","Galilee"],"peopleInVerse":["Jesus"]},"2":{"text":"And a great multitude followed him, because they saw his miracles which he did on them that were diseased.","ref":"John 6:2","synthesized":"A large crowd followed Him because they saw the signs He was performing on the sick.","sources":{"KJV":{"text":"And a great multitude followed him, because they saw his miracles which he did on them that were diseased."},"BSB":{"text":"A large crowd followed Him because they saw the signs He was performing on the sick."}},"definableWords":["saw"],"peopleInVerse":[]},"3":{"text":"And Jesus went up into a mountain, and there he sat with his disciples.","ref":"John 6:3","synthesized":"Then Jesus went up on the mountain and sat down with His disciples.","sources":{"KJV":{"text":"And Jesus went up into a mountain, and there he sat with his disciples."},"BSB":{"text":"Then Jesus went up on the mountain and sat down with His disciples."}},"definableWords":[],"peopleInVerse":["Jesus"]},"4":{"text":"And the passover, a feast of the Jews, was nigh.","ref":"John 6:4","synthesized":"Now the Jewish Feast of the Passover was near.","sources":{"KJV":{"text":"And the passover, a feast of the Jews, was nigh."},"BSB":{"text":"Now the Jewish Feast of the Passover was near."}},"definableWords":["Passover"],"peopleInVerse":[]},"5":{"text":"When Jesus then lifted up his eyes, and saw a great company come unto him, he saith unto Philip, Whence shall we buy bread, that these may eat?","ref":"John 6:5","synthesized":"When Jesus looked up and saw a large crowd coming toward Him, He said to Philip, “Where can we buy bread for these people to eat?”","sources":{"KJV":{"text":"When Jesus then lifted up his eyes, and saw a great company come unto him, he saith unto Philip, Whence shall we buy bread, that these may eat?"},"BSB":{"text":"When Jesus looked up and saw a large crowd coming toward Him, He said to Philip, “Where can we buy bread for these people to eat?”"}},"definableWords":["saw","people"],"peopleInVerse":["Jesus"]},"6":{"text":"And this he said to prove him: for he himself knew what he would do.","ref":"John 6:6","synthesized":"But He was asking this to test him, for He knew what He was about to do.","sources":{"KJV":{"text":"And this he said to prove him: for he himself knew what he would do."},"BSB":{"text":"But He was asking this to test him, for He knew what He was about to do."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"Philip answered him, Two hundred pennyworth of bread is not sufficient for them, that every one of them may take a little.","ref":"John 6:7","synthesized":"Philip answered, “Two hundred denarii would not buy enough bread for each of them to have a small piece.”","sources":{"KJV":{"text":"Philip answered him, Two hundred pennyworth of bread is not sufficient for them, that every one of them may take a little."},"BSB":{"text":"Philip answered, “Two hundred denarii would not buy enough bread for each of them to have a small piece.”"}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"One of his disciples, Andrew, Simon Peter’s brother, saith unto him,","ref":"John 6:8","synthesized":"One of His disciples, Andrew, Simon Peter’s brother, said to Him,","sources":{"KJV":{"text":"One of his disciples, Andrew, Simon Peter’s brother, saith unto him,"},"BSB":{"text":"One of His disciples, Andrew, Simon Peter’s brother, said to Him,"}},"definableWords":["one","brother"],"peopleInVerse":["Andrew","Peter"]},"9":{"text":"There is a lad here, which hath five barley loaves, and two small fishes: but what are they among so many?","ref":"John 6:9","synthesized":"“Here is a boy with five barley loaves and two small fish. But what difference will these make among so many?”","sources":{"KJV":{"text":"There is a lad here, which hath five barley loaves, and two small fishes: but what are they among so many?"},"BSB":{"text":"“Here is a boy with five barley loaves and two small fish. But what difference will these make among so many?”"}},"definableWords":["fish","make"],"peopleInVerse":[]},"10":{"text":"And Jesus said, Make the men sit down. Now there was much grass in the place. So the men sat down, in number about five thousand.","ref":"John 6:10","synthesized":"“Have the people sit down,” Jesus said. Now there was plenty of grass in that place, so the men sat down, about five thousand of them.","sources":{"KJV":{"text":"And Jesus said, Make the men sit down. Now there was much grass in the place. So the men sat down, in number about five thousand."},"BSB":{"text":"“Have the people sit down,” Jesus said. Now there was plenty of grass in that place, so the men sat down, about five thousand of them."}},"definableWords":["people","men"],"peopleInVerse":["Jesus"]},"11":{"text":"And Jesus took the loaves; and when he had given thanks, he distributed to the disciples, and the disciples to them that were set down; and likewise of the fishes as much as they would.","ref":"John 6:11","synthesized":"Then Jesus took the loaves and the fish, gave thanks, and distributed to those who were seated as much as they wanted.","sources":{"KJV":{"text":"And Jesus took the loaves; and when he had given thanks, he distributed to the disciples, and the disciples to them that were set down; and likewise of the fishes as much as they would."},"BSB":{"text":"Then Jesus took the loaves and the fish, gave thanks, and distributed to those who were seated as much as they wanted."}},"definableWords":["fish"],"peopleInVerse":["Jesus"]},"12":{"text":"When they were filled, he said unto his disciples, Gather up the fragments that remain, that nothing be lost.","ref":"John 6:12","synthesized":"And when everyone was full, He said to His disciples, “Gather the pieces that are left over, so that nothing will be wasted.”","sources":{"KJV":{"text":"When they were filled, he said unto his disciples, Gather up the fragments that remain, that nothing be lost."},"BSB":{"text":"And when everyone was full, He said to His disciples, “Gather the pieces that are left over, so that nothing will be wasted.”"}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"Therefore they gathered them together, and filled twelve baskets with the fragments of the five barley loaves, which remained over and above unto them that had eaten.","ref":"John 6:13","synthesized":"So they collected them and filled twelve baskets with the pieces of the five barley loaves left over by those who had eaten.","sources":{"KJV":{"text":"Therefore they gathered them together, and filled twelve baskets with the fragments of the five barley loaves, which remained over and above unto them that had eaten."},"BSB":{"text":"So they collected them and filled twelve baskets with the pieces of the five barley loaves left over by those who had eaten."}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"Then those men, when they had seen the miracle that Jesus did, said, This is of a truth that prophet that should come into the world.","ref":"John 6:14","synthesized":"When the people saw the sign that Jesus had performed, they began to say, “Truly this is the Prophet who is to come into the world.”","sources":{"KJV":{"text":"Then those men, when they had seen the miracle that Jesus did, said, This is of a truth that prophet that should come into the world."},"BSB":{"text":"When the people saw the sign that Jesus had performed, they began to say, “Truly this is the Prophet who is to come into the world.”"}},"definableWords":["people","saw","prophet"],"peopleInVerse":["Jesus"]},"15":{"text":"When Jesus therefore perceived that they would come and take him by force, to make him a king, he departed again into a mountain himself alone.","ref":"John 6:15","synthesized":"Then Jesus, realizing that they were about to come and make Him king by force, withdrew again to a mountain by Himself.","sources":{"KJV":{"text":"When Jesus therefore perceived that they would come and take him by force, to make him a king, he departed again into a mountain himself alone."},"BSB":{"text":"Then Jesus, realizing that they were about to come and make Him king by force, withdrew again to a mountain by Himself."}},"definableWords":["make","king"],"peopleInVerse":["Jesus"]},"16":{"text":"And when even was now come, his disciples went down unto the sea,","ref":"John 6:16","synthesized":"When evening came, His disciples went down to the sea,","sources":{"KJV":{"text":"And when even was now come, his disciples went down unto the sea,"},"BSB":{"text":"When evening came, His disciples went down to the sea,"}},"definableWords":["sea"],"peopleInVerse":[]},"17":{"text":"And entered into a ship, and went over the sea toward Capernaum. And it was now dark, and Jesus was not come to them.","ref":"John 6:17","synthesized":"got into a boat, and started across the sea to Capernaum. It was already dark, and Jesus had not yet gone out to them.","sources":{"KJV":{"text":"And entered into a ship, and went over the sea toward Capernaum. And it was now dark, and Jesus was not come to them."},"BSB":{"text":"got into a boat, and started across the sea to Capernaum. It was already dark, and Jesus had not yet gone out to them."}},"definableWords":["sea"],"peopleInVerse":["Jesus"]},"18":{"text":"And the sea arose by reason of a great wind that blew.","ref":"John 6:18","synthesized":"A strong wind was blowing, and the sea grew agitated.","sources":{"KJV":{"text":"And the sea arose by reason of a great wind that blew."},"BSB":{"text":"A strong wind was blowing, and the sea grew agitated."}},"definableWords":["strong","sea"],"peopleInVerse":[]},"19":{"text":"So when they had rowed about five and twenty or thirty furlongs, they see Jesus walking on the sea, and drawing nigh unto the ship: and they were afraid.","ref":"John 6:19","synthesized":"When they had rowed about three or four miles, they saw Jesus approaching the boat, walking on the sea—and they were terrified.","sources":{"KJV":{"text":"So when they had rowed about five and twenty or thirty furlongs, they see Jesus walking on the sea, and drawing nigh unto the ship: and they were afraid."},"BSB":{"text":"When they had rowed about three or four miles, they saw Jesus approaching the boat, walking on the sea—and they were terrified."}},"definableWords":["or","saw","sea"],"peopleInVerse":["Jesus"]},"20":{"text":"But he saith unto them, It is I; be not afraid.","ref":"John 6:20","synthesized":"But Jesus spoke up: “It is I; do not be afraid.”","sources":{"KJV":{"text":"But he saith unto them, It is I; be not afraid."},"BSB":{"text":"But Jesus spoke up: “It is I; do not be afraid.”"}},"definableWords":[],"peopleInVerse":["Jesus"]},"21":{"text":"Then they willingly received him into the ship: and immediately the ship was at the land whither they went.","ref":"John 6:21","synthesized":"Then they were willing to take Him into the boat, and at once the boat reached the shore where they were heading.","sources":{"KJV":{"text":"Then they willingly received him into the ship: and immediately the ship was at the land whither they went."},"BSB":{"text":"Then they were willing to take Him into the boat, and at once the boat reached the shore where they were heading."}},"definableWords":[],"peopleInVerse":[]},"22":{"text":"The day following, when the people which stood on the other side of the sea saw that there was none other boat there, save that one whereinto his disciples were entered, and that Jesus went not with his disciples into the boat, but that his disciples were gone away alone;","ref":"John 6:22","synthesized":"The next day, the crowd that had remained on the other side of the sea realized that only one boat had been there, and that Jesus had not boarded it with His disciples, but they had gone away alone.","sources":{"KJV":{"text":"The day following, when the people which stood on the other side of the sea saw that there was none other boat there, save that one whereinto his disciples were entered, and that Jesus went not with his disciples into the boat, but that his disciples were gone away alone;"},"BSB":{"text":"The next day, the crowd that had remained on the other side of the sea realized that only one boat had been there, and that Jesus had not boarded it with His disciples, but they had gone away alone."}},"definableWords":["day","sea","one"],"peopleInVerse":["Jesus"]},"23":{"text":"(Howbeit there came other boats from Tiberias nigh unto the place where they did eat bread, after that the Lord had given thanks:)","ref":"John 6:23","synthesized":"However, some boats from Tiberias landed near the place where the people had eaten the bread after the Lord had given thanks.","sources":{"KJV":{"text":"(Howbeit there came other boats from Tiberias nigh unto the place where they did eat bread, after that the Lord had given thanks:)"},"BSB":{"text":"However, some boats from Tiberias landed near the place where the people had eaten the bread after the Lord had given thanks."}},"definableWords":["people","Lord"],"peopleInVerse":[]},"24":{"text":"When the people therefore saw that Jesus was not there, neither his disciples, they also took shipping, and came to Capernaum, seeking for Jesus.","ref":"John 6:24","synthesized":"So when the crowd saw that neither Jesus nor His disciples were there, they got into the boats and went to Capernaum to look for Him.","sources":{"KJV":{"text":"When the people therefore saw that Jesus was not there, neither his disciples, they also took shipping, and came to Capernaum, seeking for Jesus."},"BSB":{"text":"So when the crowd saw that neither Jesus nor His disciples were there, they got into the boats and went to Capernaum to look for Him."}},"definableWords":["saw"],"peopleInVerse":["Jesus"]},"25":{"text":"And when they had found him on the other side of the sea, they said unto him, Rabbi, when camest thou hither?","ref":"John 6:25","synthesized":"When they found Him on the other side of the sea, they asked Him, “Rabbi, when did You get here?”","sources":{"KJV":{"text":"And when they had found him on the other side of the sea, they said unto him, Rabbi, when camest thou hither?"},"BSB":{"text":"When they found Him on the other side of the sea, they asked Him, “Rabbi, when did You get here?”"}},"definableWords":["sea"],"peopleInVerse":[]},"26":{"text":"Jesus answered them and said, Verily, verily, I say unto you, Ye seek me, not because ye saw the miracles, but because ye did eat of the loaves, and were filled.","ref":"John 6:26","synthesized":"Jesus replied, “Truly, truly, I tell you, it is not because you saw these signs that you are looking for Me, but because you ate the loaves and had your fill.","sources":{"KJV":{"text":"Jesus answered them and said, Verily, verily, I say unto you, Ye seek me, not because ye saw the miracles, but because ye did eat of the loaves, and were filled."},"BSB":{"text":"Jesus replied, “Truly, truly, I tell you, it is not because you saw these signs that you are looking for Me, but because you ate the loaves and had your fill."}},"definableWords":["saw","fill"],"peopleInVerse":["Jesus"]},"27":{"text":"Labour not for the meat which perisheth, but for that meat which endureth unto everlasting life, which the Son of man shall give unto you: for him hath God the Father sealed.","ref":"John 6:27","synthesized":"Do not work for food that perishes, but for food that endures to eternal life, which the Son of Man will give you. For on Him God the Father has placed His seal of approval.”","sources":{"KJV":{"text":"Labour not for the meat which perisheth, but for that meat which endureth unto everlasting life, which the Son of man shall give unto you: for him hath God the Father sealed."},"BSB":{"text":"Do not work for food that perishes, but for food that endures to eternal life, which the Son of Man will give you. For on Him God the Father has placed His seal of approval.”"}},"definableWords":["work","eternal","life","Son","man","God","Father"],"peopleInVerse":[]},"28":{"text":"Then said they unto him, What shall we do, that we might work the works of God?","ref":"John 6:28","synthesized":"Then they inquired, “What must we do to perform the works of God?”","sources":{"KJV":{"text":"Then said they unto him, What shall we do, that we might work the works of God?"},"BSB":{"text":"Then they inquired, “What must we do to perform the works of God?”"}},"definableWords":["works","God"],"peopleInVerse":[]},"29":{"text":"Jesus answered and said unto them, This is the work of God, that ye believe on him whom he hath sent.","ref":"John 6:29","synthesized":"Jesus replied, “The work of God is this: to believe in the One He has sent.”","sources":{"KJV":{"text":"Jesus answered and said unto them, This is the work of God, that ye believe on him whom he hath sent."},"BSB":{"text":"Jesus replied, “The work of God is this: to believe in the One He has sent.”"}},"definableWords":["work","God","one"],"peopleInVerse":["Jesus"]},"30":{"text":"They said therefore unto him, What sign shewest thou then, that we may see, and believe thee? what dost thou work?","ref":"John 6:30","synthesized":"So they asked Him, “What sign then will You perform, so that we may see it and believe You? What will You do?","sources":{"KJV":{"text":"They said therefore unto him, What sign shewest thou then, that we may see, and believe thee? what dost thou work?"},"BSB":{"text":"So they asked Him, “What sign then will You perform, so that we may see it and believe You? What will You do?"}},"definableWords":["see"],"peopleInVerse":[]},"31":{"text":"Our fathers did eat manna in the desert; as it is written, He gave them bread from heaven to eat.","ref":"John 6:31","synthesized":"Our fathers ate the manna in the wilderness, as it is written: ‘He gave them bread from heaven to eat.’”","sources":{"KJV":{"text":"Our fathers did eat manna in the desert; as it is written, He gave them bread from heaven to eat."},"BSB":{"text":"Our fathers ate the manna in the wilderness, as it is written: ‘He gave them bread from heaven to eat.’”"}},"definableWords":["fathers","manna","heaven"],"peopleInVerse":[]},"32":{"text":"Then Jesus said unto them, Verily, verily, I say unto you, Moses gave you not that bread from heaven; but my Father giveth you the true bread from heaven.","ref":"John 6:32","synthesized":"Jesus said to them, “Truly, truly, I tell you, it was not Moses who gave you the bread from heaven, but it is My Father who gives you the true bread from heaven.","sources":{"KJV":{"text":"Then Jesus said unto them, Verily, verily, I say unto you, Moses gave you not that bread from heaven; but my Father giveth you the true bread from heaven."},"BSB":{"text":"Jesus said to them, “Truly, truly, I tell you, it was not Moses who gave you the bread from heaven, but it is My Father who gives you the true bread from heaven."}},"definableWords":["heaven","Father"],"peopleInVerse":["Jesus","Moses"]},"33":{"text":"For the bread of God is he which cometh down from heaven, and giveth life unto the world.","ref":"John 6:33","synthesized":"For the bread of God is He who comes down from heaven and gives life to the world.”","sources":{"KJV":{"text":"For the bread of God is he which cometh down from heaven, and giveth life unto the world."},"BSB":{"text":"For the bread of God is He who comes down from heaven and gives life to the world.”"}},"definableWords":["God","heaven","life"],"peopleInVerse":[]},"34":{"text":"Then said they unto him, Lord, evermore give us this bread.","ref":"John 6:34","synthesized":"“Sir,” they said, “give us this bread at all times.”","sources":{"KJV":{"text":"Then said they unto him, Lord, evermore give us this bread."},"BSB":{"text":"“Sir,” they said, “give us this bread at all times.”"}},"definableWords":[],"peopleInVerse":[]},"35":{"text":"And Jesus said unto them, I am the bread of life: he that cometh to me shall never hunger; and he that believeth on me shall never thirst.","ref":"John 6:35","synthesized":"Jesus answered, “I am the bread of life. Whoever comes to Me will never hunger, and whoever believes in Me will never thirst.","sources":{"KJV":{"text":"And Jesus said unto them, I am the bread of life: he that cometh to me shall never hunger; and he that believeth on me shall never thirst."},"BSB":{"text":"Jesus answered, “I am the bread of life. Whoever comes to Me will never hunger, and whoever believes in Me will never thirst."}},"definableWords":["life"],"peopleInVerse":["Jesus"]},"36":{"text":"But I said unto you, That ye also have seen me, and believe not.","ref":"John 6:36","synthesized":"But as I stated, you have seen Me and still you do not believe.","sources":{"KJV":{"text":"But I said unto you, That ye also have seen me, and believe not."},"BSB":{"text":"But as I stated, you have seen Me and still you do not believe."}},"definableWords":[],"peopleInVerse":[]},"37":{"text":"All that the Father giveth me shall come to me; and him that cometh to me I will in no wise cast out.","ref":"John 6:37","synthesized":"Everyone the Father gives Me will come to Me, and the one who comes to Me I will never drive away.","sources":{"KJV":{"text":"All that the Father giveth me shall come to me; and him that cometh to me I will in no wise cast out."},"BSB":{"text":"Everyone the Father gives Me will come to Me, and the one who comes to Me I will never drive away."}},"definableWords":["Father","one"],"peopleInVerse":[]},"38":{"text":"For I came down from heaven, not to do mine own will, but the will of him that sent me.","ref":"John 6:38","synthesized":"For I have come down from heaven, not to do My own will, but to do the will of Him who sent Me.","sources":{"KJV":{"text":"For I came down from heaven, not to do mine own will, but the will of him that sent me."},"BSB":{"text":"For I have come down from heaven, not to do My own will, but to do the will of Him who sent Me."}},"definableWords":["heaven"],"peopleInVerse":[]},"39":{"text":"And this is the Father’s will which hath sent me, that of all which he hath given me I should lose nothing, but should raise it up again at the last day.","ref":"John 6:39","synthesized":"And this is the will of Him who sent Me, that I shall lose none of those He has given Me, but raise them up at the last day.","sources":{"KJV":{"text":"And this is the Father’s will which hath sent me, that of all which he hath given me I should lose nothing, but should raise it up again at the last day."},"BSB":{"text":"And this is the will of Him who sent Me, that I shall lose none of those He has given Me, but raise them up at the last day."}},"definableWords":["day"],"peopleInVerse":[]},"40":{"text":"And this is the will of him that sent me, that every one which seeth the Son, and believeth on him, may have everlasting life: and I will raise him up at the last day.","ref":"John 6:40","synthesized":"For it is My Father’s will that everyone who looks to the Son and believes in Him shall have eternal life, and I will raise him up at the last day.”","sources":{"KJV":{"text":"And this is the will of him that sent me, that every one which seeth the Son, and believeth on him, may have everlasting life: and I will raise him up at the last day."},"BSB":{"text":"For it is My Father’s will that everyone who looks to the Son and believes in Him shall have eternal life, and I will raise him up at the last day.”"}},"definableWords":["Father","Son","eternal","life","day"],"peopleInVerse":[]},"41":{"text":"The Jews then murmured at him, because he said, I am the bread which came down from heaven.","ref":"John 6:41","synthesized":"At this, the Jews began to grumble about Jesus because He had said, “I am the bread that came down from heaven.”","sources":{"KJV":{"text":"The Jews then murmured at him, because he said, I am the bread which came down from heaven."},"BSB":{"text":"At this, the Jews began to grumble about Jesus because He had said, “I am the bread that came down from heaven.”"}},"definableWords":["heaven"],"peopleInVerse":["Jesus"]},"42":{"text":"And they said, Is not this Jesus, the son of Joseph, whose father and mother we know? how is it then that he saith, I came down from heaven?","ref":"John 6:42","synthesized":"They were asking, “Is this not Jesus, the son of Joseph, whose father and mother we know? How then can He say, ‘I have come down from heaven?’”","sources":{"KJV":{"text":"And they said, Is not this Jesus, the son of Joseph, whose father and mother we know? how is it then that he saith, I came down from heaven?"},"BSB":{"text":"They were asking, “Is this not Jesus, the son of Joseph, whose father and mother we know? How then can He say, ‘I have come down from heaven?’”"}},"definableWords":["son","Joseph","father","mother","heaven"],"peopleInVerse":["Jesus","Joseph"]},"43":{"text":"Jesus therefore answered and said unto them, Murmur not among yourselves.","ref":"John 6:43","synthesized":"“Stop grumbling among yourselves,” Jesus replied.","sources":{"KJV":{"text":"Jesus therefore answered and said unto them, Murmur not among yourselves."},"BSB":{"text":"“Stop grumbling among yourselves,” Jesus replied."}},"definableWords":[],"peopleInVerse":["Jesus"]},"44":{"text":"No man can come to me, except the Father which hath sent me draw him: and I will raise him up at the last day.","ref":"John 6:44","synthesized":"“No one can come to Me unless the Father who sent Me draws him, and I will raise him up at the last day.","sources":{"KJV":{"text":"No man can come to me, except the Father which hath sent me draw him: and I will raise him up at the last day."},"BSB":{"text":"“No one can come to Me unless the Father who sent Me draws him, and I will raise him up at the last day."}},"definableWords":["one","Father","day"],"peopleInVerse":[]},"45":{"text":"It is written in the prophets, And they shall be all taught of God. Every man therefore that hath heard, and hath learned of the Father, cometh unto me.","ref":"John 6:45","synthesized":"It is written in the Prophets: ‘And they will all be taught by God.’ Everyone who has heard the Father and learned from Him comes to Me—","sources":{"KJV":{"text":"It is written in the prophets, And they shall be all taught of God. Every man therefore that hath heard, and hath learned of the Father, cometh unto me."},"BSB":{"text":"It is written in the Prophets: ‘And they will all be taught by God.’ Everyone who has heard the Father and learned from Him comes to Me—"}},"definableWords":["God","Father"],"peopleInVerse":[]},"46":{"text":"Not that any man hath seen the Father, save he which is of God, he hath seen the Father.","ref":"John 6:46","synthesized":"not that anyone has seen the Father except the One who is from God; only He has seen the Father.","sources":{"KJV":{"text":"Not that any man hath seen the Father, save he which is of God, he hath seen the Father."},"BSB":{"text":"not that anyone has seen the Father except the One who is from God; only He has seen the Father."}},"definableWords":["Father","one","God"],"peopleInVerse":[]},"47":{"text":"Verily, verily, I say unto you, He that believeth on me hath everlasting life.","ref":"John 6:47","synthesized":"Truly, truly, I tell you, he who believes has eternal life.","sources":{"KJV":{"text":"Verily, verily, I say unto you, He that believeth on me hath everlasting life."},"BSB":{"text":"Truly, truly, I tell you, he who believes has eternal life."}},"definableWords":["eternal","life"],"peopleInVerse":[]},"48":{"text":"I am that bread of life.","ref":"John 6:48","synthesized":"I am the bread of life.","sources":{"KJV":{"text":"I am that bread of life."},"BSB":{"text":"I am the bread of life."}},"definableWords":["life"],"peopleInVerse":[]},"49":{"text":"Your fathers did eat manna in the wilderness, and are dead.","ref":"John 6:49","synthesized":"Your fathers ate the manna in the wilderness, yet they died.","sources":{"KJV":{"text":"Your fathers did eat manna in the wilderness, and are dead."},"BSB":{"text":"Your fathers ate the manna in the wilderness, yet they died."}},"definableWords":["fathers","manna"],"peopleInVerse":[]},"50":{"text":"This is the bread which cometh down from heaven, that a man may eat thereof, and not die.","ref":"John 6:50","synthesized":"This is the bread that comes down from heaven, so that anyone may eat of it and not die.","sources":{"KJV":{"text":"This is the bread which cometh down from heaven, that a man may eat thereof, and not die."},"BSB":{"text":"This is the bread that comes down from heaven, so that anyone may eat of it and not die."}},"definableWords":["heaven","die"],"peopleInVerse":[]},"51":{"text":"I am the living bread which came down from heaven: if any man eat of this bread, he shall live for ever: and the bread that I will give is my flesh, which I will give for the life of the world.","ref":"John 6:51","synthesized":"I am the living bread that came down from heaven. If anyone eats of this bread, he will live forever. And this bread, which I will give for the life of the world, is My flesh.”","sources":{"KJV":{"text":"I am the living bread which came down from heaven: if any man eat of this bread, he shall live for ever: and the bread that I will give is my flesh, which I will give for the life of the world."},"BSB":{"text":"I am the living bread that came down from heaven. If anyone eats of this bread, he will live forever. And this bread, which I will give for the life of the world, is My flesh.”"}},"definableWords":["living","heaven","live","life","flesh"],"peopleInVerse":[]},"52":{"text":"The Jews therefore strove among themselves, saying, How can this man give us his flesh to eat?","ref":"John 6:52","synthesized":"At this, the Jews began to argue among themselves, “How can this man give us His flesh to eat?”","sources":{"KJV":{"text":"The Jews therefore strove among themselves, saying, How can this man give us his flesh to eat?"},"BSB":{"text":"At this, the Jews began to argue among themselves, “How can this man give us His flesh to eat?”"}},"definableWords":["man","flesh"],"peopleInVerse":[]},"53":{"text":"Then Jesus said unto them, Verily, verily, I say unto you, Except ye eat the flesh of the Son of man, and drink his blood, ye have no life in you.","ref":"John 6:53","synthesized":"So Jesus said to them, “Truly, truly, I tell you, unless you eat the flesh and drink the blood of the Son of Man, you have no life in you.","sources":{"KJV":{"text":"Then Jesus said unto them, Verily, verily, I say unto you, Except ye eat the flesh of the Son of man, and drink his blood, ye have no life in you."},"BSB":{"text":"So Jesus said to them, “Truly, truly, I tell you, unless you eat the flesh and drink the blood of the Son of Man, you have no life in you."}},"definableWords":["flesh","blood","Son","man","life"],"peopleInVerse":["Jesus"]},"54":{"text":"Whoso eateth my flesh, and drinketh my blood, hath eternal life; and I will raise him up at the last day.","ref":"John 6:54","synthesized":"Whoever eats My flesh and drinks My blood has eternal life, and I will raise him up at the last day.","sources":{"KJV":{"text":"Whoso eateth my flesh, and drinketh my blood, hath eternal life; and I will raise him up at the last day."},"BSB":{"text":"Whoever eats My flesh and drinks My blood has eternal life, and I will raise him up at the last day."}},"definableWords":["flesh","blood","eternal","life","day"],"peopleInVerse":[]},"55":{"text":"For my flesh is meat indeed, and my blood is drink indeed.","ref":"John 6:55","synthesized":"For My flesh is real food, and My blood is real drink.","sources":{"KJV":{"text":"For my flesh is meat indeed, and my blood is drink indeed."},"BSB":{"text":"For My flesh is real food, and My blood is real drink."}},"definableWords":["flesh","blood"],"peopleInVerse":[]},"56":{"text":"He that eateth my flesh, and drinketh my blood, dwelleth in me, and I in him.","ref":"John 6:56","synthesized":"Whoever eats My flesh and drinks My blood remains in Me, and I in him.","sources":{"KJV":{"text":"He that eateth my flesh, and drinketh my blood, dwelleth in me, and I in him."},"BSB":{"text":"Whoever eats My flesh and drinks My blood remains in Me, and I in him."}},"definableWords":["flesh","blood"],"peopleInVerse":[]},"57":{"text":"As the living Father hath sent me, and I live by the Father: so he that eateth me, even he shall live by me.","ref":"John 6:57","synthesized":"Just as the living Father sent Me and I live because of the Father, so also the one who feeds on Me will live because of Me.","sources":{"KJV":{"text":"As the living Father hath sent me, and I live by the Father: so he that eateth me, even he shall live by me."},"BSB":{"text":"Just as the living Father sent Me and I live because of the Father, so also the one who feeds on Me will live because of Me."}},"definableWords":["living","Father","live","one"],"peopleInVerse":[]},"58":{"text":"This is that bread which came down from heaven: not as your fathers did eat manna, and are dead: he that eateth of this bread shall live for ever.","ref":"John 6:58","synthesized":"This is the bread that came down from heaven. Unlike your fathers, who ate the manna and died, the one who eats this bread will live forever.”","sources":{"KJV":{"text":"This is that bread which came down from heaven: not as your fathers did eat manna, and are dead: he that eateth of this bread shall live for ever."},"BSB":{"text":"This is the bread that came down from heaven. Unlike your fathers, who ate the manna and died, the one who eats this bread will live forever.”"}},"definableWords":["heaven","fathers","manna","one","live"],"peopleInVerse":[]},"59":{"text":"These things said he in the synagogue, as he taught in Capernaum.","ref":"John 6:59","synthesized":"Jesus said this while teaching in the synagogue in Capernaum.","sources":{"KJV":{"text":"These things said he in the synagogue, as he taught in Capernaum."},"BSB":{"text":"Jesus said this while teaching in the synagogue in Capernaum."}},"definableWords":[],"peopleInVerse":["Jesus"]},"60":{"text":"Many therefore of his disciples, when they had heard this, said, This is an hard saying; who can hear it?","ref":"John 6:60","synthesized":"On hearing it, many of His disciples said, “This is a difficult teaching. Who can accept it?”","sources":{"KJV":{"text":"Many therefore of his disciples, when they had heard this, said, This is an hard saying; who can hear it?"},"BSB":{"text":"On hearing it, many of His disciples said, “This is a difficult teaching. Who can accept it?”"}},"definableWords":[],"peopleInVerse":[]},"61":{"text":"When Jesus knew in himself that his disciples murmured at it, he said unto them, Doth this offend you?","ref":"John 6:61","synthesized":"Aware that His disciples were grumbling about this teaching, Jesus asked them, “Does this offend you?","sources":{"KJV":{"text":"When Jesus knew in himself that his disciples murmured at it, he said unto them, Doth this offend you?"},"BSB":{"text":"Aware that His disciples were grumbling about this teaching, Jesus asked them, “Does this offend you?"}},"definableWords":[],"peopleInVerse":["Jesus"]},"62":{"text":"What and if ye shall see the Son of man ascend up where he was before?","ref":"John 6:62","synthesized":"Then what will happen if you see the Son of Man ascend to where He was before?","sources":{"KJV":{"text":"What and if ye shall see the Son of man ascend up where he was before?"},"BSB":{"text":"Then what will happen if you see the Son of Man ascend to where He was before?"}},"definableWords":["see","Son","man"],"peopleInVerse":[]},"63":{"text":"It is the spirit that quickeneth; the flesh profiteth nothing: the words that I speak unto you, they are spirit, and they are life.","ref":"John 6:63","synthesized":"The Spirit gives life; the flesh profits nothing. The words I have spoken to you are spirit and they are life.","sources":{"KJV":{"text":"It is the spirit that quickeneth; the flesh profiteth nothing: the words that I speak unto you, they are spirit, and they are life."},"BSB":{"text":"The Spirit gives life; the flesh profits nothing. The words I have spoken to you are spirit and they are life."}},"definableWords":["Spirit","life","flesh","spirit"],"peopleInVerse":[]},"64":{"text":"But there are some of you that believe not. For Jesus knew from the beginning who they were that believed not, and who should betray him.","ref":"John 6:64","synthesized":"However, there are some of you who do not believe.” (For Jesus had known from the beginning which of them did not believe and who would betray Him.)","sources":{"KJV":{"text":"But there are some of you that believe not. For Jesus knew from the beginning who they were that believed not, and who should betray him."},"BSB":{"text":"However, there are some of you who do not believe.” (For Jesus had known from the beginning which of them did not believe and who would betray Him.)"}},"definableWords":["beginning"],"peopleInVerse":["Jesus"]},"65":{"text":"And he said, Therefore said I unto you, that no man can come unto me, except it were given unto him of my Father.","ref":"John 6:65","synthesized":"Then Jesus said, “This is why I told you that no one can come to Me unless the Father has granted it to him.”","sources":{"KJV":{"text":"And he said, Therefore said I unto you, that no man can come unto me, except it were given unto him of my Father."},"BSB":{"text":"Then Jesus said, “This is why I told you that no one can come to Me unless the Father has granted it to him.”"}},"definableWords":["one","Father"],"peopleInVerse":["Jesus"]},"66":{"text":"From that time many of his disciples went back, and walked no more with him.","ref":"John 6:66","synthesized":"From that time on many of His disciples turned back and no longer walked with Him.","sources":{"KJV":{"text":"From that time many of his disciples went back, and walked no more with him."},"BSB":{"text":"From that time on many of His disciples turned back and no longer walked with Him."}},"definableWords":["walked"],"peopleInVerse":[]},"67":{"text":"Then said Jesus unto the twelve, Will ye also go away?","ref":"John 6:67","synthesized":"So Jesus asked the Twelve, “Do you want to leave too?”","sources":{"KJV":{"text":"Then said Jesus unto the twelve, Will ye also go away?"},"BSB":{"text":"So Jesus asked the Twelve, “Do you want to leave too?”"}},"definableWords":[],"peopleInVerse":["Jesus"]},"68":{"text":"Then Simon Peter answered him, Lord, to whom shall we go? thou hast the words of eternal life.","ref":"John 6:68","synthesized":"Simon Peter replied, “Lord, to whom would we go? You have the words of eternal life.","sources":{"KJV":{"text":"Then Simon Peter answered him, Lord, to whom shall we go? thou hast the words of eternal life."},"BSB":{"text":"Simon Peter replied, “Lord, to whom would we go? You have the words of eternal life."}},"definableWords":["Lord","eternal","life"],"peopleInVerse":["Peter"]},"69":{"text":"And we believe and are sure that thou art that Christ, the Son of the living God.","ref":"John 6:69","synthesized":"We believe and know that You are the Holy One of God.”","sources":{"KJV":{"text":"And we believe and are sure that thou art that Christ, the Son of the living God."},"BSB":{"text":"We believe and know that You are the Holy One of God.”"}},"definableWords":["holy","one","God"],"peopleInVerse":[]},"70":{"text":"Jesus answered them, Have not I chosen you twelve, and one of you is a devil?","ref":"John 6:70","synthesized":"Jesus answered them, “Have I not chosen you, the Twelve? Yet one of you is a devil!”","sources":{"KJV":{"text":"Jesus answered them, Have not I chosen you twelve, and one of you is a devil?"},"BSB":{"text":"Jesus answered them, “Have I not chosen you, the Twelve? Yet one of you is a devil!”"}},"definableWords":["one","devil"],"peopleInVerse":["Jesus"]},"71":{"text":"He spake of Judas Iscariot the son of Simon: for he it was that should betray him, being one of the twelve.","ref":"John 6:71","synthesized":"He was speaking about Judas, the son of Simon Iscariot. For although Judas was one of the Twelve, he was later to betray Jesus.","sources":{"KJV":{"text":"He spake of Judas Iscariot the son of Simon: for he it was that should betray him, being one of the twelve."},"BSB":{"text":"He was speaking about Judas, the son of Simon Iscariot. For although Judas was one of the Twelve, he was later to betray Jesus."}},"definableWords":["son","one"],"peopleInVerse":["Jesus"]}}},"7":{"chapter":"7","title":"RIVERS OF LIVING WATER","verses":{"1":{"text":"After these things Jesus walked in Galilee: for he would not walk in Jewry, because the Jews sought to kill him.","ref":"John 7:1","synthesized":"After this, Jesus traveled throughout Galilee. He did not want to travel in Judea, because the Jews there were trying to kill Him.","sources":{"KJV":{"text":"After these things Jesus walked in Galilee: for he would not walk in Jewry, because the Jews sought to kill him."},"BSB":{"text":"After this, Jesus traveled throughout Galilee. He did not want to travel in Judea, because the Jews there were trying to kill Him."}},"definableWords":["Galilee","Judea"],"peopleInVerse":["Jesus"]},"2":{"text":"Now the Jews’ feast of tabernacles was at hand.","ref":"John 7:2","synthesized":"However, the Jewish Feast of Tabernacles was near.","sources":{"KJV":{"text":"Now the Jews’ feast of tabernacles was at hand."},"BSB":{"text":"However, the Jewish Feast of Tabernacles was near."}},"definableWords":[],"peopleInVerse":[]},"3":{"text":"His brethren therefore said unto him, Depart hence, and go into Judaea, that thy disciples also may see the works that thou doest.","ref":"John 7:3","synthesized":"So Jesus’ brothers said to Him, “Leave here and go to Judea, so that Your disciples there may see the works You are doing.","sources":{"KJV":{"text":"His brethren therefore said unto him, Depart hence, and go into Judaea, that thy disciples also may see the works that thou doest."},"BSB":{"text":"So Jesus’ brothers said to Him, “Leave here and go to Judea, so that Your disciples there may see the works You are doing."}},"definableWords":["Judea","see","works"],"peopleInVerse":["Jesus"]},"4":{"text":"For there is no man that doeth any thing in secret, and he himself seeketh to be known openly. If thou do these things, shew thyself to the world.","ref":"John 7:4","synthesized":"For no one who wants to be known publicly acts in secret. Since You are doing these things, show Yourself to the world.”","sources":{"KJV":{"text":"For there is no man that doeth any thing in secret, and he himself seeketh to be known openly. If thou do these things, shew thyself to the world."},"BSB":{"text":"For no one who wants to be known publicly acts in secret. Since You are doing these things, show Yourself to the world.”"}},"definableWords":["one"],"peopleInVerse":[]},"5":{"text":"For neither did his brethren believe in him.","ref":"John 7:5","synthesized":"For even His own brothers did not believe in Him.","sources":{"KJV":{"text":"For neither did his brethren believe in him."},"BSB":{"text":"For even His own brothers did not believe in Him."}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"Then Jesus said unto them, My time is not yet come: but your time is alway ready.","ref":"John 7:6","synthesized":"Therefore Jesus told them, “Although your time is always at hand, My time has not yet come.","sources":{"KJV":{"text":"Then Jesus said unto them, My time is not yet come: but your time is alway ready."},"BSB":{"text":"Therefore Jesus told them, “Although your time is always at hand, My time has not yet come."}},"definableWords":[],"peopleInVerse":["Jesus"]},"7":{"text":"The world cannot hate you; but me it hateth, because I testify of it, that the works thereof are evil.","ref":"John 7:7","synthesized":"The world cannot hate you, but it hates Me, because I testify that its works are evil.","sources":{"KJV":{"text":"The world cannot hate you; but me it hateth, because I testify of it, that the works thereof are evil."},"BSB":{"text":"The world cannot hate you, but it hates Me, because I testify that its works are evil."}},"definableWords":["works","evil"],"peopleInVerse":[]},"8":{"text":"Go ye up unto this feast: I go not up yet unto this feast: for my time is not yet full come.","ref":"John 7:8","synthesized":"Go up to the feast on your own. I am not going up to this feast, because My time has not yet come.”","sources":{"KJV":{"text":"Go ye up unto this feast: I go not up yet unto this feast: for my time is not yet full come."},"BSB":{"text":"Go up to the feast on your own. I am not going up to this feast, because My time has not yet come.”"}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"When he had said these words unto them, he abode still in Galilee.","ref":"John 7:9","synthesized":"Having said this, Jesus remained in Galilee.","sources":{"KJV":{"text":"When he had said these words unto them, he abode still in Galilee."},"BSB":{"text":"Having said this, Jesus remained in Galilee."}},"definableWords":["Galilee"],"peopleInVerse":["Jesus"]},"10":{"text":"But when his brethren were gone up, then went he also up unto the feast, not openly, but as it were in secret.","ref":"John 7:10","synthesized":"But after His brothers had gone up to the feast, He also went—not publicly, but in secret.","sources":{"KJV":{"text":"But when his brethren were gone up, then went he also up unto the feast, not openly, but as it were in secret."},"BSB":{"text":"But after His brothers had gone up to the feast, He also went—not publicly, but in secret."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"Then the Jews sought him at the feast, and said, Where is he?","ref":"John 7:11","synthesized":"So the Jews were looking for Him at the feast and asking, “Where is He?”","sources":{"KJV":{"text":"Then the Jews sought him at the feast, and said, Where is he?"},"BSB":{"text":"So the Jews were looking for Him at the feast and asking, “Where is He?”"}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"And there was much murmuring among the people concerning him: for some said, He is a good man: others said, Nay; but he deceiveth the people.","ref":"John 7:12","synthesized":"Many in the crowds were whispering about Him. Some said, “He is a good man.”  But others replied, “No, He deceives the people.”","sources":{"KJV":{"text":"And there was much murmuring among the people concerning him: for some said, He is a good man: others said, Nay; but he deceiveth the people."},"BSB":{"text":"Many in the crowds were whispering about Him. Some said, “He is a good man.”  But others replied, “No, He deceives the people.”"}},"definableWords":["good","man","people"],"peopleInVerse":[]},"13":{"text":"Howbeit no man spake openly of him for fear of the Jews.","ref":"John 7:13","synthesized":"Yet no one would speak publicly about Him for fear of the Jews.","sources":{"KJV":{"text":"Howbeit no man spake openly of him for fear of the Jews."},"BSB":{"text":"Yet no one would speak publicly about Him for fear of the Jews."}},"definableWords":["one","fear"],"peopleInVerse":[]},"14":{"text":"Now about the midst of the feast Jesus went up into the temple, and taught.","ref":"John 7:14","synthesized":"About halfway through the feast, Jesus went up to the temple courts and began to teach.","sources":{"KJV":{"text":"Now about the midst of the feast Jesus went up into the temple, and taught."},"BSB":{"text":"About halfway through the feast, Jesus went up to the temple courts and began to teach."}},"definableWords":["temple"],"peopleInVerse":["Jesus"]},"15":{"text":"And the Jews marvelled, saying, How knoweth this man letters, having never learned?","ref":"John 7:15","synthesized":"The Jews were amazed and asked, “How did this man attain such learning without having studied?”","sources":{"KJV":{"text":"And the Jews marvelled, saying, How knoweth this man letters, having never learned?"},"BSB":{"text":"The Jews were amazed and asked, “How did this man attain such learning without having studied?”"}},"definableWords":["man"],"peopleInVerse":[]},"16":{"text":"Jesus answered them, and said, My doctrine is not mine, but his that sent me.","ref":"John 7:16","synthesized":"“My teaching is not My own,” Jesus replied. “It comes from Him who sent Me.","sources":{"KJV":{"text":"Jesus answered them, and said, My doctrine is not mine, but his that sent me."},"BSB":{"text":"“My teaching is not My own,” Jesus replied. “It comes from Him who sent Me."}},"definableWords":[],"peopleInVerse":["Jesus"]},"17":{"text":"If any man will do his will, he shall know of the doctrine, whether it be of God, or whether I speak of myself.","ref":"John 7:17","synthesized":"If anyone desires to do His will, he will know whether My teaching is from God or whether I speak on My own.","sources":{"KJV":{"text":"If any man will do his will, he shall know of the doctrine, whether it be of God, or whether I speak of myself."},"BSB":{"text":"If anyone desires to do His will, he will know whether My teaching is from God or whether I speak on My own."}},"definableWords":["God","or"],"peopleInVerse":[]},"18":{"text":"He that speaketh of himself seeketh his own glory: but he that seeketh his glory that sent him, the same is true, and no unrighteousness is in him.","ref":"John 7:18","synthesized":"He who speaks on his own authority seeks his own glory, but He who seeks the glory of the One who sent Him is a man of truth; in Him there is no falsehood.","sources":{"KJV":{"text":"He that speaketh of himself seeketh his own glory: but he that seeketh his glory that sent him, the same is true, and no unrighteousness is in him."},"BSB":{"text":"He who speaks on his own authority seeks his own glory, but He who seeks the glory of the One who sent Him is a man of truth; in Him there is no falsehood."}},"definableWords":["glory","one","man","truth"],"peopleInVerse":[]},"19":{"text":"Did not Moses give you the law, and yet none of you keepeth the law? Why go ye about to kill me?","ref":"John 7:19","synthesized":"Has not Moses given you the law? Yet not one of you keeps it. Why are you trying to kill Me?”","sources":{"KJV":{"text":"Did not Moses give you the law, and yet none of you keepeth the law? Why go ye about to kill me?"},"BSB":{"text":"Has not Moses given you the law? Yet not one of you keeps it. Why are you trying to kill Me?”"}},"definableWords":["law","one"],"peopleInVerse":["Moses"]},"20":{"text":"The people answered and said, Thou hast a devil: who goeth about to kill thee?","ref":"John 7:20","synthesized":"“You have a demon,” the crowd replied. “Who is trying to kill You?”","sources":{"KJV":{"text":"The people answered and said, Thou hast a devil: who goeth about to kill thee?"},"BSB":{"text":"“You have a demon,” the crowd replied. “Who is trying to kill You?”"}},"definableWords":["demon"],"peopleInVerse":[]},"21":{"text":"Jesus answered and said unto them, I have done one work, and ye all marvel.","ref":"John 7:21","synthesized":"Jesus answered them, “I did one miracle, and you are all amazed.","sources":{"KJV":{"text":"Jesus answered and said unto them, I have done one work, and ye all marvel."},"BSB":{"text":"Jesus answered them, “I did one miracle, and you are all amazed."}},"definableWords":["one"],"peopleInVerse":["Jesus"]},"22":{"text":"Moses therefore gave unto you circumcision; (not because it is of Moses, but of the fathers;) and ye on the sabbath day circumcise a man.","ref":"John 7:22","synthesized":"But because Moses gave you circumcision, you circumcise a boy on the Sabbath (not that it is from Moses, but from the patriarchs.)","sources":{"KJV":{"text":"Moses therefore gave unto you circumcision; (not because it is of Moses, but of the fathers;) and ye on the sabbath day circumcise a man."},"BSB":{"text":"But because Moses gave you circumcision, you circumcise a boy on the Sabbath (not that it is from Moses, but from the patriarchs.)"}},"definableWords":["circumcision","Sabbath"],"peopleInVerse":["Moses"]},"23":{"text":"If a man on the sabbath day receive circumcision, that the law of Moses should not be broken; are ye angry at me, because I have made a man every whit whole on the sabbath day?","ref":"John 7:23","synthesized":"If a boy can be circumcised on the Sabbath so that the law of Moses will not be broken, why are you angry with Me for making the whole man well on the Sabbath?","sources":{"KJV":{"text":"If a man on the sabbath day receive circumcision, that the law of Moses should not be broken; are ye angry at me, because I have made a man every whit whole on the sabbath day?"},"BSB":{"text":"If a boy can be circumcised on the Sabbath so that the law of Moses will not be broken, why are you angry with Me for making the whole man well on the Sabbath?"}},"definableWords":["circumcised","Sabbath","law","man","sabbath"],"peopleInVerse":["Moses"]},"24":{"text":"Judge not according to the appearance, but judge righteous judgment.","ref":"John 7:24","synthesized":"Stop judging by outward appearances, and start judging justly.”","sources":{"KJV":{"text":"Judge not according to the appearance, but judge righteous judgment."},"BSB":{"text":"Stop judging by outward appearances, and start judging justly.”"}},"definableWords":[],"peopleInVerse":[]},"25":{"text":"Then said some of them of Jerusalem, Is not this he, whom they seek to kill?","ref":"John 7:25","synthesized":"Then some of the people of Jerusalem began to say, “Isn’t this the man they are trying to kill?","sources":{"KJV":{"text":"Then said some of them of Jerusalem, Is not this he, whom they seek to kill?"},"BSB":{"text":"Then some of the people of Jerusalem began to say, “Isn’t this the man they are trying to kill?"}},"definableWords":["people","Jerusalem","man"],"peopleInVerse":[]},"26":{"text":"But, lo, he speaketh boldly, and they say nothing unto him. Do the rulers know indeed that this is the very Christ?","ref":"John 7:26","synthesized":"Yet here He is, speaking publicly, and they are not saying anything to Him. Have the rulers truly recognized that this is the Christ?","sources":{"KJV":{"text":"But, lo, he speaketh boldly, and they say nothing unto him. Do the rulers know indeed that this is the very Christ?"},"BSB":{"text":"Yet here He is, speaking publicly, and they are not saying anything to Him. Have the rulers truly recognized that this is the Christ?"}},"definableWords":["Christ"],"peopleInVerse":[]},"27":{"text":"Howbeit we know this man whence he is: but when Christ cometh, no man knoweth whence he is.","ref":"John 7:27","synthesized":"But we know where this man is from. When the Christ comes, no one will know where He is from.”","sources":{"KJV":{"text":"Howbeit we know this man whence he is: but when Christ cometh, no man knoweth whence he is."},"BSB":{"text":"But we know where this man is from. When the Christ comes, no one will know where He is from.”"}},"definableWords":["man","Christ","one"],"peopleInVerse":[]},"28":{"text":"Then cried Jesus in the temple as he taught, saying, Ye both know me, and ye know whence I am: and I am not come of myself, but he that sent me is true, whom ye know not.","ref":"John 7:28","synthesized":"Then Jesus, still teaching in the temple courts, cried out, “You know Me, and you know where I am from. I have not come of My own accord, but He who sent Me is true. You do not know Him,","sources":{"KJV":{"text":"Then cried Jesus in the temple as he taught, saying, Ye both know me, and ye know whence I am: and I am not come of myself, but he that sent me is true, whom ye know not."},"BSB":{"text":"Then Jesus, still teaching in the temple courts, cried out, “You know Me, and you know where I am from. I have not come of My own accord, but He who sent Me is true. You do not know Him,"}},"definableWords":["temple"],"peopleInVerse":["Jesus"]},"29":{"text":"But I know him: for I am from him, and he hath sent me.","ref":"John 7:29","synthesized":"but I know Him, because I am from Him and He sent Me.”","sources":{"KJV":{"text":"But I know him: for I am from him, and he hath sent me."},"BSB":{"text":"but I know Him, because I am from Him and He sent Me.”"}},"definableWords":[],"peopleInVerse":[]},"30":{"text":"Then they sought to take him: but no man laid hands on him, because his hour was not yet come.","ref":"John 7:30","synthesized":"So they tried to seize Him, but no one laid a hand on Him, because His hour had not yet come.","sources":{"KJV":{"text":"Then they sought to take him: but no man laid hands on him, because his hour was not yet come."},"BSB":{"text":"So they tried to seize Him, but no one laid a hand on Him, because His hour had not yet come."}},"definableWords":["one"],"peopleInVerse":[]},"31":{"text":"And many of the people believed on him, and said, When Christ cometh, will he do more miracles than these which this man hath done?","ref":"John 7:31","synthesized":"Many in the crowd, however, believed in Him and said, “When the Christ comes, will He perform more signs than this man?”","sources":{"KJV":{"text":"And many of the people believed on him, and said, When Christ cometh, will he do more miracles than these which this man hath done?"},"BSB":{"text":"Many in the crowd, however, believed in Him and said, “When the Christ comes, will He perform more signs than this man?”"}},"definableWords":["believed","Christ","man"],"peopleInVerse":[]},"32":{"text":"The Pharisees heard that the people murmured such things concerning him; and the Pharisees and the chief priests sent officers to take him.","ref":"John 7:32","synthesized":"When the Pharisees heard the crowd whispering these things about Jesus, they and the chief priests sent officers to arrest Him.","sources":{"KJV":{"text":"The Pharisees heard that the people murmured such things concerning him; and the Pharisees and the chief priests sent officers to take him."},"BSB":{"text":"When the Pharisees heard the crowd whispering these things about Jesus, they and the chief priests sent officers to arrest Him."}},"definableWords":[],"peopleInVerse":["Jesus"]},"33":{"text":"Then said Jesus unto them, Yet a little while am I with you, and then I go unto him that sent me.","ref":"John 7:33","synthesized":"So Jesus said, “I am with you only a little while longer, and then I am going to the One who sent Me.","sources":{"KJV":{"text":"Then said Jesus unto them, Yet a little while am I with you, and then I go unto him that sent me."},"BSB":{"text":"So Jesus said, “I am with you only a little while longer, and then I am going to the One who sent Me."}},"definableWords":["one"],"peopleInVerse":["Jesus"]},"34":{"text":"Ye shall seek me, and shall not find me: and where I am, thither ye cannot come.","ref":"John 7:34","synthesized":"You will look for Me, but you will not find Me; and where I am, you cannot come.”","sources":{"KJV":{"text":"Ye shall seek me, and shall not find me: and where I am, thither ye cannot come."},"BSB":{"text":"You will look for Me, but you will not find Me; and where I am, you cannot come.”"}},"definableWords":[],"peopleInVerse":[]},"35":{"text":"Then said the Jews among themselves, Whither will he go, that we shall not find him? will he go unto the dispersed among the Gentiles, and teach the Gentiles?","ref":"John 7:35","synthesized":"At this, the Jews said to one another, “Where does He intend to go that we will not find Him? Will He go where the Jews are dispersed among the Greeks, and teach the Greeks?","sources":{"KJV":{"text":"Then said the Jews among themselves, Whither will he go, that we shall not find him? will he go unto the dispersed among the Gentiles, and teach the Gentiles?"},"BSB":{"text":"At this, the Jews said to one another, “Where does He intend to go that we will not find Him? Will He go where the Jews are dispersed among the Greeks, and teach the Greeks?"}},"definableWords":["one"],"peopleInVerse":[]},"36":{"text":"What manner of saying is this that he said, Ye shall seek me, and shall not find me: and where I am, thither ye cannot come?","ref":"John 7:36","synthesized":"What does He mean by saying, ‘You will look for Me, but you will not find Me,’ and, ‘Where I am, you cannot come’?”","sources":{"KJV":{"text":"What manner of saying is this that he said, Ye shall seek me, and shall not find me: and where I am, thither ye cannot come?"},"BSB":{"text":"What does He mean by saying, ‘You will look for Me, but you will not find Me,’ and, ‘Where I am, you cannot come’?”"}},"definableWords":[],"peopleInVerse":[]},"37":{"text":"In the last day, that great day of the feast, Jesus stood and cried, saying, If any man thirst, let him come unto me, and drink.","ref":"John 7:37","synthesized":"On the last and greatest day of the feast, Jesus stood up and called out in a loud voice, “If anyone is thirsty, let him come to Me and drink.","sources":{"KJV":{"text":"In the last day, that great day of the feast, Jesus stood and cried, saying, If any man thirst, let him come unto me, and drink."},"BSB":{"text":"On the last and greatest day of the feast, Jesus stood up and called out in a loud voice, “If anyone is thirsty, let him come to Me and drink."}},"definableWords":["day","voice"],"peopleInVerse":["Jesus"]},"38":{"text":"He that believeth on me, as the scripture hath said, out of his belly shall flow rivers of living water.","ref":"John 7:38","synthesized":"Whoever believes in Me, as the Scripture has said: ‘Streams of living water will flow from within him.’”","sources":{"KJV":{"text":"He that believeth on me, as the scripture hath said, out of his belly shall flow rivers of living water."},"BSB":{"text":"Whoever believes in Me, as the Scripture has said: ‘Streams of living water will flow from within him.’”"}},"definableWords":["living","water"],"peopleInVerse":[]},"39":{"text":"(But this spake he of the Spirit, which they that believe on him should receive: for the Holy Ghost was not yet given; because that Jesus was not yet glorified.)","ref":"John 7:39","synthesized":"He was speaking about the Spirit, whom those who believed in Him were later to receive. For the Spirit had not yet been given, because Jesus had not yet been glorified.","sources":{"KJV":{"text":"(But this spake he of the Spirit, which they that believe on him should receive: for the Holy Ghost was not yet given; because that Jesus was not yet glorified.)"},"BSB":{"text":"He was speaking about the Spirit, whom those who believed in Him were later to receive. For the Spirit had not yet been given, because Jesus had not yet been glorified."}},"definableWords":["Spirit","believed","spirit"],"peopleInVerse":["Jesus"]},"40":{"text":"Many of the people therefore, when they heard this saying, said, Of a truth this is the Prophet.","ref":"John 7:40","synthesized":"On hearing these words, some of the people said, “This is truly the Prophet.”","sources":{"KJV":{"text":"Many of the people therefore, when they heard this saying, said, Of a truth this is the Prophet."},"BSB":{"text":"On hearing these words, some of the people said, “This is truly the Prophet.”"}},"definableWords":["people","prophet"],"peopleInVerse":[]},"41":{"text":"Others said, This is the Christ. But some said, Shall Christ come out of Galilee?","ref":"John 7:41","synthesized":"Others declared, “This is the Christ.”  But still others asked, “How can the Christ come from Galilee?","sources":{"KJV":{"text":"Others said, This is the Christ. But some said, Shall Christ come out of Galilee?"},"BSB":{"text":"Others declared, “This is the Christ.”  But still others asked, “How can the Christ come from Galilee?"}},"definableWords":["Christ","Galilee"],"peopleInVerse":[]},"42":{"text":"Hath not the scripture said, That Christ cometh of the seed of David, and out of the town of Bethlehem, where David was?","ref":"John 7:42","synthesized":"Doesn’t the Scripture say that the Christ will come from the line of David and from Bethlehem, the village where David lived?”","sources":{"KJV":{"text":"Hath not the scripture said, That Christ cometh of the seed of David, and out of the town of Bethlehem, where David was?"},"BSB":{"text":"Doesn’t the Scripture say that the Christ will come from the line of David and from Bethlehem, the village where David lived?”"}},"definableWords":["Christ"],"peopleInVerse":["David"]},"43":{"text":"So there was a division among the people because of him.","ref":"John 7:43","synthesized":"So there was division in the crowd because of Jesus.","sources":{"KJV":{"text":"So there was a division among the people because of him."},"BSB":{"text":"So there was division in the crowd because of Jesus."}},"definableWords":[],"peopleInVerse":["Jesus"]},"44":{"text":"And some of them would have taken him; but no man laid hands on him.","ref":"John 7:44","synthesized":"Some of them wanted to seize Him, but no one laid a hand on Him.","sources":{"KJV":{"text":"And some of them would have taken him; but no man laid hands on him."},"BSB":{"text":"Some of them wanted to seize Him, but no one laid a hand on Him."}},"definableWords":["one"],"peopleInVerse":[]},"45":{"text":"Then came the officers to the chief priests and Pharisees; and they said unto them, Why have ye not brought him?","ref":"John 7:45","synthesized":"Then the officers returned to the chief priests and Pharisees, who asked them, “Why didn’t you bring Him in?”","sources":{"KJV":{"text":"Then came the officers to the chief priests and Pharisees; and they said unto them, Why have ye not brought him?"},"BSB":{"text":"Then the officers returned to the chief priests and Pharisees, who asked them, “Why didn’t you bring Him in?”"}},"definableWords":[],"peopleInVerse":[]},"46":{"text":"The officers answered, Never man spake like this man.","ref":"John 7:46","synthesized":"“Never has anyone spoken like this man!” the officers answered.","sources":{"KJV":{"text":"The officers answered, Never man spake like this man."},"BSB":{"text":"“Never has anyone spoken like this man!” the officers answered."}},"definableWords":["man"],"peopleInVerse":[]},"47":{"text":"Then answered them the Pharisees, Are ye also deceived?","ref":"John 7:47","synthesized":"“Have you also been deceived?” replied the Pharisees.","sources":{"KJV":{"text":"Then answered them the Pharisees, Are ye also deceived?"},"BSB":{"text":"“Have you also been deceived?” replied the Pharisees."}},"definableWords":[],"peopleInVerse":[]},"48":{"text":"Have any of the rulers or of the Pharisees believed on him?","ref":"John 7:48","synthesized":"“Have any of the rulers or Pharisees believed in Him?","sources":{"KJV":{"text":"Have any of the rulers or of the Pharisees believed on him?"},"BSB":{"text":"“Have any of the rulers or Pharisees believed in Him?"}},"definableWords":["or","believed"],"peopleInVerse":[]},"49":{"text":"But this people who knoweth not the law are cursed.","ref":"John 7:49","synthesized":"But this crowd that does not know the law, they are under a curse.”","sources":{"KJV":{"text":"But this people who knoweth not the law are cursed."},"BSB":{"text":"But this crowd that does not know the law, they are under a curse.”"}},"definableWords":["law","curse"],"peopleInVerse":[]},"50":{"text":"Nicodemus saith unto them, (he that came to Jesus by night, being one of them,)","ref":"John 7:50","synthesized":"Nicodemus, who had gone to Jesus earlier and who himself was one of them, asked,","sources":{"KJV":{"text":"Nicodemus saith unto them, (he that came to Jesus by night, being one of them,)"},"BSB":{"text":"Nicodemus, who had gone to Jesus earlier and who himself was one of them, asked,"}},"definableWords":["one"],"peopleInVerse":["Jesus"]},"51":{"text":"Doth our law judge any man, before it hear him, and know what he doeth?","ref":"John 7:51","synthesized":"“Does our law convict a man without first hearing from him to determine what he has done?”","sources":{"KJV":{"text":"Doth our law judge any man, before it hear him, and know what he doeth?"},"BSB":{"text":"“Does our law convict a man without first hearing from him to determine what he has done?”"}},"definableWords":["law","man"],"peopleInVerse":[]},"52":{"text":"They answered and said unto him, Art thou also of Galilee? Search, and look: for out of Galilee ariseth no prophet.","ref":"John 7:52","synthesized":"“Aren’t you also from Galilee?” they replied. “Look into it, and you will see that no prophet comes out of Galilee.”","sources":{"KJV":{"text":"They answered and said unto him, Art thou also of Galilee? Search, and look: for out of Galilee ariseth no prophet."},"BSB":{"text":"“Aren’t you also from Galilee?” they replied. “Look into it, and you will see that no prophet comes out of Galilee.”"}},"definableWords":["Galilee","see","prophet"],"peopleInVerse":[]},"53":{"text":"And every man went unto his own house.","ref":"John 7:53","synthesized":"Then each went to his own home.","sources":{"KJV":{"text":"And every man went unto his own house."},"BSB":{"text":"Then each went to his own home."}},"definableWords":[],"peopleInVerse":[]}}},"8":{"chapter":"8","title":"I AM THE LIGHT OF THE WORLD","verses":{"1":{"text":"Jesus went unto the mount of Olives.","ref":"John 8:1","synthesized":"But Jesus went to the Mount of Olives.","sources":{"KJV":{"text":"Jesus went unto the mount of Olives."},"BSB":{"text":"But Jesus went to the Mount of Olives."}},"definableWords":[],"peopleInVerse":["Jesus"]},"2":{"text":"And early in the morning he came again into the temple, and all the people came unto him; and he sat down, and taught them.","ref":"John 8:2","synthesized":"Early in the morning He went back into the temple courts. All the people came to Him, and He sat down to teach them.","sources":{"KJV":{"text":"And early in the morning he came again into the temple, and all the people came unto him; and he sat down, and taught them."},"BSB":{"text":"Early in the morning He went back into the temple courts. All the people came to Him, and He sat down to teach them."}},"definableWords":["temple","people"],"peopleInVerse":[]},"3":{"text":"And the scribes and Pharisees brought unto him a woman taken in adultery; and when they had set her in the midst,","ref":"John 8:3","synthesized":"The scribes and Pharisees, however, brought to Him a woman caught in adultery. They made her stand before them","sources":{"KJV":{"text":"And the scribes and Pharisees brought unto him a woman taken in adultery; and when they had set her in the midst,"},"BSB":{"text":"The scribes and Pharisees, however, brought to Him a woman caught in adultery. They made her stand before them"}},"definableWords":["woman","made","stand"],"peopleInVerse":[]},"4":{"text":"They say unto him, Master, this woman was taken in adultery, in the very act.","ref":"John 8:4","synthesized":"and said, “Teacher, this woman was caught in the act of adultery.","sources":{"KJV":{"text":"They say unto him, Master, this woman was taken in adultery, in the very act."},"BSB":{"text":"and said, “Teacher, this woman was caught in the act of adultery."}},"definableWords":["woman"],"peopleInVerse":[]},"5":{"text":"Now Moses in the law commanded us, that such should be stoned: but what sayest thou?","ref":"John 8:5","synthesized":"In the Law Moses commanded us to stone such a woman. So what do You say?”","sources":{"KJV":{"text":"Now Moses in the law commanded us, that such should be stoned: but what sayest thou?"},"BSB":{"text":"In the Law Moses commanded us to stone such a woman. So what do You say?”"}},"definableWords":["law","stone","woman"],"peopleInVerse":["Moses"]},"6":{"text":"This they said, tempting him, that they might have to accuse him. But Jesus stooped down, and with his finger wrote on the ground, as though he heard them not.","ref":"John 8:6","synthesized":"They said this to test Him, in order to have a basis for accusing Him. But Jesus bent down and began to write on the ground with His finger.","sources":{"KJV":{"text":"This they said, tempting him, that they might have to accuse him. But Jesus stooped down, and with his finger wrote on the ground, as though he heard them not."},"BSB":{"text":"They said this to test Him, in order to have a basis for accusing Him. But Jesus bent down and began to write on the ground with His finger."}},"definableWords":["ground"],"peopleInVerse":["Jesus"]},"7":{"text":"So when they continued asking him, he lifted up himself, and said unto them, He that is without sin among you, let him first cast a stone at her.","ref":"John 8:7","synthesized":"When they continued to question Him, He straightened up and said to them, “Let him who is without sin among you be the first to cast a stone at her.”","sources":{"KJV":{"text":"So when they continued asking him, he lifted up himself, and said unto them, He that is without sin among you, let him first cast a stone at her."},"BSB":{"text":"When they continued to question Him, He straightened up and said to them, “Let him who is without sin among you be the first to cast a stone at her.”"}},"definableWords":["sin","stone"],"peopleInVerse":[]},"8":{"text":"And again he stooped down, and wrote on the ground.","ref":"John 8:8","synthesized":"And again He bent down and wrote on the ground.","sources":{"KJV":{"text":"And again he stooped down, and wrote on the ground."},"BSB":{"text":"And again He bent down and wrote on the ground."}},"definableWords":["ground"],"peopleInVerse":[]},"9":{"text":"And they which heard it, being convicted by their own conscience, went out one by one, beginning at the eldest, even unto the last: and Jesus was left alone, and the woman standing in the midst.","ref":"John 8:9","synthesized":"When they heard this, they began to go away one by one, beginning with the older ones, until only Jesus was left, with the woman standing there.","sources":{"KJV":{"text":"And they which heard it, being convicted by their own conscience, went out one by one, beginning at the eldest, even unto the last: and Jesus was left alone, and the woman standing in the midst."},"BSB":{"text":"When they heard this, they began to go away one by one, beginning with the older ones, until only Jesus was left, with the woman standing there."}},"definableWords":["one","beginning","woman"],"peopleInVerse":["Jesus"]},"10":{"text":"When Jesus had lifted up himself, and saw none but the woman, he said unto her, Woman, where are those thine accusers? hath no man condemned thee?","ref":"John 8:10","synthesized":"Then Jesus straightened up and asked her, “Woman, where are your accusers? Has no one condemned you?”","sources":{"KJV":{"text":"When Jesus had lifted up himself, and saw none but the woman, he said unto her, Woman, where are those thine accusers? hath no man condemned thee?"},"BSB":{"text":"Then Jesus straightened up and asked her, “Woman, where are your accusers? Has no one condemned you?”"}},"definableWords":["woman","one"],"peopleInVerse":["Jesus"]},"11":{"text":"She said, No man, Lord. And Jesus said unto her, Neither do I condemn thee: go, and sin no more.","ref":"John 8:11","synthesized":"“No one, Lord,” she answered.  “Then neither do I condemn you,” Jesus declared. “Now go and sin no more.”","sources":{"KJV":{"text":"She said, No man, Lord. And Jesus said unto her, Neither do I condemn thee: go, and sin no more."},"BSB":{"text":"“No one, Lord,” she answered.  “Then neither do I condemn you,” Jesus declared. “Now go and sin no more.”"}},"definableWords":["one","Lord","sin"],"peopleInVerse":["Jesus"]},"12":{"text":"Then spake Jesus again unto them, saying, I am the light of the world: he that followeth me shall not walk in darkness, but shall have the light of life.","ref":"John 8:12","synthesized":"Once again, Jesus spoke to the people and said, “I am the light of the world. Whoever follows Me will never walk in the darkness, but will have the light of life.”","sources":{"KJV":{"text":"Then spake Jesus again unto them, saying, I am the light of the world: he that followeth me shall not walk in darkness, but shall have the light of life."},"BSB":{"text":"Once again, Jesus spoke to the people and said, “I am the light of the world. Whoever follows Me will never walk in the darkness, but will have the light of life.”"}},"definableWords":["people","light","walk","darkness","life"],"peopleInVerse":["Jesus"]},"13":{"text":"The Pharisees therefore said unto him, Thou bearest record of thyself; thy record is not true.","ref":"John 8:13","synthesized":"So the Pharisees said to Him, “You are testifying about Yourself; Your testimony is not valid.”","sources":{"KJV":{"text":"The Pharisees therefore said unto him, Thou bearest record of thyself; thy record is not true."},"BSB":{"text":"So the Pharisees said to Him, “You are testifying about Yourself; Your testimony is not valid.”"}},"definableWords":[],"peopleInVerse":[]},"14":{"text":"Jesus answered and said unto them, Though I bear record of myself, yet my record is true: for I know whence I came, and whither I go; but ye cannot tell whence I come, and whither I go.","ref":"John 8:14","synthesized":"Jesus replied, “Even if I testify about Myself, My testimony is valid, because I know where I came from and where I am going. But you do not know where I came from or where I am going.","sources":{"KJV":{"text":"Jesus answered and said unto them, Though I bear record of myself, yet my record is true: for I know whence I came, and whither I go; but ye cannot tell whence I come, and whither I go."},"BSB":{"text":"Jesus replied, “Even if I testify about Myself, My testimony is valid, because I know where I came from and where I am going. But you do not know where I came from or where I am going."}},"definableWords":["or"],"peopleInVerse":["Jesus"]},"15":{"text":"Ye judge after the flesh; I judge no man.","ref":"John 8:15","synthesized":"You judge according to the flesh; I judge no one.","sources":{"KJV":{"text":"Ye judge after the flesh; I judge no man."},"BSB":{"text":"You judge according to the flesh; I judge no one."}},"definableWords":["flesh","one"],"peopleInVerse":[]},"16":{"text":"And yet if I judge, my judgment is true: for I am not alone, but I and the Father that sent me.","ref":"John 8:16","synthesized":"But even if I do judge, My judgment is true, because I am not alone; I am with the Father who sent Me.","sources":{"KJV":{"text":"And yet if I judge, my judgment is true: for I am not alone, but I and the Father that sent me."},"BSB":{"text":"But even if I do judge, My judgment is true, because I am not alone; I am with the Father who sent Me."}},"definableWords":["judgment","Father"],"peopleInVerse":[]},"17":{"text":"It is also written in your law, that the testimony of two men is true.","ref":"John 8:17","synthesized":"Even in your own Law it is written that the testimony of two men is valid.","sources":{"KJV":{"text":"It is also written in your law, that the testimony of two men is true."},"BSB":{"text":"Even in your own Law it is written that the testimony of two men is valid."}},"definableWords":["law","men"],"peopleInVerse":[]},"18":{"text":"I am one that bear witness of myself, and the Father that sent me beareth witness of me.","ref":"John 8:18","synthesized":"I am One who testifies about Myself, and the Father, who sent Me, also testifies about Me.”","sources":{"KJV":{"text":"I am one that bear witness of myself, and the Father that sent me beareth witness of me."},"BSB":{"text":"I am One who testifies about Myself, and the Father, who sent Me, also testifies about Me.”"}},"definableWords":["one","Father"],"peopleInVerse":[]},"19":{"text":"Then said they unto him, Where is thy Father? Jesus answered, Ye neither know me, nor my Father: if ye had known me, ye should have known my Father also.","ref":"John 8:19","synthesized":"“Where is Your Father?” they asked Him.  “You do not know Me or My Father,” Jesus answered. “If you knew Me, you would know My Father as well.”","sources":{"KJV":{"text":"Then said they unto him, Where is thy Father? Jesus answered, Ye neither know me, nor my Father: if ye had known me, ye should have known my Father also."},"BSB":{"text":"“Where is Your Father?” they asked Him.  “You do not know Me or My Father,” Jesus answered. “If you knew Me, you would know My Father as well.”"}},"definableWords":["Father","or"],"peopleInVerse":["Jesus"]},"20":{"text":"These words spake Jesus in the treasury, as he taught in the temple: and no man laid hands on him; for his hour was not yet come.","ref":"John 8:20","synthesized":"He spoke these words while teaching in the temple courts, near the treasury. Yet no one seized Him, because His hour had not yet come.","sources":{"KJV":{"text":"These words spake Jesus in the treasury, as he taught in the temple: and no man laid hands on him; for his hour was not yet come."},"BSB":{"text":"He spoke these words while teaching in the temple courts, near the treasury. Yet no one seized Him, because His hour had not yet come."}},"definableWords":["temple","one"],"peopleInVerse":[]},"21":{"text":"Then said Jesus again unto them, I go my way, and ye shall seek me, and shall die in your sins: whither I go, ye cannot come.","ref":"John 8:21","synthesized":"Again He said to them, “I am going away, and you will look for Me, but you will die in your sin. Where I am going, you cannot come.”","sources":{"KJV":{"text":"Then said Jesus again unto them, I go my way, and ye shall seek me, and shall die in your sins: whither I go, ye cannot come."},"BSB":{"text":"Again He said to them, “I am going away, and you will look for Me, but you will die in your sin. Where I am going, you cannot come.”"}},"definableWords":["die","sin"],"peopleInVerse":[]},"22":{"text":"Then said the Jews, Will he kill himself? because he saith, Whither I go, ye cannot come.","ref":"John 8:22","synthesized":"So the Jews began to ask, “Will He kill Himself, since He says, ‘Where I am going, you cannot come’?”","sources":{"KJV":{"text":"Then said the Jews, Will he kill himself? because he saith, Whither I go, ye cannot come."},"BSB":{"text":"So the Jews began to ask, “Will He kill Himself, since He says, ‘Where I am going, you cannot come’?”"}},"definableWords":[],"peopleInVerse":[]},"23":{"text":"And he said unto them, Ye are from beneath; I am from above: ye are of this world; I am not of this world.","ref":"John 8:23","synthesized":"Then He told them, “You are from below; I am from above. You are of this world; I am not of this world.","sources":{"KJV":{"text":"And he said unto them, Ye are from beneath; I am from above: ye are of this world; I am not of this world."},"BSB":{"text":"Then He told them, “You are from below; I am from above. You are of this world; I am not of this world."}},"definableWords":[],"peopleInVerse":[]},"24":{"text":"I said therefore unto you, that ye shall die in your sins: for if ye believe not that I am he, ye shall die in your sins.","ref":"John 8:24","synthesized":"That is why I told you that you would die in your sins. For unless you believe that I am He, you will die in your sins.”","sources":{"KJV":{"text":"I said therefore unto you, that ye shall die in your sins: for if ye believe not that I am he, ye shall die in your sins."},"BSB":{"text":"That is why I told you that you would die in your sins. For unless you believe that I am He, you will die in your sins.”"}},"definableWords":["die"],"peopleInVerse":[]},"25":{"text":"Then said they unto him, Who art thou? And Jesus saith unto them, Even the same that I said unto you from the beginning.","ref":"John 8:25","synthesized":"“Who are You?” they asked.  “Just what I have been telling you from the beginning,” Jesus replied.","sources":{"KJV":{"text":"Then said they unto him, Who art thou? And Jesus saith unto them, Even the same that I said unto you from the beginning."},"BSB":{"text":"“Who are You?” they asked.  “Just what I have been telling you from the beginning,” Jesus replied."}},"definableWords":["beginning"],"peopleInVerse":["Jesus"]},"26":{"text":"I have many things to say and to judge of you: but he that sent me is true; and I speak to the world those things which I have heard of him.","ref":"John 8:26","synthesized":"“I have much to say about you and much to judge. But the One who sent Me is truthful, and what I have heard from Him, I tell the world.”","sources":{"KJV":{"text":"I have many things to say and to judge of you: but he that sent me is true; and I speak to the world those things which I have heard of him."},"BSB":{"text":"“I have much to say about you and much to judge. But the One who sent Me is truthful, and what I have heard from Him, I tell the world.”"}},"definableWords":["one"],"peopleInVerse":[]},"27":{"text":"They understood not that he spake to them of the Father.","ref":"John 8:27","synthesized":"They did not understand that He was telling them about the Father.","sources":{"KJV":{"text":"They understood not that he spake to them of the Father."},"BSB":{"text":"They did not understand that He was telling them about the Father."}},"definableWords":["Father"],"peopleInVerse":[]},"28":{"text":"Then said Jesus unto them, When ye have lifted up the Son of man, then shall ye know that I am he, and that I do nothing of myself; but as my Father hath taught me, I speak these things.","ref":"John 8:28","synthesized":"So Jesus said, “When you have lifted up the Son of Man, then you will know that I am He, and that I do nothing on My own, but speak exactly what the Father has taught Me.","sources":{"KJV":{"text":"Then said Jesus unto them, When ye have lifted up the Son of man, then shall ye know that I am he, and that I do nothing of myself; but as my Father hath taught me, I speak these things."},"BSB":{"text":"So Jesus said, “When you have lifted up the Son of Man, then you will know that I am He, and that I do nothing on My own, but speak exactly what the Father has taught Me."}},"definableWords":["Son","man","Father"],"peopleInVerse":["Jesus"]},"29":{"text":"And he that sent me is with me: the Father hath not left me alone; for I do always those things that please him.","ref":"John 8:29","synthesized":"He who sent Me is with Me. He has not left Me alone, because I always do what pleases Him.”","sources":{"KJV":{"text":"And he that sent me is with me: the Father hath not left me alone; for I do always those things that please him."},"BSB":{"text":"He who sent Me is with Me. He has not left Me alone, because I always do what pleases Him.”"}},"definableWords":[],"peopleInVerse":[]},"30":{"text":"As he spake these words, many believed on him.","ref":"John 8:30","synthesized":"As Jesus spoke these things, many believed in Him.","sources":{"KJV":{"text":"As he spake these words, many believed on him."},"BSB":{"text":"As Jesus spoke these things, many believed in Him."}},"definableWords":["believed"],"peopleInVerse":["Jesus"]},"31":{"text":"Then said Jesus to those Jews which believed on him, If ye continue in my word, then are ye my disciples indeed;","ref":"John 8:31","synthesized":"So He said to the Jews who had believed Him, “If you continue in My word, you are truly My disciples.","sources":{"KJV":{"text":"Then said Jesus to those Jews which believed on him, If ye continue in my word, then are ye my disciples indeed;"},"BSB":{"text":"So He said to the Jews who had believed Him, “If you continue in My word, you are truly My disciples."}},"definableWords":["believed","word"],"peopleInVerse":[]},"32":{"text":"And ye shall know the truth, and the truth shall make you free.","ref":"John 8:32","synthesized":"Then you will know the truth, and the truth will set you free.”","sources":{"KJV":{"text":"And ye shall know the truth, and the truth shall make you free."},"BSB":{"text":"Then you will know the truth, and the truth will set you free.”"}},"definableWords":["truth"],"peopleInVerse":[]},"33":{"text":"They answered him, We be Abraham’s seed, and were never in bondage to any man: how sayest thou, Ye shall be made free?","ref":"John 8:33","synthesized":"“We are Abraham’s descendants,” they answered. “We have never been slaves to anyone. How can You say we will be set free?”","sources":{"KJV":{"text":"They answered him, We be Abraham’s seed, and were never in bondage to any man: how sayest thou, Ye shall be made free?"},"BSB":{"text":"“We are Abraham’s descendants,” they answered. “We have never been slaves to anyone. How can You say we will be set free?”"}},"definableWords":["Abraham"],"peopleInVerse":["Abraham"]},"34":{"text":"Jesus answered them, Verily, verily, I say unto you, Whosoever committeth sin is the servant of sin.","ref":"John 8:34","synthesized":"Jesus replied, “Truly, truly, I tell you, everyone who sins is a slave to sin.","sources":{"KJV":{"text":"Jesus answered them, Verily, verily, I say unto you, Whosoever committeth sin is the servant of sin."},"BSB":{"text":"Jesus replied, “Truly, truly, I tell you, everyone who sins is a slave to sin."}},"definableWords":["sin"],"peopleInVerse":["Jesus"]},"35":{"text":"And the servant abideth not in the house for ever: but the Son abideth ever.","ref":"John 8:35","synthesized":"A slave is not a permanent member of the family, but a son belongs to it forever.","sources":{"KJV":{"text":"And the servant abideth not in the house for ever: but the Son abideth ever."},"BSB":{"text":"A slave is not a permanent member of the family, but a son belongs to it forever."}},"definableWords":["family","son"],"peopleInVerse":[]},"36":{"text":"If the Son therefore shall make you free, ye shall be free indeed.","ref":"John 8:36","synthesized":"So if the Son sets you free, you will be free indeed.","sources":{"KJV":{"text":"If the Son therefore shall make you free, ye shall be free indeed."},"BSB":{"text":"So if the Son sets you free, you will be free indeed."}},"definableWords":["Son"],"peopleInVerse":[]},"37":{"text":"I know that ye are Abraham’s seed; but ye seek to kill me, because my word hath no place in you.","ref":"John 8:37","synthesized":"I know you are Abraham’s descendants, but you are trying to kill Me because My word has no place within you.","sources":{"KJV":{"text":"I know that ye are Abraham’s seed; but ye seek to kill me, because my word hath no place in you."},"BSB":{"text":"I know you are Abraham’s descendants, but you are trying to kill Me because My word has no place within you."}},"definableWords":["Abraham","word"],"peopleInVerse":["Abraham"]},"38":{"text":"I speak that which I have seen with my Father: and ye do that which ye have seen with your father.","ref":"John 8:38","synthesized":"I speak of what I have seen in the presence of the Father, and you do what you have heard from your father.”","sources":{"KJV":{"text":"I speak that which I have seen with my Father: and ye do that which ye have seen with your father."},"BSB":{"text":"I speak of what I have seen in the presence of the Father, and you do what you have heard from your father.”"}},"definableWords":["Father","father"],"peopleInVerse":[]},"39":{"text":"They answered and said unto him, Abraham is our father. Jesus saith unto them, If ye were Abraham’s children, ye would do the works of Abraham.","ref":"John 8:39","synthesized":"“Abraham is our father,” they replied.  “If you were children of Abraham,” said Jesus, “you would do the works of Abraham.","sources":{"KJV":{"text":"They answered and said unto him, Abraham is our father. Jesus saith unto them, If ye were Abraham’s children, ye would do the works of Abraham."},"BSB":{"text":"“Abraham is our father,” they replied.  “If you were children of Abraham,” said Jesus, “you would do the works of Abraham."}},"definableWords":["Abraham","father","works"],"peopleInVerse":["Abraham","Jesus"]},"40":{"text":"But now ye seek to kill me, a man that hath told you the truth, which I have heard of God: this did not Abraham.","ref":"John 8:40","synthesized":"But now you are trying to kill Me, a man who has told you the truth that I heard from God. Abraham never did such a thing.","sources":{"KJV":{"text":"But now ye seek to kill me, a man that hath told you the truth, which I have heard of God: this did not Abraham."},"BSB":{"text":"But now you are trying to kill Me, a man who has told you the truth that I heard from God. Abraham never did such a thing."}},"definableWords":["man","truth","God","Abraham"],"peopleInVerse":["Abraham"]},"41":{"text":"Ye do the deeds of your father. Then said they to him, We be not born of fornication; we have one Father, even God.","ref":"John 8:41","synthesized":"You are doing the works of your father.”  “We are not illegitimate children,” they declared. “Our only Father is God Himself.”","sources":{"KJV":{"text":"Ye do the deeds of your father. Then said they to him, We be not born of fornication; we have one Father, even God."},"BSB":{"text":"You are doing the works of your father.”  “We are not illegitimate children,” they declared. “Our only Father is God Himself.”"}},"definableWords":["works","father","Father","God"],"peopleInVerse":[]},"42":{"text":"Jesus said unto them, If God were your Father, ye would love me: for I proceeded forth and came from God; neither came I of myself, but he sent me.","ref":"John 8:42","synthesized":"Jesus said to them, “If God were your Father, you would love Me, for I have come here from God. I have not come on My own, but He sent Me.","sources":{"KJV":{"text":"Jesus said unto them, If God were your Father, ye would love me: for I proceeded forth and came from God; neither came I of myself, but he sent me."},"BSB":{"text":"Jesus said to them, “If God were your Father, you would love Me, for I have come here from God. I have not come on My own, but He sent Me."}},"definableWords":["God","Father","love"],"peopleInVerse":["Jesus"]},"43":{"text":"Why do ye not understand my speech? even because ye cannot hear my word.","ref":"John 8:43","synthesized":"Why do you not understand what I am saying? It is because you are unable to accept My message.","sources":{"KJV":{"text":"Why do ye not understand my speech? even because ye cannot hear my word."},"BSB":{"text":"Why do you not understand what I am saying? It is because you are unable to accept My message."}},"definableWords":[],"peopleInVerse":[]},"44":{"text":"Ye are of your father the devil, and the lusts of your father ye will do. He was a murderer from the beginning, and abode not in the truth, because there is no truth in him. When he speaketh a lie, he speaketh of his own: for he is a liar, and the father of it.","ref":"John 8:44","synthesized":"You belong to your father, the devil, and you want to carry out his desires. He was a murderer from the beginning, refusing to uphold the truth, because there is no truth in him. When he lies, he speaks his native language, because he is a liar and the father of lies.","sources":{"KJV":{"text":"Ye are of your father the devil, and the lusts of your father ye will do. He was a murderer from the beginning, and abode not in the truth, because there is no truth in him. When he speaketh a lie, he speaketh of his own: for he is a liar, and the father of it."},"BSB":{"text":"You belong to your father, the devil, and you want to carry out his desires. He was a murderer from the beginning, refusing to uphold the truth, because there is no truth in him. When he lies, he speaks his native language, because he is a liar and the father of lies."}},"definableWords":["father","devil","beginning","truth","Father"],"peopleInVerse":[]},"45":{"text":"And because I tell you the truth, ye believe me not.","ref":"John 8:45","synthesized":"But because I speak the truth, you do not believe Me!","sources":{"KJV":{"text":"And because I tell you the truth, ye believe me not."},"BSB":{"text":"But because I speak the truth, you do not believe Me!"}},"definableWords":["truth"],"peopleInVerse":[]},"46":{"text":"Which of you convinceth me of sin? And if I say the truth, why do ye not believe me?","ref":"John 8:46","synthesized":"Which of you can prove Me guilty of sin? If I speak the truth, why do you not believe Me?","sources":{"KJV":{"text":"Which of you convinceth me of sin? And if I say the truth, why do ye not believe me?"},"BSB":{"text":"Which of you can prove Me guilty of sin? If I speak the truth, why do you not believe Me?"}},"definableWords":["sin","truth"],"peopleInVerse":[]},"47":{"text":"He that is of God heareth God’s words: ye therefore hear them not, because ye are not of God.","ref":"John 8:47","synthesized":"Whoever belongs to God hears the words of God. The reason you do not hear is that you do not belong to God.”","sources":{"KJV":{"text":"He that is of God heareth God’s words: ye therefore hear them not, because ye are not of God."},"BSB":{"text":"Whoever belongs to God hears the words of God. The reason you do not hear is that you do not belong to God.”"}},"definableWords":["God","hear"],"peopleInVerse":[]},"48":{"text":"Then answered the Jews, and said unto him, Say we not well that thou art a Samaritan, and hast a devil?","ref":"John 8:48","synthesized":"The Jews answered Him, “Are we not right to say that You are a Samaritan and You have a demon?”","sources":{"KJV":{"text":"Then answered the Jews, and said unto him, Say we not well that thou art a Samaritan, and hast a devil?"},"BSB":{"text":"The Jews answered Him, “Are we not right to say that You are a Samaritan and You have a demon?”"}},"definableWords":["demon"],"peopleInVerse":[]},"49":{"text":"Jesus answered, I have not a devil; but I honour my Father, and ye do dishonour me.","ref":"John 8:49","synthesized":"“I do not have a demon,” Jesus replied, “but I honor My Father, and you dishonor Me.","sources":{"KJV":{"text":"Jesus answered, I have not a devil; but I honour my Father, and ye do dishonour me."},"BSB":{"text":"“I do not have a demon,” Jesus replied, “but I honor My Father, and you dishonor Me."}},"definableWords":["demon","Father"],"peopleInVerse":["Jesus"]},"50":{"text":"And I seek not mine own glory: there is one that seeketh and judgeth.","ref":"John 8:50","synthesized":"I do not seek My own glory. There is One who seeks it, and He is the Judge.","sources":{"KJV":{"text":"And I seek not mine own glory: there is one that seeketh and judgeth."},"BSB":{"text":"I do not seek My own glory. There is One who seeks it, and He is the Judge."}},"definableWords":["seek","glory","one"],"peopleInVerse":[]},"51":{"text":"Verily, verily, I say unto you, If a man keep my saying, he shall never see death.","ref":"John 8:51","synthesized":"Truly, truly, I tell you, if anyone keeps My word, he will never see death.”","sources":{"KJV":{"text":"Verily, verily, I say unto you, If a man keep my saying, he shall never see death."},"BSB":{"text":"Truly, truly, I tell you, if anyone keeps My word, he will never see death.”"}},"definableWords":["word","see","death"],"peopleInVerse":[]},"52":{"text":"Then said the Jews unto him, Now we know that thou hast a devil. Abraham is dead, and the prophets; and thou sayest, If a man keep my saying, he shall never taste of death.","ref":"John 8:52","synthesized":"“Now we know that You have a demon!” declared the Jews. “Abraham died, and so did the prophets, yet You say that anyone who keeps Your word will never taste death.","sources":{"KJV":{"text":"Then said the Jews unto him, Now we know that thou hast a devil. Abraham is dead, and the prophets; and thou sayest, If a man keep my saying, he shall never taste of death."},"BSB":{"text":"“Now we know that You have a demon!” declared the Jews. “Abraham died, and so did the prophets, yet You say that anyone who keeps Your word will never taste death."}},"definableWords":["demon","Abraham","word","death"],"peopleInVerse":["Abraham"]},"53":{"text":"Art thou greater than our father Abraham, which is dead? and the prophets are dead: whom makest thou thyself?","ref":"John 8:53","synthesized":"Are You greater than our father Abraham? He died, as did the prophets. Who do You claim to be?”","sources":{"KJV":{"text":"Art thou greater than our father Abraham, which is dead? and the prophets are dead: whom makest thou thyself?"},"BSB":{"text":"Are You greater than our father Abraham? He died, as did the prophets. Who do You claim to be?”"}},"definableWords":["father","Abraham"],"peopleInVerse":["Abraham"]},"54":{"text":"Jesus answered, If I honour myself, my honour is nothing: it is my Father that honoureth me; of whom ye say, that he is your God:","ref":"John 8:54","synthesized":"Jesus answered, “If I glorify Myself, My glory means nothing. The One who glorifies Me is My Father, of whom you say ‘He is our God.’","sources":{"KJV":{"text":"Jesus answered, If I honour myself, my honour is nothing: it is my Father that honoureth me; of whom ye say, that he is your God:"},"BSB":{"text":"Jesus answered, “If I glorify Myself, My glory means nothing. The One who glorifies Me is My Father, of whom you say ‘He is our God.’"}},"definableWords":["glory","one","Father","God"],"peopleInVerse":["Jesus"]},"55":{"text":"Yet ye have not known him; but I know him: and if I should say, I know him not, I shall be a liar like unto you: but I know him, and keep his saying.","ref":"John 8:55","synthesized":"You do not know Him, but I know Him. If I said I did not know Him, I would be a liar like you. But I do know Him, and I keep His word.","sources":{"KJV":{"text":"Yet ye have not known him; but I know him: and if I should say, I know him not, I shall be a liar like unto you: but I know him, and keep his saying."},"BSB":{"text":"You do not know Him, but I know Him. If I said I did not know Him, I would be a liar like you. But I do know Him, and I keep His word."}},"definableWords":["keep","word"],"peopleInVerse":[]},"56":{"text":"Your father Abraham rejoiced to see my day: and he saw it, and was glad.","ref":"John 8:56","synthesized":"Your father Abraham rejoiced that he would see My day. He saw it and was glad.”","sources":{"KJV":{"text":"Your father Abraham rejoiced to see my day: and he saw it, and was glad."},"BSB":{"text":"Your father Abraham rejoiced that he would see My day. He saw it and was glad.”"}},"definableWords":["father","Abraham","see","day","saw"],"peopleInVerse":["Abraham"]},"57":{"text":"Then said the Jews unto him, Thou art not yet fifty years old, and hast thou seen Abraham?","ref":"John 8:57","synthesized":"Then the Jews said to Him, “You are not yet fifty years old, and You have seen Abraham?”","sources":{"KJV":{"text":"Then said the Jews unto him, Thou art not yet fifty years old, and hast thou seen Abraham?"},"BSB":{"text":"Then the Jews said to Him, “You are not yet fifty years old, and You have seen Abraham?”"}},"definableWords":["years","Abraham"],"peopleInVerse":["Abraham"]},"58":{"text":"Jesus said unto them, Verily, verily, I say unto you, Before Abraham was, I am.","ref":"John 8:58","synthesized":"“Truly, truly, I tell you,” Jesus declared, “before Abraham was born, I am!”","sources":{"KJV":{"text":"Jesus said unto them, Verily, verily, I say unto you, Before Abraham was, I am."},"BSB":{"text":"“Truly, truly, I tell you,” Jesus declared, “before Abraham was born, I am!”"}},"definableWords":["Abraham"],"peopleInVerse":["Jesus","Abraham"]},"59":{"text":"Then took they up stones to cast at him: but Jesus hid himself, and went out of the temple, going through the midst of them, and so passed by.","ref":"John 8:59","synthesized":"At this, they picked up stones to throw at Him. But Jesus was hidden and went out of the temple area.","sources":{"KJV":{"text":"Then took they up stones to cast at him: but Jesus hid himself, and went out of the temple, going through the midst of them, and so passed by."},"BSB":{"text":"At this, they picked up stones to throw at Him. But Jesus was hidden and went out of the temple area."}},"definableWords":["temple"],"peopleInVerse":["Jesus"]}}},"9":{"chapter":"9","title":"HEALING THE MAN BORN BLIND","verses":{"1":{"text":"And as Jesus passed by, he saw a man which was blind from his birth.","ref":"John 9:1","synthesized":"Now as Jesus was passing by, He saw a man blind from birth,","sources":{"KJV":{"text":"And as Jesus passed by, he saw a man which was blind from his birth."},"BSB":{"text":"Now as Jesus was passing by, He saw a man blind from birth,"}},"definableWords":["saw","man"],"peopleInVerse":["Jesus"]},"2":{"text":"And his disciples asked him, saying, Master, who did sin, this man, or his parents, that he was born blind?","ref":"John 9:2","synthesized":"and His disciples asked Him, “Rabbi, who sinned, this man or his parents, that he was born blind?”","sources":{"KJV":{"text":"And his disciples asked him, saying, Master, who did sin, this man, or his parents, that he was born blind?"},"BSB":{"text":"and His disciples asked Him, “Rabbi, who sinned, this man or his parents, that he was born blind?”"}},"definableWords":["man","or"],"peopleInVerse":[]},"3":{"text":"Jesus answered, Neither hath this man sinned, nor his parents: but that the works of God should be made manifest in him.","ref":"John 9:3","synthesized":"Jesus answered, “Neither this man nor his parents sinned, but this happened so that the works of God would be displayed in him.","sources":{"KJV":{"text":"Jesus answered, Neither hath this man sinned, nor his parents: but that the works of God should be made manifest in him."},"BSB":{"text":"Jesus answered, “Neither this man nor his parents sinned, but this happened so that the works of God would be displayed in him."}},"definableWords":["man","works","God"],"peopleInVerse":["Jesus"]},"4":{"text":"I must work the works of him that sent me, while it is day: the night cometh, when no man can work.","ref":"John 9:4","synthesized":"While it is daytime, we must do the works of Him who sent Me. Night is coming, when no one can work.","sources":{"KJV":{"text":"I must work the works of him that sent me, while it is day: the night cometh, when no man can work."},"BSB":{"text":"While it is daytime, we must do the works of Him who sent Me. Night is coming, when no one can work."}},"definableWords":["works","night","one","work"],"peopleInVerse":[]},"5":{"text":"As long as I am in the world, I am the light of the world.","ref":"John 9:5","synthesized":"While I am in the world, I am the light of the world.”","sources":{"KJV":{"text":"As long as I am in the world, I am the light of the world."},"BSB":{"text":"While I am in the world, I am the light of the world.”"}},"definableWords":["light"],"peopleInVerse":[]},"6":{"text":"When he had thus spoken, he spat on the ground, and made clay of the spittle, and he anointed the eyes of the blind man with the clay,","ref":"John 9:6","synthesized":"When Jesus had said this, He spit on the ground, made some mud, and applied it to the man’s eyes.","sources":{"KJV":{"text":"When he had thus spoken, he spat on the ground, and made clay of the spittle, and he anointed the eyes of the blind man with the clay,"},"BSB":{"text":"When Jesus had said this, He spit on the ground, made some mud, and applied it to the man’s eyes."}},"definableWords":["ground","made","man"],"peopleInVerse":["Jesus"]},"7":{"text":"And said unto him, Go, wash in the pool of Siloam, (which is by interpretation, Sent.) He went his way therefore, and washed, and came seeing.","ref":"John 9:7","synthesized":"Then He told him, “Go, wash in the Pool of Siloam” (which means “Sent”). So the man went and washed, and came back seeing.","sources":{"KJV":{"text":"And said unto him, Go, wash in the pool of Siloam, (which is by interpretation, Sent.) He went his way therefore, and washed, and came seeing."},"BSB":{"text":"Then He told him, “Go, wash in the Pool of Siloam” (which means “Sent”). So the man went and washed, and came back seeing."}},"definableWords":["man"],"peopleInVerse":[]},"8":{"text":"The neighbours therefore, and they which before had seen him that he was blind, said, Is not this he that sat and begged?","ref":"John 9:8","synthesized":"At this, his neighbors and those who had formerly seen him begging began to ask, “Isn’t this the man who used to sit and beg?”","sources":{"KJV":{"text":"The neighbours therefore, and they which before had seen him that he was blind, said, Is not this he that sat and begged?"},"BSB":{"text":"At this, his neighbors and those who had formerly seen him begging began to ask, “Isn’t this the man who used to sit and beg?”"}},"definableWords":["man"],"peopleInVerse":[]},"9":{"text":"Some said, This is he: others said, He is like him: but he said, I am he.","ref":"John 9:9","synthesized":"Some claimed that he was, but others said, “No, he just looks like him.”  But the man kept saying, “I am the one.”","sources":{"KJV":{"text":"Some said, This is he: others said, He is like him: but he said, I am he."},"BSB":{"text":"Some claimed that he was, but others said, “No, he just looks like him.”  But the man kept saying, “I am the one.”"}},"definableWords":["man","one"],"peopleInVerse":[]},"10":{"text":"Therefore said they unto him, How were thine eyes opened?","ref":"John 9:10","synthesized":"“How then were your eyes opened?” they asked.","sources":{"KJV":{"text":"Therefore said they unto him, How were thine eyes opened?"},"BSB":{"text":"“How then were your eyes opened?” they asked."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"He answered and said, A man that is called Jesus made clay, and anointed mine eyes, and said unto me, Go to the pool of Siloam, and wash: and I went and washed, and I received sight.","ref":"John 9:11","synthesized":"He answered, “The man they call Jesus made some mud and anointed my eyes, and He told me to go to Siloam and wash. So I went and washed and received my sight.”","sources":{"KJV":{"text":"He answered and said, A man that is called Jesus made clay, and anointed mine eyes, and said unto me, Go to the pool of Siloam, and wash: and I went and washed, and I received sight."},"BSB":{"text":"He answered, “The man they call Jesus made some mud and anointed my eyes, and He told me to go to Siloam and wash. So I went and washed and received my sight.”"}},"definableWords":["man","made"],"peopleInVerse":["Jesus"]},"12":{"text":"Then said they unto him, Where is he? He said, I know not.","ref":"John 9:12","synthesized":"“Where is He?” they asked.  “I do not know,” he answered.","sources":{"KJV":{"text":"Then said they unto him, Where is he? He said, I know not."},"BSB":{"text":"“Where is He?” they asked.  “I do not know,” he answered."}},"definableWords":[],"peopleInVerse":[]},"13":{"text":"They brought to the Pharisees him that aforetime was blind.","ref":"John 9:13","synthesized":"They brought to the Pharisees the man who had been blind.","sources":{"KJV":{"text":"They brought to the Pharisees him that aforetime was blind."},"BSB":{"text":"They brought to the Pharisees the man who had been blind."}},"definableWords":["man"],"peopleInVerse":[]},"14":{"text":"And it was the sabbath day when Jesus made the clay, and opened his eyes.","ref":"John 9:14","synthesized":"Now the day on which Jesus had made the mud and opened his eyes was a Sabbath.","sources":{"KJV":{"text":"And it was the sabbath day when Jesus made the clay, and opened his eyes."},"BSB":{"text":"Now the day on which Jesus had made the mud and opened his eyes was a Sabbath."}},"definableWords":["day","made","Sabbath"],"peopleInVerse":["Jesus"]},"15":{"text":"Then again the Pharisees also asked him how he had received his sight. He said unto them, He put clay upon mine eyes, and I washed, and do see.","ref":"John 9:15","synthesized":"So the Pharisees also asked him how he had received his sight.  The man answered, “He put mud on my eyes, and I washed, and now I can see.”","sources":{"KJV":{"text":"Then again the Pharisees also asked him how he had received his sight. He said unto them, He put clay upon mine eyes, and I washed, and do see."},"BSB":{"text":"So the Pharisees also asked him how he had received his sight.  The man answered, “He put mud on my eyes, and I washed, and now I can see.”"}},"definableWords":["man","see"],"peopleInVerse":[]},"16":{"text":"Therefore said some of the Pharisees, This man is not of God, because he keepeth not the sabbath day. Others said, How can a man that is a sinner do such miracles? And there was a division among them.","ref":"John 9:16","synthesized":"Because of this, some of the Pharisees said, “This man is not from God, for He does not keep the Sabbath.”  But others said, “How can a sinful man perform such signs?”  And there was division among them.","sources":{"KJV":{"text":"Therefore said some of the Pharisees, This man is not of God, because he keepeth not the sabbath day. Others said, How can a man that is a sinner do such miracles? And there was a division among them."},"BSB":{"text":"Because of this, some of the Pharisees said, “This man is not from God, for He does not keep the Sabbath.”  But others said, “How can a sinful man perform such signs?”  And there was division among them."}},"definableWords":["man","God","keep","Sabbath"],"peopleInVerse":[]},"17":{"text":"They say unto the blind man again, What sayest thou of him, that he hath opened thine eyes? He said, He is a prophet.","ref":"John 9:17","synthesized":"So once again they asked the man who had been blind, “What do you say about Him, since it was your eyes He opened?”  “He is a prophet,” the man replied.","sources":{"KJV":{"text":"They say unto the blind man again, What sayest thou of him, that he hath opened thine eyes? He said, He is a prophet."},"BSB":{"text":"So once again they asked the man who had been blind, “What do you say about Him, since it was your eyes He opened?”  “He is a prophet,” the man replied."}},"definableWords":["man","prophet"],"peopleInVerse":[]},"18":{"text":"But the Jews did not believe concerning him, that he had been blind, and received his sight, until they called the parents of him that had received his sight.","ref":"John 9:18","synthesized":"The Jews still did not believe that the man had been blind and had received his sight until they summoned his parents","sources":{"KJV":{"text":"But the Jews did not believe concerning him, that he had been blind, and received his sight, until they called the parents of him that had received his sight."},"BSB":{"text":"The Jews still did not believe that the man had been blind and had received his sight until they summoned his parents"}},"definableWords":["man"],"peopleInVerse":[]},"19":{"text":"And they asked them, saying, Is this your son, who ye say was born blind? how then doth he now see?","ref":"John 9:19","synthesized":"and asked, “Is this your son, the one you say was born blind? So how is it that he can now see?”","sources":{"KJV":{"text":"And they asked them, saying, Is this your son, who ye say was born blind? how then doth he now see?"},"BSB":{"text":"and asked, “Is this your son, the one you say was born blind? So how is it that he can now see?”"}},"definableWords":["son","one","see"],"peopleInVerse":[]},"20":{"text":"His parents answered them and said, We know that this is our son, and that he was born blind:","ref":"John 9:20","synthesized":"His parents answered, “We know he is our son, and we know he was born blind.","sources":{"KJV":{"text":"His parents answered them and said, We know that this is our son, and that he was born blind:"},"BSB":{"text":"His parents answered, “We know he is our son, and we know he was born blind."}},"definableWords":["son"],"peopleInVerse":[]},"21":{"text":"But by what means he now seeth, we know not; or who hath opened his eyes, we know not: he is of age; ask him: he shall speak for himself.","ref":"John 9:21","synthesized":"But how he can now see or who opened his eyes, we do not know. Ask him. He is old enough to speak for himself.”","sources":{"KJV":{"text":"But by what means he now seeth, we know not; or who hath opened his eyes, we know not: he is of age; ask him: he shall speak for himself."},"BSB":{"text":"But how he can now see or who opened his eyes, we do not know. Ask him. He is old enough to speak for himself.”"}},"definableWords":["see","or"],"peopleInVerse":[]},"22":{"text":"These words spake his parents, because they feared the Jews: for the Jews had agreed already, that if any man did confess that he was Christ, he should be put out of the synagogue.","ref":"John 9:22","synthesized":"His parents said this because they were afraid of the Jews. For the Jews had already determined that anyone who confessed Jesus as the Christ would be put out of the synagogue.","sources":{"KJV":{"text":"These words spake his parents, because they feared the Jews: for the Jews had agreed already, that if any man did confess that he was Christ, he should be put out of the synagogue."},"BSB":{"text":"His parents said this because they were afraid of the Jews. For the Jews had already determined that anyone who confessed Jesus as the Christ would be put out of the synagogue."}},"definableWords":["Christ"],"peopleInVerse":["Jesus"]},"23":{"text":"Therefore said his parents, He is of age; ask him.","ref":"John 9:23","synthesized":"That was why his parents said, “He is old enough. Ask him.”","sources":{"KJV":{"text":"Therefore said his parents, He is of age; ask him."},"BSB":{"text":"That was why his parents said, “He is old enough. Ask him.”"}},"definableWords":[],"peopleInVerse":[]},"24":{"text":"Then again called they the man that was blind, and said unto him, Give God the praise: we know that this man is a sinner.","ref":"John 9:24","synthesized":"So a second time they called for the man who had been blind and said, “Give glory to God! We know that this man is a sinner.”","sources":{"KJV":{"text":"Then again called they the man that was blind, and said unto him, Give God the praise: we know that this man is a sinner."},"BSB":{"text":"So a second time they called for the man who had been blind and said, “Give glory to God! We know that this man is a sinner.”"}},"definableWords":["man","glory","God"],"peopleInVerse":[]},"25":{"text":"He answered and said, Whether he be a sinner or no, I know not: one thing I know, that, whereas I was blind, now I see.","ref":"John 9:25","synthesized":"He answered, “Whether He is a sinner I do not know. There is one thing I do know: I was blind, but now I see!”","sources":{"KJV":{"text":"He answered and said, Whether he be a sinner or no, I know not: one thing I know, that, whereas I was blind, now I see."},"BSB":{"text":"He answered, “Whether He is a sinner I do not know. There is one thing I do know: I was blind, but now I see!”"}},"definableWords":["one","see"],"peopleInVerse":[]},"26":{"text":"Then said they to him again, What did he to thee? how opened he thine eyes?","ref":"John 9:26","synthesized":"“What did He do to you?” they asked. “How did He open your eyes?”","sources":{"KJV":{"text":"Then said they to him again, What did he to thee? how opened he thine eyes?"},"BSB":{"text":"“What did He do to you?” they asked. “How did He open your eyes?”"}},"definableWords":[],"peopleInVerse":[]},"27":{"text":"He answered them, I have told you already, and ye did not hear: wherefore would ye hear it again? will ye also be his disciples?","ref":"John 9:27","synthesized":"He replied, “I already told you, and you did not listen. Why do you want to hear it again? Do you also want to become His disciples?”","sources":{"KJV":{"text":"He answered them, I have told you already, and ye did not hear: wherefore would ye hear it again? will ye also be his disciples?"},"BSB":{"text":"He replied, “I already told you, and you did not listen. Why do you want to hear it again? Do you also want to become His disciples?”"}},"definableWords":["hear"],"peopleInVerse":[]},"28":{"text":"Then they reviled him, and said, Thou art his disciple; but we are Moses’ disciples.","ref":"John 9:28","synthesized":"Then they heaped insults on him and said, “You are His disciple; we are disciples of Moses.","sources":{"KJV":{"text":"Then they reviled him, and said, Thou art his disciple; but we are Moses’ disciples."},"BSB":{"text":"Then they heaped insults on him and said, “You are His disciple; we are disciples of Moses."}},"definableWords":["disciple"],"peopleInVerse":["Moses"]},"29":{"text":"We know that God spake unto Moses: as for this fellow, we know not from whence he is.","ref":"John 9:29","synthesized":"We know that God spoke to Moses, but we do not know where this man is from.”","sources":{"KJV":{"text":"We know that God spake unto Moses: as for this fellow, we know not from whence he is."},"BSB":{"text":"We know that God spoke to Moses, but we do not know where this man is from.”"}},"definableWords":["God","man"],"peopleInVerse":["Moses"]},"30":{"text":"The man answered and said unto them, Why herein is a marvellous thing, that ye know not from whence he is, and yet he hath opened mine eyes.","ref":"John 9:30","synthesized":"“That is remarkable indeed!” the man said. “You do not know where He is from, and yet He opened my eyes.","sources":{"KJV":{"text":"The man answered and said unto them, Why herein is a marvellous thing, that ye know not from whence he is, and yet he hath opened mine eyes."},"BSB":{"text":"“That is remarkable indeed!” the man said. “You do not know where He is from, and yet He opened my eyes."}},"definableWords":["man"],"peopleInVerse":[]},"31":{"text":"Now we know that God heareth not sinners: but if any man be a worshipper of God, and doeth his will, him he heareth.","ref":"John 9:31","synthesized":"We know that God does not listen to sinners, but He does listen to the one who worships Him and does His will.","sources":{"KJV":{"text":"Now we know that God heareth not sinners: but if any man be a worshipper of God, and doeth his will, him he heareth."},"BSB":{"text":"We know that God does not listen to sinners, but He does listen to the one who worships Him and does His will."}},"definableWords":["God","one"],"peopleInVerse":[]},"32":{"text":"Since the world began was it not heard that any man opened the eyes of one that was born blind.","ref":"John 9:32","synthesized":"Never before has anyone heard of opening the eyes of a man born blind.","sources":{"KJV":{"text":"Since the world began was it not heard that any man opened the eyes of one that was born blind."},"BSB":{"text":"Never before has anyone heard of opening the eyes of a man born blind."}},"definableWords":["man"],"peopleInVerse":[]},"33":{"text":"If this man were not of God, he could do nothing.","ref":"John 9:33","synthesized":"If this man were not from God, He could do no such thing.”","sources":{"KJV":{"text":"If this man were not of God, he could do nothing."},"BSB":{"text":"If this man were not from God, He could do no such thing.”"}},"definableWords":["man","God"],"peopleInVerse":[]},"34":{"text":"They answered and said unto him, Thou wast altogether born in sins, and dost thou teach us? And they cast him out.","ref":"John 9:34","synthesized":"They replied, “You were born in utter sin, and you are instructing us?” And they threw him out.","sources":{"KJV":{"text":"They answered and said unto him, Thou wast altogether born in sins, and dost thou teach us? And they cast him out."},"BSB":{"text":"They replied, “You were born in utter sin, and you are instructing us?” And they threw him out."}},"definableWords":["sin"],"peopleInVerse":[]},"35":{"text":"Jesus heard that they had cast him out; and when he had found him, he said unto him, Dost thou believe on the Son of God?","ref":"John 9:35","synthesized":"When Jesus heard that they had thrown him out, He found the man and said, “Do you believe in the Son of Man?”","sources":{"KJV":{"text":"Jesus heard that they had cast him out; and when he had found him, he said unto him, Dost thou believe on the Son of God?"},"BSB":{"text":"When Jesus heard that they had thrown him out, He found the man and said, “Do you believe in the Son of Man?”"}},"definableWords":["man","Son"],"peopleInVerse":["Jesus"]},"36":{"text":"He answered and said, Who is he, Lord, that I might believe on him?","ref":"John 9:36","synthesized":"“Who is He, Sir?” he replied. “Tell me so that I may believe in Him.”","sources":{"KJV":{"text":"He answered and said, Who is he, Lord, that I might believe on him?"},"BSB":{"text":"“Who is He, Sir?” he replied. “Tell me so that I may believe in Him.”"}},"definableWords":[],"peopleInVerse":[]},"37":{"text":"And Jesus said unto him, Thou hast both seen him, and it is he that talketh with thee.","ref":"John 9:37","synthesized":"“You have already seen Him,” Jesus answered. “He is the One speaking with you.”","sources":{"KJV":{"text":"And Jesus said unto him, Thou hast both seen him, and it is he that talketh with thee."},"BSB":{"text":"“You have already seen Him,” Jesus answered. “He is the One speaking with you.”"}},"definableWords":["one"],"peopleInVerse":["Jesus"]},"38":{"text":"And he said, Lord, I believe. And he worshipped him.","ref":"John 9:38","synthesized":"“Lord, I believe,” he said. And he worshiped Jesus.","sources":{"KJV":{"text":"And he said, Lord, I believe. And he worshipped him."},"BSB":{"text":"“Lord, I believe,” he said. And he worshiped Jesus."}},"definableWords":["Lord"],"peopleInVerse":["Jesus"]},"39":{"text":"And Jesus said, For judgment I am come into this world, that they which see not might see; and that they which see might be made blind.","ref":"John 9:39","synthesized":"Then Jesus declared, “For judgment I have come into this world, so that the blind may see and those who see may become blind.”","sources":{"KJV":{"text":"And Jesus said, For judgment I am come into this world, that they which see not might see; and that they which see might be made blind."},"BSB":{"text":"Then Jesus declared, “For judgment I have come into this world, so that the blind may see and those who see may become blind.”"}},"definableWords":["judgment","see"],"peopleInVerse":["Jesus"]},"40":{"text":"And some of the Pharisees which were with him heard these words, and said unto him, Are we blind also?","ref":"John 9:40","synthesized":"Some of the Pharisees who were with Him heard this, and they asked Him, “Are we blind too?”","sources":{"KJV":{"text":"And some of the Pharisees which were with him heard these words, and said unto him, Are we blind also?"},"BSB":{"text":"Some of the Pharisees who were with Him heard this, and they asked Him, “Are we blind too?”"}},"definableWords":[],"peopleInVerse":[]},"41":{"text":"Jesus said unto them, If ye were blind, ye should have no sin: but now ye say, We see; therefore your sin remaineth.","ref":"John 9:41","synthesized":"“If you were blind,” Jesus replied, “you would not be guilty of sin. But since you claim you can see, your guilt remains.”","sources":{"KJV":{"text":"Jesus said unto them, If ye were blind, ye should have no sin: but now ye say, We see; therefore your sin remaineth."},"BSB":{"text":"“If you were blind,” Jesus replied, “you would not be guilty of sin. But since you claim you can see, your guilt remains.”"}},"definableWords":["sin","see"],"peopleInVerse":["Jesus"]}}},"10":{"chapter":"10","title":"I AM THE GOOD SHEPHERD","verses":{"1":{"text":"Verily, verily, I say unto you, He that entereth not by the door into the sheepfold, but climbeth up some other way, the same is a thief and a robber.","ref":"John 10:1","synthesized":"“Truly, truly, I tell you, whoever does not enter the sheepfold by the gate, but climbs in some other way, is a thief and a robber.","sources":{"KJV":{"text":"Verily, verily, I say unto you, He that entereth not by the door into the sheepfold, but climbeth up some other way, the same is a thief and a robber."},"BSB":{"text":"“Truly, truly, I tell you, whoever does not enter the sheepfold by the gate, but climbs in some other way, is a thief and a robber."}},"definableWords":["way"],"peopleInVerse":[],"kingdomLens":"Jesus declares 'I am the door' and 'I am the good shepherd.' The good shepherd LAYS DOWN his life for the sheep — unlike the hireling who flees when the wolf comes. Then the radical claim: 'I and my Father are one' (10:30). They take up stones to kill him for blasphemy. He says 'before Abraham was, I AM' — directly applying the divine name of Exodus 3:14 to himself.","cultural":{"title":"I am the Good Shepherd","detail":"Ancient Near East shepherds went BEFORE the flock — not behind like Western shepherds. Sheep follow the voice they recognize. Multiple flocks could mix at a well; when shepherds went different directions, each flock followed its own shepherd. Jesus: 'my sheep hear my voice.'","sources":"SWRV Kingdom Study Protocol — synthesis from approved library (Rule 06)"}},"2":{"text":"But he that entereth in by the door is the shepherd of the sheep.","ref":"John 10:2","synthesized":"But the one who enters by the gate is the shepherd of the sheep.","sources":{"KJV":{"text":"But he that entereth in by the door is the shepherd of the sheep."},"BSB":{"text":"But the one who enters by the gate is the shepherd of the sheep."}},"definableWords":["one","shepherd"],"peopleInVerse":[]},"3":{"text":"To him the porter openeth; and the sheep hear his voice: and he calleth his own sheep by name, and leadeth them out.","ref":"John 10:3","synthesized":"The gatekeeper opens the gate for him, and the sheep listen for his voice. He calls his own sheep by name and leads them out.","sources":{"KJV":{"text":"To him the porter openeth; and the sheep hear his voice: and he calleth his own sheep by name, and leadeth them out."},"BSB":{"text":"The gatekeeper opens the gate for him, and the sheep listen for his voice. He calls his own sheep by name and leads them out."}},"definableWords":["voice","name"],"peopleInVerse":[]},"4":{"text":"And when he putteth forth his own sheep, he goeth before them, and the sheep follow him: for they know his voice.","ref":"John 10:4","synthesized":"When he has brought out all his own, he goes on ahead of them, and his sheep follow him because they know his voice.","sources":{"KJV":{"text":"And when he putteth forth his own sheep, he goeth before them, and the sheep follow him: for they know his voice."},"BSB":{"text":"When he has brought out all his own, he goes on ahead of them, and his sheep follow him because they know his voice."}},"definableWords":["voice"],"peopleInVerse":[]},"5":{"text":"And a stranger will they not follow, but will flee from him: for they know not the voice of strangers.","ref":"John 10:5","synthesized":"But they will never follow a stranger; in fact, they will flee from him because they do not recognize his voice.”","sources":{"KJV":{"text":"And a stranger will they not follow, but will flee from him: for they know not the voice of strangers."},"BSB":{"text":"But they will never follow a stranger; in fact, they will flee from him because they do not recognize his voice.”"}},"definableWords":["stranger","voice"],"peopleInVerse":[]},"6":{"text":"This parable spake Jesus unto them: but they understood not what things they were which he spake unto them.","ref":"John 10:6","synthesized":"Jesus spoke to them using this illustration, but they did not understand what He was telling them.","sources":{"KJV":{"text":"This parable spake Jesus unto them: but they understood not what things they were which he spake unto them."},"BSB":{"text":"Jesus spoke to them using this illustration, but they did not understand what He was telling them."}},"definableWords":[],"peopleInVerse":["Jesus"]},"7":{"text":"Then said Jesus unto them again, Verily, verily, I say unto you, I am the door of the sheep.","ref":"John 10:7","synthesized":"So He said to them again, “Truly, truly, I tell you, I am the gate for the sheep.","sources":{"KJV":{"text":"Then said Jesus unto them again, Verily, verily, I say unto you, I am the door of the sheep."},"BSB":{"text":"So He said to them again, “Truly, truly, I tell you, I am the gate for the sheep."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"All that ever came before me are thieves and robbers: but the sheep did not hear them.","ref":"John 10:8","synthesized":"All who came before Me were thieves and robbers, but the sheep did not listen to them.","sources":{"KJV":{"text":"All that ever came before me are thieves and robbers: but the sheep did not hear them."},"BSB":{"text":"All who came before Me were thieves and robbers, but the sheep did not listen to them."}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"I am the door: by me if any man enter in, he shall be saved, and shall go in and out, and find pasture.","ref":"John 10:9","synthesized":"I am the gate. If anyone enters through Me, he will be saved. He will come in and go out and find pasture.","sources":{"KJV":{"text":"I am the door: by me if any man enter in, he shall be saved, and shall go in and out, and find pasture."},"BSB":{"text":"I am the gate. If anyone enters through Me, he will be saved. He will come in and go out and find pasture."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"The thief cometh not, but for to steal, and to kill, and to destroy: I am come that they might have life, and that they might have it more abundantly.","ref":"John 10:10","synthesized":"The thief comes only to steal and kill and destroy. I have come that they may have life, and have it in all its fullness.","sources":{"KJV":{"text":"The thief cometh not, but for to steal, and to kill, and to destroy: I am come that they might have life, and that they might have it more abundantly."},"BSB":{"text":"The thief comes only to steal and kill and destroy. I have come that they may have life, and have it in all its fullness."}},"definableWords":["life"],"peopleInVerse":[]},"11":{"text":"I am the good shepherd: the good shepherd giveth his life for the sheep.","ref":"John 10:11","synthesized":"I am the good shepherd. The good shepherd lays down His life for the sheep.","sources":{"KJV":{"text":"I am the good shepherd: the good shepherd giveth his life for the sheep."},"BSB":{"text":"I am the good shepherd. The good shepherd lays down His life for the sheep."}},"definableWords":["good","shepherd","life"],"peopleInVerse":[]},"12":{"text":"But he that is an hireling, and not the shepherd, whose own the sheep are not, seeth the wolf coming, and leaveth the sheep, and fleeth: and the wolf catcheth them, and scattereth the sheep.","ref":"John 10:12","synthesized":"The hired hand is not the shepherd, and the sheep are not his own. When he sees the wolf coming, he abandons the sheep and runs away. Then the wolf pounces on them and scatters the flock.","sources":{"KJV":{"text":"But he that is an hireling, and not the shepherd, whose own the sheep are not, seeth the wolf coming, and leaveth the sheep, and fleeth: and the wolf catcheth them, and scattereth the sheep."},"BSB":{"text":"The hired hand is not the shepherd, and the sheep are not his own. When he sees the wolf coming, he abandons the sheep and runs away. Then the wolf pounces on them and scatters the flock."}},"definableWords":["shepherd"],"peopleInVerse":[]},"13":{"text":"The hireling fleeth, because he is an hireling, and careth not for the sheep.","ref":"John 10:13","synthesized":"The man runs away because he is a hired servant and is unconcerned for the sheep.","sources":{"KJV":{"text":"The hireling fleeth, because he is an hireling, and careth not for the sheep."},"BSB":{"text":"The man runs away because he is a hired servant and is unconcerned for the sheep."}},"definableWords":["man","servant"],"peopleInVerse":[]},"14":{"text":"I am the good shepherd, and know my sheep, and am known of mine.","ref":"John 10:14","synthesized":"I am the good shepherd. I know My sheep and My sheep know Me,","sources":{"KJV":{"text":"I am the good shepherd, and know my sheep, and am known of mine."},"BSB":{"text":"I am the good shepherd. I know My sheep and My sheep know Me,"}},"definableWords":["good","shepherd"],"peopleInVerse":[]},"15":{"text":"As the Father knoweth me, even so know I the Father: and I lay down my life for the sheep.","ref":"John 10:15","synthesized":"just as the Father knows Me and I know the Father. And I lay down My life for the sheep.","sources":{"KJV":{"text":"As the Father knoweth me, even so know I the Father: and I lay down my life for the sheep."},"BSB":{"text":"just as the Father knows Me and I know the Father. And I lay down My life for the sheep."}},"definableWords":["Father","life"],"peopleInVerse":[]},"16":{"text":"And other sheep I have, which are not of this fold: them also I must bring, and they shall hear my voice; and there shall be one fold, and one shepherd.","ref":"John 10:16","synthesized":"I have other sheep that are not of this fold. I must bring them in as well, and they will listen to My voice. Then there will be one flock and one shepherd.","sources":{"KJV":{"text":"And other sheep I have, which are not of this fold: them also I must bring, and they shall hear my voice; and there shall be one fold, and one shepherd."},"BSB":{"text":"I have other sheep that are not of this fold. I must bring them in as well, and they will listen to My voice. Then there will be one flock and one shepherd."}},"definableWords":["voice","one","shepherd"],"peopleInVerse":[]},"17":{"text":"Therefore doth my Father love me, because I lay down my life, that I might take it again.","ref":"John 10:17","synthesized":"The reason the Father loves Me is that I lay down My life in order to take it up again.","sources":{"KJV":{"text":"Therefore doth my Father love me, because I lay down my life, that I might take it again."},"BSB":{"text":"The reason the Father loves Me is that I lay down My life in order to take it up again."}},"definableWords":["Father","life"],"peopleInVerse":[]},"18":{"text":"No man taketh it from me, but I lay it down of myself. I have power to lay it down, and I have power to take it again. This commandment have I received of my Father.","ref":"John 10:18","synthesized":"No one takes it from Me, but I lay it down of My own accord. I have authority to lay it down and authority to take it up again. This charge I have received from My Father.”","sources":{"KJV":{"text":"No man taketh it from me, but I lay it down of myself. I have power to lay it down, and I have power to take it again. This commandment have I received of my Father."},"BSB":{"text":"No one takes it from Me, but I lay it down of My own accord. I have authority to lay it down and authority to take it up again. This charge I have received from My Father.”"}},"definableWords":["one","charge","Father"],"peopleInVerse":[]},"19":{"text":"There was a division therefore again among the Jews for these sayings.","ref":"John 10:19","synthesized":"Again there was division among the Jews because of Jesus’ message.","sources":{"KJV":{"text":"There was a division therefore again among the Jews for these sayings."},"BSB":{"text":"Again there was division among the Jews because of Jesus’ message."}},"definableWords":[],"peopleInVerse":["Jesus"]},"20":{"text":"And many of them said, He hath a devil, and is mad; why hear ye him?","ref":"John 10:20","synthesized":"Many of them said, “He is demon-possessed and insane. Why would you listen to Him?”","sources":{"KJV":{"text":"And many of them said, He hath a devil, and is mad; why hear ye him?"},"BSB":{"text":"Many of them said, “He is demon-possessed and insane. Why would you listen to Him?”"}},"definableWords":["demon"],"peopleInVerse":[]},"21":{"text":"Others said, These are not the words of him that hath a devil. Can a devil open the eyes of the blind?","ref":"John 10:21","synthesized":"But others replied, “These are not the words of a man possessed by a demon. Can a demon open the eyes of the blind?”","sources":{"KJV":{"text":"Others said, These are not the words of him that hath a devil. Can a devil open the eyes of the blind?"},"BSB":{"text":"But others replied, “These are not the words of a man possessed by a demon. Can a demon open the eyes of the blind?”"}},"definableWords":["man","demon"],"peopleInVerse":[]},"22":{"text":"And it was at Jerusalem the feast of the dedication, and it was winter.","ref":"John 10:22","synthesized":"At that time the Feast of Dedication took place in Jerusalem. It was winter,","sources":{"KJV":{"text":"And it was at Jerusalem the feast of the dedication, and it was winter."},"BSB":{"text":"At that time the Feast of Dedication took place in Jerusalem. It was winter,"}},"definableWords":["Jerusalem"],"peopleInVerse":[]},"23":{"text":"And Jesus walked in the temple in Solomon’s porch.","ref":"John 10:23","synthesized":"and Jesus was walking in the temple courts in Solomon’s Colonnade.","sources":{"KJV":{"text":"And Jesus walked in the temple in Solomon’s porch."},"BSB":{"text":"and Jesus was walking in the temple courts in Solomon’s Colonnade."}},"definableWords":["temple"],"peopleInVerse":["Jesus","Solomon"]},"24":{"text":"Then came the Jews round about him, and said unto him, How long dost thou make us to doubt? If thou be the Christ, tell us plainly.","ref":"John 10:24","synthesized":"So the Jews gathered around Him and demanded, “How long will You keep us in suspense? If You are the Christ, tell us plainly.”","sources":{"KJV":{"text":"Then came the Jews round about him, and said unto him, How long dost thou make us to doubt? If thou be the Christ, tell us plainly."},"BSB":{"text":"So the Jews gathered around Him and demanded, “How long will You keep us in suspense? If You are the Christ, tell us plainly.”"}},"definableWords":["keep","Christ"],"peopleInVerse":[]},"25":{"text":"Jesus answered them, I told you, and ye believed not: the works that I do in my Father’s name, they bear witness of me.","ref":"John 10:25","synthesized":"“I already told you,” Jesus replied, “but you did not believe. The works I do in My Father’s name testify on My behalf.","sources":{"KJV":{"text":"Jesus answered them, I told you, and ye believed not: the works that I do in my Father’s name, they bear witness of me."},"BSB":{"text":"“I already told you,” Jesus replied, “but you did not believe. The works I do in My Father’s name testify on My behalf."}},"definableWords":["works","Father","name"],"peopleInVerse":["Jesus"]},"26":{"text":"But ye believe not, because ye are not of my sheep, as I said unto you.","ref":"John 10:26","synthesized":"But because you are not My sheep, you refuse to believe.","sources":{"KJV":{"text":"But ye believe not, because ye are not of my sheep, as I said unto you."},"BSB":{"text":"But because you are not My sheep, you refuse to believe."}},"definableWords":[],"peopleInVerse":[]},"27":{"text":"My sheep hear my voice, and I know them, and they follow me:","ref":"John 10:27","synthesized":"My sheep listen to My voice; I know them, and they follow Me.","sources":{"KJV":{"text":"My sheep hear my voice, and I know them, and they follow me:"},"BSB":{"text":"My sheep listen to My voice; I know them, and they follow Me."}},"definableWords":["voice"],"peopleInVerse":[]},"28":{"text":"And I give unto them eternal life; and they shall never perish, neither shall any man pluck them out of my hand.","ref":"John 10:28","synthesized":"I give them eternal life, and they will never perish. No one can snatch them out of My hand.","sources":{"KJV":{"text":"And I give unto them eternal life; and they shall never perish, neither shall any man pluck them out of my hand."},"BSB":{"text":"I give them eternal life, and they will never perish. No one can snatch them out of My hand."}},"definableWords":["eternal","life","one"],"peopleInVerse":[]},"29":{"text":"My Father, which gave them me, is greater than all; and no man is able to pluck them out of my Father’s hand.","ref":"John 10:29","synthesized":"My Father who has given them to Me is greater than all. No one can snatch them out of My Father’s hand.","sources":{"KJV":{"text":"My Father, which gave them me, is greater than all; and no man is able to pluck them out of my Father’s hand."},"BSB":{"text":"My Father who has given them to Me is greater than all. No one can snatch them out of My Father’s hand."}},"definableWords":["Father","one"],"peopleInVerse":[]},"30":{"text":"I and my Father are one.","ref":"John 10:30","synthesized":"I and the Father are one.”","sources":{"KJV":{"text":"I and my Father are one."},"BSB":{"text":"I and the Father are one.”"}},"definableWords":["Father","one"],"peopleInVerse":[]},"31":{"text":"Then the Jews took up stones again to stone him.","ref":"John 10:31","synthesized":"At this, the Jews again picked up stones to stone Him.","sources":{"KJV":{"text":"Then the Jews took up stones again to stone him."},"BSB":{"text":"At this, the Jews again picked up stones to stone Him."}},"definableWords":["stone"],"peopleInVerse":[]},"32":{"text":"Jesus answered them, Many good works have I shewed you from my Father; for which of those works do ye stone me?","ref":"John 10:32","synthesized":"But Jesus responded, “I have shown you many good works from the Father. For which of these do you stone Me?”","sources":{"KJV":{"text":"Jesus answered them, Many good works have I shewed you from my Father; for which of those works do ye stone me?"},"BSB":{"text":"But Jesus responded, “I have shown you many good works from the Father. For which of these do you stone Me?”"}},"definableWords":["good","works","Father","stone"],"peopleInVerse":["Jesus"]},"33":{"text":"The Jews answered him, saying, For a good work we stone thee not; but for blasphemy; and because that thou, being a man, makest thyself God.","ref":"John 10:33","synthesized":"“We are not stoning You for any good work,” said the Jews, “but for blasphemy, because You, who are a man, declare Yourself to be God.”","sources":{"KJV":{"text":"The Jews answered him, saying, For a good work we stone thee not; but for blasphemy; and because that thou, being a man, makest thyself God."},"BSB":{"text":"“We are not stoning You for any good work,” said the Jews, “but for blasphemy, because You, who are a man, declare Yourself to be God.”"}},"definableWords":["good","work","man","God"],"peopleInVerse":[]},"34":{"text":"Jesus answered them, Is it not written in your law, I said, Ye are gods?","ref":"John 10:34","synthesized":"Jesus replied, “Is it not written in your Law: ‘I have said you are gods’?","sources":{"KJV":{"text":"Jesus answered them, Is it not written in your law, I said, Ye are gods?"},"BSB":{"text":"Jesus replied, “Is it not written in your Law: ‘I have said you are gods’?"}},"definableWords":["law"],"peopleInVerse":["Jesus"]},"35":{"text":"If he called them gods, unto whom the word of God came, and the scripture cannot be broken;","ref":"John 10:35","synthesized":"If he called them gods to whom the word of God came—and the Scripture cannot be broken—","sources":{"KJV":{"text":"If he called them gods, unto whom the word of God came, and the scripture cannot be broken;"},"BSB":{"text":"If he called them gods to whom the word of God came—and the Scripture cannot be broken—"}},"definableWords":["word","God"],"peopleInVerse":[]},"36":{"text":"Say ye of him, whom the Father hath sanctified, and sent into the world, Thou blasphemest; because I said, I am the Son of God?","ref":"John 10:36","synthesized":"then what about the One whom the Father sanctified and sent into the world? How then can you accuse Me of blasphemy for stating that I am the Son of God?","sources":{"KJV":{"text":"Say ye of him, whom the Father hath sanctified, and sent into the world, Thou blasphemest; because I said, I am the Son of God?"},"BSB":{"text":"then what about the One whom the Father sanctified and sent into the world? How then can you accuse Me of blasphemy for stating that I am the Son of God?"}},"definableWords":["one","Father","Son","God"],"peopleInVerse":[]},"37":{"text":"If I do not the works of my Father, believe me not.","ref":"John 10:37","synthesized":"If I am not doing the works of My Father, then do not believe Me.","sources":{"KJV":{"text":"If I do not the works of my Father, believe me not."},"BSB":{"text":"If I am not doing the works of My Father, then do not believe Me."}},"definableWords":["works","Father"],"peopleInVerse":[]},"38":{"text":"But if I do, though ye believe not me, believe the works: that ye may know, and believe, that the Father is in me, and I in him.","ref":"John 10:38","synthesized":"But if I am doing them, even though you do not believe Me, believe the works themselves, so that you may know and understand that the Father is in Me, and I am in the Father.”","sources":{"KJV":{"text":"But if I do, though ye believe not me, believe the works: that ye may know, and believe, that the Father is in me, and I in him."},"BSB":{"text":"But if I am doing them, even though you do not believe Me, believe the works themselves, so that you may know and understand that the Father is in Me, and I am in the Father.”"}},"definableWords":["works","Father"],"peopleInVerse":[]},"39":{"text":"Therefore they sought again to take him: but he escaped out of their hand,","ref":"John 10:39","synthesized":"At this, they tried again to seize Him, but He escaped their grasp.","sources":{"KJV":{"text":"Therefore they sought again to take him: but he escaped out of their hand,"},"BSB":{"text":"At this, they tried again to seize Him, but He escaped their grasp."}},"definableWords":[],"peopleInVerse":[]},"40":{"text":"And went away again beyond Jordan into the place where John at first baptized; and there he abode.","ref":"John 10:40","synthesized":"Then Jesus went back across the Jordan to the place where John had first been baptizing, and He stayed there.","sources":{"KJV":{"text":"And went away again beyond Jordan into the place where John at first baptized; and there he abode."},"BSB":{"text":"Then Jesus went back across the Jordan to the place where John had first been baptizing, and He stayed there."}},"definableWords":[],"peopleInVerse":["Jesus","John"]},"41":{"text":"And many resorted unto him, and said, John did no miracle: but all things that John spake of this man were true.","ref":"John 10:41","synthesized":"Many came to Him and said, “Although John never performed a sign, everything he said about this man was true.”","sources":{"KJV":{"text":"And many resorted unto him, and said, John did no miracle: but all things that John spake of this man were true."},"BSB":{"text":"Many came to Him and said, “Although John never performed a sign, everything he said about this man was true.”"}},"definableWords":["man"],"peopleInVerse":["John"]},"42":{"text":"And many believed on him there.","ref":"John 10:42","synthesized":"And many in that place believed in Jesus.","sources":{"KJV":{"text":"And many believed on him there."},"BSB":{"text":"And many in that place believed in Jesus."}},"definableWords":["believed"],"peopleInVerse":["Jesus"]}}},"11":{"chapter":"11","title":"THE RAISING OF LAZARUS","verses":{"1":{"text":"Now a certain man was sick, named Lazarus, of Bethany, the town of Mary and her sister Martha.","ref":"John 11:1","synthesized":"At this time a man named Lazarus was sick. He lived in Bethany, the village of Mary and her sister Martha.","sources":{"KJV":{"text":"Now a certain man was sick, named Lazarus, of Bethany, the town of Mary and her sister Martha."},"BSB":{"text":"At this time a man named Lazarus was sick. He lived in Bethany, the village of Mary and her sister Martha."}},"definableWords":["man","sister"],"peopleInVerse":["Mary"]},"2":{"text":"(It was that Mary which anointed the Lord with ointment, and wiped his feet with her hair, whose brother Lazarus was sick.)","ref":"John 11:2","synthesized":"(Mary, whose brother Lazarus was sick, was to anoint the Lord with perfume and wipe His feet with her hair.)","sources":{"KJV":{"text":"(It was that Mary which anointed the Lord with ointment, and wiped his feet with her hair, whose brother Lazarus was sick.)"},"BSB":{"text":"(Mary, whose brother Lazarus was sick, was to anoint the Lord with perfume and wipe His feet with her hair.)"}},"definableWords":["brother","anoint","Lord"],"peopleInVerse":["Mary"]},"3":{"text":"Therefore his sisters sent unto him, saying, Lord, behold, he whom thou lovest is sick.","ref":"John 11:3","synthesized":"So the sisters sent word to Jesus, “Lord, the one You love is sick.”","sources":{"KJV":{"text":"Therefore his sisters sent unto him, saying, Lord, behold, he whom thou lovest is sick."},"BSB":{"text":"So the sisters sent word to Jesus, “Lord, the one You love is sick.”"}},"definableWords":["word","Lord","one","love"],"peopleInVerse":["Jesus"]},"4":{"text":"When Jesus heard that, he said, This sickness is not unto death, but for the glory of God, that the Son of God might be glorified thereby.","ref":"John 11:4","synthesized":"When Jesus heard this, He said, “This sickness will not end in death. No, it is for the glory of God, so that the Son of God may be glorified through it.”","sources":{"KJV":{"text":"When Jesus heard that, he said, This sickness is not unto death, but for the glory of God, that the Son of God might be glorified thereby."},"BSB":{"text":"When Jesus heard this, He said, “This sickness will not end in death. No, it is for the glory of God, so that the Son of God may be glorified through it.”"}},"definableWords":["death","glory","God","Son"],"peopleInVerse":["Jesus"]},"5":{"text":"Now Jesus loved Martha, and her sister, and Lazarus.","ref":"John 11:5","synthesized":"Now Jesus loved Martha and her sister and Lazarus.","sources":{"KJV":{"text":"Now Jesus loved Martha, and her sister, and Lazarus."},"BSB":{"text":"Now Jesus loved Martha and her sister and Lazarus."}},"definableWords":["sister"],"peopleInVerse":["Jesus"]},"6":{"text":"When he had heard therefore that he was sick, he abode two days still in the same place where he was.","ref":"John 11:6","synthesized":"So on hearing that Lazarus was sick, He stayed where He was for two days,","sources":{"KJV":{"text":"When he had heard therefore that he was sick, he abode two days still in the same place where he was."},"BSB":{"text":"So on hearing that Lazarus was sick, He stayed where He was for two days,"}},"definableWords":["days"],"peopleInVerse":[]},"7":{"text":"Then after that saith he to his disciples, Let us go into Judaea again.","ref":"John 11:7","synthesized":"and then He said to the disciples, “Let us go back to Judea.”","sources":{"KJV":{"text":"Then after that saith he to his disciples, Let us go into Judaea again."},"BSB":{"text":"and then He said to the disciples, “Let us go back to Judea.”"}},"definableWords":["Judea"],"peopleInVerse":[]},"8":{"text":"His disciples say unto him, Master, the Jews of late sought to stone thee; and goest thou thither again?","ref":"John 11:8","synthesized":"“Rabbi,” they replied, “the Jews just tried to stone You, and You are going back there?”","sources":{"KJV":{"text":"His disciples say unto him, Master, the Jews of late sought to stone thee; and goest thou thither again?"},"BSB":{"text":"“Rabbi,” they replied, “the Jews just tried to stone You, and You are going back there?”"}},"definableWords":["stone"],"peopleInVerse":[]},"9":{"text":"Jesus answered, Are there not twelve hours in the day? If any man walk in the day, he stumbleth not, because he seeth the light of this world.","ref":"John 11:9","synthesized":"Jesus answered, “Are there not twelve hours of daylight? If anyone walks in the daytime, he will not stumble, because he sees by the light of this world.","sources":{"KJV":{"text":"Jesus answered, Are there not twelve hours in the day? If any man walk in the day, he stumbleth not, because he seeth the light of this world."},"BSB":{"text":"Jesus answered, “Are there not twelve hours of daylight? If anyone walks in the daytime, he will not stumble, because he sees by the light of this world."}},"definableWords":["light"],"peopleInVerse":["Jesus"]},"10":{"text":"But if a man walk in the night, he stumbleth, because there is no light in him.","ref":"John 11:10","synthesized":"But if anyone walks at night, he will stumble, because he has no light.”","sources":{"KJV":{"text":"But if a man walk in the night, he stumbleth, because there is no light in him."},"BSB":{"text":"But if anyone walks at night, he will stumble, because he has no light.”"}},"definableWords":["night","light"],"peopleInVerse":[]},"11":{"text":"These things said he: and after that he saith unto them, Our friend Lazarus sleepeth; but I go, that I may awake him out of sleep.","ref":"John 11:11","synthesized":"After He had said this, He told them, “Our friend Lazarus has fallen asleep, but I am going there to wake him up.”","sources":{"KJV":{"text":"These things said he: and after that he saith unto them, Our friend Lazarus sleepeth; but I go, that I may awake him out of sleep."},"BSB":{"text":"After He had said this, He told them, “Our friend Lazarus has fallen asleep, but I am going there to wake him up.”"}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"Then said his disciples, Lord, if he sleep, he shall do well.","ref":"John 11:12","synthesized":"His disciples replied, “Lord, if he is sleeping, he will get better.”","sources":{"KJV":{"text":"Then said his disciples, Lord, if he sleep, he shall do well."},"BSB":{"text":"His disciples replied, “Lord, if he is sleeping, he will get better.”"}},"definableWords":["Lord"],"peopleInVerse":[]},"13":{"text":"Howbeit Jesus spake of his death: but they thought that he had spoken of taking of rest in sleep.","ref":"John 11:13","synthesized":"They thought that Jesus was talking about actual sleep, but He was speaking about the death of Lazarus.","sources":{"KJV":{"text":"Howbeit Jesus spake of his death: but they thought that he had spoken of taking of rest in sleep."},"BSB":{"text":"They thought that Jesus was talking about actual sleep, but He was speaking about the death of Lazarus."}},"definableWords":["death"],"peopleInVerse":["Jesus"]},"14":{"text":"Then said Jesus unto them plainly, Lazarus is dead.","ref":"John 11:14","synthesized":"So Jesus told them plainly, “Lazarus is dead,","sources":{"KJV":{"text":"Then said Jesus unto them plainly, Lazarus is dead."},"BSB":{"text":"So Jesus told them plainly, “Lazarus is dead,"}},"definableWords":[],"peopleInVerse":["Jesus"]},"15":{"text":"And I am glad for your sakes that I was not there, to the intent ye may believe; nevertheless let us go unto him.","ref":"John 11:15","synthesized":"and for your sake I am glad I was not there, so that you may believe. But let us go to him.”","sources":{"KJV":{"text":"And I am glad for your sakes that I was not there, to the intent ye may believe; nevertheless let us go unto him."},"BSB":{"text":"and for your sake I am glad I was not there, so that you may believe. But let us go to him.”"}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"Then said Thomas, which is called Didymus, unto his fellowdisciples, Let us also go, that we may die with him.","ref":"John 11:16","synthesized":"Then Thomas called Didymus said to his fellow disciples, “Let us also go, so that we may die with Him.”","sources":{"KJV":{"text":"Then said Thomas, which is called Didymus, unto his fellowdisciples, Let us also go, that we may die with him."},"BSB":{"text":"Then Thomas called Didymus said to his fellow disciples, “Let us also go, so that we may die with Him.”"}},"definableWords":["die"],"peopleInVerse":[]},"17":{"text":"Then when Jesus came, he found that he had lain in the grave four days already.","ref":"John 11:17","synthesized":"When Jesus arrived, He found that Lazarus had already spent four days in the tomb.","sources":{"KJV":{"text":"Then when Jesus came, he found that he had lain in the grave four days already."},"BSB":{"text":"When Jesus arrived, He found that Lazarus had already spent four days in the tomb."}},"definableWords":["days"],"peopleInVerse":["Jesus"]},"18":{"text":"Now Bethany was nigh unto Jerusalem, about fifteen furlongs off:","ref":"John 11:18","synthesized":"Now Bethany was near Jerusalem, a little less than two miles away,","sources":{"KJV":{"text":"Now Bethany was nigh unto Jerusalem, about fifteen furlongs off:"},"BSB":{"text":"Now Bethany was near Jerusalem, a little less than two miles away,"}},"definableWords":["Jerusalem"],"peopleInVerse":[]},"19":{"text":"And many of the Jews came to Martha and Mary, to comfort them concerning their brother.","ref":"John 11:19","synthesized":"and many of the Jews had come to Martha and Mary to console them in the loss of their brother.","sources":{"KJV":{"text":"And many of the Jews came to Martha and Mary, to comfort them concerning their brother."},"BSB":{"text":"and many of the Jews had come to Martha and Mary to console them in the loss of their brother."}},"definableWords":["brother"],"peopleInVerse":["Mary"]},"20":{"text":"Then Martha, as soon as she heard that Jesus was coming, went and met him: but Mary sat still in the house.","ref":"John 11:20","synthesized":"So when Martha heard that Jesus was coming, she went out to meet Him; but Mary stayed at home.","sources":{"KJV":{"text":"Then Martha, as soon as she heard that Jesus was coming, went and met him: but Mary sat still in the house."},"BSB":{"text":"So when Martha heard that Jesus was coming, she went out to meet Him; but Mary stayed at home."}},"definableWords":[],"peopleInVerse":["Jesus","Mary"]},"21":{"text":"Then said Martha unto Jesus, Lord, if thou hadst been here, my brother had not died.","ref":"John 11:21","synthesized":"Martha said to Jesus, “Lord, if You had been here, my brother would not have died.","sources":{"KJV":{"text":"Then said Martha unto Jesus, Lord, if thou hadst been here, my brother had not died."},"BSB":{"text":"Martha said to Jesus, “Lord, if You had been here, my brother would not have died."}},"definableWords":["Lord","brother"],"peopleInVerse":["Jesus"]},"22":{"text":"But I know, that even now, whatsoever thou wilt ask of God, God will give it thee.","ref":"John 11:22","synthesized":"But even now I know that God will give You whatever You ask of Him.”","sources":{"KJV":{"text":"But I know, that even now, whatsoever thou wilt ask of God, God will give it thee."},"BSB":{"text":"But even now I know that God will give You whatever You ask of Him.”"}},"definableWords":["God"],"peopleInVerse":[]},"23":{"text":"Jesus saith unto her, Thy brother shall rise again.","ref":"John 11:23","synthesized":"“Your brother will rise again,” Jesus told her.","sources":{"KJV":{"text":"Jesus saith unto her, Thy brother shall rise again."},"BSB":{"text":"“Your brother will rise again,” Jesus told her."}},"definableWords":["brother"],"peopleInVerse":["Jesus"]},"24":{"text":"Martha saith unto him, I know that he shall rise again in the resurrection at the last day.","ref":"John 11:24","synthesized":"Martha replied, “I know that he will rise again in the resurrection at the last day.”","sources":{"KJV":{"text":"Martha saith unto him, I know that he shall rise again in the resurrection at the last day."},"BSB":{"text":"Martha replied, “I know that he will rise again in the resurrection at the last day.”"}},"definableWords":["resurrection","day"],"peopleInVerse":[]},"25":{"text":"Jesus said unto her, I am the resurrection, and the life: he that believeth in me, though he were dead, yet shall he live:","ref":"John 11:25","synthesized":"Jesus said to her, “I am the resurrection and the life. Whoever believes in Me will live, even though he dies.","sources":{"KJV":{"text":"Jesus said unto her, I am the resurrection, and the life: he that believeth in me, though he were dead, yet shall he live:"},"BSB":{"text":"Jesus said to her, “I am the resurrection and the life. Whoever believes in Me will live, even though he dies."}},"definableWords":["resurrection","life","live"],"peopleInVerse":["Jesus"]},"26":{"text":"And whosoever liveth and believeth in me shall never die. Believest thou this?","ref":"John 11:26","synthesized":"And everyone who lives and believes in Me will never die. Do you believe this?”","sources":{"KJV":{"text":"And whosoever liveth and believeth in me shall never die. Believest thou this?"},"BSB":{"text":"And everyone who lives and believes in Me will never die. Do you believe this?”"}},"definableWords":["die"],"peopleInVerse":[]},"27":{"text":"She saith unto him, Yea, Lord: I believe that thou art the Christ, the Son of God, which should come into the world.","ref":"John 11:27","synthesized":"“Yes, Lord,” she answered, “I believe that You are the Christ, the Son of God, who was to come into the world.”","sources":{"KJV":{"text":"She saith unto him, Yea, Lord: I believe that thou art the Christ, the Son of God, which should come into the world."},"BSB":{"text":"“Yes, Lord,” she answered, “I believe that You are the Christ, the Son of God, who was to come into the world.”"}},"definableWords":["Lord","Christ","Son","God"],"peopleInVerse":[]},"28":{"text":"And when she had so said, she went her way, and called Mary her sister secretly, saying, The Master is come, and calleth for thee.","ref":"John 11:28","synthesized":"After Martha had said this, she went back and called her sister Mary aside to tell her, “The Teacher is here and is asking for you.”","sources":{"KJV":{"text":"And when she had so said, she went her way, and called Mary her sister secretly, saying, The Master is come, and calleth for thee."},"BSB":{"text":"After Martha had said this, she went back and called her sister Mary aside to tell her, “The Teacher is here and is asking for you.”"}},"definableWords":["sister"],"peopleInVerse":["Mary"]},"29":{"text":"As soon as she heard that, she arose quickly, and came unto him.","ref":"John 11:29","synthesized":"And when Mary heard this, she got up quickly and went to Him.","sources":{"KJV":{"text":"As soon as she heard that, she arose quickly, and came unto him."},"BSB":{"text":"And when Mary heard this, she got up quickly and went to Him."}},"definableWords":[],"peopleInVerse":["Mary"]},"30":{"text":"Now Jesus was not yet come into the town, but was in that place where Martha met him.","ref":"John 11:30","synthesized":"Now Jesus had not yet entered the village, but was still at the place where Martha had met Him.","sources":{"KJV":{"text":"Now Jesus was not yet come into the town, but was in that place where Martha met him."},"BSB":{"text":"Now Jesus had not yet entered the village, but was still at the place where Martha had met Him."}},"definableWords":[],"peopleInVerse":["Jesus"]},"31":{"text":"The Jews then which were with her in the house, and comforted her, when they saw Mary, that she rose up hastily and went out, followed her, saying, She goeth unto the grave to weep there.","ref":"John 11:31","synthesized":"When the Jews who were in the house consoling Mary saw how quickly she got up and went out, they followed her, supposing she was going to the tomb to mourn there.","sources":{"KJV":{"text":"The Jews then which were with her in the house, and comforted her, when they saw Mary, that she rose up hastily and went out, followed her, saying, She goeth unto the grave to weep there."},"BSB":{"text":"When the Jews who were in the house consoling Mary saw how quickly she got up and went out, they followed her, supposing she was going to the tomb to mourn there."}},"definableWords":["house","saw"],"peopleInVerse":["Mary"]},"32":{"text":"Then when Mary was come where Jesus was, and saw him, she fell down at his feet, saying unto him, Lord, if thou hadst been here, my brother had not died.","ref":"John 11:32","synthesized":"When Mary came to Jesus and saw Him, she fell at His feet and said, “Lord, if You had been here, my brother would not have died.”","sources":{"KJV":{"text":"Then when Mary was come where Jesus was, and saw him, she fell down at his feet, saying unto him, Lord, if thou hadst been here, my brother had not died."},"BSB":{"text":"When Mary came to Jesus and saw Him, she fell at His feet and said, “Lord, if You had been here, my brother would not have died.”"}},"definableWords":["saw","Lord","brother"],"peopleInVerse":["Mary","Jesus"]},"33":{"text":"When Jesus therefore saw her weeping, and the Jews also weeping which came with her, he groaned in the spirit, and was troubled,","ref":"John 11:33","synthesized":"When Jesus saw her weeping, and the Jews who had come with her also weeping, He was deeply moved in spirit and troubled.","sources":{"KJV":{"text":"When Jesus therefore saw her weeping, and the Jews also weeping which came with her, he groaned in the spirit, and was troubled,"},"BSB":{"text":"When Jesus saw her weeping, and the Jews who had come with her also weeping, He was deeply moved in spirit and troubled."}},"definableWords":["saw","spirit"],"peopleInVerse":["Jesus"]},"34":{"text":"And said, Where have ye laid him? They said unto him, Lord, come and see.","ref":"John 11:34","synthesized":"“Where have you put him?” He asked.  “Come and see, Lord,” they answered.","sources":{"KJV":{"text":"And said, Where have ye laid him? They said unto him, Lord, come and see."},"BSB":{"text":"“Where have you put him?” He asked.  “Come and see, Lord,” they answered."}},"definableWords":["see","Lord"],"peopleInVerse":[]},"35":{"text":"Jesus wept.","ref":"John 11:35","synthesized":"Jesus wept.","sources":{"KJV":{"text":"Jesus wept."},"BSB":{"text":"Jesus wept."}},"definableWords":[],"peopleInVerse":["Jesus"]},"36":{"text":"Then said the Jews, Behold how he loved him!","ref":"John 11:36","synthesized":"Then the Jews said, “See how He loved him!”","sources":{"KJV":{"text":"Then said the Jews, Behold how he loved him!"},"BSB":{"text":"Then the Jews said, “See how He loved him!”"}},"definableWords":["see"],"peopleInVerse":[]},"37":{"text":"And some of them said, Could not this man, which opened the eyes of the blind, have caused that even this man should not have died?","ref":"John 11:37","synthesized":"But some of them asked, “Could not this man who opened the eyes of the blind also have kept Lazarus from dying?”","sources":{"KJV":{"text":"And some of them said, Could not this man, which opened the eyes of the blind, have caused that even this man should not have died?"},"BSB":{"text":"But some of them asked, “Could not this man who opened the eyes of the blind also have kept Lazarus from dying?”"}},"definableWords":["man"],"peopleInVerse":[]},"38":{"text":"Jesus therefore again groaning in himself cometh to the grave. It was a cave, and a stone lay upon it.","ref":"John 11:38","synthesized":"Jesus, once again deeply moved, came to the tomb. It was a cave with a stone laid across the entrance.","sources":{"KJV":{"text":"Jesus therefore again groaning in himself cometh to the grave. It was a cave, and a stone lay upon it."},"BSB":{"text":"Jesus, once again deeply moved, came to the tomb. It was a cave with a stone laid across the entrance."}},"definableWords":["stone"],"peopleInVerse":["Jesus"]},"39":{"text":"Jesus said, Take ye away the stone. Martha, the sister of him that was dead, saith unto him, Lord, by this time he stinketh: for he hath been dead four days.","ref":"John 11:39","synthesized":"“Take away the stone,” Jesus said.  “Lord, by now he stinks,” said Martha, the sister of the dead man. “It has already been four days.”","sources":{"KJV":{"text":"Jesus said, Take ye away the stone. Martha, the sister of him that was dead, saith unto him, Lord, by this time he stinketh: for he hath been dead four days."},"BSB":{"text":"“Take away the stone,” Jesus said.  “Lord, by now he stinks,” said Martha, the sister of the dead man. “It has already been four days.”"}},"definableWords":["stone","Lord","sister","man","days"],"peopleInVerse":["Jesus"]},"40":{"text":"Jesus saith unto her, Said I not unto thee, that, if thou wouldest believe, thou shouldest see the glory of God?","ref":"John 11:40","synthesized":"Jesus replied, “Did I not tell you that if you believed, you would see the glory of God?”","sources":{"KJV":{"text":"Jesus saith unto her, Said I not unto thee, that, if thou wouldest believe, thou shouldest see the glory of God?"},"BSB":{"text":"Jesus replied, “Did I not tell you that if you believed, you would see the glory of God?”"}},"definableWords":["believed","see","glory","God"],"peopleInVerse":["Jesus"]},"41":{"text":"Then they took away the stone from the place where the dead was laid. And Jesus lifted up his eyes, and said, Father, I thank thee that thou hast heard me.","ref":"John 11:41","synthesized":"So they took away the stone. Then Jesus lifted His eyes upward and said, “Father, I thank You that You have heard Me.","sources":{"KJV":{"text":"Then they took away the stone from the place where the dead was laid. And Jesus lifted up his eyes, and said, Father, I thank thee that thou hast heard me."},"BSB":{"text":"So they took away the stone. Then Jesus lifted His eyes upward and said, “Father, I thank You that You have heard Me."}},"definableWords":["stone","Father"],"peopleInVerse":["Jesus"]},"42":{"text":"And I knew that thou hearest me always: but because of the people which stand by I said it, that they may believe that thou hast sent me.","ref":"John 11:42","synthesized":"I knew that You always hear Me, but I say this for the benefit of the people standing here, so they may believe that You sent Me.”","sources":{"KJV":{"text":"And I knew that thou hearest me always: but because of the people which stand by I said it, that they may believe that thou hast sent me."},"BSB":{"text":"I knew that You always hear Me, but I say this for the benefit of the people standing here, so they may believe that You sent Me.”"}},"definableWords":["hear","people"],"peopleInVerse":[]},"43":{"text":"And when he thus had spoken, he cried with a loud voice, Lazarus, come forth.","ref":"John 11:43","synthesized":"After Jesus had said this, He called out in a loud voice, “Lazarus, come out!”","sources":{"KJV":{"text":"And when he thus had spoken, he cried with a loud voice, Lazarus, come forth."},"BSB":{"text":"After Jesus had said this, He called out in a loud voice, “Lazarus, come out!”"}},"definableWords":["voice"],"peopleInVerse":["Jesus"]},"44":{"text":"And he that was dead came forth, bound hand and foot with graveclothes: and his face was bound about with a napkin. Jesus saith unto them, Loose him, and let him go.","ref":"John 11:44","synthesized":"The man who had been dead came out with his hands and feet bound in strips of linen, and his face wrapped in a cloth.  “Unwrap him and let him go,” Jesus told them.","sources":{"KJV":{"text":"And he that was dead came forth, bound hand and foot with graveclothes: and his face was bound about with a napkin. Jesus saith unto them, Loose him, and let him go."},"BSB":{"text":"The man who had been dead came out with his hands and feet bound in strips of linen, and his face wrapped in a cloth.  “Unwrap him and let him go,” Jesus told them."}},"definableWords":["man"],"peopleInVerse":["Jesus"]},"45":{"text":"Then many of the Jews which came to Mary, and had seen the things which Jesus did, believed on him.","ref":"John 11:45","synthesized":"Therefore many of the Jews who had come to Mary, and had seen what Jesus did, believed in Him.","sources":{"KJV":{"text":"Then many of the Jews which came to Mary, and had seen the things which Jesus did, believed on him."},"BSB":{"text":"Therefore many of the Jews who had come to Mary, and had seen what Jesus did, believed in Him."}},"definableWords":["believed"],"peopleInVerse":["Mary","Jesus"]},"46":{"text":"But some of them went their ways to the Pharisees, and told them what things Jesus had done.","ref":"John 11:46","synthesized":"But some of them went to the Pharisees and told them what Jesus had done.","sources":{"KJV":{"text":"But some of them went their ways to the Pharisees, and told them what things Jesus had done."},"BSB":{"text":"But some of them went to the Pharisees and told them what Jesus had done."}},"definableWords":[],"peopleInVerse":["Jesus"]},"47":{"text":"Then gathered the chief priests and the Pharisees a council, and said, What do we? for this man doeth many miracles.","ref":"John 11:47","synthesized":"Then the chief priests and Pharisees convened the Sanhedrin and said, “What are we to do? This man is performing many signs.","sources":{"KJV":{"text":"Then gathered the chief priests and the Pharisees a council, and said, What do we? for this man doeth many miracles."},"BSB":{"text":"Then the chief priests and Pharisees convened the Sanhedrin and said, “What are we to do? This man is performing many signs."}},"definableWords":["man"],"peopleInVerse":[]},"48":{"text":"If we let him thus alone, all men will believe on him: and the Romans shall come and take away both our place and nation.","ref":"John 11:48","synthesized":"If we let Him go on like this, everyone will believe in Him, and then the Romans will come and take away both our place and our nation.”","sources":{"KJV":{"text":"If we let him thus alone, all men will believe on him: and the Romans shall come and take away both our place and nation."},"BSB":{"text":"If we let Him go on like this, everyone will believe in Him, and then the Romans will come and take away both our place and our nation.”"}},"definableWords":["nation"],"peopleInVerse":[]},"49":{"text":"And one of them, named Caiaphas, being the high priest that same year, said unto them, Ye know nothing at all,","ref":"John 11:49","synthesized":"But one of them, named Caiaphas, who was high priest that year, said to them, “You know nothing at all!","sources":{"KJV":{"text":"And one of them, named Caiaphas, being the high priest that same year, said unto them, Ye know nothing at all,"},"BSB":{"text":"But one of them, named Caiaphas, who was high priest that year, said to them, “You know nothing at all!"}},"definableWords":["one","priest","year"],"peopleInVerse":["Caiaphas"]},"50":{"text":"Nor consider that it is expedient for us, that one man should die for the people, and that the whole nation perish not.","ref":"John 11:50","synthesized":"You do not realize that it is better for you that one man die for the people than that the whole nation perish.”","sources":{"KJV":{"text":"Nor consider that it is expedient for us, that one man should die for the people, and that the whole nation perish not."},"BSB":{"text":"You do not realize that it is better for you that one man die for the people than that the whole nation perish.”"}},"definableWords":["one","man","die","people","nation"],"peopleInVerse":[]},"51":{"text":"And this spake he not of himself: but being high priest that year, he prophesied that Jesus should die for that nation;","ref":"John 11:51","synthesized":"Caiaphas did not say this on his own. Instead, as high priest that year, he was prophesying that Jesus would die for the nation,","sources":{"KJV":{"text":"And this spake he not of himself: but being high priest that year, he prophesied that Jesus should die for that nation;"},"BSB":{"text":"Caiaphas did not say this on his own. Instead, as high priest that year, he was prophesying that Jesus would die for the nation,"}},"definableWords":["priest","year","die","nation"],"peopleInVerse":["Caiaphas","Jesus"]},"52":{"text":"And not for that nation only, but that also he should gather together in one the children of God that were scattered abroad.","ref":"John 11:52","synthesized":"and not only for the nation, but also for the scattered children of God, to gather them together into one.","sources":{"KJV":{"text":"And not for that nation only, but that also he should gather together in one the children of God that were scattered abroad."},"BSB":{"text":"and not only for the nation, but also for the scattered children of God, to gather them together into one."}},"definableWords":["nation","God","one"],"peopleInVerse":[]},"53":{"text":"Then from that day forth they took counsel together for to put him to death.","ref":"John 11:53","synthesized":"So from that day on they plotted to kill Him.","sources":{"KJV":{"text":"Then from that day forth they took counsel together for to put him to death."},"BSB":{"text":"So from that day on they plotted to kill Him."}},"definableWords":["day"],"peopleInVerse":[]},"54":{"text":"Jesus therefore walked no more openly among the Jews; but went thence unto a country near to the wilderness, into a city called Ephraim, and there continued with his disciples.","ref":"John 11:54","synthesized":"As a result, Jesus no longer went about publicly among the Jews, but He withdrew to a town called Ephraim in an area near the wilderness. And He stayed there with the disciples.","sources":{"KJV":{"text":"Jesus therefore walked no more openly among the Jews; but went thence unto a country near to the wilderness, into a city called Ephraim, and there continued with his disciples."},"BSB":{"text":"As a result, Jesus no longer went about publicly among the Jews, but He withdrew to a town called Ephraim in an area near the wilderness. And He stayed there with the disciples."}},"definableWords":[],"peopleInVerse":["Jesus"]},"55":{"text":"And the Jews’ passover was nigh at hand: and many went out of the country up to Jerusalem before the passover, to purify themselves.","ref":"John 11:55","synthesized":"Now the Jewish Passover was near, and many people went up from the country to Jerusalem to purify themselves before the Passover.","sources":{"KJV":{"text":"And the Jews’ passover was nigh at hand: and many went out of the country up to Jerusalem before the passover, to purify themselves."},"BSB":{"text":"Now the Jewish Passover was near, and many people went up from the country to Jerusalem to purify themselves before the Passover."}},"definableWords":["Passover","people","Jerusalem"],"peopleInVerse":[]},"56":{"text":"Then sought they for Jesus, and spake among themselves, as they stood in the temple, What think ye, that he will not come to the feast?","ref":"John 11:56","synthesized":"They kept looking for Jesus and asking one another as they stood in the temple courts, “What do you think? Will He come to the feast at all?”","sources":{"KJV":{"text":"Then sought they for Jesus, and spake among themselves, as they stood in the temple, What think ye, that he will not come to the feast?"},"BSB":{"text":"They kept looking for Jesus and asking one another as they stood in the temple courts, “What do you think? Will He come to the feast at all?”"}},"definableWords":["one","temple"],"peopleInVerse":["Jesus"]},"57":{"text":"Now both the chief priests and the Pharisees had given a commandment, that, if any man knew where he were, he should shew it, that they might take him.","ref":"John 11:57","synthesized":"But the chief priests and Pharisees had given orders that anyone who knew where He was must report it, so that they could arrest Him.","sources":{"KJV":{"text":"Now both the chief priests and the Pharisees had given a commandment, that, if any man knew where he were, he should shew it, that they might take him."},"BSB":{"text":"But the chief priests and Pharisees had given orders that anyone who knew where He was must report it, so that they could arrest Him."}},"definableWords":[],"peopleInVerse":[]}}},"12":{"chapter":"12","title":"MARY ANOINTS JESUS","verses":{"1":{"text":"Then Jesus six days before the passover came to Bethany, where Lazarus was, which had been dead, whom he raised from the dead.","ref":"John 12:1","synthesized":"Six days before the Passover, Jesus came to Bethany, the hometown of Lazarus, whom He had raised from the dead.","sources":{"KJV":{"text":"Then Jesus six days before the passover came to Bethany, where Lazarus was, which had been dead, whom he raised from the dead."},"BSB":{"text":"Six days before the Passover, Jesus came to Bethany, the hometown of Lazarus, whom He had raised from the dead."}},"definableWords":["days","Passover"],"peopleInVerse":["Jesus"]},"2":{"text":"There they made him a supper; and Martha served: but Lazarus was one of them that sat at the table with him.","ref":"John 12:2","synthesized":"So they hosted a dinner for Jesus there. Martha served, and Lazarus was among those reclining at the table with Him.","sources":{"KJV":{"text":"There they made him a supper; and Martha served: but Lazarus was one of them that sat at the table with him."},"BSB":{"text":"So they hosted a dinner for Jesus there. Martha served, and Lazarus was among those reclining at the table with Him."}},"definableWords":[],"peopleInVerse":["Jesus"]},"3":{"text":"Then took Mary a pound of ointment of spikenard, very costly, and anointed the feet of Jesus, and wiped his feet with her hair: and the house was filled with the odour of the ointment.","ref":"John 12:3","synthesized":"Then Mary took about a pint of expensive perfume, made of pure nard, and she anointed Jesus’ feet and wiped them with her hair. And the house was filled with the fragrance of the perfume.","sources":{"KJV":{"text":"Then took Mary a pound of ointment of spikenard, very costly, and anointed the feet of Jesus, and wiped his feet with her hair: and the house was filled with the odour of the ointment."},"BSB":{"text":"Then Mary took about a pint of expensive perfume, made of pure nard, and she anointed Jesus’ feet and wiped them with her hair. And the house was filled with the fragrance of the perfume."}},"definableWords":["made","house"],"peopleInVerse":["Mary","Jesus"]},"4":{"text":"Then saith one of his disciples, Judas Iscariot, Simon’s son, which should betray him,","ref":"John 12:4","synthesized":"But one of His disciples, Judas Iscariot, who was going to betray Him, asked,","sources":{"KJV":{"text":"Then saith one of his disciples, Judas Iscariot, Simon’s son, which should betray him,"},"BSB":{"text":"But one of His disciples, Judas Iscariot, who was going to betray Him, asked,"}},"definableWords":["one"],"peopleInVerse":[]},"5":{"text":"Why was not this ointment sold for three hundred pence, and given to the poor?","ref":"John 12:5","synthesized":"“Why wasn’t this perfume sold for three hundred denarii and the money given to the poor?”","sources":{"KJV":{"text":"Why was not this ointment sold for three hundred pence, and given to the poor?"},"BSB":{"text":"“Why wasn’t this perfume sold for three hundred denarii and the money given to the poor?”"}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"This he said, not that he cared for the poor; but because he was a thief, and had the bag, and bare what was put therein.","ref":"John 12:6","synthesized":"Judas did not say this because he cared about the poor, but because he was a thief. As keeper of the money bag, he used to take from what was put into it.","sources":{"KJV":{"text":"This he said, not that he cared for the poor; but because he was a thief, and had the bag, and bare what was put therein."},"BSB":{"text":"Judas did not say this because he cared about the poor, but because he was a thief. As keeper of the money bag, he used to take from what was put into it."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"Then said Jesus, Let her alone: against the day of my burying hath she kept this.","ref":"John 12:7","synthesized":"“Leave her alone,” Jesus replied. “She has kept this perfume in preparation for the day of My burial.","sources":{"KJV":{"text":"Then said Jesus, Let her alone: against the day of my burying hath she kept this."},"BSB":{"text":"“Leave her alone,” Jesus replied. “She has kept this perfume in preparation for the day of My burial."}},"definableWords":["day"],"peopleInVerse":["Jesus"]},"8":{"text":"For the poor always ye have with you; but me ye have not always.","ref":"John 12:8","synthesized":"The poor you will always have with you, but you will not always have Me.”","sources":{"KJV":{"text":"For the poor always ye have with you; but me ye have not always."},"BSB":{"text":"The poor you will always have with you, but you will not always have Me.”"}},"definableWords":[],"peopleInVerse":[]},"9":{"text":"Much people of the Jews therefore knew that he was there: and they came not for Jesus’ sake only, but that they might see Lazarus also, whom he had raised from the dead.","ref":"John 12:9","synthesized":"Meanwhile a large crowd of Jews learned that Jesus was there. And they came not only because of Him, but also to see Lazarus, whom He had raised from the dead.","sources":{"KJV":{"text":"Much people of the Jews therefore knew that he was there: and they came not for Jesus’ sake only, but that they might see Lazarus also, whom he had raised from the dead."},"BSB":{"text":"Meanwhile a large crowd of Jews learned that Jesus was there. And they came not only because of Him, but also to see Lazarus, whom He had raised from the dead."}},"definableWords":["see"],"peopleInVerse":["Jesus"]},"10":{"text":"But the chief priests consulted that they might put Lazarus also to death;","ref":"John 12:10","synthesized":"So the chief priests made plans to kill Lazarus as well,","sources":{"KJV":{"text":"But the chief priests consulted that they might put Lazarus also to death;"},"BSB":{"text":"So the chief priests made plans to kill Lazarus as well,"}},"definableWords":["made"],"peopleInVerse":[]},"11":{"text":"Because that by reason of him many of the Jews went away, and believed on Jesus.","ref":"John 12:11","synthesized":"for on account of him many of the Jews were deserting them and believing in Jesus.","sources":{"KJV":{"text":"Because that by reason of him many of the Jews went away, and believed on Jesus."},"BSB":{"text":"for on account of him many of the Jews were deserting them and believing in Jesus."}},"definableWords":[],"peopleInVerse":["Jesus"]},"12":{"text":"On the next day much people that were come to the feast, when they heard that Jesus was coming to Jerusalem,","ref":"John 12:12","synthesized":"The next day the great crowd that had come to the feast heard that Jesus was coming to Jerusalem.","sources":{"KJV":{"text":"On the next day much people that were come to the feast, when they heard that Jesus was coming to Jerusalem,"},"BSB":{"text":"The next day the great crowd that had come to the feast heard that Jesus was coming to Jerusalem."}},"definableWords":["day","great","Jerusalem"],"peopleInVerse":["Jesus"]},"13":{"text":"Took branches of palm trees, and went forth to meet him, and cried, Hosanna: Blessed is the King of Israel that cometh in the name of the Lord.","ref":"John 12:13","synthesized":"They took palm branches and went out to meet Him, shouting:  “Hosanna!”   “Blessed is He who comes in the name of the Lord!”   “Blessed is the King of Israel!”","sources":{"KJV":{"text":"Took branches of palm trees, and went forth to meet him, and cried, Hosanna: Blessed is the King of Israel that cometh in the name of the Lord."},"BSB":{"text":"They took palm branches and went out to meet Him, shouting:  “Hosanna!”   “Blessed is He who comes in the name of the Lord!”   “Blessed is the King of Israel!”"}},"definableWords":["blessed","name","Lord","King","Israel"],"peopleInVerse":[]},"14":{"text":"And Jesus, when he had found a young ass, sat thereon; as it is written,","ref":"John 12:14","synthesized":"Finding a young donkey, Jesus sat on it, as it is written:","sources":{"KJV":{"text":"And Jesus, when he had found a young ass, sat thereon; as it is written,"},"BSB":{"text":"Finding a young donkey, Jesus sat on it, as it is written:"}},"definableWords":[],"peopleInVerse":["Jesus"]},"15":{"text":"Fear not, daughter of Sion: behold, thy King cometh, sitting on an ass’s colt.","ref":"John 12:15","synthesized":"“Do not be afraid, O Daughter of Zion. See, your King is coming, seated on the colt of a donkey.”","sources":{"KJV":{"text":"Fear not, daughter of Sion: behold, thy King cometh, sitting on an ass’s colt."},"BSB":{"text":"“Do not be afraid, O Daughter of Zion. See, your King is coming, seated on the colt of a donkey.”"}},"definableWords":["daughter","Zion","see","King"],"peopleInVerse":[]},"16":{"text":"These things understood not his disciples at the first: but when Jesus was glorified, then remembered they that these things were written of him, and that they had done these things unto him.","ref":"John 12:16","synthesized":"At first His disciples did not understand these things, but after Jesus was glorified they remembered what had been done to Him, and they realized that these very things had also been written about Him.","sources":{"KJV":{"text":"These things understood not his disciples at the first: but when Jesus was glorified, then remembered they that these things were written of him, and that they had done these things unto him."},"BSB":{"text":"At first His disciples did not understand these things, but after Jesus was glorified they remembered what had been done to Him, and they realized that these very things had also been written about Him."}},"definableWords":["remembered"],"peopleInVerse":["Jesus"]},"17":{"text":"The people therefore that was with him when he called Lazarus out of his grave, and raised him from the dead, bare record.","ref":"John 12:17","synthesized":"Meanwhile, many people continued to testify that they had been with Jesus when He called Lazarus from the tomb and raised him from the dead.","sources":{"KJV":{"text":"The people therefore that was with him when he called Lazarus out of his grave, and raised him from the dead, bare record."},"BSB":{"text":"Meanwhile, many people continued to testify that they had been with Jesus when He called Lazarus from the tomb and raised him from the dead."}},"definableWords":["people"],"peopleInVerse":["Jesus"]},"18":{"text":"For this cause the people also met him, for that they heard that he had done this miracle.","ref":"John 12:18","synthesized":"That is also why the crowd went out to meet Him, because they heard that He had performed this sign.","sources":{"KJV":{"text":"For this cause the people also met him, for that they heard that he had done this miracle."},"BSB":{"text":"That is also why the crowd went out to meet Him, because they heard that He had performed this sign."}},"definableWords":[],"peopleInVerse":[]},"19":{"text":"The Pharisees therefore said among themselves, Perceive ye how ye prevail nothing? behold, the world is gone after him.","ref":"John 12:19","synthesized":"Then the Pharisees said to one another, “You can see that this is doing you no good. Look how the whole world has gone after Him!”","sources":{"KJV":{"text":"The Pharisees therefore said among themselves, Perceive ye how ye prevail nothing? behold, the world is gone after him."},"BSB":{"text":"Then the Pharisees said to one another, “You can see that this is doing you no good. Look how the whole world has gone after Him!”"}},"definableWords":["one","see","good"],"peopleInVerse":[]},"20":{"text":"And there were certain Greeks among them that came up to worship at the feast:","ref":"John 12:20","synthesized":"Now there were some Greeks among those who went up to worship at the feast.","sources":{"KJV":{"text":"And there were certain Greeks among them that came up to worship at the feast:"},"BSB":{"text":"Now there were some Greeks among those who went up to worship at the feast."}},"definableWords":["worship"],"peopleInVerse":[]},"21":{"text":"The same came therefore to Philip, which was of Bethsaida of Galilee, and desired him, saying, Sir, we would see Jesus.","ref":"John 12:21","synthesized":"They came to Philip, who was from Bethsaida in Galilee, and requested of him, “Sir, we want to see Jesus.”","sources":{"KJV":{"text":"The same came therefore to Philip, which was of Bethsaida of Galilee, and desired him, saying, Sir, we would see Jesus."},"BSB":{"text":"They came to Philip, who was from Bethsaida in Galilee, and requested of him, “Sir, we want to see Jesus.”"}},"definableWords":["Galilee","see"],"peopleInVerse":["Jesus"]},"22":{"text":"Philip cometh and telleth Andrew: and again Andrew and Philip tell Jesus.","ref":"John 12:22","synthesized":"Philip relayed this appeal to Andrew, and both of them went and told Jesus.","sources":{"KJV":{"text":"Philip cometh and telleth Andrew: and again Andrew and Philip tell Jesus."},"BSB":{"text":"Philip relayed this appeal to Andrew, and both of them went and told Jesus."}},"definableWords":[],"peopleInVerse":["Andrew","Jesus"]},"23":{"text":"And Jesus answered them, saying, The hour is come, that the Son of man should be glorified.","ref":"John 12:23","synthesized":"But Jesus replied, “The hour has come for the Son of Man to be glorified.","sources":{"KJV":{"text":"And Jesus answered them, saying, The hour is come, that the Son of man should be glorified."},"BSB":{"text":"But Jesus replied, “The hour has come for the Son of Man to be glorified."}},"definableWords":["Son","man"],"peopleInVerse":["Jesus"]},"24":{"text":"Verily, verily, I say unto you, Except a corn of wheat fall into the ground and die, it abideth alone: but if it die, it bringeth forth much fruit.","ref":"John 12:24","synthesized":"Truly, truly, I tell you, unless a kernel of wheat falls to the ground and dies, it remains only a seed; but if it dies, it bears much fruit.","sources":{"KJV":{"text":"Verily, verily, I say unto you, Except a corn of wheat fall into the ground and die, it abideth alone: but if it die, it bringeth forth much fruit."},"BSB":{"text":"Truly, truly, I tell you, unless a kernel of wheat falls to the ground and dies, it remains only a seed; but if it dies, it bears much fruit."}},"definableWords":["ground","seed"],"peopleInVerse":[]},"25":{"text":"He that loveth his life shall lose it; and he that hateth his life in this world shall keep it unto life eternal.","ref":"John 12:25","synthesized":"Whoever loves his life will lose it, but whoever hates his life in this world will keep it for eternal life.","sources":{"KJV":{"text":"He that loveth his life shall lose it; and he that hateth his life in this world shall keep it unto life eternal."},"BSB":{"text":"Whoever loves his life will lose it, but whoever hates his life in this world will keep it for eternal life."}},"definableWords":["life","keep","eternal"],"peopleInVerse":[]},"26":{"text":"If any man serve me, let him follow me; and where I am, there shall also my servant be: if any man serve me, him will my Father honour.","ref":"John 12:26","synthesized":"If anyone serves Me, he must follow Me; and where I am, My servant will be as well. If anyone serves Me, the Father will honor him.","sources":{"KJV":{"text":"If any man serve me, let him follow me; and where I am, there shall also my servant be: if any man serve me, him will my Father honour."},"BSB":{"text":"If anyone serves Me, he must follow Me; and where I am, My servant will be as well. If anyone serves Me, the Father will honor him."}},"definableWords":["servant","Father"],"peopleInVerse":[]},"27":{"text":"Now is my soul troubled; and what shall I say? Father, save me from this hour: but for this cause came I unto this hour.","ref":"John 12:27","synthesized":"Now My soul is troubled, and what shall I say? ‘Father, save Me from this hour’? No, it is for this purpose that I have come to this hour.","sources":{"KJV":{"text":"Now is my soul troubled; and what shall I say? Father, save me from this hour: but for this cause came I unto this hour."},"BSB":{"text":"Now My soul is troubled, and what shall I say? ‘Father, save Me from this hour’? No, it is for this purpose that I have come to this hour."}},"definableWords":["soul","Father"],"peopleInVerse":[]},"28":{"text":"Father, glorify thy name. Then came there a voice from heaven, saying, I have both glorified it, and will glorify it again.","ref":"John 12:28","synthesized":"Father, glorify Your name!”  Then a voice came from heaven: “I have glorified it, and I will glorify it again.”","sources":{"KJV":{"text":"Father, glorify thy name. Then came there a voice from heaven, saying, I have both glorified it, and will glorify it again."},"BSB":{"text":"Father, glorify Your name!”  Then a voice came from heaven: “I have glorified it, and I will glorify it again.”"}},"definableWords":["Father","name","voice","heaven"],"peopleInVerse":[]},"29":{"text":"The people therefore, that stood by, and heard it, said that it thundered: others said, An angel spake to him.","ref":"John 12:29","synthesized":"The crowd standing there heard it and said that it had thundered. Others said that an angel had spoken to Him.","sources":{"KJV":{"text":"The people therefore, that stood by, and heard it, said that it thundered: others said, An angel spake to him."},"BSB":{"text":"The crowd standing there heard it and said that it had thundered. Others said that an angel had spoken to Him."}},"definableWords":["angel"],"peopleInVerse":[]},"30":{"text":"Jesus answered and said, This voice came not because of me, but for your sakes.","ref":"John 12:30","synthesized":"In response, Jesus said, “This voice was not for My benefit, but yours.","sources":{"KJV":{"text":"Jesus answered and said, This voice came not because of me, but for your sakes."},"BSB":{"text":"In response, Jesus said, “This voice was not for My benefit, but yours."}},"definableWords":["voice"],"peopleInVerse":["Jesus"]},"31":{"text":"Now is the judgment of this world: now shall the prince of this world be cast out.","ref":"John 12:31","synthesized":"Now judgment is upon this world; now the prince of this world will be cast out.","sources":{"KJV":{"text":"Now is the judgment of this world: now shall the prince of this world be cast out."},"BSB":{"text":"Now judgment is upon this world; now the prince of this world will be cast out."}},"definableWords":["judgment","prince"],"peopleInVerse":[]},"32":{"text":"And I, if I be lifted up from the earth, will draw all men unto me.","ref":"John 12:32","synthesized":"And I, when I am lifted up from the earth, will draw everyone to Myself.”","sources":{"KJV":{"text":"And I, if I be lifted up from the earth, will draw all men unto me."},"BSB":{"text":"And I, when I am lifted up from the earth, will draw everyone to Myself.”"}},"definableWords":["earth"],"peopleInVerse":[]},"33":{"text":"This he said, signifying what death he should die.","ref":"John 12:33","synthesized":"He said this to indicate the kind of death He was going to die.","sources":{"KJV":{"text":"This he said, signifying what death he should die."},"BSB":{"text":"He said this to indicate the kind of death He was going to die."}},"definableWords":["death","die"],"peopleInVerse":[]},"34":{"text":"The people answered him, We have heard out of the law that Christ abideth for ever: and how sayest thou, The Son of man must be lifted up? who is this Son of man?","ref":"John 12:34","synthesized":"The crowd replied, “We have heard from the Law that the Christ will remain forever. So how can You say that the Son of Man must be lifted up? Who is this Son of Man?”","sources":{"KJV":{"text":"The people answered him, We have heard out of the law that Christ abideth for ever: and how sayest thou, The Son of man must be lifted up? who is this Son of man?"},"BSB":{"text":"The crowd replied, “We have heard from the Law that the Christ will remain forever. So how can You say that the Son of Man must be lifted up? Who is this Son of Man?”"}},"definableWords":["law","Christ","Son","man"],"peopleInVerse":[]},"35":{"text":"Then Jesus said unto them, Yet a little while is the light with you. Walk while ye have the light, lest darkness come upon you: for he that walketh in darkness knoweth not whither he goeth.","ref":"John 12:35","synthesized":"Then Jesus told them, “For a little while longer, the Light will be among you. Walk while you have the Light, so that darkness will not overtake you. The one who walks in the darkness does not know where he is going.","sources":{"KJV":{"text":"Then Jesus said unto them, Yet a little while is the light with you. Walk while ye have the light, lest darkness come upon you: for he that walketh in darkness knoweth not whither he goeth."},"BSB":{"text":"Then Jesus told them, “For a little while longer, the Light will be among you. Walk while you have the Light, so that darkness will not overtake you. The one who walks in the darkness does not know where he is going."}},"definableWords":["light","walk","darkness","one"],"peopleInVerse":["Jesus"]},"36":{"text":"While ye have light, believe in the light, that ye may be the children of light. These things spake Jesus, and departed, and did hide himself from them.","ref":"John 12:36","synthesized":"While you have the Light, believe in the Light, so that you may become sons of light.”  After Jesus had spoken these things, He went away and was hidden from them.","sources":{"KJV":{"text":"While ye have light, believe in the light, that ye may be the children of light. These things spake Jesus, and departed, and did hide himself from them."},"BSB":{"text":"While you have the Light, believe in the Light, so that you may become sons of light.”  After Jesus had spoken these things, He went away and was hidden from them."}},"definableWords":["light","sons"],"peopleInVerse":["Jesus"]},"37":{"text":"But though he had done so many miracles before them, yet they believed not on him:","ref":"John 12:37","synthesized":"Although Jesus had performed so many signs in their presence, they still did not believe in Him.","sources":{"KJV":{"text":"But though he had done so many miracles before them, yet they believed not on him:"},"BSB":{"text":"Although Jesus had performed so many signs in their presence, they still did not believe in Him."}},"definableWords":[],"peopleInVerse":["Jesus"]},"38":{"text":"That the saying of Esaias the prophet might be fulfilled, which he spake, Lord, who hath believed our report? and to whom hath the arm of the Lord been revealed?","ref":"John 12:38","synthesized":"This was to fulfill the word of Isaiah the prophet:  “Lord, who has believed our message? And to whom has the arm of the Lord been revealed?”","sources":{"KJV":{"text":"That the saying of Esaias the prophet might be fulfilled, which he spake, Lord, who hath believed our report? and to whom hath the arm of the Lord been revealed?"},"BSB":{"text":"This was to fulfill the word of Isaiah the prophet:  “Lord, who has believed our message? And to whom has the arm of the Lord been revealed?”"}},"definableWords":["word","prophet","Lord","believed"],"peopleInVerse":["Isaiah"]},"39":{"text":"Therefore they could not believe, because that Esaias said again,","ref":"John 12:39","synthesized":"For this reason they were unable to believe. For again, Isaiah says:","sources":{"KJV":{"text":"Therefore they could not believe, because that Esaias said again,"},"BSB":{"text":"For this reason they were unable to believe. For again, Isaiah says:"}},"definableWords":[],"peopleInVerse":["Isaiah"]},"40":{"text":"He hath blinded their eyes, and hardened their heart; that they should not see with their eyes, nor understand with their heart, and be converted, and I should heal them.","ref":"John 12:40","synthesized":"“He has blinded their eyes and hardened their hearts, so that they cannot see with their eyes, and understand with their hearts, and turn, and I would heal them.”","sources":{"KJV":{"text":"He hath blinded their eyes, and hardened their heart; that they should not see with their eyes, nor understand with their heart, and be converted, and I should heal them."},"BSB":{"text":"“He has blinded their eyes and hardened their hearts, so that they cannot see with their eyes, and understand with their hearts, and turn, and I would heal them.”"}},"definableWords":["see","heal"],"peopleInVerse":[]},"41":{"text":"These things said Esaias, when he saw his glory, and spake of him.","ref":"John 12:41","synthesized":"Isaiah said these things because he saw Jesus’ glory and spoke about Him.","sources":{"KJV":{"text":"These things said Esaias, when he saw his glory, and spake of him."},"BSB":{"text":"Isaiah said these things because he saw Jesus’ glory and spoke about Him."}},"definableWords":["saw","glory"],"peopleInVerse":["Isaiah","Jesus"]},"42":{"text":"Nevertheless among the chief rulers also many believed on him; but because of the Pharisees they did not confess him, lest they should be put out of the synagogue:","ref":"John 12:42","synthesized":"Nevertheless, many of the leaders believed in Him; but because of the Pharisees they did not confess Him, for fear that they would be put out of the synagogue.","sources":{"KJV":{"text":"Nevertheless among the chief rulers also many believed on him; but because of the Pharisees they did not confess him, lest they should be put out of the synagogue:"},"BSB":{"text":"Nevertheless, many of the leaders believed in Him; but because of the Pharisees they did not confess Him, for fear that they would be put out of the synagogue."}},"definableWords":["believed","fear"],"peopleInVerse":[]},"43":{"text":"For they loved the praise of men more than the praise of God.","ref":"John 12:43","synthesized":"For they loved praise from men more than praise from God.","sources":{"KJV":{"text":"For they loved the praise of men more than the praise of God."},"BSB":{"text":"For they loved praise from men more than praise from God."}},"definableWords":["praise","men","God"],"peopleInVerse":[]},"44":{"text":"Jesus cried and said, He that believeth on me, believeth not on me, but on him that sent me.","ref":"John 12:44","synthesized":"Then Jesus cried out, “Whoever believes in Me does not believe in Me alone, but in the One who sent Me.","sources":{"KJV":{"text":"Jesus cried and said, He that believeth on me, believeth not on me, but on him that sent me."},"BSB":{"text":"Then Jesus cried out, “Whoever believes in Me does not believe in Me alone, but in the One who sent Me."}},"definableWords":["one"],"peopleInVerse":["Jesus"]},"45":{"text":"And he that seeth me seeth him that sent me.","ref":"John 12:45","synthesized":"And whoever sees Me sees the One who sent Me.","sources":{"KJV":{"text":"And he that seeth me seeth him that sent me."},"BSB":{"text":"And whoever sees Me sees the One who sent Me."}},"definableWords":["one"],"peopleInVerse":[]},"46":{"text":"I am come a light into the world, that whosoever believeth on me should not abide in darkness.","ref":"John 12:46","synthesized":"I have come into the world as a light, so that no one who believes in Me should remain in darkness.","sources":{"KJV":{"text":"I am come a light into the world, that whosoever believeth on me should not abide in darkness."},"BSB":{"text":"I have come into the world as a light, so that no one who believes in Me should remain in darkness."}},"definableWords":["light","one","darkness"],"peopleInVerse":[]},"47":{"text":"And if any man hear my words, and believe not, I judge him not: for I came not to judge the world, but to save the world.","ref":"John 12:47","synthesized":"As for anyone who hears My words and does not keep them, I do not judge him. For I have not come to judge the world, but to save the world.","sources":{"KJV":{"text":"And if any man hear my words, and believe not, I judge him not: for I came not to judge the world, but to save the world."},"BSB":{"text":"As for anyone who hears My words and does not keep them, I do not judge him. For I have not come to judge the world, but to save the world."}},"definableWords":["keep"],"peopleInVerse":[]},"48":{"text":"He that rejecteth me, and receiveth not my words, hath one that judgeth him: the word that I have spoken, the same shall judge him in the last day.","ref":"John 12:48","synthesized":"There is a judge for the one who rejects Me and does not receive My words: The word that I have spoken will judge him on the last day.","sources":{"KJV":{"text":"He that rejecteth me, and receiveth not my words, hath one that judgeth him: the word that I have spoken, the same shall judge him in the last day."},"BSB":{"text":"There is a judge for the one who rejects Me and does not receive My words: The word that I have spoken will judge him on the last day."}},"definableWords":["one","word","day"],"peopleInVerse":[]},"49":{"text":"For I have not spoken of myself; but the Father which sent me, he gave me a commandment, what I should say, and what I should speak.","ref":"John 12:49","synthesized":"I have not spoken on My own, but the Father who sent Me has commanded Me what to say and how to say it.","sources":{"KJV":{"text":"For I have not spoken of myself; but the Father which sent me, he gave me a commandment, what I should say, and what I should speak."},"BSB":{"text":"I have not spoken on My own, but the Father who sent Me has commanded Me what to say and how to say it."}},"definableWords":["Father"],"peopleInVerse":[]},"50":{"text":"And I know that his commandment is life everlasting: whatsoever I speak therefore, even as the Father said unto me, so I speak.","ref":"John 12:50","synthesized":"And I know that His command leads to eternal life. So I speak exactly what the Father has told Me to say.”","sources":{"KJV":{"text":"And I know that his commandment is life everlasting: whatsoever I speak therefore, even as the Father said unto me, so I speak."},"BSB":{"text":"And I know that His command leads to eternal life. So I speak exactly what the Father has told Me to say.”"}},"definableWords":["eternal","life","Father"],"peopleInVerse":[]}}},"13":{"chapter":"13","title":"THE FOOT WASHING","verses":{"1":{"text":"Now before the feast of the passover, when Jesus knew that his hour was come that he should depart out of this world unto the Father, having loved his own which were in the world, he loved them unto the end.","ref":"John 13:1","synthesized":"It was now just before the Passover Feast, and Jesus knew that His hour had come to leave this world and return to the Father. Having loved His own who were in the world, He loved them to the very end.","sources":{"KJV":{"text":"Now before the feast of the passover, when Jesus knew that his hour was come that he should depart out of this world unto the Father, having loved his own which were in the world, he loved them unto the end."},"BSB":{"text":"It was now just before the Passover Feast, and Jesus knew that His hour had come to leave this world and return to the Father. Having loved His own who were in the world, He loved them to the very end."}},"definableWords":["Passover","Father"],"peopleInVerse":["Jesus"]},"2":{"text":"And supper being ended, the devil having now put into the heart of Judas Iscariot, Simon’s son, to betray him;","ref":"John 13:2","synthesized":"The evening meal was underway, and the devil had already put into the heart of Judas, the son of Simon Iscariot, to betray Jesus.","sources":{"KJV":{"text":"And supper being ended, the devil having now put into the heart of Judas Iscariot, Simon’s son, to betray him;"},"BSB":{"text":"The evening meal was underway, and the devil had already put into the heart of Judas, the son of Simon Iscariot, to betray Jesus."}},"definableWords":["devil","heart","son"],"peopleInVerse":["Jesus"]},"3":{"text":"Jesus knowing that the Father had given all things into his hands, and that he was come from God, and went to God;","ref":"John 13:3","synthesized":"Jesus knew that the Father had delivered all things into His hands, and that He had come from God and was returning to God.","sources":{"KJV":{"text":"Jesus knowing that the Father had given all things into his hands, and that he was come from God, and went to God;"},"BSB":{"text":"Jesus knew that the Father had delivered all things into His hands, and that He had come from God and was returning to God."}},"definableWords":["Father","God"],"peopleInVerse":["Jesus"]},"4":{"text":"He riseth from supper, and laid aside his garments; and took a towel, and girded himself.","ref":"John 13:4","synthesized":"So He got up from the supper, laid aside His outer garments, and wrapped a towel around His waist.","sources":{"KJV":{"text":"He riseth from supper, and laid aside his garments; and took a towel, and girded himself."},"BSB":{"text":"So He got up from the supper, laid aside His outer garments, and wrapped a towel around His waist."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"After that he poureth water into a bason, and began to wash the disciples’ feet, and to wipe them with the towel wherewith he was girded.","ref":"John 13:5","synthesized":"After that, He poured water into a basin and began to wash the disciples’ feet and dry them with the towel that was around Him.","sources":{"KJV":{"text":"After that he poureth water into a bason, and began to wash the disciples’ feet, and to wipe them with the towel wherewith he was girded."},"BSB":{"text":"After that, He poured water into a basin and began to wash the disciples’ feet and dry them with the towel that was around Him."}},"definableWords":["water"],"peopleInVerse":[]},"6":{"text":"Then cometh he to Simon Peter: and Peter saith unto him, Lord, dost thou wash my feet?","ref":"John 13:6","synthesized":"He came to Simon Peter, who asked Him, “Lord, are You going to wash my feet?”","sources":{"KJV":{"text":"Then cometh he to Simon Peter: and Peter saith unto him, Lord, dost thou wash my feet?"},"BSB":{"text":"He came to Simon Peter, who asked Him, “Lord, are You going to wash my feet?”"}},"definableWords":["Lord"],"peopleInVerse":["Peter"]},"7":{"text":"Jesus answered and said unto him, What I do thou knowest not now; but thou shalt know hereafter.","ref":"John 13:7","synthesized":"Jesus replied, “You do not realize now what I am doing, but later you will understand.”","sources":{"KJV":{"text":"Jesus answered and said unto him, What I do thou knowest not now; but thou shalt know hereafter."},"BSB":{"text":"Jesus replied, “You do not realize now what I am doing, but later you will understand.”"}},"definableWords":[],"peopleInVerse":["Jesus"]},"8":{"text":"Peter saith unto him, Thou shalt never wash my feet. Jesus answered him, If I wash thee not, thou hast no part with me.","ref":"John 13:8","synthesized":"“Never shall You wash my feet!” Peter told Him.  Jesus answered, “Unless I wash you, you have no part with Me.”","sources":{"KJV":{"text":"Peter saith unto him, Thou shalt never wash my feet. Jesus answered him, If I wash thee not, thou hast no part with me."},"BSB":{"text":"“Never shall You wash my feet!” Peter told Him.  Jesus answered, “Unless I wash you, you have no part with Me.”"}},"definableWords":[],"peopleInVerse":["Peter","Jesus"]},"9":{"text":"Simon Peter saith unto him, Lord, not my feet only, but also my hands and my head.","ref":"John 13:9","synthesized":"“Then, Lord,” Simon Peter replied, “not only my feet, but my hands and my head as well!”","sources":{"KJV":{"text":"Simon Peter saith unto him, Lord, not my feet only, but also my hands and my head."},"BSB":{"text":"“Then, Lord,” Simon Peter replied, “not only my feet, but my hands and my head as well!”"}},"definableWords":["Lord"],"peopleInVerse":["Peter"]},"10":{"text":"Jesus saith to him, He that is washed needeth not save to wash his feet, but is clean every whit: and ye are clean, but not all.","ref":"John 13:10","synthesized":"Jesus told him, “Whoever has already bathed needs only to wash his feet, and he will be completely clean. And you are clean, though not all of you.”","sources":{"KJV":{"text":"Jesus saith to him, He that is washed needeth not save to wash his feet, but is clean every whit: and ye are clean, but not all."},"BSB":{"text":"Jesus told him, “Whoever has already bathed needs only to wash his feet, and he will be completely clean. And you are clean, though not all of you.”"}},"definableWords":[],"peopleInVerse":["Jesus"]},"11":{"text":"For he knew who should betray him; therefore said he, Ye are not all clean.","ref":"John 13:11","synthesized":"For He knew who would betray Him. That is why He said, “Not all of you are clean.”","sources":{"KJV":{"text":"For he knew who should betray him; therefore said he, Ye are not all clean."},"BSB":{"text":"For He knew who would betray Him. That is why He said, “Not all of you are clean.”"}},"definableWords":[],"peopleInVerse":[]},"12":{"text":"So after he had washed their feet, and had taken his garments, and was set down again, he said unto them, Know ye what I have done to you?","ref":"John 13:12","synthesized":"When Jesus had washed their feet and put on His outer garments, He reclined with them again and asked, “Do you know what I have done for you?","sources":{"KJV":{"text":"So after he had washed their feet, and had taken his garments, and was set down again, he said unto them, Know ye what I have done to you?"},"BSB":{"text":"When Jesus had washed their feet and put on His outer garments, He reclined with them again and asked, “Do you know what I have done for you?"}},"definableWords":[],"peopleInVerse":["Jesus"]},"13":{"text":"Ye call me Master and Lord: and ye say well; for so I am.","ref":"John 13:13","synthesized":"You call Me Teacher and Lord, and rightly so, because I am.","sources":{"KJV":{"text":"Ye call me Master and Lord: and ye say well; for so I am."},"BSB":{"text":"You call Me Teacher and Lord, and rightly so, because I am."}},"definableWords":["Lord"],"peopleInVerse":[]},"14":{"text":"If I then, your Lord and Master, have washed your feet; ye also ought to wash one another’s feet.","ref":"John 13:14","synthesized":"So if I, your Lord and Teacher, have washed your feet, you also should wash one another’s feet.","sources":{"KJV":{"text":"If I then, your Lord and Master, have washed your feet; ye also ought to wash one another’s feet."},"BSB":{"text":"So if I, your Lord and Teacher, have washed your feet, you also should wash one another’s feet."}},"definableWords":["Lord","one"],"peopleInVerse":[]},"15":{"text":"For I have given you an example, that ye should do as I have done to you.","ref":"John 13:15","synthesized":"I have set you an example so that you should do as I have done for you.","sources":{"KJV":{"text":"For I have given you an example, that ye should do as I have done to you."},"BSB":{"text":"I have set you an example so that you should do as I have done for you."}},"definableWords":[],"peopleInVerse":[]},"16":{"text":"Verily, verily, I say unto you, The servant is not greater than his lord; neither he that is sent greater than he that sent him.","ref":"John 13:16","synthesized":"Truly, truly, I tell you, no servant is greater than his master, nor is a messenger greater than the one who sent him.","sources":{"KJV":{"text":"Verily, verily, I say unto you, The servant is not greater than his lord; neither he that is sent greater than he that sent him."},"BSB":{"text":"Truly, truly, I tell you, no servant is greater than his master, nor is a messenger greater than the one who sent him."}},"definableWords":["servant","one"],"peopleInVerse":[]},"17":{"text":"If ye know these things, happy are ye if ye do them.","ref":"John 13:17","synthesized":"If you know these things, you will be blessed if you do them.","sources":{"KJV":{"text":"If ye know these things, happy are ye if ye do them."},"BSB":{"text":"If you know these things, you will be blessed if you do them."}},"definableWords":["blessed"],"peopleInVerse":[]},"18":{"text":"I speak not of you all: I know whom I have chosen: but that the scripture may be fulfilled, He that eateth bread with me hath lifted up his heel against me.","ref":"John 13:18","synthesized":"I am not speaking about all of you; I know whom I have chosen. But this is to fulfill the Scripture: ‘The one who shares My bread has lifted up his heel against Me.’","sources":{"KJV":{"text":"I speak not of you all: I know whom I have chosen: but that the scripture may be fulfilled, He that eateth bread with me hath lifted up his heel against me."},"BSB":{"text":"I am not speaking about all of you; I know whom I have chosen. But this is to fulfill the Scripture: ‘The one who shares My bread has lifted up his heel against Me.’"}},"definableWords":["one"],"peopleInVerse":[]},"19":{"text":"Now I tell you before it come, that, when it is come to pass, ye may believe that I am he.","ref":"John 13:19","synthesized":"I am telling you now before it happens, so that when it comes to pass, you will believe that I am He.","sources":{"KJV":{"text":"Now I tell you before it come, that, when it is come to pass, ye may believe that I am he."},"BSB":{"text":"I am telling you now before it happens, so that when it comes to pass, you will believe that I am He."}},"definableWords":[],"peopleInVerse":[]},"20":{"text":"Verily, verily, I say unto you, He that receiveth whomsoever I send receiveth me; and he that receiveth me receiveth him that sent me.","ref":"John 13:20","synthesized":"Truly, truly, I tell you, whoever receives the one I send receives Me, and whoever receives Me receives the One who sent Me.”","sources":{"KJV":{"text":"Verily, verily, I say unto you, He that receiveth whomsoever I send receiveth me; and he that receiveth me receiveth him that sent me."},"BSB":{"text":"Truly, truly, I tell you, whoever receives the one I send receives Me, and whoever receives Me receives the One who sent Me.”"}},"definableWords":["one"],"peopleInVerse":[]},"21":{"text":"When Jesus had thus said, he was troubled in spirit, and testified, and said, Verily, verily, I say unto you, that one of you shall betray me.","ref":"John 13:21","synthesized":"After Jesus had said this, He became troubled in spirit and testified, “Truly, truly, I tell you, one of you will betray Me.”","sources":{"KJV":{"text":"When Jesus had thus said, he was troubled in spirit, and testified, and said, Verily, verily, I say unto you, that one of you shall betray me."},"BSB":{"text":"After Jesus had said this, He became troubled in spirit and testified, “Truly, truly, I tell you, one of you will betray Me.”"}},"definableWords":["spirit","one"],"peopleInVerse":["Jesus"]},"22":{"text":"Then the disciples looked one on another, doubting of whom he spake.","ref":"John 13:22","synthesized":"The disciples looked at one another, perplexed as to which of them He meant.","sources":{"KJV":{"text":"Then the disciples looked one on another, doubting of whom he spake."},"BSB":{"text":"The disciples looked at one another, perplexed as to which of them He meant."}},"definableWords":["one"],"peopleInVerse":[]},"23":{"text":"Now there was leaning on Jesus’ bosom one of his disciples, whom Jesus loved.","ref":"John 13:23","synthesized":"One of His disciples, the one whom Jesus loved, was reclining at His side.","sources":{"KJV":{"text":"Now there was leaning on Jesus’ bosom one of his disciples, whom Jesus loved."},"BSB":{"text":"One of His disciples, the one whom Jesus loved, was reclining at His side."}},"definableWords":["one"],"peopleInVerse":["Jesus"]},"24":{"text":"Simon Peter therefore beckoned to him, that he should ask who it should be of whom he spake.","ref":"John 13:24","synthesized":"So Simon Peter motioned to him to ask Jesus which one He was talking about.","sources":{"KJV":{"text":"Simon Peter therefore beckoned to him, that he should ask who it should be of whom he spake."},"BSB":{"text":"So Simon Peter motioned to him to ask Jesus which one He was talking about."}},"definableWords":["one"],"peopleInVerse":["Peter","Jesus"]},"25":{"text":"He then lying on Jesus’ breast saith unto him, Lord, who is it?","ref":"John 13:25","synthesized":"Leaning back against Jesus, he asked, “Lord, who is it?”","sources":{"KJV":{"text":"He then lying on Jesus’ breast saith unto him, Lord, who is it?"},"BSB":{"text":"Leaning back against Jesus, he asked, “Lord, who is it?”"}},"definableWords":["Lord"],"peopleInVerse":["Jesus"]},"26":{"text":"Jesus answered, He it is, to whom I shall give a sop, when I have dipped it. And when he had dipped the sop, he gave it to Judas Iscariot, the son of Simon.","ref":"John 13:26","synthesized":"Jesus answered, “It is the one to whom I give this morsel after I have dipped it.” Then He dipped the morsel and gave it to Judas son of Simon Iscariot.","sources":{"KJV":{"text":"Jesus answered, He it is, to whom I shall give a sop, when I have dipped it. And when he had dipped the sop, he gave it to Judas Iscariot, the son of Simon."},"BSB":{"text":"Jesus answered, “It is the one to whom I give this morsel after I have dipped it.” Then He dipped the morsel and gave it to Judas son of Simon Iscariot."}},"definableWords":["one","son"],"peopleInVerse":["Jesus"]},"27":{"text":"And after the sop Satan entered into him. Then said Jesus unto him, That thou doest, do quickly.","ref":"John 13:27","synthesized":"And when Judas had taken the morsel, Satan entered into him.  Then Jesus said to Judas, “What you are about to do, do quickly.”","sources":{"KJV":{"text":"And after the sop Satan entered into him. Then said Jesus unto him, That thou doest, do quickly."},"BSB":{"text":"And when Judas had taken the morsel, Satan entered into him.  Then Jesus said to Judas, “What you are about to do, do quickly.”"}},"definableWords":["Satan"],"peopleInVerse":["Jesus"]},"28":{"text":"Now no man at the table knew for what intent he spake this unto him.","ref":"John 13:28","synthesized":"But no one at the table knew why Jesus had said this to him.","sources":{"KJV":{"text":"Now no man at the table knew for what intent he spake this unto him."},"BSB":{"text":"But no one at the table knew why Jesus had said this to him."}},"definableWords":["one"],"peopleInVerse":["Jesus"]},"29":{"text":"For some of them thought, because Judas had the bag, that Jesus had said unto him, Buy those things that we have need of against the feast; or, that he should give something to the poor.","ref":"John 13:29","synthesized":"Since Judas kept the money bag, some thought that Jesus was telling him to buy what was needed for the feast, or to give something to the poor.","sources":{"KJV":{"text":"For some of them thought, because Judas had the bag, that Jesus had said unto him, Buy those things that we have need of against the feast; or, that he should give something to the poor."},"BSB":{"text":"Since Judas kept the money bag, some thought that Jesus was telling him to buy what was needed for the feast, or to give something to the poor."}},"definableWords":["or"],"peopleInVerse":["Jesus"]},"30":{"text":"He then having received the sop went immediately out: and it was night.","ref":"John 13:30","synthesized":"As soon as he had received the morsel, Judas went out into the night.","sources":{"KJV":{"text":"He then having received the sop went immediately out: and it was night."},"BSB":{"text":"As soon as he had received the morsel, Judas went out into the night."}},"definableWords":["night"],"peopleInVerse":[]},"31":{"text":"Therefore, when he was gone out, Jesus said, Now is the Son of man glorified, and God is glorified in him.","ref":"John 13:31","synthesized":"When Judas had gone out, Jesus said, “Now the Son of Man is glorified, and God is glorified in Him.","sources":{"KJV":{"text":"Therefore, when he was gone out, Jesus said, Now is the Son of man glorified, and God is glorified in him."},"BSB":{"text":"When Judas had gone out, Jesus said, “Now the Son of Man is glorified, and God is glorified in Him."}},"definableWords":["Son","man","God"],"peopleInVerse":["Jesus"]},"32":{"text":"If God be glorified in him, God shall also glorify him in himself, and shall straightway glorify him.","ref":"John 13:32","synthesized":"If God is glorified in Him, God will also glorify the Son in Himself—and will glorify Him at once.","sources":{"KJV":{"text":"If God be glorified in him, God shall also glorify him in himself, and shall straightway glorify him."},"BSB":{"text":"If God is glorified in Him, God will also glorify the Son in Himself—and will glorify Him at once."}},"definableWords":["God","Son"],"peopleInVerse":[]},"33":{"text":"Little children, yet a little while I am with you. Ye shall seek me: and as I said unto the Jews, Whither I go, ye cannot come; so now I say to you.","ref":"John 13:33","synthesized":"Little children, I am with you only a little while longer. You will look for Me, and as I said to the Jews, so now I say to you: ‘Where I am going, you cannot come.’","sources":{"KJV":{"text":"Little children, yet a little while I am with you. Ye shall seek me: and as I said unto the Jews, Whither I go, ye cannot come; so now I say to you."},"BSB":{"text":"Little children, I am with you only a little while longer. You will look for Me, and as I said to the Jews, so now I say to you: ‘Where I am going, you cannot come.’"}},"definableWords":[],"peopleInVerse":[]},"34":{"text":"A new commandment I give unto you, That ye love one another; as I have loved you, that ye also love one another.","ref":"John 13:34","synthesized":"A new commandment I give you: Love one another. As I have loved you, so you also must love one another.","sources":{"KJV":{"text":"A new commandment I give unto you, That ye love one another; as I have loved you, that ye also love one another."},"BSB":{"text":"A new commandment I give you: Love one another. As I have loved you, so you also must love one another."}},"definableWords":["commandment","love","one"],"peopleInVerse":[]},"35":{"text":"By this shall all men know that ye are my disciples, if ye have love one to another.","ref":"John 13:35","synthesized":"By this everyone will know that you are My disciples, if you love one another.”","sources":{"KJV":{"text":"By this shall all men know that ye are my disciples, if ye have love one to another."},"BSB":{"text":"By this everyone will know that you are My disciples, if you love one another.”"}},"definableWords":["love","one"],"peopleInVerse":[]},"36":{"text":"Simon Peter said unto him, Lord, whither goest thou? Jesus answered him, Whither I go, thou canst not follow me now; but thou shalt follow me afterwards.","ref":"John 13:36","synthesized":"“Lord, where are You going?” Simon Peter asked.  Jesus answered, “Where I am going, you cannot follow Me now, but you will follow later.”","sources":{"KJV":{"text":"Simon Peter said unto him, Lord, whither goest thou? Jesus answered him, Whither I go, thou canst not follow me now; but thou shalt follow me afterwards."},"BSB":{"text":"“Lord, where are You going?” Simon Peter asked.  Jesus answered, “Where I am going, you cannot follow Me now, but you will follow later.”"}},"definableWords":["Lord"],"peopleInVerse":["Peter","Jesus"]},"37":{"text":"Peter said unto him, Lord, why cannot I follow thee now? I will lay down my life for thy sake.","ref":"John 13:37","synthesized":"“Lord,” said Peter, “why can’t I follow You now? I will lay down my life for You.”","sources":{"KJV":{"text":"Peter said unto him, Lord, why cannot I follow thee now? I will lay down my life for thy sake."},"BSB":{"text":"“Lord,” said Peter, “why can’t I follow You now? I will lay down my life for You.”"}},"definableWords":["Lord","life"],"peopleInVerse":["Peter"]},"38":{"text":"Jesus answered him, Wilt thou lay down thy life for my sake? Verily, verily, I say unto thee, The cock shall not crow, till thou hast denied me thrice.","ref":"John 13:38","synthesized":"“Will you lay down your life for Me?” Jesus replied. “Truly, truly, I tell you, before the rooster crows, you will deny Me three times.","sources":{"KJV":{"text":"Jesus answered him, Wilt thou lay down thy life for my sake? Verily, verily, I say unto thee, The cock shall not crow, till thou hast denied me thrice."},"BSB":{"text":"“Will you lay down your life for Me?” Jesus replied. “Truly, truly, I tell you, before the rooster crows, you will deny Me three times."}},"definableWords":["life"],"peopleInVerse":["Jesus"]}}},"14":{"chapter":"14","title":"I AM THE WAY, THE TRUTH, THE LIFE","verses":{"1":{"text":"Let not your heart be troubled: ye believe in God, believe also in me.","ref":"John 14:1","synthesized":"“Do not let your hearts be troubled. You believe in God; believe in Me as well.","sources":{"KJV":{"text":"Let not your heart be troubled: ye believe in God, believe also in me."},"BSB":{"text":"“Do not let your hearts be troubled. You believe in God; believe in Me as well."}},"definableWords":["God"],"peopleInVerse":[],"kingdomLens":"The night before he dies, Jesus tells his disciples 'In my Father's house are many mansions.' He's going to prepare a place. Thomas asks how to get there. Jesus: 'I am the way, the truth, and the life: no man cometh unto the Father, but by me' (14:6). The most exclusive and the most welcoming claim ever made. No other way — but the way is open to anyone.","cultural":{"title":"I am the way, the truth, and the life","detail":"First-century Jewish weddings: the groom would leave the bride at engagement to prepare an addition to his father's house for them to live in. When the place was ready (only the father decided when), he came back unexpectedly to take her. Jesus uses exactly this imagery (14:2-3).","sources":"SWRV Kingdom Study Protocol — synthesis from approved library (Rule 06)"}},"2":{"text":"In my Father’s house are many mansions: if it were not so, I would have told you. I go to prepare a place for you.","ref":"John 14:2","synthesized":"In My Father’s house are many rooms. If it were not so, would I have told you that I am going there to prepare a place for you?","sources":{"KJV":{"text":"In my Father’s house are many mansions: if it were not so, I would have told you. I go to prepare a place for you."},"BSB":{"text":"In My Father’s house are many rooms. If it were not so, would I have told you that I am going there to prepare a place for you?"}},"definableWords":["Father","house"],"peopleInVerse":[]},"3":{"text":"And if I go and prepare a place for you, I will come again, and receive you unto myself; that where I am, there ye may be also.","ref":"John 14:3","synthesized":"And if I go and prepare a place for you, I will come back and welcome you into My presence, so that you also may be where I am.","sources":{"KJV":{"text":"And if I go and prepare a place for you, I will come again, and receive you unto myself; that where I am, there ye may be also."},"BSB":{"text":"And if I go and prepare a place for you, I will come back and welcome you into My presence, so that you also may be where I am."}},"definableWords":[],"peopleInVerse":[]},"4":{"text":"And whither I go ye know, and the way ye know.","ref":"John 14:4","synthesized":"You know the way to the place where I am going.”","sources":{"KJV":{"text":"And whither I go ye know, and the way ye know."},"BSB":{"text":"You know the way to the place where I am going.”"}},"definableWords":["way"],"peopleInVerse":[]},"5":{"text":"Thomas saith unto him, Lord, we know not whither thou goest; and how can we know the way?","ref":"John 14:5","synthesized":"“Lord,” said Thomas, “we do not know where You are going, so how can we know the way?”","sources":{"KJV":{"text":"Thomas saith unto him, Lord, we know not whither thou goest; and how can we know the way?"},"BSB":{"text":"“Lord,” said Thomas, “we do not know where You are going, so how can we know the way?”"}},"definableWords":["Lord","way"],"peopleInVerse":[]},"6":{"text":"Jesus saith unto him, I am the way, the truth, and the life: no man cometh unto the Father, but by me.","ref":"John 14:6","synthesized":"Jesus answered, “I am the way and the truth and the life. No one comes to the Father except through Me.","sources":{"KJV":{"text":"Jesus saith unto him, I am the way, the truth, and the life: no man cometh unto the Father, but by me."},"BSB":{"text":"Jesus answered, “I am the way and the truth and the life. No one comes to the Father except through Me."}},"definableWords":["way","truth","life","one","Father"],"peopleInVerse":["Jesus"]},"7":{"text":"If ye had known me, ye should have known my Father also: and from henceforth ye know him, and have seen him.","ref":"John 14:7","synthesized":"If you had known Me, you would know My Father as well. From now on you do know Him and have seen Him.”","sources":{"KJV":{"text":"If ye had known me, ye should have known my Father also: and from henceforth ye know him, and have seen him."},"BSB":{"text":"If you had known Me, you would know My Father as well. From now on you do know Him and have seen Him.”"}},"definableWords":["Father"],"peopleInVerse":[]},"8":{"text":"Philip saith unto him, Lord, shew us the Father, and it sufficeth us.","ref":"John 14:8","synthesized":"Philip said to Him, “Lord, show us the Father, and that will be enough for us.”","sources":{"KJV":{"text":"Philip saith unto him, Lord, shew us the Father, and it sufficeth us."},"BSB":{"text":"Philip said to Him, “Lord, show us the Father, and that will be enough for us.”"}},"definableWords":["Lord","Father"],"peopleInVerse":[]},"9":{"text":"Jesus saith unto him, Have I been so long time with you, and yet hast thou not known me, Philip? he that hath seen me hath seen the Father; and how sayest thou then, Shew us the Father?","ref":"John 14:9","synthesized":"Jesus replied, “Philip, I have been with you all this time, and still you do not know Me? Anyone who has seen Me has seen the Father. How can you say, ‘Show us the Father’?","sources":{"KJV":{"text":"Jesus saith unto him, Have I been so long time with you, and yet hast thou not known me, Philip? he that hath seen me hath seen the Father; and how sayest thou then, Shew us the Father?"},"BSB":{"text":"Jesus replied, “Philip, I have been with you all this time, and still you do not know Me? Anyone who has seen Me has seen the Father. How can you say, ‘Show us the Father’?"}},"definableWords":["Father"],"peopleInVerse":["Jesus"]},"10":{"text":"Believest thou not that I am in the Father, and the Father in me? the words that I speak unto you I speak not of myself: but the Father that dwelleth in me, he doeth the works.","ref":"John 14:10","synthesized":"Do you not believe that I am in the Father and the Father is in Me? The words I say to you, I do not speak on My own. Instead, it is the Father dwelling in Me, performing His works.","sources":{"KJV":{"text":"Believest thou not that I am in the Father, and the Father in me? the words that I speak unto you I speak not of myself: but the Father that dwelleth in me, he doeth the works."},"BSB":{"text":"Do you not believe that I am in the Father and the Father is in Me? The words I say to you, I do not speak on My own. Instead, it is the Father dwelling in Me, performing His works."}},"definableWords":["Father","works"],"peopleInVerse":[]},"11":{"text":"Believe me that I am in the Father, and the Father in me: or else believe me for the very works’ sake.","ref":"John 14:11","synthesized":"Believe Me that I am in the Father and the Father is in Me—or at least believe on account of the works themselves.","sources":{"KJV":{"text":"Believe me that I am in the Father, and the Father in me: or else believe me for the very works’ sake."},"BSB":{"text":"Believe Me that I am in the Father and the Father is in Me—or at least believe on account of the works themselves."}},"definableWords":["Father","or","works"],"peopleInVerse":[]},"12":{"text":"Verily, verily, I say unto you, He that believeth on me, the works that I do shall he do also; and greater works than these shall he do; because I go unto my Father.","ref":"John 14:12","synthesized":"Truly, truly, I tell you, whoever believes in Me will also do the works that I am doing. He will do even greater things than these, because I am going to the Father.","sources":{"KJV":{"text":"Verily, verily, I say unto you, He that believeth on me, the works that I do shall he do also; and greater works than these shall he do; because I go unto my Father."},"BSB":{"text":"Truly, truly, I tell you, whoever believes in Me will also do the works that I am doing. He will do even greater things than these, because I am going to the Father."}},"definableWords":["works","Father"],"peopleInVerse":[]},"13":{"text":"And whatsoever ye shall ask in my name, that will I do, that the Father may be glorified in the Son.","ref":"John 14:13","synthesized":"And I will do whatever you ask in My name, so that the Father may be glorified in the Son.","sources":{"KJV":{"text":"And whatsoever ye shall ask in my name, that will I do, that the Father may be glorified in the Son."},"BSB":{"text":"And I will do whatever you ask in My name, so that the Father may be glorified in the Son."}},"definableWords":["name","Father","Son"],"peopleInVerse":[]},"14":{"text":"If ye shall ask any thing in my name, I will do it.","ref":"John 14:14","synthesized":"If you ask Me for anything in My name, I will do it.","sources":{"KJV":{"text":"If ye shall ask any thing in my name, I will do it."},"BSB":{"text":"If you ask Me for anything in My name, I will do it."}},"definableWords":["name"],"peopleInVerse":[]},"15":{"text":"If ye love me, keep my commandments.","ref":"John 14:15","synthesized":"If you love Me, you will keep My commandments.","sources":{"KJV":{"text":"If ye love me, keep my commandments."},"BSB":{"text":"If you love Me, you will keep My commandments."}},"definableWords":["love","keep"],"peopleInVerse":[]},"16":{"text":"And I will pray the Father, and he shall give you another Comforter, that he may abide with you for ever;","ref":"John 14:16","synthesized":"And I will ask the Father, and He will give you another Advocate to be with you forever—","sources":{"KJV":{"text":"And I will pray the Father, and he shall give you another Comforter, that he may abide with you for ever;"},"BSB":{"text":"And I will ask the Father, and He will give you another Advocate to be with you forever—"}},"definableWords":["Father"],"peopleInVerse":[]},"17":{"text":"Even the Spirit of truth; whom the world cannot receive, because it seeth him not, neither knoweth him: but ye know him; for he dwelleth with you, and shall be in you.","ref":"John 14:17","synthesized":"the Spirit of truth. The world cannot receive Him, because it neither sees Him nor knows Him. But you do know Him, for He abides with you and will be in you.","sources":{"KJV":{"text":"Even the Spirit of truth; whom the world cannot receive, because it seeth him not, neither knoweth him: but ye know him; for he dwelleth with you, and shall be in you."},"BSB":{"text":"the Spirit of truth. The world cannot receive Him, because it neither sees Him nor knows Him. But you do know Him, for He abides with you and will be in you."}},"definableWords":["Spirit","truth"],"peopleInVerse":[]},"18":{"text":"I will not leave you comfortless: I will come to you.","ref":"John 14:18","synthesized":"I will not leave you as orphans; I will come to you.","sources":{"KJV":{"text":"I will not leave you comfortless: I will come to you."},"BSB":{"text":"I will not leave you as orphans; I will come to you."}},"definableWords":[],"peopleInVerse":[]},"19":{"text":"Yet a little while, and the world seeth me no more; but ye see me: because I live, ye shall live also.","ref":"John 14:19","synthesized":"In a little while the world will see Me no more, but you will see Me. Because I live, you also will live.","sources":{"KJV":{"text":"Yet a little while, and the world seeth me no more; but ye see me: because I live, ye shall live also."},"BSB":{"text":"In a little while the world will see Me no more, but you will see Me. Because I live, you also will live."}},"definableWords":["see","live"],"peopleInVerse":[]},"20":{"text":"At that day ye shall know that I am in my Father, and ye in me, and I in you.","ref":"John 14:20","synthesized":"On that day you will know that I am in My Father, and you are in Me, and I am in you.","sources":{"KJV":{"text":"At that day ye shall know that I am in my Father, and ye in me, and I in you."},"BSB":{"text":"On that day you will know that I am in My Father, and you are in Me, and I am in you."}},"definableWords":["day","Father"],"peopleInVerse":[]},"21":{"text":"He that hath my commandments, and keepeth them, he it is that loveth me: and he that loveth me shall be loved of my Father, and I will love him, and will manifest myself to him.","ref":"John 14:21","synthesized":"Whoever has My commandments and keeps them is the one who loves Me. The one who loves Me will be loved by My Father, and I will love him and reveal Myself to him.”","sources":{"KJV":{"text":"He that hath my commandments, and keepeth them, he it is that loveth me: and he that loveth me shall be loved of my Father, and I will love him, and will manifest myself to him."},"BSB":{"text":"Whoever has My commandments and keeps them is the one who loves Me. The one who loves Me will be loved by My Father, and I will love him and reveal Myself to him.”"}},"definableWords":["one","Father","love"],"peopleInVerse":[]},"22":{"text":"Judas saith unto him, not Iscariot, Lord, how is it that thou wilt manifest thyself unto us, and not unto the world?","ref":"John 14:22","synthesized":"Judas (not Iscariot) asked Him, “Lord, why are You going to reveal Yourself to us and not to the world?”","sources":{"KJV":{"text":"Judas saith unto him, not Iscariot, Lord, how is it that thou wilt manifest thyself unto us, and not unto the world?"},"BSB":{"text":"Judas (not Iscariot) asked Him, “Lord, why are You going to reveal Yourself to us and not to the world?”"}},"definableWords":["Lord"],"peopleInVerse":[]},"23":{"text":"Jesus answered and said unto him, If a man love me, he will keep my words: and my Father will love him, and we will come unto him, and make our abode with him.","ref":"John 14:23","synthesized":"Jesus replied, “If anyone loves Me, he will keep My word. My Father will love him, and We will come to him and make Our home with him.","sources":{"KJV":{"text":"Jesus answered and said unto him, If a man love me, he will keep my words: and my Father will love him, and we will come unto him, and make our abode with him."},"BSB":{"text":"Jesus replied, “If anyone loves Me, he will keep My word. My Father will love him, and We will come to him and make Our home with him."}},"definableWords":["keep","word","Father","love","make"],"peopleInVerse":["Jesus"]},"24":{"text":"He that loveth me not keepeth not my sayings: and the word which ye hear is not mine, but the Father’s which sent me.","ref":"John 14:24","synthesized":"Whoever does not love Me does not keep My words. The word that you hear is not My own, but it is from the Father who sent Me.","sources":{"KJV":{"text":"He that loveth me not keepeth not my sayings: and the word which ye hear is not mine, but the Father’s which sent me."},"BSB":{"text":"Whoever does not love Me does not keep My words. The word that you hear is not My own, but it is from the Father who sent Me."}},"definableWords":["love","keep","word","hear","Father"],"peopleInVerse":[]},"25":{"text":"These things have I spoken unto you, being yet present with you.","ref":"John 14:25","synthesized":"All this I have spoken to you while I am still with you.","sources":{"KJV":{"text":"These things have I spoken unto you, being yet present with you."},"BSB":{"text":"All this I have spoken to you while I am still with you."}},"definableWords":[],"peopleInVerse":[]},"26":{"text":"But the Comforter, which is the Holy Ghost, whom the Father will send in my name, he shall teach you all things, and bring all things to your remembrance, whatsoever I have said unto you.","ref":"John 14:26","synthesized":"But the Advocate, the Holy Spirit, whom the Father will send in My name, will teach you all things and will remind you of everything I have told you.","sources":{"KJV":{"text":"But the Comforter, which is the Holy Ghost, whom the Father will send in my name, he shall teach you all things, and bring all things to your remembrance, whatsoever I have said unto you."},"BSB":{"text":"But the Advocate, the Holy Spirit, whom the Father will send in My name, will teach you all things and will remind you of everything I have told you."}},"definableWords":["holy","Spirit","Father","name"],"peopleInVerse":[]},"27":{"text":"Peace I leave with you, my peace I give unto you: not as the world giveth, give I unto you. Let not your heart be troubled, neither let it be afraid.","ref":"John 14:27","synthesized":"Peace I leave with you; My peace I give to you. I do not give to you as the world gives. Do not let your hearts be troubled; do not be afraid.","sources":{"KJV":{"text":"Peace I leave with you, my peace I give unto you: not as the world giveth, give I unto you. Let not your heart be troubled, neither let it be afraid."},"BSB":{"text":"Peace I leave with you; My peace I give to you. I do not give to you as the world gives. Do not let your hearts be troubled; do not be afraid."}},"definableWords":["peace"],"peopleInVerse":[]},"28":{"text":"Ye have heard how I said unto you, I go away, and come again unto you. If ye loved me, ye would rejoice, because I said, I go unto the Father: for my Father is greater than I.","ref":"John 14:28","synthesized":"You heard Me say, ‘I am going away, and I am coming back to you.’ If you loved Me, you would rejoice that I am going to the Father, because the Father is greater than I.","sources":{"KJV":{"text":"Ye have heard how I said unto you, I go away, and come again unto you. If ye loved me, ye would rejoice, because I said, I go unto the Father: for my Father is greater than I."},"BSB":{"text":"You heard Me say, ‘I am going away, and I am coming back to you.’ If you loved Me, you would rejoice that I am going to the Father, because the Father is greater than I."}},"definableWords":["Father"],"peopleInVerse":[]},"29":{"text":"And now I have told you before it come to pass, that, when it is come to pass, ye might believe.","ref":"John 14:29","synthesized":"And now I have told you before it happens, so that when it does happen, you will believe.","sources":{"KJV":{"text":"And now I have told you before it come to pass, that, when it is come to pass, ye might believe."},"BSB":{"text":"And now I have told you before it happens, so that when it does happen, you will believe."}},"definableWords":[],"peopleInVerse":[]},"30":{"text":"Hereafter I will not talk much with you: for the prince of this world cometh, and hath nothing in me.","ref":"John 14:30","synthesized":"I will not speak with you much longer, for the prince of this world is coming, and he has no claim on Me.","sources":{"KJV":{"text":"Hereafter I will not talk much with you: for the prince of this world cometh, and hath nothing in me."},"BSB":{"text":"I will not speak with you much longer, for the prince of this world is coming, and he has no claim on Me."}},"definableWords":["prince"],"peopleInVerse":[]},"31":{"text":"But that the world may know that I love the Father; and as the Father gave me commandment, even so I do. Arise, let us go hence.","ref":"John 14:31","synthesized":"But I do exactly what the Father has commanded Me, so that the world may know that I love the Father.  Get up! Let us go on from here.","sources":{"KJV":{"text":"But that the world may know that I love the Father; and as the Father gave me commandment, even so I do. Arise, let us go hence."},"BSB":{"text":"But I do exactly what the Father has commanded Me, so that the world may know that I love the Father.  Get up! Let us go on from here."}},"definableWords":["Father","love"],"peopleInVerse":[]}}},"15":{"chapter":"15","title":"I AM THE TRUE VINE","verses":{"1":{"text":"I am the true vine, and my Father is the husbandman.","ref":"John 15:1","synthesized":"“I am the true vine, and My Father is the keeper of the vineyard.","sources":{"KJV":{"text":"I am the true vine, and my Father is the husbandman."},"BSB":{"text":"“I am the true vine, and My Father is the keeper of the vineyard."}},"definableWords":["Father"],"peopleInVerse":[]},"2":{"text":"Every branch in me that beareth not fruit he taketh away: and every branch that beareth fruit, he purgeth it, that it may bring forth more fruit.","ref":"John 15:2","synthesized":"He cuts off every branch in Me that bears no fruit, and every branch that does bear fruit, He prunes to make it even more fruitful.","sources":{"KJV":{"text":"Every branch in me that beareth not fruit he taketh away: and every branch that beareth fruit, he purgeth it, that it may bring forth more fruit."},"BSB":{"text":"He cuts off every branch in Me that bears no fruit, and every branch that does bear fruit, He prunes to make it even more fruitful."}},"definableWords":["make","fruitful"],"peopleInVerse":[]},"3":{"text":"Now ye are clean through the word which I have spoken unto you.","ref":"John 15:3","synthesized":"You are already clean because of the word I have spoken to you.","sources":{"KJV":{"text":"Now ye are clean through the word which I have spoken unto you."},"BSB":{"text":"You are already clean because of the word I have spoken to you."}},"definableWords":["word"],"peopleInVerse":[]},"4":{"text":"Abide in me, and I in you. As the branch cannot bear fruit of itself, except it abide in the vine; no more can ye, except ye abide in me.","ref":"John 15:4","synthesized":"Remain in Me, and I will remain in you. Just as no branch can bear fruit by itself unless it remains in the vine, neither can you bear fruit unless you remain in Me.","sources":{"KJV":{"text":"Abide in me, and I in you. As the branch cannot bear fruit of itself, except it abide in the vine; no more can ye, except ye abide in me."},"BSB":{"text":"Remain in Me, and I will remain in you. Just as no branch can bear fruit by itself unless it remains in the vine, neither can you bear fruit unless you remain in Me."}},"definableWords":[],"peopleInVerse":[]},"5":{"text":"I am the vine, ye are the branches: He that abideth in me, and I in him, the same bringeth forth much fruit: for without me ye can do nothing.","ref":"John 15:5","synthesized":"I am the vine and you are the branches. The one who remains in Me, and I in him, will bear much fruit. For apart from Me you can do nothing.","sources":{"KJV":{"text":"I am the vine, ye are the branches: He that abideth in me, and I in him, the same bringeth forth much fruit: for without me ye can do nothing."},"BSB":{"text":"I am the vine and you are the branches. The one who remains in Me, and I in him, will bear much fruit. For apart from Me you can do nothing."}},"definableWords":["one"],"peopleInVerse":[]},"6":{"text":"If a man abide not in me, he is cast forth as a branch, and is withered; and men gather them, and cast them into the fire, and they are burned.","ref":"John 15:6","synthesized":"If anyone does not remain in Me, he is like a branch that is thrown away and withers. Such branches are gathered up, thrown into the fire, and burned.","sources":{"KJV":{"text":"If a man abide not in me, he is cast forth as a branch, and is withered; and men gather them, and cast them into the fire, and they are burned."},"BSB":{"text":"If anyone does not remain in Me, he is like a branch that is thrown away and withers. Such branches are gathered up, thrown into the fire, and burned."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"If ye abide in me, and my words abide in you, ye shall ask what ye will, and it shall be done unto you.","ref":"John 15:7","synthesized":"If you remain in Me and My words remain in you, ask whatever you wish, and it will be done for you.","sources":{"KJV":{"text":"If ye abide in me, and my words abide in you, ye shall ask what ye will, and it shall be done unto you."},"BSB":{"text":"If you remain in Me and My words remain in you, ask whatever you wish, and it will be done for you."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"Herein is my Father glorified, that ye bear much fruit; so shall ye be my disciples.","ref":"John 15:8","synthesized":"This is to My Father’s glory, that you bear much fruit, proving yourselves to be My disciples.","sources":{"KJV":{"text":"Herein is my Father glorified, that ye bear much fruit; so shall ye be my disciples."},"BSB":{"text":"This is to My Father’s glory, that you bear much fruit, proving yourselves to be My disciples."}},"definableWords":["Father","glory"],"peopleInVerse":[]},"9":{"text":"As the Father hath loved me, so have I loved you: continue ye in my love.","ref":"John 15:9","synthesized":"As the Father has loved Me, so have I loved you. Remain in My love.","sources":{"KJV":{"text":"As the Father hath loved me, so have I loved you: continue ye in my love."},"BSB":{"text":"As the Father has loved Me, so have I loved you. Remain in My love."}},"definableWords":["Father","love"],"peopleInVerse":[]},"10":{"text":"If ye keep my commandments, ye shall abide in my love; even as I have kept my Father’s commandments, and abide in his love.","ref":"John 15:10","synthesized":"If you keep My commandments, you will remain in My love, just as I have kept My Father’s commandments and remain in His love.","sources":{"KJV":{"text":"If ye keep my commandments, ye shall abide in my love; even as I have kept my Father’s commandments, and abide in his love."},"BSB":{"text":"If you keep My commandments, you will remain in My love, just as I have kept My Father’s commandments and remain in His love."}},"definableWords":["keep","love","Father"],"peopleInVerse":[]},"11":{"text":"These things have I spoken unto you, that my joy might remain in you, and that your joy might be full.","ref":"John 15:11","synthesized":"I have told you these things so that My joy may be in you and your joy may be complete.","sources":{"KJV":{"text":"These things have I spoken unto you, that my joy might remain in you, and that your joy might be full."},"BSB":{"text":"I have told you these things so that My joy may be in you and your joy may be complete."}},"definableWords":["joy"],"peopleInVerse":[]},"12":{"text":"This is my commandment, That ye love one another, as I have loved you.","ref":"John 15:12","synthesized":"This is My commandment, that you love one another as I have loved you.","sources":{"KJV":{"text":"This is my commandment, That ye love one another, as I have loved you."},"BSB":{"text":"This is My commandment, that you love one another as I have loved you."}},"definableWords":["commandment","love","one"],"peopleInVerse":[]},"13":{"text":"Greater love hath no man than this, that a man lay down his life for his friends.","ref":"John 15:13","synthesized":"Greater love has no one than this, that he lay down his life for his friends.","sources":{"KJV":{"text":"Greater love hath no man than this, that a man lay down his life for his friends."},"BSB":{"text":"Greater love has no one than this, that he lay down his life for his friends."}},"definableWords":["love","one","life"],"peopleInVerse":[]},"14":{"text":"Ye are my friends, if ye do whatsoever I command you.","ref":"John 15:14","synthesized":"You are My friends if you do what I command you.","sources":{"KJV":{"text":"Ye are my friends, if ye do whatsoever I command you."},"BSB":{"text":"You are My friends if you do what I command you."}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"Henceforth I call you not servants; for the servant knoweth not what his lord doeth: but I have called you friends; for all things that I have heard of my Father I have made known unto you.","ref":"John 15:15","synthesized":"No longer do I call you servants, for a servant does not understand what his master is doing. But I have called you friends, because everything I have learned from My Father I have made known to you.","sources":{"KJV":{"text":"Henceforth I call you not servants; for the servant knoweth not what his lord doeth: but I have called you friends; for all things that I have heard of my Father I have made known unto you."},"BSB":{"text":"No longer do I call you servants, for a servant does not understand what his master is doing. But I have called you friends, because everything I have learned from My Father I have made known to you."}},"definableWords":["servants","servant","Father","made"],"peopleInVerse":[]},"16":{"text":"Ye have not chosen me, but I have chosen you, and ordained you, that ye should go and bring forth fruit, and that your fruit should remain: that whatsoever ye shall ask of the Father in my name, he may give it you.","ref":"John 15:16","synthesized":"You did not choose Me, but I chose you. And I appointed you to go and bear fruit—fruit that will remain—so that whatever you ask the Father in My name, He will give you.","sources":{"KJV":{"text":"Ye have not chosen me, but I have chosen you, and ordained you, that ye should go and bring forth fruit, and that your fruit should remain: that whatsoever ye shall ask of the Father in my name, he may give it you."},"BSB":{"text":"You did not choose Me, but I chose you. And I appointed you to go and bear fruit—fruit that will remain—so that whatever you ask the Father in My name, He will give you."}},"definableWords":["Father","name"],"peopleInVerse":[]},"17":{"text":"These things I command you, that ye love one another.","ref":"John 15:17","synthesized":"This is My command to you: Love one another.","sources":{"KJV":{"text":"These things I command you, that ye love one another."},"BSB":{"text":"This is My command to you: Love one another."}},"definableWords":["love","one"],"peopleInVerse":[]},"18":{"text":"If the world hate you, ye know that it hated me before it hated you.","ref":"John 15:18","synthesized":"If the world hates you, understand that it hated Me first.","sources":{"KJV":{"text":"If the world hate you, ye know that it hated me before it hated you."},"BSB":{"text":"If the world hates you, understand that it hated Me first."}},"definableWords":[],"peopleInVerse":[]},"19":{"text":"If ye were of the world, the world would love his own: but because ye are not of the world, but I have chosen you out of the world, therefore the world hateth you.","ref":"John 15:19","synthesized":"If you were of the world, it would love you as its own. Instead, the world hates you, because you are not of the world, but I have chosen you out of the world.","sources":{"KJV":{"text":"If ye were of the world, the world would love his own: but because ye are not of the world, but I have chosen you out of the world, therefore the world hateth you."},"BSB":{"text":"If you were of the world, it would love you as its own. Instead, the world hates you, because you are not of the world, but I have chosen you out of the world."}},"definableWords":["love"],"peopleInVerse":[]},"20":{"text":"Remember the word that I said unto you, The servant is not greater than his lord. If they have persecuted me, they will also persecute you; if they have kept my saying, they will keep yours also.","ref":"John 15:20","synthesized":"Remember the word that I spoke to you: ‘No servant is greater than his master.’ If they persecuted Me, they will persecute you as well; if they kept My word, they will keep yours as well.","sources":{"KJV":{"text":"Remember the word that I said unto you, The servant is not greater than his lord. If they have persecuted me, they will also persecute you; if they have kept my saying, they will keep yours also."},"BSB":{"text":"Remember the word that I spoke to you: ‘No servant is greater than his master.’ If they persecuted Me, they will persecute you as well; if they kept My word, they will keep yours as well."}},"definableWords":["remember","word","servant","keep"],"peopleInVerse":[]},"21":{"text":"But all these things will they do unto you for my name’s sake, because they know not him that sent me.","ref":"John 15:21","synthesized":"But they will treat you like this because of My name, since they do not know the One who sent Me.","sources":{"KJV":{"text":"But all these things will they do unto you for my name’s sake, because they know not him that sent me."},"BSB":{"text":"But they will treat you like this because of My name, since they do not know the One who sent Me."}},"definableWords":["name","one"],"peopleInVerse":[]},"22":{"text":"If I had not come and spoken unto them, they had not had sin: but now they have no cloak for their sin.","ref":"John 15:22","synthesized":"If I had not come and spoken to them, they would not be guilty of sin. Now, however, they have no excuse for their sin.","sources":{"KJV":{"text":"If I had not come and spoken unto them, they had not had sin: but now they have no cloak for their sin."},"BSB":{"text":"If I had not come and spoken to them, they would not be guilty of sin. Now, however, they have no excuse for their sin."}},"definableWords":["sin"],"peopleInVerse":[]},"23":{"text":"He that hateth me hateth my Father also.","ref":"John 15:23","synthesized":"Whoever hates Me hates My Father as well.","sources":{"KJV":{"text":"He that hateth me hateth my Father also."},"BSB":{"text":"Whoever hates Me hates My Father as well."}},"definableWords":["Father"],"peopleInVerse":[]},"24":{"text":"If I had not done among them the works which none other man did, they had not had sin: but now have they both seen and hated both me and my Father.","ref":"John 15:24","synthesized":"If I had not done among them the works that no one else did, they would not be guilty of sin; but now they have seen and hated both Me and My Father.","sources":{"KJV":{"text":"If I had not done among them the works which none other man did, they had not had sin: but now have they both seen and hated both me and my Father."},"BSB":{"text":"If I had not done among them the works that no one else did, they would not be guilty of sin; but now they have seen and hated both Me and My Father."}},"definableWords":["works","one","sin","Father"],"peopleInVerse":[]},"25":{"text":"But this cometh to pass, that the word might be fulfilled that is written in their law, They hated me without a cause.","ref":"John 15:25","synthesized":"But this is to fulfill what is written in their Law: ‘They hated Me without reason.’","sources":{"KJV":{"text":"But this cometh to pass, that the word might be fulfilled that is written in their law, They hated me without a cause."},"BSB":{"text":"But this is to fulfill what is written in their Law: ‘They hated Me without reason.’"}},"definableWords":["law"],"peopleInVerse":[]},"26":{"text":"But when the Comforter is come, whom I will send unto you from the Father, even the Spirit of truth, which proceedeth from the Father, he shall testify of me:","ref":"John 15:26","synthesized":"When the Advocate comes, whom I will send to you from the Father—the Spirit of truth who proceeds from the Father—He will testify about Me.","sources":{"KJV":{"text":"But when the Comforter is come, whom I will send unto you from the Father, even the Spirit of truth, which proceedeth from the Father, he shall testify of me:"},"BSB":{"text":"When the Advocate comes, whom I will send to you from the Father—the Spirit of truth who proceeds from the Father—He will testify about Me."}},"definableWords":["Father","Spirit","truth"],"peopleInVerse":[]},"27":{"text":"And ye also shall bear witness, because ye have been with me from the beginning.","ref":"John 15:27","synthesized":"And you also must testify, because you have been with Me from the beginning.","sources":{"KJV":{"text":"And ye also shall bear witness, because ye have been with me from the beginning."},"BSB":{"text":"And you also must testify, because you have been with Me from the beginning."}},"definableWords":["beginning"],"peopleInVerse":[]}}},"16":{"chapter":"16","title":"THE COMFORTER PROMISED","verses":{"1":{"text":"These things have I spoken unto you, that ye should not be offended.","ref":"John 16:1","synthesized":"“I have told you these things so that you will not fall away.","sources":{"KJV":{"text":"These things have I spoken unto you, that ye should not be offended."},"BSB":{"text":"“I have told you these things so that you will not fall away."}},"definableWords":[],"peopleInVerse":[]},"2":{"text":"They shall put you out of the synagogues: yea, the time cometh, that whosoever killeth you will think that he doeth God service.","ref":"John 16:2","synthesized":"They will put you out of the synagogues. In fact, a time is coming when anyone who kills you will think he is offering a service to God.","sources":{"KJV":{"text":"They shall put you out of the synagogues: yea, the time cometh, that whosoever killeth you will think that he doeth God service."},"BSB":{"text":"They will put you out of the synagogues. In fact, a time is coming when anyone who kills you will think he is offering a service to God."}},"definableWords":["offering","God"],"peopleInVerse":[]},"3":{"text":"And these things will they do unto you, because they have not known the Father, nor me.","ref":"John 16:3","synthesized":"They will do these things because they have not known the Father or Me.","sources":{"KJV":{"text":"And these things will they do unto you, because they have not known the Father, nor me."},"BSB":{"text":"They will do these things because they have not known the Father or Me."}},"definableWords":["Father","or"],"peopleInVerse":[]},"4":{"text":"But these things have I told you, that when the time shall come, ye may remember that I told you of them. And these things I said not unto you at the beginning, because I was with you.","ref":"John 16:4","synthesized":"But I have told you these things so that when their hour comes, you will remember that I told you about them. I did not tell you these things from the beginning, because I was with you.","sources":{"KJV":{"text":"But these things have I told you, that when the time shall come, ye may remember that I told you of them. And these things I said not unto you at the beginning, because I was with you."},"BSB":{"text":"But I have told you these things so that when their hour comes, you will remember that I told you about them. I did not tell you these things from the beginning, because I was with you."}},"definableWords":["remember","beginning"],"peopleInVerse":[]},"5":{"text":"But now I go my way to him that sent me; and none of you asketh me, Whither goest thou?","ref":"John 16:5","synthesized":"Now, however, I am going to Him who sent Me; yet none of you asks Me, ‘Where are You going?’","sources":{"KJV":{"text":"But now I go my way to him that sent me; and none of you asketh me, Whither goest thou?"},"BSB":{"text":"Now, however, I am going to Him who sent Me; yet none of you asks Me, ‘Where are You going?’"}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"But because I have said these things unto you, sorrow hath filled your heart.","ref":"John 16:6","synthesized":"Instead, your hearts are filled with sorrow because I have told you these things.","sources":{"KJV":{"text":"But because I have said these things unto you, sorrow hath filled your heart."},"BSB":{"text":"Instead, your hearts are filled with sorrow because I have told you these things."}},"definableWords":[],"peopleInVerse":[]},"7":{"text":"Nevertheless I tell you the truth; It is expedient for you that I go away: for if I go not away, the Comforter will not come unto you; but if I depart, I will send him unto you.","ref":"John 16:7","synthesized":"But I tell you the truth, it is for your benefit that I am going away. Unless I go away, the Advocate will not come to you; but if I go, I will send Him to you.","sources":{"KJV":{"text":"Nevertheless I tell you the truth; It is expedient for you that I go away: for if I go not away, the Comforter will not come unto you; but if I depart, I will send him unto you."},"BSB":{"text":"But I tell you the truth, it is for your benefit that I am going away. Unless I go away, the Advocate will not come to you; but if I go, I will send Him to you."}},"definableWords":["truth"],"peopleInVerse":[]},"8":{"text":"And when he is come, he will reprove the world of sin, and of righteousness, and of judgment:","ref":"John 16:8","synthesized":"And when He comes, He will convict the world in regard to sin and righteousness and judgment:","sources":{"KJV":{"text":"And when he is come, he will reprove the world of sin, and of righteousness, and of judgment:"},"BSB":{"text":"And when He comes, He will convict the world in regard to sin and righteousness and judgment:"}},"definableWords":["sin","righteousness","judgment"],"peopleInVerse":[]},"9":{"text":"Of sin, because they believe not on me;","ref":"John 16:9","synthesized":"in regard to sin, because they do not believe in Me;","sources":{"KJV":{"text":"Of sin, because they believe not on me;"},"BSB":{"text":"in regard to sin, because they do not believe in Me;"}},"definableWords":["sin"],"peopleInVerse":[]},"10":{"text":"Of righteousness, because I go to my Father, and ye see me no more;","ref":"John 16:10","synthesized":"in regard to righteousness, because I am going to the Father and you will no longer see Me;","sources":{"KJV":{"text":"Of righteousness, because I go to my Father, and ye see me no more;"},"BSB":{"text":"in regard to righteousness, because I am going to the Father and you will no longer see Me;"}},"definableWords":["righteousness","Father","see"],"peopleInVerse":[]},"11":{"text":"Of judgment, because the prince of this world is judged.","ref":"John 16:11","synthesized":"and in regard to judgment, because the prince of this world has been condemned.","sources":{"KJV":{"text":"Of judgment, because the prince of this world is judged."},"BSB":{"text":"and in regard to judgment, because the prince of this world has been condemned."}},"definableWords":["judgment","prince"],"peopleInVerse":[]},"12":{"text":"I have yet many things to say unto you, but ye cannot bear them now.","ref":"John 16:12","synthesized":"I still have much to tell you, but you cannot yet bear to hear it.","sources":{"KJV":{"text":"I have yet many things to say unto you, but ye cannot bear them now."},"BSB":{"text":"I still have much to tell you, but you cannot yet bear to hear it."}},"definableWords":["hear"],"peopleInVerse":[]},"13":{"text":"Howbeit when he, the Spirit of truth, is come, he will guide you into all truth: for he shall not speak of himself; but whatsoever he shall hear, that shall he speak: and he will shew you things to come.","ref":"John 16:13","synthesized":"However, when the Spirit of truth comes, He will guide you into all truth. For He will not speak on His own, but He will speak what He hears, and He will declare to you what is to come.","sources":{"KJV":{"text":"Howbeit when he, the Spirit of truth, is come, he will guide you into all truth: for he shall not speak of himself; but whatsoever he shall hear, that shall he speak: and he will shew you things to come."},"BSB":{"text":"However, when the Spirit of truth comes, He will guide you into all truth. For He will not speak on His own, but He will speak what He hears, and He will declare to you what is to come."}},"definableWords":["Spirit","truth"],"peopleInVerse":[]},"14":{"text":"He shall glorify me: for he shall receive of mine, and shall shew it unto you.","ref":"John 16:14","synthesized":"He will glorify Me by taking from what is Mine and disclosing it to you.","sources":{"KJV":{"text":"He shall glorify me: for he shall receive of mine, and shall shew it unto you."},"BSB":{"text":"He will glorify Me by taking from what is Mine and disclosing it to you."}},"definableWords":[],"peopleInVerse":[]},"15":{"text":"All things that the Father hath are mine: therefore said I, that he shall take of mine, and shall shew it unto you.","ref":"John 16:15","synthesized":"Everything that belongs to the Father is Mine. That is why I said that the Spirit will take from what is Mine and disclose it to you.","sources":{"KJV":{"text":"All things that the Father hath are mine: therefore said I, that he shall take of mine, and shall shew it unto you."},"BSB":{"text":"Everything that belongs to the Father is Mine. That is why I said that the Spirit will take from what is Mine and disclose it to you."}},"definableWords":["Father","Spirit"],"peopleInVerse":[]},"16":{"text":"A little while, and ye shall not see me: and again, a little while, and ye shall see me, because I go to the Father.","ref":"John 16:16","synthesized":"In a little while you will see Me no more, and then after a little while you will see Me.”","sources":{"KJV":{"text":"A little while, and ye shall not see me: and again, a little while, and ye shall see me, because I go to the Father."},"BSB":{"text":"In a little while you will see Me no more, and then after a little while you will see Me.”"}},"definableWords":["see"],"peopleInVerse":[]},"17":{"text":"Then said some of his disciples among themselves, What is this that he saith unto us, A little while, and ye shall not see me: and again, a little while, and ye shall see me: and, Because I go to the Father?","ref":"John 16:17","synthesized":"Then some of His disciples asked one another, “Why is He telling us, ‘In a little while you will not see Me, and then after a little while you will see Me’ and ‘Because I am going to the Father’?”","sources":{"KJV":{"text":"Then said some of his disciples among themselves, What is this that he saith unto us, A little while, and ye shall not see me: and again, a little while, and ye shall see me: and, Because I go to the Father?"},"BSB":{"text":"Then some of His disciples asked one another, “Why is He telling us, ‘In a little while you will not see Me, and then after a little while you will see Me’ and ‘Because I am going to the Father’?”"}},"definableWords":["one","see","Father"],"peopleInVerse":[]},"18":{"text":"They said therefore, What is this that he saith, A little while? we cannot tell what he saith.","ref":"John 16:18","synthesized":"They kept asking, “Why is He saying, ‘a little while’? We do not understand what He is saying.”","sources":{"KJV":{"text":"They said therefore, What is this that he saith, A little while? we cannot tell what he saith."},"BSB":{"text":"They kept asking, “Why is He saying, ‘a little while’? We do not understand what He is saying.”"}},"definableWords":[],"peopleInVerse":[]},"19":{"text":"Now Jesus knew that they were desirous to ask him, and said unto them, Do ye enquire among yourselves of that I said, A little while, and ye shall not see me: and again, a little while, and ye shall see me?","ref":"John 16:19","synthesized":"Aware that they wanted to question Him, Jesus said to them, “Are you asking one another why I said, ‘In a little while you will not see Me, and then after a little while you will see Me’?","sources":{"KJV":{"text":"Now Jesus knew that they were desirous to ask him, and said unto them, Do ye enquire among yourselves of that I said, A little while, and ye shall not see me: and again, a little while, and ye shall see me?"},"BSB":{"text":"Aware that they wanted to question Him, Jesus said to them, “Are you asking one another why I said, ‘In a little while you will not see Me, and then after a little while you will see Me’?"}},"definableWords":["one","see"],"peopleInVerse":["Jesus"]},"20":{"text":"Verily, verily, I say unto you, That ye shall weep and lament, but the world shall rejoice: and ye shall be sorrowful, but your sorrow shall be turned into joy.","ref":"John 16:20","synthesized":"Truly, truly, I tell you, you will weep and wail while the world rejoices. You will grieve, but your grief will turn to joy.","sources":{"KJV":{"text":"Verily, verily, I say unto you, That ye shall weep and lament, but the world shall rejoice: and ye shall be sorrowful, but your sorrow shall be turned into joy."},"BSB":{"text":"Truly, truly, I tell you, you will weep and wail while the world rejoices. You will grieve, but your grief will turn to joy."}},"definableWords":["joy"],"peopleInVerse":[]},"21":{"text":"A woman when she is in travail hath sorrow, because her hour is come: but as soon as she is delivered of the child, she remembereth no more the anguish, for joy that a man is born into the world.","ref":"John 16:21","synthesized":"A woman has pain in childbirth because her time has come; but when she brings forth her child, she forgets her anguish because of her joy that a child has been born into the world.","sources":{"KJV":{"text":"A woman when she is in travail hath sorrow, because her hour is come: but as soon as she is delivered of the child, she remembereth no more the anguish, for joy that a man is born into the world."},"BSB":{"text":"A woman has pain in childbirth because her time has come; but when she brings forth her child, she forgets her anguish because of her joy that a child has been born into the world."}},"definableWords":["woman","joy"],"peopleInVerse":[]},"22":{"text":"And ye now therefore have sorrow: but I will see you again, and your heart shall rejoice, and your joy no man taketh from you.","ref":"John 16:22","synthesized":"So also you have sorrow now, but I will see you again and your hearts will rejoice, and no one will take away your joy.","sources":{"KJV":{"text":"And ye now therefore have sorrow: but I will see you again, and your heart shall rejoice, and your joy no man taketh from you."},"BSB":{"text":"So also you have sorrow now, but I will see you again and your hearts will rejoice, and no one will take away your joy."}},"definableWords":["see","one","joy"],"peopleInVerse":[]},"23":{"text":"And in that day ye shall ask me nothing. Verily, verily, I say unto you, Whatsoever ye shall ask the Father in my name, he will give it you.","ref":"John 16:23","synthesized":"In that day you will no longer ask Me anything. Truly, truly, I tell you, whatever you ask the Father in My name, He will give you.","sources":{"KJV":{"text":"And in that day ye shall ask me nothing. Verily, verily, I say unto you, Whatsoever ye shall ask the Father in my name, he will give it you."},"BSB":{"text":"In that day you will no longer ask Me anything. Truly, truly, I tell you, whatever you ask the Father in My name, He will give you."}},"definableWords":["day","Father","name"],"peopleInVerse":[]},"24":{"text":"Hitherto have ye asked nothing in my name: ask, and ye shall receive, that your joy may be full.","ref":"John 16:24","synthesized":"Until now you have not asked for anything in My name. Ask and you will receive, so that your joy may be complete.","sources":{"KJV":{"text":"Hitherto have ye asked nothing in my name: ask, and ye shall receive, that your joy may be full."},"BSB":{"text":"Until now you have not asked for anything in My name. Ask and you will receive, so that your joy may be complete."}},"definableWords":["name","joy"],"peopleInVerse":[]},"25":{"text":"These things have I spoken unto you in proverbs: but the time cometh, when I shall no more speak unto you in proverbs, but I shall shew you plainly of the Father.","ref":"John 16:25","synthesized":"I have spoken these things to you in figures of speech. An hour is coming when I will no longer speak to you this way, but will tell you plainly about the Father.","sources":{"KJV":{"text":"These things have I spoken unto you in proverbs: but the time cometh, when I shall no more speak unto you in proverbs, but I shall shew you plainly of the Father."},"BSB":{"text":"I have spoken these things to you in figures of speech. An hour is coming when I will no longer speak to you this way, but will tell you plainly about the Father."}},"definableWords":["way","Father"],"peopleInVerse":[]},"26":{"text":"At that day ye shall ask in my name: and I say not unto you, that I will pray the Father for you:","ref":"John 16:26","synthesized":"In that day you will ask in My name. I am not saying that I will ask the Father on your behalf.","sources":{"KJV":{"text":"At that day ye shall ask in my name: and I say not unto you, that I will pray the Father for you:"},"BSB":{"text":"In that day you will ask in My name. I am not saying that I will ask the Father on your behalf."}},"definableWords":["day","name","Father"],"peopleInVerse":[]},"27":{"text":"For the Father himself loveth you, because ye have loved me, and have believed that I came out from God.","ref":"John 16:27","synthesized":"For the Father Himself loves you, because you have loved Me and have believed that I came from God.","sources":{"KJV":{"text":"For the Father himself loveth you, because ye have loved me, and have believed that I came out from God."},"BSB":{"text":"For the Father Himself loves you, because you have loved Me and have believed that I came from God."}},"definableWords":["Father","believed","God"],"peopleInVerse":[]},"28":{"text":"I came forth from the Father, and am come into the world: again, I leave the world, and go to the Father.","ref":"John 16:28","synthesized":"I came from the Father and entered the world. In turn, I will leave the world and go to the Father.”","sources":{"KJV":{"text":"I came forth from the Father, and am come into the world: again, I leave the world, and go to the Father."},"BSB":{"text":"I came from the Father and entered the world. In turn, I will leave the world and go to the Father.”"}},"definableWords":["Father"],"peopleInVerse":[]},"29":{"text":"His disciples said unto him, Lo, now speakest thou plainly, and speakest no proverb.","ref":"John 16:29","synthesized":"His disciples said, “See, now You are speaking plainly and without figures of speech.","sources":{"KJV":{"text":"His disciples said unto him, Lo, now speakest thou plainly, and speakest no proverb."},"BSB":{"text":"His disciples said, “See, now You are speaking plainly and without figures of speech."}},"definableWords":["see"],"peopleInVerse":[]},"30":{"text":"Now are we sure that thou knowest all things, and needest not that any man should ask thee: by this we believe that thou camest forth from God.","ref":"John 16:30","synthesized":"Now we understand that You know all things and that You have no need for anyone to question You. Because of this, we believe that You came from God.”","sources":{"KJV":{"text":"Now are we sure that thou knowest all things, and needest not that any man should ask thee: by this we believe that thou camest forth from God."},"BSB":{"text":"Now we understand that You know all things and that You have no need for anyone to question You. Because of this, we believe that You came from God.”"}},"definableWords":["God"],"peopleInVerse":[]},"31":{"text":"Jesus answered them, Do ye now believe?","ref":"John 16:31","synthesized":"“Do you finally believe?” Jesus replied.","sources":{"KJV":{"text":"Jesus answered them, Do ye now believe?"},"BSB":{"text":"“Do you finally believe?” Jesus replied."}},"definableWords":[],"peopleInVerse":["Jesus"]},"32":{"text":"Behold, the hour cometh, yea, is now come, that ye shall be scattered, every man to his own, and shall leave me alone: and yet I am not alone, because the Father is with me.","ref":"John 16:32","synthesized":"“Look, an hour is coming and has already come when you will be scattered, each to his own home, and you will leave Me all alone. Yet I am not alone, because the Father is with Me.","sources":{"KJV":{"text":"Behold, the hour cometh, yea, is now come, that ye shall be scattered, every man to his own, and shall leave me alone: and yet I am not alone, because the Father is with me."},"BSB":{"text":"“Look, an hour is coming and has already come when you will be scattered, each to his own home, and you will leave Me all alone. Yet I am not alone, because the Father is with Me."}},"definableWords":["Father"],"peopleInVerse":[]},"33":{"text":"These things I have spoken unto you, that in me ye might have peace. In the world ye shall have tribulation: but be of good cheer; I have overcome the world.","ref":"John 16:33","synthesized":"I have told you these things so that in Me you may have peace. In the world you will have tribulation. But take courage; I have overcome the world!”","sources":{"KJV":{"text":"These things I have spoken unto you, that in me ye might have peace. In the world ye shall have tribulation: but be of good cheer; I have overcome the world."},"BSB":{"text":"I have told you these things so that in Me you may have peace. In the world you will have tribulation. But take courage; I have overcome the world!”"}},"definableWords":["peace","overcome"],"peopleInVerse":[]}}},"17":{"chapter":"17","title":"THE HIGH PRIESTLY PRAYER","verses":{"1":{"text":"These words spake Jesus, and lifted up his eyes to heaven, and said, Father, the hour is come; glorify thy Son, that thy Son also may glorify thee:","ref":"John 17:1","synthesized":"When Jesus had spoken these things, He lifted up His eyes to heaven and said, “Father, the hour has come. Glorify Your Son, that Your Son may glorify You.","sources":{"KJV":{"text":"These words spake Jesus, and lifted up his eyes to heaven, and said, Father, the hour is come; glorify thy Son, that thy Son also may glorify thee:"},"BSB":{"text":"When Jesus had spoken these things, He lifted up His eyes to heaven and said, “Father, the hour has come. Glorify Your Son, that Your Son may glorify You."}},"definableWords":["heaven","Father","Son"],"peopleInVerse":["Jesus"]},"2":{"text":"As thou hast given him power over all flesh, that he should give eternal life to as many as thou hast given him.","ref":"John 17:2","synthesized":"For You granted Him authority over all people, so that He may give eternal life to all those You have given Him.","sources":{"KJV":{"text":"As thou hast given him power over all flesh, that he should give eternal life to as many as thou hast given him."},"BSB":{"text":"For You granted Him authority over all people, so that He may give eternal life to all those You have given Him."}},"definableWords":["people","eternal","life"],"peopleInVerse":[]},"3":{"text":"And this is life eternal, that they might know thee the only true God, and Jesus Christ, whom thou hast sent.","ref":"John 17:3","synthesized":"Now this is eternal life, that they may know You, the only true God, and Jesus Christ, whom You have sent.","sources":{"KJV":{"text":"And this is life eternal, that they might know thee the only true God, and Jesus Christ, whom thou hast sent."},"BSB":{"text":"Now this is eternal life, that they may know You, the only true God, and Jesus Christ, whom You have sent."}},"definableWords":["eternal","life","God","Christ"],"peopleInVerse":["Jesus"]},"4":{"text":"I have glorified thee on the earth: I have finished the work which thou gavest me to do.","ref":"John 17:4","synthesized":"I have glorified You on earth by accomplishing the work You gave Me to do.","sources":{"KJV":{"text":"I have glorified thee on the earth: I have finished the work which thou gavest me to do."},"BSB":{"text":"I have glorified You on earth by accomplishing the work You gave Me to do."}},"definableWords":["earth","work"],"peopleInVerse":[]},"5":{"text":"And now, O Father, glorify thou me with thine own self with the glory which I had with thee before the world was.","ref":"John 17:5","synthesized":"And now, Father, glorify Me in Your presence with the glory I had with You before the world existed.","sources":{"KJV":{"text":"And now, O Father, glorify thou me with thine own self with the glory which I had with thee before the world was."},"BSB":{"text":"And now, Father, glorify Me in Your presence with the glory I had with You before the world existed."}},"definableWords":["Father","glory"],"peopleInVerse":[]},"6":{"text":"I have manifested thy name unto the men which thou gavest me out of the world: thine they were, and thou gavest them me; and they have kept thy word.","ref":"John 17:6","synthesized":"I have revealed Your name to those You have given Me out of the world. They were Yours; You gave them to Me, and they have kept Your word.","sources":{"KJV":{"text":"I have manifested thy name unto the men which thou gavest me out of the world: thine they were, and thou gavest them me; and they have kept thy word."},"BSB":{"text":"I have revealed Your name to those You have given Me out of the world. They were Yours; You gave them to Me, and they have kept Your word."}},"definableWords":["name","word"],"peopleInVerse":[]},"7":{"text":"Now they have known that all things whatsoever thou hast given me are of thee.","ref":"John 17:7","synthesized":"Now they know that everything You have given Me comes from You.","sources":{"KJV":{"text":"Now they have known that all things whatsoever thou hast given me are of thee."},"BSB":{"text":"Now they know that everything You have given Me comes from You."}},"definableWords":[],"peopleInVerse":[]},"8":{"text":"For I have given unto them the words which thou gavest me; and they have received them, and have known surely that I came out from thee, and they have believed that thou didst send me.","ref":"John 17:8","synthesized":"For I have given them the words You gave Me, and they have received them. They knew with certainty that I came from You, and they believed that You sent Me.","sources":{"KJV":{"text":"For I have given unto them the words which thou gavest me; and they have received them, and have known surely that I came out from thee, and they have believed that thou didst send me."},"BSB":{"text":"For I have given them the words You gave Me, and they have received them. They knew with certainty that I came from You, and they believed that You sent Me."}},"definableWords":["believed"],"peopleInVerse":[]},"9":{"text":"I pray for them: I pray not for the world, but for them which thou hast given me; for they are thine.","ref":"John 17:9","synthesized":"I ask on their behalf. I do not ask on behalf of the world, but on behalf of those You have given Me; for they are Yours.","sources":{"KJV":{"text":"I pray for them: I pray not for the world, but for them which thou hast given me; for they are thine."},"BSB":{"text":"I ask on their behalf. I do not ask on behalf of the world, but on behalf of those You have given Me; for they are Yours."}},"definableWords":[],"peopleInVerse":[]},"10":{"text":"And all mine are thine, and thine are mine; and I am glorified in them.","ref":"John 17:10","synthesized":"All I have is Yours, and all You have is Mine; and in them I have been glorified.","sources":{"KJV":{"text":"And all mine are thine, and thine are mine; and I am glorified in them."},"BSB":{"text":"All I have is Yours, and all You have is Mine; and in them I have been glorified."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"And now I am no more in the world, but these are in the world, and I come to thee. Holy Father, keep through thine own name those whom thou hast given me, that they may be one, as we are.","ref":"John 17:11","synthesized":"I will no longer be in the world, but they are in the world, and I am coming to You.  Holy Father, protect them by Your name, the name You gave Me, so that they may be one as We are one.","sources":{"KJV":{"text":"And now I am no more in the world, but these are in the world, and I come to thee. Holy Father, keep through thine own name those whom thou hast given me, that they may be one, as we are."},"BSB":{"text":"I will no longer be in the world, but they are in the world, and I am coming to You.  Holy Father, protect them by Your name, the name You gave Me, so that they may be one as We are one."}},"definableWords":["holy","Father","name","one"],"peopleInVerse":[]},"12":{"text":"While I was with them in the world, I kept them in thy name: those that thou gavest me I have kept, and none of them is lost, but the son of perdition; that the scripture might be fulfilled.","ref":"John 17:12","synthesized":"While I was with them, I protected and preserved them by Your name, the name You gave Me. Not one of them has been lost, except the son of destruction, so that the Scripture would be fulfilled.","sources":{"KJV":{"text":"While I was with them in the world, I kept them in thy name: those that thou gavest me I have kept, and none of them is lost, but the son of perdition; that the scripture might be fulfilled."},"BSB":{"text":"While I was with them, I protected and preserved them by Your name, the name You gave Me. Not one of them has been lost, except the son of destruction, so that the Scripture would be fulfilled."}},"definableWords":["name","one","son"],"peopleInVerse":[]},"13":{"text":"And now come I to thee; and these things I speak in the world, that they might have my joy fulfilled in themselves.","ref":"John 17:13","synthesized":"But now I am coming to You; and I am saying these things while I am in the world, so that they may have My joy fulfilled within them.","sources":{"KJV":{"text":"And now come I to thee; and these things I speak in the world, that they might have my joy fulfilled in themselves."},"BSB":{"text":"But now I am coming to You; and I am saying these things while I am in the world, so that they may have My joy fulfilled within them."}},"definableWords":["joy"],"peopleInVerse":[]},"14":{"text":"I have given them thy word; and the world hath hated them, because they are not of the world, even as I am not of the world.","ref":"John 17:14","synthesized":"I have given them Your word and the world has hated them; for they are not of the world, just as I am not of the world.","sources":{"KJV":{"text":"I have given them thy word; and the world hath hated them, because they are not of the world, even as I am not of the world."},"BSB":{"text":"I have given them Your word and the world has hated them; for they are not of the world, just as I am not of the world."}},"definableWords":["word"],"peopleInVerse":[]},"15":{"text":"I pray not that thou shouldest take them out of the world, but that thou shouldest keep them from the evil.","ref":"John 17:15","synthesized":"I am not asking that You take them out of the world, but that You keep them from the evil one.","sources":{"KJV":{"text":"I pray not that thou shouldest take them out of the world, but that thou shouldest keep them from the evil."},"BSB":{"text":"I am not asking that You take them out of the world, but that You keep them from the evil one."}},"definableWords":["keep","evil","one"],"peopleInVerse":[]},"16":{"text":"They are not of the world, even as I am not of the world.","ref":"John 17:16","synthesized":"They are not of the world, just as I am not of the world.","sources":{"KJV":{"text":"They are not of the world, even as I am not of the world."},"BSB":{"text":"They are not of the world, just as I am not of the world."}},"definableWords":[],"peopleInVerse":[]},"17":{"text":"Sanctify them through thy truth: thy word is truth.","ref":"John 17:17","synthesized":"Sanctify them by the truth; Your word is truth.","sources":{"KJV":{"text":"Sanctify them through thy truth: thy word is truth."},"BSB":{"text":"Sanctify them by the truth; Your word is truth."}},"definableWords":["truth","word"],"peopleInVerse":[]},"18":{"text":"As thou hast sent me into the world, even so have I also sent them into the world.","ref":"John 17:18","synthesized":"As You sent Me into the world, I have also sent them into the world.","sources":{"KJV":{"text":"As thou hast sent me into the world, even so have I also sent them into the world."},"BSB":{"text":"As You sent Me into the world, I have also sent them into the world."}},"definableWords":[],"peopleInVerse":[]},"19":{"text":"And for their sakes I sanctify myself, that they also might be sanctified through the truth.","ref":"John 17:19","synthesized":"For them I sanctify Myself, so that they too may be sanctified by the truth.","sources":{"KJV":{"text":"And for their sakes I sanctify myself, that they also might be sanctified through the truth."},"BSB":{"text":"For them I sanctify Myself, so that they too may be sanctified by the truth."}},"definableWords":["truth"],"peopleInVerse":[]},"20":{"text":"Neither pray I for these alone, but for them also which shall believe on me through their word;","ref":"John 17:20","synthesized":"I am not asking on behalf of them alone, but also on behalf of those who will believe in Me through their message,","sources":{"KJV":{"text":"Neither pray I for these alone, but for them also which shall believe on me through their word;"},"BSB":{"text":"I am not asking on behalf of them alone, but also on behalf of those who will believe in Me through their message,"}},"definableWords":[],"peopleInVerse":[]},"21":{"text":"That they all may be one; as thou, Father, art in me, and I in thee, that they also may be one in us: that the world may believe that thou hast sent me.","ref":"John 17:21","synthesized":"that all of them may be one, as You, Father, are in Me, and I am in You. May they also be in Us, so that the world may believe that You sent Me.","sources":{"KJV":{"text":"That they all may be one; as thou, Father, art in me, and I in thee, that they also may be one in us: that the world may believe that thou hast sent me."},"BSB":{"text":"that all of them may be one, as You, Father, are in Me, and I am in You. May they also be in Us, so that the world may believe that You sent Me."}},"definableWords":["one","Father"],"peopleInVerse":[]},"22":{"text":"And the glory which thou gavest me I have given them; that they may be one, even as we are one:","ref":"John 17:22","synthesized":"I have given them the glory You gave Me, so that they may be one as We are one—","sources":{"KJV":{"text":"And the glory which thou gavest me I have given them; that they may be one, even as we are one:"},"BSB":{"text":"I have given them the glory You gave Me, so that they may be one as We are one—"}},"definableWords":["glory","one"],"peopleInVerse":[]},"23":{"text":"I in them, and thou in me, that they may be made perfect in one; and that the world may know that thou hast sent me, and hast loved them, as thou hast loved me.","ref":"John 17:23","synthesized":"I in them and You in Me—that they may be perfectly united, so that the world may know that You sent Me and have loved them just as You have loved Me.","sources":{"KJV":{"text":"I in them, and thou in me, that they may be made perfect in one; and that the world may know that thou hast sent me, and hast loved them, as thou hast loved me."},"BSB":{"text":"I in them and You in Me—that they may be perfectly united, so that the world may know that You sent Me and have loved them just as You have loved Me."}},"definableWords":[],"peopleInVerse":[]},"24":{"text":"Father, I will that they also, whom thou hast given me, be with me where I am; that they may behold my glory, which thou hast given me: for thou lovedst me before the foundation of the world.","ref":"John 17:24","synthesized":"Father, I want those You have given Me to be with Me where I am, that they may see the glory You gave Me because You loved Me before the foundation of the world.","sources":{"KJV":{"text":"Father, I will that they also, whom thou hast given me, be with me where I am; that they may behold my glory, which thou hast given me: for thou lovedst me before the foundation of the world."},"BSB":{"text":"Father, I want those You have given Me to be with Me where I am, that they may see the glory You gave Me because You loved Me before the foundation of the world."}},"definableWords":["Father","see","glory"],"peopleInVerse":[]},"25":{"text":"O righteous Father, the world hath not known thee: but I have known thee, and these have known that thou hast sent me.","ref":"John 17:25","synthesized":"Righteous Father, although the world has not known You, I know You, and they know that You sent Me.","sources":{"KJV":{"text":"O righteous Father, the world hath not known thee: but I have known thee, and these have known that thou hast sent me."},"BSB":{"text":"Righteous Father, although the world has not known You, I know You, and they know that You sent Me."}},"definableWords":["righteous","Father"],"peopleInVerse":[]},"26":{"text":"And I have declared unto them thy name, and will declare it: that the love wherewith thou hast loved me may be in them, and I in them.","ref":"John 17:26","synthesized":"And I have made Your name known to them and will continue to make it known, so that the love You have for Me may be in them, and I in them.”","sources":{"KJV":{"text":"And I have declared unto them thy name, and will declare it: that the love wherewith thou hast loved me may be in them, and I in them."},"BSB":{"text":"And I have made Your name known to them and will continue to make it known, so that the love You have for Me may be in them, and I in them.”"}},"definableWords":["made","name","make","love"],"peopleInVerse":[]}}},"18":{"chapter":"18","title":"THE ARREST AND TRIAL","verses":{"1":{"text":"When Jesus had spoken these words, he went forth with his disciples over the brook Cedron, where was a garden, into the which he entered, and his disciples.","ref":"John 18:1","synthesized":"After Jesus had spoken these words, He went out with His disciples across the Kidron Valley, where they entered a garden.","sources":{"KJV":{"text":"When Jesus had spoken these words, he went forth with his disciples over the brook Cedron, where was a garden, into the which he entered, and his disciples."},"BSB":{"text":"After Jesus had spoken these words, He went out with His disciples across the Kidron Valley, where they entered a garden."}},"definableWords":["garden"],"peopleInVerse":["Jesus"]},"2":{"text":"And Judas also, which betrayed him, knew the place: for Jesus ofttimes resorted thither with his disciples.","ref":"John 18:2","synthesized":"Now Judas His betrayer also knew the place, because Jesus had often met there with His disciples.","sources":{"KJV":{"text":"And Judas also, which betrayed him, knew the place: for Jesus ofttimes resorted thither with his disciples."},"BSB":{"text":"Now Judas His betrayer also knew the place, because Jesus had often met there with His disciples."}},"definableWords":[],"peopleInVerse":["Jesus"]},"3":{"text":"Judas then, having received a band of men and officers from the chief priests and Pharisees, cometh thither with lanterns and torches and weapons.","ref":"John 18:3","synthesized":"So Judas brought a band of soldiers and officers from the chief priests and Pharisees. They arrived at the garden carrying lanterns, torches, and weapons.","sources":{"KJV":{"text":"Judas then, having received a band of men and officers from the chief priests and Pharisees, cometh thither with lanterns and torches and weapons."},"BSB":{"text":"So Judas brought a band of soldiers and officers from the chief priests and Pharisees. They arrived at the garden carrying lanterns, torches, and weapons."}},"definableWords":["garden"],"peopleInVerse":[]},"4":{"text":"Jesus therefore, knowing all things that should come upon him, went forth, and said unto them, Whom seek ye?","ref":"John 18:4","synthesized":"Jesus, knowing all that was coming upon Him, stepped forward and asked them, “Whom are you seeking?”","sources":{"KJV":{"text":"Jesus therefore, knowing all things that should come upon him, went forth, and said unto them, Whom seek ye?"},"BSB":{"text":"Jesus, knowing all that was coming upon Him, stepped forward and asked them, “Whom are you seeking?”"}},"definableWords":[],"peopleInVerse":["Jesus"]},"5":{"text":"They answered him, Jesus of Nazareth. Jesus saith unto them, I am he. And Judas also, which betrayed him, stood with them.","ref":"John 18:5","synthesized":"“Jesus of Nazareth,” they answered.  Jesus said, “I am He.”  And Judas His betrayer was standing there with them.","sources":{"KJV":{"text":"They answered him, Jesus of Nazareth. Jesus saith unto them, I am he. And Judas also, which betrayed him, stood with them."},"BSB":{"text":"“Jesus of Nazareth,” they answered.  Jesus said, “I am He.”  And Judas His betrayer was standing there with them."}},"definableWords":[],"peopleInVerse":["Jesus"]},"6":{"text":"As soon then as he had said unto them, I am he, they went backward, and fell to the ground.","ref":"John 18:6","synthesized":"When Jesus said, “I am He,” they drew back and fell to the ground.","sources":{"KJV":{"text":"As soon then as he had said unto them, I am he, they went backward, and fell to the ground."},"BSB":{"text":"When Jesus said, “I am He,” they drew back and fell to the ground."}},"definableWords":["ground"],"peopleInVerse":["Jesus"]},"7":{"text":"Then asked he them again, Whom seek ye? And they said, Jesus of Nazareth.","ref":"John 18:7","synthesized":"So He asked them again, “Whom are you seeking?”  “Jesus of Nazareth,” they answered.","sources":{"KJV":{"text":"Then asked he them again, Whom seek ye? And they said, Jesus of Nazareth."},"BSB":{"text":"So He asked them again, “Whom are you seeking?”  “Jesus of Nazareth,” they answered."}},"definableWords":[],"peopleInVerse":["Jesus"]},"8":{"text":"Jesus answered, I have told you that I am he: if therefore ye seek me, let these go their way:","ref":"John 18:8","synthesized":"“I told you that I am He,” Jesus replied. “So if you are looking for Me, let these men go.”","sources":{"KJV":{"text":"Jesus answered, I have told you that I am he: if therefore ye seek me, let these go their way:"},"BSB":{"text":"“I told you that I am He,” Jesus replied. “So if you are looking for Me, let these men go.”"}},"definableWords":["men"],"peopleInVerse":["Jesus"]},"9":{"text":"That the saying might be fulfilled, which he spake, Of them which thou gavest me have I lost none.","ref":"John 18:9","synthesized":"This was to fulfill the word He had spoken: “I have not lost one of those You have given Me.”","sources":{"KJV":{"text":"That the saying might be fulfilled, which he spake, Of them which thou gavest me have I lost none."},"BSB":{"text":"This was to fulfill the word He had spoken: “I have not lost one of those You have given Me.”"}},"definableWords":["word","one"],"peopleInVerse":[]},"10":{"text":"Then Simon Peter having a sword drew it, and smote the high priest’s servant, and cut off his right ear. The servant’s name was Malchus.","ref":"John 18:10","synthesized":"Then Simon Peter drew his sword and struck the servant of the high priest, cutting off his right ear. The servant’s name was Malchus.","sources":{"KJV":{"text":"Then Simon Peter having a sword drew it, and smote the high priest’s servant, and cut off his right ear. The servant’s name was Malchus."},"BSB":{"text":"Then Simon Peter drew his sword and struck the servant of the high priest, cutting off his right ear. The servant’s name was Malchus."}},"definableWords":["servant","priest","name"],"peopleInVerse":["Peter"]},"11":{"text":"Then said Jesus unto Peter, Put up thy sword into the sheath: the cup which my Father hath given me, shall I not drink it?","ref":"John 18:11","synthesized":"“Put your sword back in its sheath!” Jesus said to Peter. “Shall I not drink the cup the Father has given Me?”","sources":{"KJV":{"text":"Then said Jesus unto Peter, Put up thy sword into the sheath: the cup which my Father hath given me, shall I not drink it?"},"BSB":{"text":"“Put your sword back in its sheath!” Jesus said to Peter. “Shall I not drink the cup the Father has given Me?”"}},"definableWords":["Father"],"peopleInVerse":["Jesus","Peter"]},"12":{"text":"Then the band and the captain and officers of the Jews took Jesus, and bound him,","ref":"John 18:12","synthesized":"Then the band of soldiers, with its commander and the officers of the Jews, arrested Jesus and bound Him.","sources":{"KJV":{"text":"Then the band and the captain and officers of the Jews took Jesus, and bound him,"},"BSB":{"text":"Then the band of soldiers, with its commander and the officers of the Jews, arrested Jesus and bound Him."}},"definableWords":[],"peopleInVerse":["Jesus"]},"13":{"text":"And led him away to Annas first; for he was father in law to Caiaphas, which was the high priest that same year.","ref":"John 18:13","synthesized":"They brought Him first to Annas, who was the father-in-law of Caiaphas, the high priest that year.","sources":{"KJV":{"text":"And led him away to Annas first; for he was father in law to Caiaphas, which was the high priest that same year."},"BSB":{"text":"They brought Him first to Annas, who was the father-in-law of Caiaphas, the high priest that year."}},"definableWords":["father","law","priest","year"],"peopleInVerse":["Caiaphas"]},"14":{"text":"Now Caiaphas was he, which gave counsel to the Jews, that it was expedient that one man should die for the people.","ref":"John 18:14","synthesized":"Caiaphas was the one who had advised the Jews that it would be better if one man died for the people.","sources":{"KJV":{"text":"Now Caiaphas was he, which gave counsel to the Jews, that it was expedient that one man should die for the people."},"BSB":{"text":"Caiaphas was the one who had advised the Jews that it would be better if one man died for the people."}},"definableWords":["one","man","people"],"peopleInVerse":["Caiaphas"]},"15":{"text":"And Simon Peter followed Jesus, and so did another disciple: that disciple was known unto the high priest, and went in with Jesus into the palace of the high priest.","ref":"John 18:15","synthesized":"Now Simon Peter and another disciple were following Jesus. Since that disciple was known to the high priest, he also went with Jesus into the courtyard of the high priest.","sources":{"KJV":{"text":"And Simon Peter followed Jesus, and so did another disciple: that disciple was known unto the high priest, and went in with Jesus into the palace of the high priest."},"BSB":{"text":"Now Simon Peter and another disciple were following Jesus. Since that disciple was known to the high priest, he also went with Jesus into the courtyard of the high priest."}},"definableWords":["disciple","priest"],"peopleInVerse":["Peter","Jesus"]},"16":{"text":"But Peter stood at the door without. Then went out that other disciple, which was known unto the high priest, and spake unto her that kept the door, and brought in Peter.","ref":"John 18:16","synthesized":"But Peter stood outside at the door. Then the disciple who was known to the high priest went out and spoke to the doorkeeper, and brought Peter in.","sources":{"KJV":{"text":"But Peter stood at the door without. Then went out that other disciple, which was known unto the high priest, and spake unto her that kept the door, and brought in Peter."},"BSB":{"text":"But Peter stood outside at the door. Then the disciple who was known to the high priest went out and spoke to the doorkeeper, and brought Peter in."}},"definableWords":["disciple","priest"],"peopleInVerse":["Peter"]},"17":{"text":"Then saith the damsel that kept the door unto Peter, Art not thou also one of this man’s disciples? He saith, I am not.","ref":"John 18:17","synthesized":"At this, the servant girl watching the door said to Peter, “Aren’t you also one of this man’s disciples?”  “I am not,” he answered.","sources":{"KJV":{"text":"Then saith the damsel that kept the door unto Peter, Art not thou also one of this man’s disciples? He saith, I am not."},"BSB":{"text":"At this, the servant girl watching the door said to Peter, “Aren’t you also one of this man’s disciples?”  “I am not,” he answered."}},"definableWords":["servant","one","man"],"peopleInVerse":["Peter"]},"18":{"text":"And the servants and officers stood there, who had made a fire of coals; for it was cold: and they warmed themselves: and Peter stood with them, and warmed himself.","ref":"John 18:18","synthesized":"Because it was cold, the servants and officers were standing around a charcoal fire they had made to keep warm. And Peter was also standing with them, warming himself.","sources":{"KJV":{"text":"And the servants and officers stood there, who had made a fire of coals; for it was cold: and they warmed themselves: and Peter stood with them, and warmed himself."},"BSB":{"text":"Because it was cold, the servants and officers were standing around a charcoal fire they had made to keep warm. And Peter was also standing with them, warming himself."}},"definableWords":["servants","made","keep"],"peopleInVerse":["Peter"]},"19":{"text":"The high priest then asked Jesus of his disciples, and of his doctrine.","ref":"John 18:19","synthesized":"Meanwhile, the high priest questioned Jesus about His disciples and His teaching.","sources":{"KJV":{"text":"The high priest then asked Jesus of his disciples, and of his doctrine."},"BSB":{"text":"Meanwhile, the high priest questioned Jesus about His disciples and His teaching."}},"definableWords":["priest"],"peopleInVerse":["Jesus"]},"20":{"text":"Jesus answered him, I spake openly to the world; I ever taught in the synagogue, and in the temple, whither the Jews always resort; and in secret have I said nothing.","ref":"John 18:20","synthesized":"“I have spoken openly to the world,” Jesus answered. “I always taught in the synagogues and at the temple, where all the Jews come together. I said nothing in secret.","sources":{"KJV":{"text":"Jesus answered him, I spake openly to the world; I ever taught in the synagogue, and in the temple, whither the Jews always resort; and in secret have I said nothing."},"BSB":{"text":"“I have spoken openly to the world,” Jesus answered. “I always taught in the synagogues and at the temple, where all the Jews come together. I said nothing in secret."}},"definableWords":["temple"],"peopleInVerse":["Jesus"]},"21":{"text":"Why askest thou me? ask them which heard me, what I have said unto them: behold, they know what I said.","ref":"John 18:21","synthesized":"Why are you asking Me? Ask those who heard My message. Surely they know what I said.”","sources":{"KJV":{"text":"Why askest thou me? ask them which heard me, what I have said unto them: behold, they know what I said."},"BSB":{"text":"Why are you asking Me? Ask those who heard My message. Surely they know what I said.”"}},"definableWords":[],"peopleInVerse":[]},"22":{"text":"And when he had thus spoken, one of the officers which stood by struck Jesus with the palm of his hand, saying, Answerest thou the high priest so?","ref":"John 18:22","synthesized":"When Jesus had said this, one of the officers standing nearby slapped Him in the face and said, “Is this how You answer the high priest?”","sources":{"KJV":{"text":"And when he had thus spoken, one of the officers which stood by struck Jesus with the palm of his hand, saying, Answerest thou the high priest so?"},"BSB":{"text":"When Jesus had said this, one of the officers standing nearby slapped Him in the face and said, “Is this how You answer the high priest?”"}},"definableWords":["one","priest"],"peopleInVerse":["Jesus"]},"23":{"text":"Jesus answered him, If I have spoken evil, bear witness of the evil: but if well, why smitest thou me?","ref":"John 18:23","synthesized":"Jesus replied, “If I said something wrong, testify as to what was wrong. But if I spoke correctly, why did you strike Me?”","sources":{"KJV":{"text":"Jesus answered him, If I have spoken evil, bear witness of the evil: but if well, why smitest thou me?"},"BSB":{"text":"Jesus replied, “If I said something wrong, testify as to what was wrong. But if I spoke correctly, why did you strike Me?”"}},"definableWords":[],"peopleInVerse":["Jesus"]},"24":{"text":"Now Annas had sent him bound unto Caiaphas the high priest.","ref":"John 18:24","synthesized":"Then Annas sent Him, still bound, to Caiaphas the high priest.","sources":{"KJV":{"text":"Now Annas had sent him bound unto Caiaphas the high priest."},"BSB":{"text":"Then Annas sent Him, still bound, to Caiaphas the high priest."}},"definableWords":["priest"],"peopleInVerse":["Caiaphas"]},"25":{"text":"And Simon Peter stood and warmed himself. They said therefore unto him, Art not thou also one of his disciples? He denied it, and said, I am not.","ref":"John 18:25","synthesized":"Simon Peter was still standing and warming himself. So they asked him, “Aren’t you also one of His disciples?”  He denied it and said, “I am not.”","sources":{"KJV":{"text":"And Simon Peter stood and warmed himself. They said therefore unto him, Art not thou also one of his disciples? He denied it, and said, I am not."},"BSB":{"text":"Simon Peter was still standing and warming himself. So they asked him, “Aren’t you also one of His disciples?”  He denied it and said, “I am not.”"}},"definableWords":["one"],"peopleInVerse":["Peter"]},"26":{"text":"One of the servants of the high priest, being his kinsman whose ear Peter cut off, saith, Did not I see thee in the garden with him?","ref":"John 18:26","synthesized":"One of the high priest’s servants, a relative of the man whose ear Peter had cut off, asked, “Didn’t I see you with Him in the garden?”","sources":{"KJV":{"text":"One of the servants of the high priest, being his kinsman whose ear Peter cut off, saith, Did not I see thee in the garden with him?"},"BSB":{"text":"One of the high priest’s servants, a relative of the man whose ear Peter had cut off, asked, “Didn’t I see you with Him in the garden?”"}},"definableWords":["one","priest","servants","man","see","garden"],"peopleInVerse":["Peter"]},"27":{"text":"Peter then denied again: and immediately the cock crew.","ref":"John 18:27","synthesized":"Peter denied it once more, and immediately a rooster crowed.","sources":{"KJV":{"text":"Peter then denied again: and immediately the cock crew."},"BSB":{"text":"Peter denied it once more, and immediately a rooster crowed."}},"definableWords":[],"peopleInVerse":["Peter"]},"28":{"text":"Then led they Jesus from Caiaphas unto the hall of judgment: and it was early; and they themselves went not into the judgment hall, lest they should be defiled; but that they might eat the passover.","ref":"John 18:28","synthesized":"Then they led Jesus away from Caiaphas into the Praetorium. By now it was early morning, and the Jews did not enter the Praetorium, to avoid being defiled and unable to eat the Passover.","sources":{"KJV":{"text":"Then led they Jesus from Caiaphas unto the hall of judgment: and it was early; and they themselves went not into the judgment hall, lest they should be defiled; but that they might eat the passover."},"BSB":{"text":"Then they led Jesus away from Caiaphas into the Praetorium. By now it was early morning, and the Jews did not enter the Praetorium, to avoid being defiled and unable to eat the Passover."}},"definableWords":["Passover"],"peopleInVerse":["Jesus","Caiaphas"]},"29":{"text":"Pilate then went out unto them, and said, What accusation bring ye against this man?","ref":"John 18:29","synthesized":"So Pilate went out to them and asked, “What accusation are you bringing against this man?”","sources":{"KJV":{"text":"Pilate then went out unto them, and said, What accusation bring ye against this man?"},"BSB":{"text":"So Pilate went out to them and asked, “What accusation are you bringing against this man?”"}},"definableWords":["man"],"peopleInVerse":["Pilate"]},"30":{"text":"They answered and said unto him, If he were not a malefactor, we would not have delivered him up unto thee.","ref":"John 18:30","synthesized":"“If He were not a criminal,” they replied, “we would not have handed Him over to you.”","sources":{"KJV":{"text":"They answered and said unto him, If he were not a malefactor, we would not have delivered him up unto thee."},"BSB":{"text":"“If He were not a criminal,” they replied, “we would not have handed Him over to you.”"}},"definableWords":[],"peopleInVerse":[]},"31":{"text":"Then said Pilate unto them, Take ye him, and judge him according to your law. The Jews therefore said unto him, It is not lawful for us to put any man to death:","ref":"John 18:31","synthesized":"“You take Him and judge Him by your own law,” Pilate told them.  “We are not permitted to execute anyone,” the Jews replied.","sources":{"KJV":{"text":"Then said Pilate unto them, Take ye him, and judge him according to your law. The Jews therefore said unto him, It is not lawful for us to put any man to death:"},"BSB":{"text":"“You take Him and judge Him by your own law,” Pilate told them.  “We are not permitted to execute anyone,” the Jews replied."}},"definableWords":["law"],"peopleInVerse":["Pilate"]},"32":{"text":"That the saying of Jesus might be fulfilled, which he spake, signifying what death he should die.","ref":"John 18:32","synthesized":"This was to fulfill the word that Jesus had spoken to indicate the kind of death He was going to die.","sources":{"KJV":{"text":"That the saying of Jesus might be fulfilled, which he spake, signifying what death he should die."},"BSB":{"text":"This was to fulfill the word that Jesus had spoken to indicate the kind of death He was going to die."}},"definableWords":["word","death","die"],"peopleInVerse":["Jesus"]},"33":{"text":"Then Pilate entered into the judgment hall again, and called Jesus, and said unto him, Art thou the King of the Jews?","ref":"John 18:33","synthesized":"Pilate went back into the Praetorium, summoned Jesus, and asked Him, “Are You the King of the Jews?”","sources":{"KJV":{"text":"Then Pilate entered into the judgment hall again, and called Jesus, and said unto him, Art thou the King of the Jews?"},"BSB":{"text":"Pilate went back into the Praetorium, summoned Jesus, and asked Him, “Are You the King of the Jews?”"}},"definableWords":["King"],"peopleInVerse":["Pilate","Jesus"]},"34":{"text":"Jesus answered him, Sayest thou this thing of thyself, or did others tell it thee of me?","ref":"John 18:34","synthesized":"“Are you saying this on your own,” Jesus asked, “or did others tell you about Me?”","sources":{"KJV":{"text":"Jesus answered him, Sayest thou this thing of thyself, or did others tell it thee of me?"},"BSB":{"text":"“Are you saying this on your own,” Jesus asked, “or did others tell you about Me?”"}},"definableWords":["or"],"peopleInVerse":["Jesus"]},"35":{"text":"Pilate answered, Am I a Jew? Thine own nation and the chief priests have delivered thee unto me: what hast thou done?","ref":"John 18:35","synthesized":"“Am I a Jew?” Pilate replied. “Your own people and chief priests handed You over to me. What have You done?”","sources":{"KJV":{"text":"Pilate answered, Am I a Jew? Thine own nation and the chief priests have delivered thee unto me: what hast thou done?"},"BSB":{"text":"“Am I a Jew?” Pilate replied. “Your own people and chief priests handed You over to me. What have You done?”"}},"definableWords":["Jew","people"],"peopleInVerse":["Pilate"]},"36":{"text":"Jesus answered, My kingdom is not of this world: if my kingdom were of this world, then would my servants fight, that I should not be delivered to the Jews: but now is my kingdom not from hence.","ref":"John 18:36","synthesized":"Jesus answered, “My kingdom is not of this world; if it were, My servants would fight to prevent My arrest by the Jews. But now My kingdom is not of this realm.”","sources":{"KJV":{"text":"Jesus answered, My kingdom is not of this world: if my kingdom were of this world, then would my servants fight, that I should not be delivered to the Jews: but now is my kingdom not from hence."},"BSB":{"text":"Jesus answered, “My kingdom is not of this world; if it were, My servants would fight to prevent My arrest by the Jews. But now My kingdom is not of this realm.”"}},"definableWords":["kingdom","servants","fight"],"peopleInVerse":["Jesus"]},"37":{"text":"Pilate therefore said unto him, Art thou a king then? Jesus answered, Thou sayest that I am a king. To this end was I born, and for this cause came I into the world, that I should bear witness unto the truth. Every one that is of the truth heareth my voice.","ref":"John 18:37","synthesized":"“Then You are a king!” Pilate said.  “You say that I am a king,” Jesus answered. “For this reason I was born and have come into the world, to testify to the truth. Everyone who belongs to the truth listens to My voice.”","sources":{"KJV":{"text":"Pilate therefore said unto him, Art thou a king then? Jesus answered, Thou sayest that I am a king. To this end was I born, and for this cause came I into the world, that I should bear witness unto the truth. Every one that is of the truth heareth my voice."},"BSB":{"text":"“Then You are a king!” Pilate said.  “You say that I am a king,” Jesus answered. “For this reason I was born and have come into the world, to testify to the truth. Everyone who belongs to the truth listens to My voice.”"}},"definableWords":["king","King","truth","voice"],"peopleInVerse":["Pilate","Jesus"]},"38":{"text":"Pilate saith unto him, What is truth? And when he had said this, he went out again unto the Jews, and saith unto them, I find in him no fault at all.","ref":"John 18:38","synthesized":"“What is truth?” Pilate asked.  And having said this, he went out again to the Jews and told them, “I find no basis for a charge against Him.","sources":{"KJV":{"text":"Pilate saith unto him, What is truth? And when he had said this, he went out again unto the Jews, and saith unto them, I find in him no fault at all."},"BSB":{"text":"“What is truth?” Pilate asked.  And having said this, he went out again to the Jews and told them, “I find no basis for a charge against Him."}},"definableWords":["truth","charge"],"peopleInVerse":["Pilate"]},"39":{"text":"But ye have a custom, that I should release unto you one at the passover: will ye therefore that I release unto you the King of the Jews?","ref":"John 18:39","synthesized":"But it is your custom that I release to you one prisoner at the Passover. So then, do you want me to release to you the King of the Jews?”","sources":{"KJV":{"text":"But ye have a custom, that I should release unto you one at the passover: will ye therefore that I release unto you the King of the Jews?"},"BSB":{"text":"But it is your custom that I release to you one prisoner at the Passover. So then, do you want me to release to you the King of the Jews?”"}},"definableWords":["one","Passover","King"],"peopleInVerse":[]},"40":{"text":"Then cried they all again, saying, Not this man, but Barabbas. Now Barabbas was a robber.","ref":"John 18:40","synthesized":"“Not this man,” they shouted, “but Barabbas!” (Now Barabbas was an insurrectionist.)","sources":{"KJV":{"text":"Then cried they all again, saying, Not this man, but Barabbas. Now Barabbas was a robber."},"BSB":{"text":"“Not this man,” they shouted, “but Barabbas!” (Now Barabbas was an insurrectionist.)"}},"definableWords":["man"],"peopleInVerse":[]}}},"19":{"chapter":"19","title":"THE CRUCIFIXION (JOHN)","verses":{"1":{"text":"Then Pilate therefore took Jesus, and scourged him.","ref":"John 19:1","synthesized":"Then Pilate took Jesus and had Him flogged.","sources":{"KJV":{"text":"Then Pilate therefore took Jesus, and scourged him."},"BSB":{"text":"Then Pilate took Jesus and had Him flogged."}},"definableWords":[],"peopleInVerse":["Pilate","Jesus"],"kingdomLens":"John was an eyewitness — the only Gospel writer who actually stood at the cross. He records details no other Gospel does: the sign in three languages (19:20), Jesus' care for his mother (19:26-27), the soldiers casting lots (fulfilling Ps 22:18), the unbroken bones (fulfilling Exod 12:46, the Passover lamb), the pierced side and the flow of blood and water (19:34) — and 'IT IS FINISHED' (19:30).","cultural":{"title":"The crucifixion (John)","detail":"John 19:35 — 'And he that saw it bare record, and his record is true: and he knoweth that he saith true, that ye might believe.' John insisted on his eyewitness testimony. The flow of blood and water is now recognized as medical evidence that Jesus' heart had ruptured — confirming death.","sources":"SWRV Kingdom Study Protocol — synthesis from approved library (Rule 06)"}},"2":{"text":"And the soldiers platted a crown of thorns, and put it on his head, and they put on him a purple robe,","ref":"John 19:2","synthesized":"The soldiers twisted together a crown of thorns, set it on His head, and dressed Him in a purple robe.","sources":{"KJV":{"text":"And the soldiers platted a crown of thorns, and put it on his head, and they put on him a purple robe,"},"BSB":{"text":"The soldiers twisted together a crown of thorns, set it on His head, and dressed Him in a purple robe."}},"definableWords":["crown"],"peopleInVerse":[]},"3":{"text":"And said, Hail, King of the Jews! and they smote him with their hands.","ref":"John 19:3","synthesized":"And they went up to Him again and again, saying, “Hail, King of the Jews!” and slapping Him in the face.","sources":{"KJV":{"text":"And said, Hail, King of the Jews! and they smote him with their hands."},"BSB":{"text":"And they went up to Him again and again, saying, “Hail, King of the Jews!” and slapping Him in the face."}},"definableWords":["King"],"peopleInVerse":[]},"4":{"text":"Pilate therefore went forth again, and saith unto them, Behold, I bring him forth to you, that ye may know that I find no fault in him.","ref":"John 19:4","synthesized":"Once again Pilate came out and said to the Jews, “Look, I am bringing Him out to you to let you know that I find no basis for a charge against Him.”","sources":{"KJV":{"text":"Pilate therefore went forth again, and saith unto them, Behold, I bring him forth to you, that ye may know that I find no fault in him."},"BSB":{"text":"Once again Pilate came out and said to the Jews, “Look, I am bringing Him out to you to let you know that I find no basis for a charge against Him.”"}},"definableWords":["charge"],"peopleInVerse":["Pilate"]},"5":{"text":"Then came Jesus forth, wearing the crown of thorns, and the purple robe. And Pilate saith unto them, Behold the man!","ref":"John 19:5","synthesized":"When Jesus came out wearing the crown of thorns and the purple robe, Pilate said to them, “Here is the man!”","sources":{"KJV":{"text":"Then came Jesus forth, wearing the crown of thorns, and the purple robe. And Pilate saith unto them, Behold the man!"},"BSB":{"text":"When Jesus came out wearing the crown of thorns and the purple robe, Pilate said to them, “Here is the man!”"}},"definableWords":["crown","man"],"peopleInVerse":["Jesus","Pilate"]},"6":{"text":"When the chief priests therefore and officers saw him, they cried out, saying, Crucify him, crucify him. Pilate saith unto them, Take ye him, and crucify him: for I find no fault in him.","ref":"John 19:6","synthesized":"As soon as the chief priests and officers saw Him, they shouted, “Crucify Him! Crucify Him!”  “You take Him and crucify Him,” Pilate replied, “for I find no basis for a charge against Him.”","sources":{"KJV":{"text":"When the chief priests therefore and officers saw him, they cried out, saying, Crucify him, crucify him. Pilate saith unto them, Take ye him, and crucify him: for I find no fault in him."},"BSB":{"text":"As soon as the chief priests and officers saw Him, they shouted, “Crucify Him! Crucify Him!”  “You take Him and crucify Him,” Pilate replied, “for I find no basis for a charge against Him.”"}},"definableWords":["saw","charge"],"peopleInVerse":["Pilate"]},"7":{"text":"The Jews answered him, We have a law, and by our law he ought to die, because he made himself the Son of God.","ref":"John 19:7","synthesized":"“We have a law,” answered the Jews, “and according to that law He must die, because He declared Himself to be the Son of God.”","sources":{"KJV":{"text":"The Jews answered him, We have a law, and by our law he ought to die, because he made himself the Son of God."},"BSB":{"text":"“We have a law,” answered the Jews, “and according to that law He must die, because He declared Himself to be the Son of God.”"}},"definableWords":["law","die","Son","God"],"peopleInVerse":[]},"8":{"text":"When Pilate therefore heard that saying, he was the more afraid;","ref":"John 19:8","synthesized":"When Pilate heard this statement, he was even more afraid,","sources":{"KJV":{"text":"When Pilate therefore heard that saying, he was the more afraid;"},"BSB":{"text":"When Pilate heard this statement, he was even more afraid,"}},"definableWords":[],"peopleInVerse":["Pilate"]},"9":{"text":"And went again into the judgment hall, and saith unto Jesus, Whence art thou? But Jesus gave him no answer.","ref":"John 19:9","synthesized":"and he went back into the Praetorium. “Where are You from?” he asked.  But Jesus gave no answer.","sources":{"KJV":{"text":"And went again into the judgment hall, and saith unto Jesus, Whence art thou? But Jesus gave him no answer."},"BSB":{"text":"and he went back into the Praetorium. “Where are You from?” he asked.  But Jesus gave no answer."}},"definableWords":[],"peopleInVerse":["Jesus"]},"10":{"text":"Then saith Pilate unto him, Speakest thou not unto me? knowest thou not that I have power to crucify thee, and have power to release thee?","ref":"John 19:10","synthesized":"So Pilate said to Him, “Do You refuse to speak to me? Do You not know that I have authority to release You and authority to crucify You?”","sources":{"KJV":{"text":"Then saith Pilate unto him, Speakest thou not unto me? knowest thou not that I have power to crucify thee, and have power to release thee?"},"BSB":{"text":"So Pilate said to Him, “Do You refuse to speak to me? Do You not know that I have authority to release You and authority to crucify You?”"}},"definableWords":[],"peopleInVerse":["Pilate"]},"11":{"text":"Jesus answered, Thou couldest have no power at all against me, except it were given thee from above: therefore he that delivered me unto thee hath the greater sin.","ref":"John 19:11","synthesized":"Jesus answered, “You would have no authority over Me if it were not given to you from above. Therefore the one who handed Me over to you is guilty of greater sin.”","sources":{"KJV":{"text":"Jesus answered, Thou couldest have no power at all against me, except it were given thee from above: therefore he that delivered me unto thee hath the greater sin."},"BSB":{"text":"Jesus answered, “You would have no authority over Me if it were not given to you from above. Therefore the one who handed Me over to you is guilty of greater sin.”"}},"definableWords":["one","sin"],"peopleInVerse":["Jesus"]},"12":{"text":"And from thenceforth Pilate sought to release him: but the Jews cried out, saying, If thou let this man go, thou art not Caesar’s friend: whosoever maketh himself a king speaketh against Caesar.","ref":"John 19:12","synthesized":"From then on, Pilate tried to release Him, but the Jews kept shouting, “If you release this man, you are no friend of Caesar. Anyone who declares himself a king is defying Caesar.”","sources":{"KJV":{"text":"And from thenceforth Pilate sought to release him: but the Jews cried out, saying, If thou let this man go, thou art not Caesar’s friend: whosoever maketh himself a king speaketh against Caesar."},"BSB":{"text":"From then on, Pilate tried to release Him, but the Jews kept shouting, “If you release this man, you are no friend of Caesar. Anyone who declares himself a king is defying Caesar.”"}},"definableWords":["man","king"],"peopleInVerse":["Pilate"]},"13":{"text":"When Pilate therefore heard that saying, he brought Jesus forth, and sat down in the judgment seat in a place that is called the Pavement, but in the Hebrew, Gabbatha.","ref":"John 19:13","synthesized":"When Pilate heard these words, he brought Jesus out and sat on the judgment seat at a place called the Stone Pavement, which in Hebrew is Gabbatha.","sources":{"KJV":{"text":"When Pilate therefore heard that saying, he brought Jesus forth, and sat down in the judgment seat in a place that is called the Pavement, but in the Hebrew, Gabbatha."},"BSB":{"text":"When Pilate heard these words, he brought Jesus out and sat on the judgment seat at a place called the Stone Pavement, which in Hebrew is Gabbatha."}},"definableWords":["judgment","stone"],"peopleInVerse":["Pilate","Jesus"]},"14":{"text":"And it was the preparation of the passover, and about the sixth hour: and he saith unto the Jews, Behold your King!","ref":"John 19:14","synthesized":"It was the day of Preparation for the Passover, about the sixth hour. And Pilate said to the Jews, “Here is your King!”","sources":{"KJV":{"text":"And it was the preparation of the passover, and about the sixth hour: and he saith unto the Jews, Behold your King!"},"BSB":{"text":"It was the day of Preparation for the Passover, about the sixth hour. And Pilate said to the Jews, “Here is your King!”"}},"definableWords":["day","Passover","King"],"peopleInVerse":["Pilate"]},"15":{"text":"But they cried out, Away with him, away with him, crucify him. Pilate saith unto them, Shall I crucify your King? The chief priests answered, We have no king but Caesar.","ref":"John 19:15","synthesized":"At this, they shouted, “Away with Him! Away with Him! Crucify Him!”  “Shall I crucify your King?” Pilate asked.  “We have no king but Caesar,” replied the chief priests.","sources":{"KJV":{"text":"But they cried out, Away with him, away with him, crucify him. Pilate saith unto them, Shall I crucify your King? The chief priests answered, We have no king but Caesar."},"BSB":{"text":"At this, they shouted, “Away with Him! Away with Him! Crucify Him!”  “Shall I crucify your King?” Pilate asked.  “We have no king but Caesar,” replied the chief priests."}},"definableWords":["King","king"],"peopleInVerse":["Pilate"]},"16":{"text":"Then delivered he him therefore unto them to be crucified. And they took Jesus, and led him away.","ref":"John 19:16","synthesized":"Then Pilate handed Jesus over to be crucified, and the soldiers took Him away.","sources":{"KJV":{"text":"Then delivered he him therefore unto them to be crucified. And they took Jesus, and led him away."},"BSB":{"text":"Then Pilate handed Jesus over to be crucified, and the soldiers took Him away."}},"definableWords":[],"peopleInVerse":["Pilate","Jesus"]},"17":{"text":"And he bearing his cross went forth into a place called the place of a skull, which is called in the Hebrew Golgotha:","ref":"John 19:17","synthesized":"Carrying His own cross, He went out to The Place of the Skull, which in Hebrew is called Golgotha.","sources":{"KJV":{"text":"And he bearing his cross went forth into a place called the place of a skull, which is called in the Hebrew Golgotha:"},"BSB":{"text":"Carrying His own cross, He went out to The Place of the Skull, which in Hebrew is called Golgotha."}},"definableWords":[],"peopleInVerse":[]},"18":{"text":"Where they crucified him, and two other with him, on either side one, and Jesus in the midst.","ref":"John 19:18","synthesized":"There they crucified Him, and with Him two others, one on each side, with Jesus in the middle.","sources":{"KJV":{"text":"Where they crucified him, and two other with him, on either side one, and Jesus in the midst."},"BSB":{"text":"There they crucified Him, and with Him two others, one on each side, with Jesus in the middle."}},"definableWords":["one"],"peopleInVerse":["Jesus"]},"19":{"text":"And Pilate wrote a title, and put it on the cross. And the writing was, JESUS OF NAZARETH THE KING OF THE JEWS.","ref":"John 19:19","synthesized":"Pilate also had a notice posted on the cross. It read:  JESUS OF NAZARETH,  THE KING OF THE JEWS.","sources":{"KJV":{"text":"And Pilate wrote a title, and put it on the cross. And the writing was, JESUS OF NAZARETH THE KING OF THE JEWS."},"BSB":{"text":"Pilate also had a notice posted on the cross. It read:  JESUS OF NAZARETH,  THE KING OF THE JEWS."}},"definableWords":["King"],"peopleInVerse":["Pilate"]},"20":{"text":"This title then read many of the Jews: for the place where Jesus was crucified was nigh to the city: and it was written in Hebrew, and Greek, and Latin.","ref":"John 19:20","synthesized":"Many of the Jews read this sign, because the place where Jesus was crucified was near the city, and it was written in Hebrew, Latin, and Greek.","sources":{"KJV":{"text":"This title then read many of the Jews: for the place where Jesus was crucified was nigh to the city: and it was written in Hebrew, and Greek, and Latin."},"BSB":{"text":"Many of the Jews read this sign, because the place where Jesus was crucified was near the city, and it was written in Hebrew, Latin, and Greek."}},"definableWords":["Greek"],"peopleInVerse":["Jesus"]},"21":{"text":"Then said the chief priests of the Jews to Pilate, Write not, The King of the Jews; but that he said, I am King of the Jews.","ref":"John 19:21","synthesized":"So the chief priests of the Jews said to Pilate, “Do not write, ‘The King of the Jews,’ but only that He said, ‘I am the King of the Jews.’”","sources":{"KJV":{"text":"Then said the chief priests of the Jews to Pilate, Write not, The King of the Jews; but that he said, I am King of the Jews."},"BSB":{"text":"So the chief priests of the Jews said to Pilate, “Do not write, ‘The King of the Jews,’ but only that He said, ‘I am the King of the Jews.’”"}},"definableWords":["King"],"peopleInVerse":["Pilate"]},"22":{"text":"Pilate answered, What I have written I have written.","ref":"John 19:22","synthesized":"Pilate answered, “What I have written, I have written.”","sources":{"KJV":{"text":"Pilate answered, What I have written I have written."},"BSB":{"text":"Pilate answered, “What I have written, I have written.”"}},"definableWords":[],"peopleInVerse":["Pilate"]},"23":{"text":"Then the soldiers, when they had crucified Jesus, took his garments, and made four parts, to every soldier a part; and also his coat: now the coat was without seam, woven from the top throughout.","ref":"John 19:23","synthesized":"When the soldiers had crucified Jesus, they divided His garments into four parts, one for each soldier, with the tunic remaining. It was seamless, woven in one piece from top to bottom.","sources":{"KJV":{"text":"Then the soldiers, when they had crucified Jesus, took his garments, and made four parts, to every soldier a part; and also his coat: now the coat was without seam, woven from the top throughout."},"BSB":{"text":"When the soldiers had crucified Jesus, they divided His garments into four parts, one for each soldier, with the tunic remaining. It was seamless, woven in one piece from top to bottom."}},"definableWords":["one"],"peopleInVerse":["Jesus"]},"24":{"text":"They said therefore among themselves, Let us not rend it, but cast lots for it, whose it shall be: that the scripture might be fulfilled, which saith, They parted my raiment among them, and for my vesture they did cast lots. These things therefore the soldiers did.","ref":"John 19:24","synthesized":"So they said to one another, “Let us not tear it. Instead, let us cast lots to see who will get it.” This was to fulfill the Scripture:  “They divided My garments among them, and cast lots for My clothing.”   So that is what the soldiers did.","sources":{"KJV":{"text":"They said therefore among themselves, Let us not rend it, but cast lots for it, whose it shall be: that the scripture might be fulfilled, which saith, They parted my raiment among them, and for my vesture they did cast lots. These things therefore the soldiers did."},"BSB":{"text":"So they said to one another, “Let us not tear it. Instead, let us cast lots to see who will get it.” This was to fulfill the Scripture:  “They divided My garments among them, and cast lots for My clothing.”   So that is what the soldiers did."}},"definableWords":["one","see"],"peopleInVerse":[]},"25":{"text":"Now there stood by the cross of Jesus his mother, and his mother’s sister, Mary the wife of Cleophas, and Mary Magdalene.","ref":"John 19:25","synthesized":"Near the cross of Jesus stood His mother and her sister, as well as Mary the wife of Clopas and Mary Magdalene.","sources":{"KJV":{"text":"Now there stood by the cross of Jesus his mother, and his mother’s sister, Mary the wife of Cleophas, and Mary Magdalene."},"BSB":{"text":"Near the cross of Jesus stood His mother and her sister, as well as Mary the wife of Clopas and Mary Magdalene."}},"definableWords":["mother","sister","wife"],"peopleInVerse":["Jesus","Mary"]},"26":{"text":"When Jesus therefore saw his mother, and the disciple standing by, whom he loved, he saith unto his mother, Woman, behold thy son!","ref":"John 19:26","synthesized":"When Jesus saw His mother and the disciple whom He loved standing nearby, He said to His mother, “Woman, here is your son.”","sources":{"KJV":{"text":"When Jesus therefore saw his mother, and the disciple standing by, whom he loved, he saith unto his mother, Woman, behold thy son!"},"BSB":{"text":"When Jesus saw His mother and the disciple whom He loved standing nearby, He said to His mother, “Woman, here is your son.”"}},"definableWords":["saw","mother","disciple","woman","son"],"peopleInVerse":["Jesus"]},"27":{"text":"Then saith he to the disciple, Behold thy mother! And from that hour that disciple took her unto his own home.","ref":"John 19:27","synthesized":"Then He said to the disciple, “Here is your mother.” So from that hour, this disciple took her into his home.","sources":{"KJV":{"text":"Then saith he to the disciple, Behold thy mother! And from that hour that disciple took her unto his own home."},"BSB":{"text":"Then He said to the disciple, “Here is your mother.” So from that hour, this disciple took her into his home."}},"definableWords":["disciple","mother"],"peopleInVerse":[]},"28":{"text":"After this, Jesus knowing that all things were now accomplished, that the scripture might be fulfilled, saith, I thirst.","ref":"John 19:28","synthesized":"After this, knowing that everything had now been accomplished, and to fulfill the Scripture, Jesus said, “I am thirsty.”","sources":{"KJV":{"text":"After this, Jesus knowing that all things were now accomplished, that the scripture might be fulfilled, saith, I thirst."},"BSB":{"text":"After this, knowing that everything had now been accomplished, and to fulfill the Scripture, Jesus said, “I am thirsty.”"}},"definableWords":[],"peopleInVerse":["Jesus"]},"29":{"text":"Now there was set a vessel full of vinegar: and they filled a spunge with vinegar, and put it upon hyssop, and put it to his mouth.","ref":"John 19:29","synthesized":"A jar of sour wine was sitting there. So they soaked a sponge in the wine, put it on a stalk of hyssop, and lifted it to His mouth.","sources":{"KJV":{"text":"Now there was set a vessel full of vinegar: and they filled a spunge with vinegar, and put it upon hyssop, and put it to his mouth."},"BSB":{"text":"A jar of sour wine was sitting there. So they soaked a sponge in the wine, put it on a stalk of hyssop, and lifted it to His mouth."}},"definableWords":[],"peopleInVerse":[]},"30":{"text":"When Jesus therefore had received the vinegar, he said, It is finished: and he bowed his head, and gave up the ghost.","ref":"John 19:30","synthesized":"When Jesus had received the sour wine, He said, “It is finished.” And bowing His head, He yielded up His spirit.","sources":{"KJV":{"text":"When Jesus therefore had received the vinegar, he said, It is finished: and he bowed his head, and gave up the ghost."},"BSB":{"text":"When Jesus had received the sour wine, He said, “It is finished.” And bowing His head, He yielded up His spirit."}},"definableWords":["spirit"],"peopleInVerse":["Jesus"]},"31":{"text":"The Jews therefore, because it was the preparation, that the bodies should not remain upon the cross on the sabbath day, (for that sabbath day was an high day,) besought Pilate that their legs might be broken, and that they might be taken away.","ref":"John 19:31","synthesized":"It was the day of Preparation, and the next day was a High Sabbath. In order that the bodies would not remain on the cross during the Sabbath, the Jews asked Pilate to have the legs broken and the bodies removed.","sources":{"KJV":{"text":"The Jews therefore, because it was the preparation, that the bodies should not remain upon the cross on the sabbath day, (for that sabbath day was an high day,) besought Pilate that their legs might be broken, and that they might be taken away."},"BSB":{"text":"It was the day of Preparation, and the next day was a High Sabbath. In order that the bodies would not remain on the cross during the Sabbath, the Jews asked Pilate to have the legs broken and the bodies removed."}},"definableWords":["day","Sabbath","sabbath"],"peopleInVerse":["Pilate"]},"32":{"text":"Then came the soldiers, and brake the legs of the first, and of the other which was crucified with him.","ref":"John 19:32","synthesized":"So the soldiers came and broke the legs of the first man who had been crucified with Jesus, and those of the other.","sources":{"KJV":{"text":"Then came the soldiers, and brake the legs of the first, and of the other which was crucified with him."},"BSB":{"text":"So the soldiers came and broke the legs of the first man who had been crucified with Jesus, and those of the other."}},"definableWords":["man"],"peopleInVerse":["Jesus"]},"33":{"text":"But when they came to Jesus, and saw that he was dead already, they brake not his legs:","ref":"John 19:33","synthesized":"But when they came to Jesus and saw that He was already dead, they did not break His legs.","sources":{"KJV":{"text":"But when they came to Jesus, and saw that he was dead already, they brake not his legs:"},"BSB":{"text":"But when they came to Jesus and saw that He was already dead, they did not break His legs."}},"definableWords":["saw"],"peopleInVerse":["Jesus"]},"34":{"text":"But one of the soldiers with a spear pierced his side, and forthwith came there out blood and water.","ref":"John 19:34","synthesized":"Instead, one of the soldiers pierced His side with a spear, and immediately blood and water flowed out.","sources":{"KJV":{"text":"But one of the soldiers with a spear pierced his side, and forthwith came there out blood and water."},"BSB":{"text":"Instead, one of the soldiers pierced His side with a spear, and immediately blood and water flowed out."}},"definableWords":["one","blood","water"],"peopleInVerse":[]},"35":{"text":"And he that saw it bare record, and his record is true: and he knoweth that he saith true, that ye might believe.","ref":"John 19:35","synthesized":"The one who saw it has testified to this, and his testimony is true. He knows that he is telling the truth, so that you also may believe.","sources":{"KJV":{"text":"And he that saw it bare record, and his record is true: and he knoweth that he saith true, that ye might believe."},"BSB":{"text":"The one who saw it has testified to this, and his testimony is true. He knows that he is telling the truth, so that you also may believe."}},"definableWords":["one","saw","truth"],"peopleInVerse":[]},"36":{"text":"For these things were done, that the scripture should be fulfilled, A bone of him shall not be broken.","ref":"John 19:36","synthesized":"Now these things happened so that the Scripture would be fulfilled: “Not one of His bones will be broken.”","sources":{"KJV":{"text":"For these things were done, that the scripture should be fulfilled, A bone of him shall not be broken."},"BSB":{"text":"Now these things happened so that the Scripture would be fulfilled: “Not one of His bones will be broken.”"}},"definableWords":["one","bones"],"peopleInVerse":[]},"37":{"text":"And again another scripture saith, They shall look on him whom they pierced.","ref":"John 19:37","synthesized":"And, as another Scripture says: “They will look on the One they have pierced.”","sources":{"KJV":{"text":"And again another scripture saith, They shall look on him whom they pierced."},"BSB":{"text":"And, as another Scripture says: “They will look on the One they have pierced.”"}},"definableWords":["one"],"peopleInVerse":[]},"38":{"text":"And after this Joseph of Arimathaea, being a disciple of Jesus, but secretly for fear of the Jews, besought Pilate that he might take away the body of Jesus: and Pilate gave him leave. He came therefore, and took the body of Jesus.","ref":"John 19:38","synthesized":"Afterward, Joseph of Arimathea, who was a disciple of Jesus (but secretly for fear of the Jews), asked Pilate to let him remove the body of Jesus. Pilate gave him permission, so he came and removed His body.","sources":{"KJV":{"text":"And after this Joseph of Arimathaea, being a disciple of Jesus, but secretly for fear of the Jews, besought Pilate that he might take away the body of Jesus: and Pilate gave him leave. He came therefore, and took the body of Jesus."},"BSB":{"text":"Afterward, Joseph of Arimathea, who was a disciple of Jesus (but secretly for fear of the Jews), asked Pilate to let him remove the body of Jesus. Pilate gave him permission, so he came and removed His body."}},"definableWords":["Joseph","disciple","fear"],"peopleInVerse":["Joseph","Jesus","Pilate"]},"39":{"text":"And there came also Nicodemus, which at the first came to Jesus by night, and brought a mixture of myrrh and aloes, about an hundred pound weight.","ref":"John 19:39","synthesized":"Nicodemus, who had previously come to Jesus at night, also brought a mixture of myrrh and aloes, about seventy-five pounds.","sources":{"KJV":{"text":"And there came also Nicodemus, which at the first came to Jesus by night, and brought a mixture of myrrh and aloes, about an hundred pound weight."},"BSB":{"text":"Nicodemus, who had previously come to Jesus at night, also brought a mixture of myrrh and aloes, about seventy-five pounds."}},"definableWords":["night"],"peopleInVerse":["Jesus"]},"40":{"text":"Then took they the body of Jesus, and wound it in linen clothes with the spices, as the manner of the Jews is to bury.","ref":"John 19:40","synthesized":"So they took the body of Jesus and wrapped it in linen cloths with the spices, according to the Jewish burial custom.","sources":{"KJV":{"text":"Then took they the body of Jesus, and wound it in linen clothes with the spices, as the manner of the Jews is to bury."},"BSB":{"text":"So they took the body of Jesus and wrapped it in linen cloths with the spices, according to the Jewish burial custom."}},"definableWords":[],"peopleInVerse":["Jesus"]},"41":{"text":"Now in the place where he was crucified there was a garden; and in the garden a new sepulchre, wherein was never man yet laid.","ref":"John 19:41","synthesized":"Now there was a garden in the place where Jesus was crucified, and in the garden a new tomb in which no one had yet been laid.","sources":{"KJV":{"text":"Now in the place where he was crucified there was a garden; and in the garden a new sepulchre, wherein was never man yet laid."},"BSB":{"text":"Now there was a garden in the place where Jesus was crucified, and in the garden a new tomb in which no one had yet been laid."}},"definableWords":["garden","one"],"peopleInVerse":["Jesus"]},"42":{"text":"There laid they Jesus therefore because of the Jews’ preparation day; for the sepulchre was nigh at hand.","ref":"John 19:42","synthesized":"And because it was the Jewish day of Preparation and the tomb was nearby, they placed Jesus there.","sources":{"KJV":{"text":"There laid they Jesus therefore because of the Jews’ preparation day; for the sepulchre was nigh at hand."},"BSB":{"text":"And because it was the Jewish day of Preparation and the tomb was nearby, they placed Jesus there."}},"definableWords":["day"],"peopleInVerse":["Jesus"]}}},"20":{"chapter":"20","title":"THE EMPTY TOMB AND THOMAS","verses":{"1":{"text":"The first day of the week cometh Mary Magdalene early, when it was yet dark, unto the sepulchre, and seeth the stone taken away from the sepulchre.","ref":"John 20:1","synthesized":"Early on the first day of the week, while it was still dark, Mary Magdalene went to the tomb and saw that the stone had been removed from the entrance.","sources":{"KJV":{"text":"The first day of the week cometh Mary Magdalene early, when it was yet dark, unto the sepulchre, and seeth the stone taken away from the sepulchre."},"BSB":{"text":"Early on the first day of the week, while it was still dark, Mary Magdalene went to the tomb and saw that the stone had been removed from the entrance."}},"definableWords":["day","saw","stone"],"peopleInVerse":["Mary"],"kingdomLens":"Mary Magdalene comes to the tomb 'when it was yet dark' on the first day of the week. The stone is rolled away. Two angels sit where the body had been. Then Jesus speaks her name: 'Mary.' She turns and says 'Rabboni' (Aramaic: my Teacher). Of all the people Jesus could have appeared to first, he chose the woman from whom he cast seven demons. The first witness of the resurrection — in a culture that did not accept women's legal testimony — is a redeemed woman.","cultural":{"title":"The empty tomb","detail":"The Sabbath ended Saturday night. 'The first day of the week' became the Christian Sunday. The word 'Sunday' in many languages reflects this: domingo (Spanish, 'the Lord's Day').","sources":"SWRV Kingdom Study Protocol — synthesis from approved library (Rule 06)"}},"2":{"text":"Then she runneth, and cometh to Simon Peter, and to the other disciple, whom Jesus loved, and saith unto them, They have taken away the LORD out of the sepulchre, and we know not where they have laid him.","ref":"John 20:2","synthesized":"So she came running to Simon Peter and the other disciple, the one whom Jesus loved. “They have taken the Lord out of the tomb,” she said, “and we do not know where they have put Him!”","sources":{"KJV":{"text":"Then she runneth, and cometh to Simon Peter, and to the other disciple, whom Jesus loved, and saith unto them, They have taken away the LORD out of the sepulchre, and we know not where they have laid him."},"BSB":{"text":"So she came running to Simon Peter and the other disciple, the one whom Jesus loved. “They have taken the Lord out of the tomb,” she said, “and we do not know where they have put Him!”"}},"definableWords":["disciple","one","Lord"],"peopleInVerse":["Peter","Jesus"]},"3":{"text":"Peter therefore went forth, and that other disciple, and came to the sepulchre.","ref":"John 20:3","synthesized":"Then Peter and the other disciple set out for the tomb.","sources":{"KJV":{"text":"Peter therefore went forth, and that other disciple, and came to the sepulchre."},"BSB":{"text":"Then Peter and the other disciple set out for the tomb."}},"definableWords":["disciple"],"peopleInVerse":["Peter"]},"4":{"text":"So they ran both together: and the other disciple did outrun Peter, and came first to the sepulchre.","ref":"John 20:4","synthesized":"The two were running together, but the other disciple outran Peter and reached the tomb first.","sources":{"KJV":{"text":"So they ran both together: and the other disciple did outrun Peter, and came first to the sepulchre."},"BSB":{"text":"The two were running together, but the other disciple outran Peter and reached the tomb first."}},"definableWords":["disciple"],"peopleInVerse":["Peter"]},"5":{"text":"And he stooping down, and looking in, saw the linen clothes lying; yet went he not in.","ref":"John 20:5","synthesized":"He bent down and looked in at the linen cloths lying there, but he did not go in.","sources":{"KJV":{"text":"And he stooping down, and looking in, saw the linen clothes lying; yet went he not in."},"BSB":{"text":"He bent down and looked in at the linen cloths lying there, but he did not go in."}},"definableWords":[],"peopleInVerse":[]},"6":{"text":"Then cometh Simon Peter following him, and went into the sepulchre, and seeth the linen clothes lie,","ref":"John 20:6","synthesized":"Simon Peter arrived just after him. He entered the tomb and saw the linen cloths lying there.","sources":{"KJV":{"text":"Then cometh Simon Peter following him, and went into the sepulchre, and seeth the linen clothes lie,"},"BSB":{"text":"Simon Peter arrived just after him. He entered the tomb and saw the linen cloths lying there."}},"definableWords":["saw"],"peopleInVerse":["Peter"]},"7":{"text":"And the napkin, that was about his head, not lying with the linen clothes, but wrapped together in a place by itself.","ref":"John 20:7","synthesized":"The cloth that had been around Jesus’ head was rolled up, lying separate from the linen cloths.","sources":{"KJV":{"text":"And the napkin, that was about his head, not lying with the linen clothes, but wrapped together in a place by itself."},"BSB":{"text":"The cloth that had been around Jesus’ head was rolled up, lying separate from the linen cloths."}},"definableWords":[],"peopleInVerse":["Jesus"]},"8":{"text":"Then went in also that other disciple, which came first to the sepulchre, and he saw, and believed.","ref":"John 20:8","synthesized":"Then the other disciple, who had reached the tomb first, also went in. And he saw and believed.","sources":{"KJV":{"text":"Then went in also that other disciple, which came first to the sepulchre, and he saw, and believed."},"BSB":{"text":"Then the other disciple, who had reached the tomb first, also went in. And he saw and believed."}},"definableWords":["disciple","saw","believed"],"peopleInVerse":[]},"9":{"text":"For as yet they knew not the scripture, that he must rise again from the dead.","ref":"John 20:9","synthesized":"For they still did not understand from the Scripture that Jesus had to rise from the dead.","sources":{"KJV":{"text":"For as yet they knew not the scripture, that he must rise again from the dead."},"BSB":{"text":"For they still did not understand from the Scripture that Jesus had to rise from the dead."}},"definableWords":[],"peopleInVerse":["Jesus"]},"10":{"text":"Then the disciples went away again unto their own home.","ref":"John 20:10","synthesized":"Then the disciples returned to their homes.","sources":{"KJV":{"text":"Then the disciples went away again unto their own home."},"BSB":{"text":"Then the disciples returned to their homes."}},"definableWords":[],"peopleInVerse":[]},"11":{"text":"But Mary stood without at the sepulchre weeping: and as she wept, she stooped down, and looked into the sepulchre,","ref":"John 20:11","synthesized":"But Mary stood outside the tomb weeping. And as she wept, she bent down to look into the tomb,","sources":{"KJV":{"text":"But Mary stood without at the sepulchre weeping: and as she wept, she stooped down, and looked into the sepulchre,"},"BSB":{"text":"But Mary stood outside the tomb weeping. And as she wept, she bent down to look into the tomb,"}},"definableWords":[],"peopleInVerse":["Mary"]},"12":{"text":"And seeth two angels in white sitting, the one at the head, and the other at the feet, where the body of Jesus had lain.","ref":"John 20:12","synthesized":"and she saw two angels in white sitting where the body of Jesus had lain, one at the head and the other at the feet.","sources":{"KJV":{"text":"And seeth two angels in white sitting, the one at the head, and the other at the feet, where the body of Jesus had lain."},"BSB":{"text":"and she saw two angels in white sitting where the body of Jesus had lain, one at the head and the other at the feet."}},"definableWords":["saw","one"],"peopleInVerse":["Jesus"]},"13":{"text":"And they say unto her, Woman, why weepest thou? She saith unto them, Because they have taken away my LORD, and I know not where they have laid him.","ref":"John 20:13","synthesized":"“Woman, why are you weeping?” they asked.  “Because they have taken my Lord away,” she said, “and I do not know where they have put Him.”","sources":{"KJV":{"text":"And they say unto her, Woman, why weepest thou? She saith unto them, Because they have taken away my LORD, and I know not where they have laid him."},"BSB":{"text":"“Woman, why are you weeping?” they asked.  “Because they have taken my Lord away,” she said, “and I do not know where they have put Him.”"}},"definableWords":["woman","Lord"],"peopleInVerse":[]},"14":{"text":"And when she had thus said, she turned herself back, and saw Jesus standing, and knew not that it was Jesus.","ref":"John 20:14","synthesized":"When she had said this, she turned around and saw Jesus standing there; but she did not recognize that it was Jesus.","sources":{"KJV":{"text":"And when she had thus said, she turned herself back, and saw Jesus standing, and knew not that it was Jesus."},"BSB":{"text":"When she had said this, she turned around and saw Jesus standing there; but she did not recognize that it was Jesus."}},"definableWords":["saw"],"peopleInVerse":["Jesus"]},"15":{"text":"Jesus saith unto her, Woman, why weepest thou? whom seekest thou? She, supposing him to be the gardener, saith unto him, Sir, if thou have borne him hence, tell me where thou hast laid him, and I will take him away.","ref":"John 20:15","synthesized":"“Woman, why are you weeping?” Jesus asked. “Whom are you seeking?”  Thinking He was the gardener, she said, “Sir, if you have carried Him off, tell me where you have put Him, and I will get Him.”","sources":{"KJV":{"text":"Jesus saith unto her, Woman, why weepest thou? whom seekest thou? She, supposing him to be the gardener, saith unto him, Sir, if thou have borne him hence, tell me where thou hast laid him, and I will take him away."},"BSB":{"text":"“Woman, why are you weeping?” Jesus asked. “Whom are you seeking?”  Thinking He was the gardener, she said, “Sir, if you have carried Him off, tell me where you have put Him, and I will get Him.”"}},"definableWords":["woman"],"peopleInVerse":["Jesus"]},"16":{"text":"Jesus saith unto her, Mary. She turned herself, and saith unto him, Rabboni; which is to say, Master.","ref":"John 20:16","synthesized":"Jesus said to her, “Mary.”  She turned and said to Him in Hebrew, “Rabboni!” (which means “Teacher”).","sources":{"KJV":{"text":"Jesus saith unto her, Mary. She turned herself, and saith unto him, Rabboni; which is to say, Master."},"BSB":{"text":"Jesus said to her, “Mary.”  She turned and said to Him in Hebrew, “Rabboni!” (which means “Teacher”)."}},"definableWords":[],"peopleInVerse":["Jesus","Mary"]},"17":{"text":"Jesus saith unto her, Touch me not; for I am not yet ascended to my Father: but go to my brethren, and say unto them, I ascend unto my Father, and your Father; and to my God, and your God.","ref":"John 20:17","synthesized":"“Do not cling to Me,” Jesus said, “for I have not yet ascended to the Father. But go and tell My brothers, ‘I am ascending to My Father and your Father, to My God and your God.’”","sources":{"KJV":{"text":"Jesus saith unto her, Touch me not; for I am not yet ascended to my Father: but go to my brethren, and say unto them, I ascend unto my Father, and your Father; and to my God, and your God."},"BSB":{"text":"“Do not cling to Me,” Jesus said, “for I have not yet ascended to the Father. But go and tell My brothers, ‘I am ascending to My Father and your Father, to My God and your God.’”"}},"definableWords":["Father","God"],"peopleInVerse":["Jesus"]},"18":{"text":"Mary Magdalene came and told the disciples that she had seen the LORD, and that he had spoken these things unto her.","ref":"John 20:18","synthesized":"Mary Magdalene went and announced to the disciples, “I have seen the Lord!” And she told them what He had said to her.","sources":{"KJV":{"text":"Mary Magdalene came and told the disciples that she had seen the LORD, and that he had spoken these things unto her."},"BSB":{"text":"Mary Magdalene went and announced to the disciples, “I have seen the Lord!” And she told them what He had said to her."}},"definableWords":["Lord"],"peopleInVerse":["Mary"]},"19":{"text":"Then the same day at evening, being the first day of the week, when the doors were shut where the disciples were assembled for fear of the Jews, came Jesus and stood in the midst, and saith unto them, Peace be unto you.","ref":"John 20:19","synthesized":"It was the first day of the week, and that very evening, while the disciples were together with the doors locked for fear of the Jews, Jesus came and stood among them. “Peace be with you!” He said to them.","sources":{"KJV":{"text":"Then the same day at evening, being the first day of the week, when the doors were shut where the disciples were assembled for fear of the Jews, came Jesus and stood in the midst, and saith unto them, Peace be unto you."},"BSB":{"text":"It was the first day of the week, and that very evening, while the disciples were together with the doors locked for fear of the Jews, Jesus came and stood among them. “Peace be with you!” He said to them."}},"definableWords":["day","fear","peace"],"peopleInVerse":["Jesus"]},"20":{"text":"And when he had so said, he shewed unto them his hands and his side. Then were the disciples glad, when they saw the LORD.","ref":"John 20:20","synthesized":"After He had said this, He showed them His hands and His side.  The disciples rejoiced when they saw the Lord.","sources":{"KJV":{"text":"And when he had so said, he shewed unto them his hands and his side. Then were the disciples glad, when they saw the LORD."},"BSB":{"text":"After He had said this, He showed them His hands and His side.  The disciples rejoiced when they saw the Lord."}},"definableWords":["saw","Lord"],"peopleInVerse":[]},"21":{"text":"Then said Jesus to them again, Peace be unto you: as my Father hath sent me, even so send I you.","ref":"John 20:21","synthesized":"Again Jesus said to them, “Peace be with you. As the Father has sent Me, so also I am sending you.”","sources":{"KJV":{"text":"Then said Jesus to them again, Peace be unto you: as my Father hath sent me, even so send I you."},"BSB":{"text":"Again Jesus said to them, “Peace be with you. As the Father has sent Me, so also I am sending you.”"}},"definableWords":["peace","Father"],"peopleInVerse":["Jesus"]},"22":{"text":"And when he had said this, he breathed on them, and saith unto them, Receive ye the Holy Ghost:","ref":"John 20:22","synthesized":"When He had said this, He breathed on them and said, “Receive the Holy Spirit.","sources":{"KJV":{"text":"And when he had said this, he breathed on them, and saith unto them, Receive ye the Holy Ghost:"},"BSB":{"text":"When He had said this, He breathed on them and said, “Receive the Holy Spirit."}},"definableWords":["holy","Spirit"],"peopleInVerse":[]},"23":{"text":"Whose soever sins ye remit, they are remitted unto them; and whose soever sins ye retain, they are retained.","ref":"John 20:23","synthesized":"If you forgive anyone his sins, they are forgiven; if you withhold forgiveness from anyone, it is withheld.”","sources":{"KJV":{"text":"Whose soever sins ye remit, they are remitted unto them; and whose soever sins ye retain, they are retained."},"BSB":{"text":"If you forgive anyone his sins, they are forgiven; if you withhold forgiveness from anyone, it is withheld.”"}},"definableWords":["forgive"],"peopleInVerse":[]},"24":{"text":"But Thomas, one of the twelve, called Didymus, was not with them when Jesus came.","ref":"John 20:24","synthesized":"Now Thomas called Didymus, one of the Twelve, was not with the disciples when Jesus came.","sources":{"KJV":{"text":"But Thomas, one of the twelve, called Didymus, was not with them when Jesus came."},"BSB":{"text":"Now Thomas called Didymus, one of the Twelve, was not with the disciples when Jesus came."}},"definableWords":["one"],"peopleInVerse":["Jesus"]},"25":{"text":"The other disciples therefore said unto him, We have seen the LORD. But he said unto them, Except I shall see in his hands the print of the nails, and put my finger into the print of the nails, and thrust my hand into his side, I will not believe.","ref":"John 20:25","synthesized":"So the other disciples told him, “We have seen the Lord!”  But he replied, “Unless I see the nail marks in His hands, and put my finger where the nails have been, and put my hand into His side, I will never believe.”","sources":{"KJV":{"text":"The other disciples therefore said unto him, We have seen the LORD. But he said unto them, Except I shall see in his hands the print of the nails, and put my finger into the print of the nails, and thrust my hand into his side, I will not believe."},"BSB":{"text":"So the other disciples told him, “We have seen the Lord!”  But he replied, “Unless I see the nail marks in His hands, and put my finger where the nails have been, and put my hand into His side, I will never believe.”"}},"definableWords":["Lord","see"],"peopleInVerse":[]},"26":{"text":"And after eight days again his disciples were within, and Thomas with them: then came Jesus, the doors being shut, and stood in the midst, and said, Peace be unto you.","ref":"John 20:26","synthesized":"Eight days later, His disciples were once again inside with the doors locked, and Thomas was with them. Jesus came and stood among them and said, “Peace be with you.”","sources":{"KJV":{"text":"And after eight days again his disciples were within, and Thomas with them: then came Jesus, the doors being shut, and stood in the midst, and said, Peace be unto you."},"BSB":{"text":"Eight days later, His disciples were once again inside with the doors locked, and Thomas was with them. Jesus came and stood among them and said, “Peace be with you.”"}},"definableWords":["days","peace"],"peopleInVerse":["Jesus"]},"27":{"text":"Then saith he to Thomas, Reach hither thy finger, and behold my hands; and reach hither thy hand, and thrust it into my side: and be not faithless, but believing.","ref":"John 20:27","synthesized":"Then Jesus said to Thomas, “Put your finger here and look at My hands. Reach out your hand and put it into My side. Stop doubting and believe.”","sources":{"KJV":{"text":"Then saith he to Thomas, Reach hither thy finger, and behold my hands; and reach hither thy hand, and thrust it into my side: and be not faithless, but believing."},"BSB":{"text":"Then Jesus said to Thomas, “Put your finger here and look at My hands. Reach out your hand and put it into My side. Stop doubting and believe.”"}},"definableWords":[],"peopleInVerse":["Jesus"]},"28":{"text":"And Thomas answered and said unto him, My LORD and my God.","ref":"John 20:28","synthesized":"Thomas replied, “My Lord and my God!”","sources":{"KJV":{"text":"And Thomas answered and said unto him, My LORD and my God."},"BSB":{"text":"Thomas replied, “My Lord and my God!”"}},"definableWords":["Lord","God"],"peopleInVerse":[]},"29":{"text":"Jesus saith unto him, Thomas, because thou hast seen me, thou hast believed: blessed are they that have not seen, and yet have believed.","ref":"John 20:29","synthesized":"Jesus said to him, “Because you have seen Me, you have believed; blessed are those who have not seen and yet have believed.”","sources":{"KJV":{"text":"Jesus saith unto him, Thomas, because thou hast seen me, thou hast believed: blessed are they that have not seen, and yet have believed."},"BSB":{"text":"Jesus said to him, “Because you have seen Me, you have believed; blessed are those who have not seen and yet have believed.”"}},"definableWords":["believed","blessed"],"peopleInVerse":["Jesus"]},"30":{"text":"And many other signs truly did Jesus in the presence of his disciples, which are not written in this book:","ref":"John 20:30","synthesized":"Jesus performed many other signs in the presence of His disciples, which are not written in this book.","sources":{"KJV":{"text":"And many other signs truly did Jesus in the presence of his disciples, which are not written in this book:"},"BSB":{"text":"Jesus performed many other signs in the presence of His disciples, which are not written in this book."}},"definableWords":[],"peopleInVerse":["Jesus"]},"31":{"text":"But these are written, that ye might believe that Jesus is the Christ, the Son of God; and that believing ye might have life through his name.","ref":"John 20:31","synthesized":"But these are written so that you may believe that Jesus is the Christ, the Son of God, and that by believing you may have life in His name.","sources":{"KJV":{"text":"But these are written, that ye might believe that Jesus is the Christ, the Son of God; and that believing ye might have life through his name."},"BSB":{"text":"But these are written so that you may believe that Jesus is the Christ, the Son of God, and that by believing you may have life in His name."}},"definableWords":["Christ","Son","God","life","name"],"peopleInVerse":["Jesus"]}}},"21":{"chapter":"21","title":"FEED MY SHEEP","verses":{"1":{"text":"After these things Jesus shewed himself again to the disciples at the sea of Tiberias; and on this wise shewed he himself.","ref":"John 21:1","synthesized":"Later, by the Sea of Tiberias, Jesus again revealed Himself to the disciples. He made Himself known in this way:","sources":{"KJV":{"text":"After these things Jesus shewed himself again to the disciples at the sea of Tiberias; and on this wise shewed he himself."},"BSB":{"text":"Later, by the Sea of Tiberias, Jesus again revealed Himself to the disciples. He made Himself known in this way:"}},"definableWords":["sea","made","way"],"peopleInVerse":["Jesus"]},"2":{"text":"There were together Simon Peter, and Thomas called Didymus, and Nathanael of Cana in Galilee, and the sons of Zebedee, and two other of his disciples.","ref":"John 21:2","synthesized":"Simon Peter, Thomas called Didymus, Nathanael from Cana in Galilee, the sons of Zebedee, and two other disciples were together.","sources":{"KJV":{"text":"There were together Simon Peter, and Thomas called Didymus, and Nathanael of Cana in Galilee, and the sons of Zebedee, and two other of his disciples."},"BSB":{"text":"Simon Peter, Thomas called Didymus, Nathanael from Cana in Galilee, the sons of Zebedee, and two other disciples were together."}},"definableWords":["Galilee","sons"],"peopleInVerse":["Peter"]},"3":{"text":"Simon Peter saith unto them, I go a fishing. They say unto him, We also go with thee. They went forth, and entered into a ship immediately; and that night they caught nothing.","ref":"John 21:3","synthesized":"Simon Peter told them, “I am going fishing.”  “We will go with you,” they said. So they went out and got into the boat, but caught nothing that night.","sources":{"KJV":{"text":"Simon Peter saith unto them, I go a fishing. They say unto him, We also go with thee. They went forth, and entered into a ship immediately; and that night they caught nothing."},"BSB":{"text":"Simon Peter told them, “I am going fishing.”  “We will go with you,” they said. So they went out and got into the boat, but caught nothing that night."}},"definableWords":["night"],"peopleInVerse":["Peter"]},"4":{"text":"But when the morning was now come, Jesus stood on the shore: but the disciples knew not that it was Jesus.","ref":"John 21:4","synthesized":"Early in the morning, Jesus stood on the shore, but the disciples did not recognize that it was Jesus.","sources":{"KJV":{"text":"But when the morning was now come, Jesus stood on the shore: but the disciples knew not that it was Jesus."},"BSB":{"text":"Early in the morning, Jesus stood on the shore, but the disciples did not recognize that it was Jesus."}},"definableWords":[],"peopleInVerse":["Jesus"]},"5":{"text":"Then Jesus saith unto them, Children, have ye any meat? They answered him, No.","ref":"John 21:5","synthesized":"So He called out to them, “Children, do you have any fish?”  “No,” they answered.","sources":{"KJV":{"text":"Then Jesus saith unto them, Children, have ye any meat? They answered him, No."},"BSB":{"text":"So He called out to them, “Children, do you have any fish?”  “No,” they answered."}},"definableWords":["fish"],"peopleInVerse":[]},"6":{"text":"And he said unto them, Cast the net on the right side of the ship, and ye shall find. They cast therefore, and now they were not able to draw it for the multitude of fishes.","ref":"John 21:6","synthesized":"He told them, “Cast the net on the right side of the boat, and you will find some.” So they cast it there, and they were unable to haul it in because of the great number of fish.","sources":{"KJV":{"text":"And he said unto them, Cast the net on the right side of the ship, and ye shall find. They cast therefore, and now they were not able to draw it for the multitude of fishes."},"BSB":{"text":"He told them, “Cast the net on the right side of the boat, and you will find some.” So they cast it there, and they were unable to haul it in because of the great number of fish."}},"definableWords":["great","fish"],"peopleInVerse":[]},"7":{"text":"Therefore that disciple whom Jesus loved saith unto Peter, It is the Lord. Now when Simon Peter heard that it was the Lord, he girt his fisher’s coat unto him, (for he was naked,) and did cast himself into the sea.","ref":"John 21:7","synthesized":"Then the disciple whom Jesus loved said to Peter, “It is the Lord!” As soon as Simon Peter heard that it was the Lord, he put on his outer garment (for he had removed it) and jumped into the sea.","sources":{"KJV":{"text":"Therefore that disciple whom Jesus loved saith unto Peter, It is the Lord. Now when Simon Peter heard that it was the Lord, he girt his fisher’s coat unto him, (for he was naked,) and did cast himself into the sea."},"BSB":{"text":"Then the disciple whom Jesus loved said to Peter, “It is the Lord!” As soon as Simon Peter heard that it was the Lord, he put on his outer garment (for he had removed it) and jumped into the sea."}},"definableWords":["disciple","Lord","sea"],"peopleInVerse":["Jesus","Peter"]},"8":{"text":"And the other disciples came in a little ship; (for they were not far from land, but as it were two hundred cubits,) dragging the net with fishes.","ref":"John 21:8","synthesized":"The other disciples came ashore in the boat. They dragged in the net full of fish, for they were not far from land, only about a hundred yards.","sources":{"KJV":{"text":"And the other disciples came in a little ship; (for they were not far from land, but as it were two hundred cubits,) dragging the net with fishes."},"BSB":{"text":"The other disciples came ashore in the boat. They dragged in the net full of fish, for they were not far from land, only about a hundred yards."}},"definableWords":["fish","land"],"peopleInVerse":[]},"9":{"text":"As soon then as they were come to land, they saw a fire of coals there, and fish laid thereon, and bread.","ref":"John 21:9","synthesized":"When they landed, they saw a charcoal fire there with fish on it, and some bread.","sources":{"KJV":{"text":"As soon then as they were come to land, they saw a fire of coals there, and fish laid thereon, and bread."},"BSB":{"text":"When they landed, they saw a charcoal fire there with fish on it, and some bread."}},"definableWords":["saw","fish"],"peopleInVerse":[]},"10":{"text":"Jesus saith unto them, Bring of the fish which ye have now caught.","ref":"John 21:10","synthesized":"Jesus told them, “Bring some of the fish you have just caught.”","sources":{"KJV":{"text":"Jesus saith unto them, Bring of the fish which ye have now caught."},"BSB":{"text":"Jesus told them, “Bring some of the fish you have just caught.”"}},"definableWords":["fish"],"peopleInVerse":["Jesus"]},"11":{"text":"Simon Peter went up, and drew the net to land full of great fishes, an hundred and fifty and three: and for all there were so many, yet was not the net broken.","ref":"John 21:11","synthesized":"So Simon Peter went aboard and dragged the net ashore. It was full of large fish, 153, but even with so many, the net was not torn.","sources":{"KJV":{"text":"Simon Peter went up, and drew the net to land full of great fishes, an hundred and fifty and three: and for all there were so many, yet was not the net broken."},"BSB":{"text":"So Simon Peter went aboard and dragged the net ashore. It was full of large fish, 153, but even with so many, the net was not torn."}},"definableWords":["fish"],"peopleInVerse":["Peter"]},"12":{"text":"Jesus saith unto them, Come and dine. And none of the disciples durst ask him, Who art thou? knowing that it was the Lord.","ref":"John 21:12","synthesized":"“Come, have breakfast,” Jesus said to them. None of the disciples dared to ask Him, “Who are You?” They knew it was the Lord.","sources":{"KJV":{"text":"Jesus saith unto them, Come and dine. And none of the disciples durst ask him, Who art thou? knowing that it was the Lord."},"BSB":{"text":"“Come, have breakfast,” Jesus said to them. None of the disciples dared to ask Him, “Who are You?” They knew it was the Lord."}},"definableWords":["Lord"],"peopleInVerse":["Jesus"]},"13":{"text":"Jesus then cometh, and taketh bread, and giveth them, and fish likewise.","ref":"John 21:13","synthesized":"Jesus came and took the bread and gave it to them, and He did the same with the fish.","sources":{"KJV":{"text":"Jesus then cometh, and taketh bread, and giveth them, and fish likewise."},"BSB":{"text":"Jesus came and took the bread and gave it to them, and He did the same with the fish."}},"definableWords":["fish"],"peopleInVerse":["Jesus"]},"14":{"text":"This is now the third time that Jesus shewed himself to his disciples, after that he was risen from the dead.","ref":"John 21:14","synthesized":"This was now the third time that Jesus appeared to the disciples after He was raised from the dead.","sources":{"KJV":{"text":"This is now the third time that Jesus shewed himself to his disciples, after that he was risen from the dead."},"BSB":{"text":"This was now the third time that Jesus appeared to the disciples after He was raised from the dead."}},"definableWords":[],"peopleInVerse":["Jesus"]},"15":{"text":"So when they had dined, Jesus saith to Simon Peter, Simon, son of Jonas, lovest thou me more than these? He saith unto him, Yea, Lord; thou knowest that I love thee. He saith unto him, Feed my lambs.","ref":"John 21:15","synthesized":"When they had finished eating, Jesus asked Simon Peter, “Simon son of John, do you love Me more than these?”  “Yes, Lord,” he answered, “You know I love You.”  Jesus replied, “Feed My lambs.”","sources":{"KJV":{"text":"So when they had dined, Jesus saith to Simon Peter, Simon, son of Jonas, lovest thou me more than these? He saith unto him, Yea, Lord; thou knowest that I love thee. He saith unto him, Feed my lambs."},"BSB":{"text":"When they had finished eating, Jesus asked Simon Peter, “Simon son of John, do you love Me more than these?”  “Yes, Lord,” he answered, “You know I love You.”  Jesus replied, “Feed My lambs.”"}},"definableWords":["son","love","Lord"],"peopleInVerse":["Jesus","Peter","John"]},"16":{"text":"He saith to him again the second time, Simon, son of Jonas, lovest thou me? He saith unto him, Yea, Lord; thou knowest that I love thee. He saith unto him, Feed my sheep.","ref":"John 21:16","synthesized":"Jesus asked a second time, “Simon son of John, do you love Me?”  “Yes, Lord,” he answered, “You know I love You.”  Jesus told him, “Shepherd My sheep.”","sources":{"KJV":{"text":"He saith to him again the second time, Simon, son of Jonas, lovest thou me? He saith unto him, Yea, Lord; thou knowest that I love thee. He saith unto him, Feed my sheep."},"BSB":{"text":"Jesus asked a second time, “Simon son of John, do you love Me?”  “Yes, Lord,” he answered, “You know I love You.”  Jesus told him, “Shepherd My sheep.”"}},"definableWords":["son","love","Lord","shepherd"],"peopleInVerse":["Jesus","John"]},"17":{"text":"He saith unto him the third time, Simon, son of Jonas, lovest thou me? Peter was grieved because he said unto him the third time, Lovest thou me? And he said unto him, Lord, thou knowest all things; thou knowest that I love thee. Jesus saith unto him, Feed my sheep.","ref":"John 21:17","synthesized":"Jesus asked a third time, “Simon son of John, do you love Me?”  Peter was deeply hurt that Jesus had asked him a third time, “Do you love Me?”  “Lord, You know all things,” he replied. “You know I love You.”  Jesus said to him, “Feed My sheep.","sources":{"KJV":{"text":"He saith unto him the third time, Simon, son of Jonas, lovest thou me? Peter was grieved because he said unto him the third time, Lovest thou me? And he said unto him, Lord, thou knowest all things; thou knowest that I love thee. Jesus saith unto him, Feed my sheep."},"BSB":{"text":"Jesus asked a third time, “Simon son of John, do you love Me?”  Peter was deeply hurt that Jesus had asked him a third time, “Do you love Me?”  “Lord, You know all things,” he replied. “You know I love You.”  Jesus said to him, “Feed My sheep."}},"definableWords":["son","love","Lord"],"peopleInVerse":["Jesus","John","Peter"]},"18":{"text":"Verily, verily, I say unto thee, When thou wast young, thou girdedst thyself, and walkedst whither thou wouldest: but when thou shalt be old, thou shalt stretch forth thy hands, and another shall gird thee, and carry thee whither thou wouldest not.","ref":"John 21:18","synthesized":"Truly, truly, I tell you, when you were young, you dressed yourself and walked where you wanted; but when you are old, you will stretch out your hands, and someone else will dress you and lead you where you do not want to go.”","sources":{"KJV":{"text":"Verily, verily, I say unto thee, When thou wast young, thou girdedst thyself, and walkedst whither thou wouldest: but when thou shalt be old, thou shalt stretch forth thy hands, and another shall gird thee, and carry thee whither thou wouldest not."},"BSB":{"text":"Truly, truly, I tell you, when you were young, you dressed yourself and walked where you wanted; but when you are old, you will stretch out your hands, and someone else will dress you and lead you where you do not want to go.”"}},"definableWords":["walked"],"peopleInVerse":[]},"19":{"text":"This spake he, signifying by what death he should glorify God. And when he had spoken this, he saith unto him, Follow me.","ref":"John 21:19","synthesized":"Jesus said this to indicate the kind of death by which Peter would glorify God.  And after He had said this, He told him, “Follow Me.”","sources":{"KJV":{"text":"This spake he, signifying by what death he should glorify God. And when he had spoken this, he saith unto him, Follow me."},"BSB":{"text":"Jesus said this to indicate the kind of death by which Peter would glorify God.  And after He had said this, He told him, “Follow Me.”"}},"definableWords":["death","God"],"peopleInVerse":["Jesus","Peter"]},"20":{"text":"Then Peter, turning about, seeth the disciple whom Jesus loved following; which also leaned on his breast at supper, and said, Lord, which is he that betrayeth thee?","ref":"John 21:20","synthesized":"Peter turned and saw the disciple whom Jesus loved following them. He was the one who had leaned back against Jesus at the supper to ask, “Lord, who is going to betray You?”","sources":{"KJV":{"text":"Then Peter, turning about, seeth the disciple whom Jesus loved following; which also leaned on his breast at supper, and said, Lord, which is he that betrayeth thee?"},"BSB":{"text":"Peter turned and saw the disciple whom Jesus loved following them. He was the one who had leaned back against Jesus at the supper to ask, “Lord, who is going to betray You?”"}},"definableWords":["saw","disciple","one","Lord"],"peopleInVerse":["Peter","Jesus"]},"21":{"text":"Peter seeing him saith to Jesus, Lord, and what shall this man do?","ref":"John 21:21","synthesized":"When Peter saw him, he asked, “Lord, what about him?”","sources":{"KJV":{"text":"Peter seeing him saith to Jesus, Lord, and what shall this man do?"},"BSB":{"text":"When Peter saw him, he asked, “Lord, what about him?”"}},"definableWords":["saw","Lord"],"peopleInVerse":["Peter"]},"22":{"text":"Jesus saith unto him, If I will that he tarry till I come, what is that to thee? follow thou me.","ref":"John 21:22","synthesized":"Jesus answered, “If I want him to remain until I return, what is that to you? You follow Me!”","sources":{"KJV":{"text":"Jesus saith unto him, If I will that he tarry till I come, what is that to thee? follow thou me."},"BSB":{"text":"Jesus answered, “If I want him to remain until I return, what is that to you? You follow Me!”"}},"definableWords":[],"peopleInVerse":["Jesus"]},"23":{"text":"Then went this saying abroad among the brethren, that that disciple should not die: yet Jesus said not unto him, He shall not die; but, If I will that he tarry till I come, what is that to thee?","ref":"John 21:23","synthesized":"Because of this, the rumor spread among the brothers that this disciple would not die. However, Jesus did not say that he would not die, but only, “If I want him to remain until I return, what is that to you?”","sources":{"KJV":{"text":"Then went this saying abroad among the brethren, that that disciple should not die: yet Jesus said not unto him, He shall not die; but, If I will that he tarry till I come, what is that to thee?"},"BSB":{"text":"Because of this, the rumor spread among the brothers that this disciple would not die. However, Jesus did not say that he would not die, but only, “If I want him to remain until I return, what is that to you?”"}},"definableWords":["disciple","die"],"peopleInVerse":["Jesus"]},"24":{"text":"This is the disciple which testifieth of these things, and wrote these things: and we know that his testimony is true.","ref":"John 21:24","synthesized":"This is the disciple who testifies to these things and who has written them down. And we know that his testimony is true.","sources":{"KJV":{"text":"This is the disciple which testifieth of these things, and wrote these things: and we know that his testimony is true."},"BSB":{"text":"This is the disciple who testifies to these things and who has written them down. And we know that his testimony is true."}},"definableWords":["disciple"],"peopleInVerse":[]},"25":{"text":"And there are also many other things which Jesus did, the which, if they should be written every one, I suppose that even the world itself could not contain the books that should be written. Amen.","ref":"John 21:25","synthesized":"There are many more things that Jesus did. If all of them were written down, I suppose that not even the world itself would have space for the books that would be written.","sources":{"KJV":{"text":"And there are also many other things which Jesus did, the which, if they should be written every one, I suppose that even the world itself could not contain the books that should be written. Amen."},"BSB":{"text":"There are many more things that Jesus did. If all of them were written down, I suppose that not even the world itself would have space for the books that would be written."}},"definableWords":[],"peopleInVerse":["Jesus"]}}}};